window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["s"]={"Stanisław": "<b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Szymon": "<b>Szymon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim’on</i>, lub <i><b>שִׁמְעוֹן</b></i> <i>Szime’on</i>, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wysłuchał”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, biblijnego. Początkowo stosowana w polskich przekładach Biblii forma tego imienia <b>Symeon</b> to rzadziej dziś używana forma, bardziej rozpowszechniona na Wschodzie. Niektórzy autorzy uznają imię za greckie, widząc w nim bądź tylko zhellenizowaną formę semickiego Szimeon, bądź rzeczywiste imię pochodzenia greckiego. W <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiografii</a> istnieje podział na świętych o imieniu <b>Szymon</b> i <b>Symeon</b> będącego oboczną formą pierwszego imienia.", "Sebastian": "<b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Sławomir": "<b>Sławomir</b>, <b>Sławimir</b>, <b>Sławomier</b>, <b>Sławmir</b> – staropolskie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Sławo-</i> („sława, sławić”) i <i>-mir</i> („pokój, spokój, dobro, świat”). Imię to prawdopodobnie znaczyło tyle, co „ten, który zdobywa sławę poprzez pokój, pokojowe zachowanie, zaprowadzanie porządku, spokoju” (w przeciwieństwie do imion typu <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, w których sława zdobywana jest w walce).", "Stefan": "<b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sylwester": "<b>Sylwester</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>silvestris</em> oznaczającego „żyjący w lesie”, „dziki”. Poświadczone w Polsce od 1220 roku. Dawniej uważano, że imię <a href=\"https://pl.wikipedia.org/wiki/Lasota_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lasota</a> powstało jako odpowiednik znaczeniowy Sylwestra, jednak Lasota jest poświadczony na ziemiach polskich w dokumentach wcześniej i był szerzej nadawany. Odnotowano dziesięciu świętych Sylwestrów, patronów tego imienia.", "Serhii": "<p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Szczepan": "<b>Szczepan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pierwotna spolonizowana forma greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>, przejęta do polszczyzny w czasach najdawniejszych, jeszcze przed ustaleniem się w języku polskim spółgłoski <i><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">f</a></i> – która była wówczas zastępowana przez <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[p]</a> lub <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[b]</a> (tę drugą w zapożyczeniach niemieckich lub w wyrazach przejętych za niemieckim pośrednictwem) – w brzmieniu <b>Szczepan</b> i dopiero wtórnie sprowadzona do języka polskiego w brzmieniu <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Seweryn": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Siarhei": "<p>Siarhei, Siarhiej, Syarhei lub Syarhey (bieloruski: Сяргей) to białoruska transkrypcja słowiańskiego męskiego nazwiska Sergey. Do znanych osób z nazwiska należą: Siarhei Charnou (ur. 1979), białoruski biegacz wyścigowy Siarhiej Dubaviec (ur. 1959), białorska dziennikarka Siarhei Kukharenka (ur. 1976), białoruška judoka Siarhei Lahun (1988-2011), białoruskie ciężarosta Siarhei Navumchyk (ur. 1961), białorowski dziennikarz i polityk...</p>", "Samuel": "<b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Stepan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sergiusz": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Sergii": "<p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Sviatoslav": "<p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Serghei": "<p>Serghei to rumuńskojęzyczne imię i nazwisko mężczyzny: Serghei Alexeev Serghei Cleșcenco Serghei Covalciuc SergheiCovaliov Serghei Donico-Iordăchescu Serghei Dubrovin Serghei Gafina Serghei Gheorghiev Serghei Lașcencov Serghei Marghiev Sergei Mariniuc Serghey Namașco Sergheu Nicolau Serghei Pașcenco Sergei Pogreban Serghei Rogaciov Serghey Stolearenco Serghey Stroenco Serghei Țvetcov i rumuńska nazwisko: Larion Serghei Valentina Serghea Vasile...</p>", "Simon": "<p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Sergiy": "<p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Sergei": "<p>Sergius to męskie imię pochodzenia starożytnego Rzymu po nazwie łacińskiej geny Sergia lub Sergii w czasach królewskich i republikańskich. Jest to powszechne chrześcijańskie imię, na cześć św. Sergiusa, i było to imię czterech papieży.</p>", "Sergiu": "<p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Santiago": "<p>Santiago (lat. Santiago) - rodzaj pszczół, z plemienia Eucerini rodziny Apidae.</p>", "Steven": "<p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Stanislaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Stephen": "<p>Stephen Hawking Stephen King Stephen Harper może odnosić się do:</p>", "Serafin": "<b>Serafin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego \"płomienny\". Nazwa często spotykana w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Stanley": "<p>Edward Smith-Stanley, 13. gróf Derby (21 kwietnia 1775 - 30 czerwca 1851; w latach 1776-1832 jego tytuł zapisywany był jako Lord Stanley, w latach 1832-1834 - jako The Lord Stanley) - brytyjski polityk, naturalista, землевладелец i kolekcjoner. W jego cześć nazwano chińskiego papuga z kościami.</p>", "Sean": "<b>Jan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἰωάννης od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> rdzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;יחנ&#8206; – łaska) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Po <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajsku</a> יוחנן (<i>Johanan</i>) oznacza „Jahwe jest łaskawy”. Według <a href=\"https://pl.wikipedia.org/wiki/Ewangelia\" target=\"_blank\" rel=\"noopener noreferrer\">Ewangelii</a> imię to nosił <a href=\"https://pl.wikipedia.org/wiki/Prorok\" target=\"_blank\" rel=\"noopener noreferrer\">prorok</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Aposto%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">apostoł</a> <a href=\"https://pl.wikipedia.org/wiki/Jan_Ewangelista\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Ewangelista</a>. Zostało ono przejęte najpierw do greki, a potem do łaciny. Rozpowszechniło się we wszystkich krajach <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskich</a>.", "Szczęsny": "<b>Szczęsny</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a>, po raz pierwszy notowane w <a href=\"https://pl.wikipedia.org/wiki/1422\" target=\"_blank\" rel=\"noopener noreferrer\">1422</a> roku. Wywodzi się od słowa „szczęśliwy” i jest uważane za odpowiednik znaczeniowy <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Feliks\" target=\"_blank\" rel=\"noopener noreferrer\">Feliks</a> i greckiego <a href=\"https://pl.wikipedia.org/wiki/Makary\" target=\"_blank\" rel=\"noopener noreferrer\">Makary</a>. Patronem tego imienia jest święty <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Szcz%C4%99sny_Feli%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt Szczęsny Feliński</a>, wspominany <a href=\"https://pl.wikipedia.org/wiki/17_wrze%C5%9Bnia\" target=\"_blank\" rel=\"noopener noreferrer\">17 września</a>.", "Sambor": "<b>Sambor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie, złożone z członów <i>Sam-</i> („samotny”) oraz <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „walczącego samotnie”.", "Shota": "<p>Sётакон (jap. ショタコン) - genr w mangach i anime, przedstawiający romantyczne i seksualne relacje z udziałem małych chłopców.</p>", "Sylweriusz": "<b>Sylweriusz</b>, <b>Sylwery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Sylweriusz_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">papież Sylweriusz</a>.", "Sobiesław": "Imię <i>Sobiesław</i> jest przykładem <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskiego</a>, złożonego, osobowego imienia dwuczłonowego, które jest <a href=\"https://pl.wikipedia.org/wiki/Relikt\" target=\"_blank\" rel=\"noopener noreferrer\">reliktem</a> <a href=\"https://pl.wikipedia.org/wiki/Poganie\" target=\"_blank\" rel=\"noopener noreferrer\">pogańskich</a> imion używanych we wczesnym średniowieczu przez <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian</a>. Składa się z członu <i>Sobie-</i> i <i>-sław</i> („sława”). Oznacza „zachowujący sławę dla siebie” lub „zapracowujący na sławę dla siebie”. <a href=\"https://pl.wikipedia.org/wiki/Witold_Taszycki\" target=\"_blank\" rel=\"noopener noreferrer\">Witold Taszycki</a> zaliczył je do grupy najstarszych polskich imion osobowych&#8201;.", "Sven": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Scott": "<p>Scott (ang. Scott) - nazwisko pochodzenia szkockiego, a także imię i toponim.</p>", "Sylwiusz": "Imię pochodzenia łacińskiego od słowa silvio oznaczającego: leśny, dziki, żyjący w lesie.", "Sandro": "<p>Sandro (lat. Sandro) - rodzaj raka, jedyny w rodzinie Sandroidae z oddziału bokopłynów (Crangonyctoidea, Gammarida). Endemiczne źródła słodkowodne i jaskini w Madagaskarze.</p>", "Salvatore": "<p>⁇ Salvatore ⁇ (z włoski - ⁇ Zbawiciel ⁇) - piosenka amerykańskiej piosenkarki Lany Del Rey w czwartym albumie studiowym Honeymoon.</p>", "Saba": "<b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Saturnin": "<b>Saturnin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od imienia boga rolnictwa <a href=\"https://pl.wikipedia.org/wiki/Saturn_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Saturna</a>. Wśród patronów – <a href=\"https://pl.wikipedia.org/wiki/Saturnin_z_Tuluzy\" target=\"_blank\" rel=\"noopener noreferrer\">św. Saturnin</a>, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>) i inni liczni święci.", "Stephan": "<p>Christian-Friedrich Stephan, lub Stefan (niem. Christian Friedrich Stephan, 1757, Leipzig - 17 grudnia 1814, Sankt-Petersburg) - rosyjski botanik pochodzenia niemieckiego.</p>", "Siergiej": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Solomon": "<p>Salomon (lat. שׁלֹמֹה, Shlomoh; greck. Σολομών Solomōn), lub Salomon, również nazywany Jedidiah (Hebraj. יְדִידְיָהּ), jest w Biblii Hebraicznej (1 Królów: 1 Królów 1-11, Kronik: 1 Kroników 28-29, 2 Kroników 1-9), w Biblii Koranu i, zgodnie z Księgą Krótków, królem. Jesteś synem Davida.</p>", "Sławek": "<p>Sławek to polskie imię i nazwisko pochodzące od niego. Nazwa jest diminutiwem od wszystkich nazw z rzęskiem -sław- (Mirosław, Sławomir itp.).</p>", "Symeon": "<b>Szymon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim’on</i>, lub <i><b>שִׁמְעוֹן</b></i> <i>Szime’on</i>, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wysłuchał”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, biblijnego. Początkowo stosowana w polskich przekładach Biblii forma tego imienia <b>Symeon</b> to rzadziej dziś używana forma, bardziej rozpowszechniona na Wschodzie. Niektórzy autorzy uznają imię za greckie, widząc w nim bądź tylko zhellenizowaną formę semickiego Szimeon, bądź rzeczywiste imię pochodzenia greckiego. W <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiografii</a> istnieje podział na świętych o imieniu <b>Szymon</b> i <b>Symeon</b> będącego oboczną formą pierwszego imienia.", "Stiven": "<p>- To męskie imię. Wśród znanych osób z nazwiskiem jest: Stiven Bibo, albanianki piłkarz Steve Burtt Jr.</p>", "Svyatoslav": "<p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Shmuel": "<p>Szmuel lub Schmuel to nowoczesna hebrajska forma imienia Samuela. Szmuel i jego odmiany mogą odnosić się do: Samuela (Biblia), hebrajskiego biblijnego proroka Księgi Samuela, księgi Tanach Shmuela Hakatana, Tanna (mistrza Mishnaic) Samuela Nehardea, Amora (mistrz Talmudic)</p>", "Siegfried": "<p>Siegfried - austriacki zespół muzyczny, który wykonuje swoją muzykę w kierunku epicznego vikingowego metalu.</p>", "Stuart": "<p>John Stuart, 3 r. Earl of Bute (w języku angielskim John Stuart, 25 maja 1713 - 10 marca 1792) - szkocki szlachetny i angielski urzędnik państwowy, premier Wielkiej Brytanii (z 1762 do 1763 r.), pierwszy Szkocjanin na stanowisku premiera po akcie o Zjednoczeniu 1707 r.</p>", "Sagar": "<p>Sagar może być: Miasto Sagar w stanie Madhya Pradesh w Indiach. Sagar, w stanie Madhya Pradesh, India.</p>", "Samson": "<b>Samson</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Szimszon, שִׁמְשׁוֹן, co pochodzi od słowa <i>szemesz</i> – „słońce”, lub <i>szamen</i> – „silny”, „siłacz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> شمشون, wym. Szamszun) – ostatni z Sędziów opisanych w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowej</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Księdze Sędziów</i></a> r. 13-16. Trzeci zaś licząc od końca dla <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego Izraela</a>; po nim sędziami byli <a href=\"https://pl.wikipedia.org/wiki/Heli\" target=\"_blank\" rel=\"noopener noreferrer\">Heli</a> i <a href=\"https://pl.wikipedia.org/wiki/Samuel_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel</a>. W przeciwieństwie do wielu postaci opisanych w Starym Testamencie, nie jest wymieniony w <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranie</a>. Jako jedyny sędzia w Księdze Sędziów wybrany przez Boga przed narodzeniem do roli, którą miał spełnić i to bez wcześniejszych próśb ludu o ratunek. Jego wyjątkowość poświadcza zrodzenie z niepłodnej (jak <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaak</a>, Samuel czy <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a>). Był obdarzony nadludzką siłą, którą wykorzystywał do walki z wrogami Izraela – <a href=\"https://pl.wikipedia.org/wiki/Filistyni\" target=\"_blank\" rel=\"noopener noreferrer\">Filistynami</a>. Dokonywał czynów niemożliwych dla zwykłych ludzi: zabił lwa gołymi rękami, pokonał armię wroga oślą szczęką i siłą własnych mięśni, wyrwał bramę miasta wraz z odrzwiami, zburzył budynek. Był <a href=\"https://pl.wikipedia.org/wiki/Nazireat\" target=\"_blank\" rel=\"noopener noreferrer\">nazirejczykiem</a> – jednak nie z własnego wyboru – ale z powziętego przed jego narodzeniem suwerennego postanowienia Boga.", "Selim": "<b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Suresh": "<p>Suresh to indyjskie imię męskie pochodzące z sanskrytu sureśa (zestaw sura i īśa). Jego znaczenie jest \"Władca Bogów\" i jest to epitet dla hinduskich bogów Indry, Brahmy, Wisnu i Shiwy.</p>", "Sanjay": "<p>Sanjay, również pisane Sanjai, Sanjey, Sanje i Sunjay, jest męskim imieniem pochodzenia sanskryckiego oznaczającym \"triumfant\", z sanskryckiej Sañjaya (सञ्जय), i może odnosić się do:</p>", "Sławoj": "<b>Sławoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, nienotowane w dawnych dokumentach i stanowiące najprawdopodobniej XIX-wieczny <a href=\"https://pl.wikipedia.org/wiki/Neologizm\" target=\"_blank\" rel=\"noopener noreferrer\">neologizm</a> stworzony na wzór dwuczłonowych <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a>. Istniało natomiast staropolskie imię złożone z tych samych dwóch członów w zmienionej kolejności: <a href=\"https://pl.wikipedia.org/wiki/Wojs%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Wojsław</a>.", "Stanislas": "<p>Louis Stanislas Renoult (Francuz: Louis Stanisla Renoult) - francuski piosenkarz, kompozytor, aranżera, dyrygent i pedagog, znany w środowisku muzycznym pod nazwą Stanislas.</p>", "Salomon": "<b>Salomon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> imienia שְׁלֹמֹה<i> (Shelomo)</i> należącego do słynnego z mądrości króla <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a> – <a href=\"https://pl.wikipedia.org/wiki/Salomon_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomona</a>. Istnieje kilku świętych katolickich o tym imieniu.", "Shamil": "<p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Sławosz": "<b>Sławosz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię słowiańskie</a>. Zdrobniona forma dwuczłonowych imion typu <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomir\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomir</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awos%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Sławosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Dziwis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Dziwisław</a> z członem <i>Sław-</i> albo <i>-sław</i>. Również imię używane samodzielnie o znaczeniu „sławny, znakomity, godny chwały”.", "Sam": "<p>Sam (ang. Sam) - skrócenie męskich i żeńskich nazw Samuel, Samuel, Samantha, Samhit, ale może być pełnym nazwiskiem, a także zarówno męskim, jak i żeńskim.</p>", "Severyn": "<p>Severyn (ukraina: Северин) to ukraińskie imię męskie. Może odnosić się do: Severyn Nalyvaiko (?).</p>", "Sergej": "<p>blu (wcześniej wychodził pod nazwą ⁇ sergej ⁇) - niemiecki gлянcny miesięcznik dla mężczyzn homoseksualnych, wydany od 1997 roku. Od czasu wydania pierwszego numeru czasopisma ma największy tiragę wśród czasopism tego typu w Niemczech.</p>", "Sultan": "<p>Sultan (wietn. xun-tan; arab. سلطان Sultān) jest tytułem króla w krajach, w których islam jest narodowy, i ma wiele znaczeń z czasem. Sultan to początkowo arabskie imię abstrakcyjne, które oznacza \"mocarstwo\", \"mocarstwa\" lub \"dominację\".</p>", "Santino": "<p>Santino to włoskie męskie imię lub nazwa, co oznacza \"mały święty\" w języku włoskim. Jest to diminutiwna wersja nazwy Santo, co oznacza \"święty\" lub \"święte\".</p>", "Serhat": "<p>Serhat (tur. Serhat), prawdziwe imię Ahmet Serhat Hajipashalioglu (tur.</p>", "Sascha": "<p>Aleksander Dimitrenko (uk. Aleksander Dimitrenko, rodzaj.</p>", "Süleyman": "<p>Sulejman Hynaligski (azerski Süleyman) - XVIII-wieczny azerbaijski poeta pochodzenia kinaligskiego.</p>", "Salah": "Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Shahar": "<p>Shahar może odnosić się do: Shahar (bóg), bóstwo w ugaritskiej religii Shahar (gazin)</p>", "Salman": "Salman (również jako Salmaan lub Selman, arab. سلمان) popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>błogosławiony</i>, także <i>pokój</i>.", "Sinan": "<p>Koca Mi'mār Sinān Āġā, (Turkish Ottoman: قوجو معمار سنان آغا) Arkitekt Sinani (Albanian), Mimar Sinan (Turk) (15 kwietnia 1489 - 9 kwietnia 1588) był głównym architektem Ottomanu (Turkisch: mimar) i inżynierem budowlanym dla królów Suleiman I, Selim II i Murad III. Znane pod nazwą Koca Mi'mâr Sinân Âğâ, \"Sinan Agha the Grand Architect\", był odpowiedzialny za zbudowanie ponad 300 budowli...</p>", "Steve": "<p>SZ: SZ jest zjawiskiem atmosferycznym, który wygląda jak długa pasma światła w niebie. Steve Jobs - książka, biografia współzałożyciela Apple Inc Steve'a Jobs'a.</p>", "Shimon": "<p>Szymon (Heb. שמעון) - imię i nazwisko.</p>", "Saul": "<b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Sorin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sachin": "<p>Sachin jest miastem censusem w okręgu Surat w stanie Gujarat w Indiach.</p>", "Sylvester": "<p>Sylvester James (ang. Sylvester James; 6 września 1947 - 16 grudnia 1988), znany również jako Sylvester - amerykański piosenkarz w gatunku disco, rhythm-and-bluz i soul.</p>", "Sylwin": "<b>Sylwin</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, utworzone od męskiego <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusz</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, który wskazywał na pochodzenie od kogoś lub zdrabniał. W Kościele katolickim istniało czterech świętych o tym imieniu. <b>Sylwin</b> nadawany jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1847\" target=\"_blank\" rel=\"noopener noreferrer\">1847</a> roku.", "Światosław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sava": "<p>Sava jest rzeką w Europie, jest jej odległością. Pływa przez Słowenię, Chorwację, a północną część granicy Bosni i Hercegowiny, do Serbii, wpadając do rzeki Danude w Beogradzie.</p>", "Sebastien": "<p>Sébastien to powszechne francuskie imię. Jest to francuska forma łacińskiego imienia Sebastianus, co oznacza \"od Sebaste\".</p>", "Son": "<p>Son to wietnamskie słowo o wielu znaczeniu. Czerwony i czerwony: jeden kolor.</p>", "Sasza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Aleksander</b>.</p><b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Stephane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stephan</b>.</p><p>Christian-Friedrich Stephan, lub Stefan (niem. Christian Friedrich Stephan, 1757, Leipzig - 17 grudnia 1814, Sankt-Petersburg) - rosyjski botanik pochodzenia niemieckiego.</p>", "Sabir": "<b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Sasha": "<p>Alexander Paul Cow (ang. Alexander Paul Coe; rod.</p>", "Stan": "<p>Stan (rosyjski: Стэн) - trzeci single Eminema z jego albumu The Marshall Mathers LP, nagrany wspólnie z piosenkarką Dido.</p>", "Samer": "<p>Samer jest gminą w francuskiej prowincji Pas-de-Calais w regionie Hauts-de-France.</p>", "Serwacy": "<b>Serwacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „ten, który został zbawiony”.", "Sabin": "<b>Sabin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>sabinus</i> oznaczającego pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Sabinowie\" target=\"_blank\" rel=\"noopener noreferrer\">Sabinów</a>, plemienia zamieszkującego środkową <a href=\"https://pl.wikipedia.org/wiki/Italia_(kraina_historyczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Italię</a>. Wśród patronów św.&#160;<a href=\"https://pl.wikipedia.org/wiki/Sabin_ze_Spoleto\" target=\"_blank\" rel=\"noopener noreferrer\">Sabin ze Spoleto</a>, biskup i męczennik (†303).", "Simion": "<p>Simion to rumuńska męska nazwa. Znani ludzie z tej nazwy to: Simion Bărnuțiu Simion Bughici Simion Coman Simion Cuciuc Simion Cuţov Simion Furdui Simion Galeţchi Simion Ghimpu Simion Grişciuc Simión Ismailciuc Simiony Florea Marian Simeon G.</p>", "Suleyman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suleiman</b>.</p><p>Suleiman (arabski: سُلَيْمان, romanized: sulaymān; angielski: or) jest arabskim imieniem żydowskiego i koranskiego króla i islamskiego proroka Salomona. Sulejman Wielki (1494-1566) był najdłużej rządzijącym sultanem Imperium Osmańskiego.</p>", "Slawomir": "<p>Sławomir (polskie wymowa: [swaˈvɔmir]) to polskie imię męskie pochodzenia słowiańskiego. Składa się z sławy (\"sława, sławę\") i mir (\"pokój, świat\").</p>", "Santos": "<p>Santos (szp. i port. - Nieźle.</p>", "Ścibor": "<b>Czścibor</b>, <b>Ścibor</b>, <b>Czcibor</b>, <b>Cibor</b>, <b>Czesbor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Znaczenie imienia: „walczący o cześć”, „obrońca czci”, lub „czczący walkę”. Od członów „czci-” (daw. „czści-”), „czcij”, od czcić (daw. czścić, porównaj cześć) oraz „bor-” – od daw. „borzyć” „walczyć” (porównaj „borykać się”).", "Sai": "<p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Stewart": "<p>Stewart: Stewart to skrócie botaniczne, które oznacza, że autorem taksy jest Robert Stewart. Stewart SF01 - bolida, opracowana i zbudowana przez drużynę Stewart Grand Prix do udziału w Mistrzostwach Świata w wyścigach samochodowych w klasie Formuły 1 sezonu 1997 roku.</p>", "Shahid": "<b>Szahid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شَهيد&#8206;, <i>šahīd</i>, „świadek, męczennik”) − termin wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a>, oznaczający osobę, która oddaje swoje życie w sprawie wiary, za co ma obiecaną nagrodę wieczną, czyli życie w raju (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCanna\" target=\"_blank\" rel=\"noopener noreferrer\">dżanna</a>).", "Sander": "<p>Sander: Sander (lat. Sander) - rodzaj rodziny okon (Percidae). Sander - skrócie botaniczne, oznaczające, że autorem taksy jest Sander, Henry Frederick Conrad.</p>", "Spencer": "<p>Walter Baldwin Spencer (ang. Walter Baldwin Spencer) - angielsko-australijski zoolog i antropolog.</p>", "Suleiman": "<p>Suleiman (arabski: سُلَيْمان, romanized: sulaymān; angielski: or) jest arabskim imieniem żydowskiego i koranskiego króla i islamskiego proroka Salomona. Sulejman Wielki (1494-1566) był najdłużej rządzijącym sultanem Imperium Osmańskiego.</p>", "Sameer": "<p>Samir (zwany również Sameer) to męskie imię, które jest powszechne w Azji Południowej, na Bliskim Wschodzie i w Azji Środkowej. W arabskim samir (سمير) oznacza \"święty\", \"społeczny\", \"lojalny\" lub \"pyszny\".</p>", "Sarvar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sarwar</b>.</p><p>Sarwar to imię osobiste, najbardziej popularne wśród muzułmanów pochodzenia indyjskiego, pakistańskiego lub bangladeszkiego. Pochodzi z perskiego (سرور), co oznacza \"przywódca\" lub \"głównika\".</p>", "Sarath": "<p>BMP-2 ⁇ Sarath ⁇ (⁇ Koło zwycięstwa ⁇) - indyjska modyfikacja sowieckiego BMP-2, przeznaczona do transportu składu osobistego do przedniego krawędzi, zwiększenia jego mobilności, uzbrojenia i ochronności na polu bitwy w warunkach stosowania broni jądrowej i wspólnych działań z czołgami w walce. Jej licencjonowana produkcja jest założona na заводе Ordnance Factory Medak.</p>", "Semion": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Semyon</b>.</p><p>Simeon () to imię, pochodzące z hebrajskiego שמעון (Biblijna Šimʿon, Tiberiana Šimʿôn), zwykle przetłumaczane w języku angielskim jako Shimon. W greckim jest napisane Συμεών, stąd i po łacinie Symeon.</p>", "Sharon": "<b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Satish": "<p>Satish to męskie indyjskie imię (lub nazwisko patronymiczne). Do znanych osób z tym nazwiskiem należą: Satish K.</p>", "Seth": "<p>Seth (w języku hebrajskim: שֵׁת Šet lub Šēṯ, w arabskim: شِيث Sheeth, oznaczający 'stawiać, wyznaczać'), według judaizmu, chrześcijaństwa, mandaeizmu i islamu jest trzecim synem Adama i Ewy, a także jednym z trzech ich synów, o których mowa w Biblii hebrajskiej, wraz z Kainem i Abela. Według Księgi Rodzaju 4:25, Seth urodził się po zabójstwie Kaina, a Ewa wierzyła, że Bóg umieścił go w miejscu...</p>", "Surendra": "<p>Surendra to indyjskie imię męskie. Wśród znanych osób z tym nazwiskiem są: Surendra (aktorzy), indyjski piosenkarz i aktor Surendra Bhave Surendra Chaturvedi Surendra Dubey Surendra Gambhir Surendra Hiranandani Surendra Jain Surendra Jha 'Suman' Surendra Kumar Datta Surendra Kumor Sinha Surendra Lal Surendra Lath Surendra Mishra Surendra Mohanty Surendra Motilal Patel Surendra Nath Mitra Surendra NAT Surendra z Nepalu Surendra Pal Surendra...</p>", "Siemowit": "<b>Siemowit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Siemo-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-wit</i> („pan, władca”, por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*vitъ</i> – „pan, możny”). Imię to wyrażało życzenie, aby nim obdarzony przewodził swojej wspólnocie. Spopularyzowało się ono w czasach nowszych w zniekształconej formie jako <a href=\"https://pl.wikipedia.org/wiki/Ziemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ziemowit</a>. <b>Siemowit</b> był imieniem charakterystycznym dla <a href=\"https://pl.wikipedia.org/wiki/Piastowie\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii piastowskiej</a> i występował wśród <a href=\"https://pl.wikipedia.org/wiki/Piastowie_mazowieccy\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów mazowieckich</a> do <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>.", "Salem": "<p>Salem - izraelski metal-grupa założona w 1985 roku przez Zeeva Tannenboima. Salem to pionierów w Izraelu wśród rodzajów \"Wschodniego Metala\" i \"Ekstremalnego Metala\".</p>", "Sewer": "<b>Sewer</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Przymiotnik\" target=\"_blank\" rel=\"noopener noreferrer\">przymiotnika</a> <i>severus</i>, 'surowy, poważny'. Należało w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a> do popularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognominów</a> (przydomków). W latach 193-235 w Rzymie panowała dynastia <a href=\"https://pl.wikipedia.org/wiki/Sewerowie\" target=\"_blank\" rel=\"noopener noreferrer\">Sewerów</a>, do której należeli m.in. <a href=\"https://pl.wikipedia.org/wiki/Septymiusz_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Septymiusz Sewer</a>, <a href=\"https://pl.wikipedia.org/wiki/Karakalla\" target=\"_blank\" rel=\"noopener noreferrer\">Karakalla</a>, <a href=\"https://pl.wikipedia.org/wiki/Heliogabal_(cesarz_rzymski)\" target=\"_blank\" rel=\"noopener noreferrer\">Heliogabal</a>, <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander Sewer</a>. Od niego zostało następnie utworzone imię <a href=\"https://pl.wikipedia.org/wiki/Seweryn\" target=\"_blank\" rel=\"noopener noreferrer\">Seweryn</a>.", "Siegmund": "<p>Siegmund (niem. Siegmund; 26 lipca 1439 - 1 lutego 1501, zamek Blutenburg) - książę Bawarii-Munychena w latach 1460 - 1467, książę Bawaria-Dachau od 1467 roku.</p>", "Sherif": "<p>Sherif, złożony również jako Sharif (a w krajach, w których rumuńska rumuńskość jest normą, Cherif lub Charif), jest właściwą nazwą pochodzącą z arabskiego słowa sharīf (شريف, 'noble', 'wyżytkowany', 'honorowy'), pierwotnie tytuł oznaczający osobę pochodzącą od rodziny islamskiego proroka Mahometa. Szersze, tytuł sharīf był historycznie stosowany do każdego z szlachetnych przodków lub politycznej wyższości w krajach islamskich.</p>", "Srinivas": "<p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Sali": "<p>Sali (tur. Sali) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Sharif": "<p>Omar ash-Sharif (arabski: عمر الشريف)  Omar al-Sharif , angielski .</p>", "Selçuk": "<p>Selçuk jest dzielnicą w prowincji Izmir w Turcji. Ogromnie obszarzyła 280 km2 i liczba ludności w 2007 roku wynosiła 34002 osoby, a jej gęstość 121 osób/km2.</p>", "Seli̇m": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Selima</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Selim</b>.</p><b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Sunny": "<p>⁇ Sunny ⁇ (z angielskiego - ⁇ Solnyшко ⁇) - piosenka napisana przez Bobby Hebb.</p>", "Sykstus": "<b>Sykstus</b>, Sykst – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie przejęte poprzez <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacinę</a> z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greki</a>, pochodzące od greckiego imienia Ksustos (<i>ksustós</i> - „wygładzony, elegancki”), w którym przez analogię do łacińskiego imienia <i>Sextus</i> (Sekstus – „szósty”) doszło do przestawienia głosek. Imię to było nadawane w Polsce od średniowiecza, poświadczone w formie pochodnej Syksta (m.) oraz w <a href=\"https://pl.wikipedia.org/wiki/1265\" target=\"_blank\" rel=\"noopener noreferrer\">1265</a> roku w łac. formie <i>Sixtus</i>; możliwe staropolskie zdrobnienia: Syc, Syc(z)ek, Syc(z)ko, Sych, Sychno, Sychta, Sysz, Syszek, Syszka, Syszko. Istnieje pięciu świętych katolickich o tym imieniu.", "Serik": "<p>Serik jest okręg w prowincji Antalya w Turcji. Ogromnie obszarzyła 1334 km2 i liczba ludności w 2007 roku wynosiła 105755 osób, a jego gęstość wynosi 79 osób/km2.</p>", "Sidney": "<p>Sydney (ang. Sidney, Sithney, Seyn (ang.</p>", "Shiva": "<p>Shiva lub Niska Baba (sansk: शिव Śiva), znany również jako Mahadeva lub Ma-ha-đə-ba (; sansk: महादेव:, n.e. 'Wielki Bóg', Mahādevaḥ, [mɐɦaːd̪eːʋɐh) jest jednym z ważnych bogów hinduizmu.</p>", "Stoyan": "<p>Stoyan (bułgarski: Стоян) jest bułgarskim imieniem pochodzącym z czasownika stoya (стоя \"stać\"). Wariant Stoian pojawia się również w języku serbskim, rumuńskim i w północnej Grecji jako Stogiannis (Στογιάννης).</p>", "Sudip": "<p>Sudip to indyjskie i nepalski męskie imię. Do osób z tym nazwiskiem należą: Sudip Bandyopadhyay (ur.</p>", "Szarbel": "<b>Sarbeliusz</b>, <b>Sarbel</b>, <b>Szarbel</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, odnoszące się do człowieka noszącego szerokie spodnie, a więc <a href=\"https://pl.wikipedia.org/wiki/Scyci\" target=\"_blank\" rel=\"noopener noreferrer\">Scyty</a> lub <a href=\"https://pl.wikipedia.org/wiki/Asyryjczycy\" target=\"_blank\" rel=\"noopener noreferrer\">Asyryjczyka</a>. Podstawę imienia stanowi <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskie</a> słowo <i>sarbalin</i> oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Szarawary\" target=\"_blank\" rel=\"noopener noreferrer\">szarawary</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers.</a> <i>szalwār</i> ‘spodnie’).", "Świętosław": "<b>Świętosław</b>, <b>Święcesław</b>, <b>Święcsław</b>, <b>Święsław</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorw.</a> <i>Svjetoslav</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a> <i>Svetoslav</i>) – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Złożone jest z członów: <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sław</i> („sława”) i oznacza człowieka cieszącego się mocną sławą. W materiałach źródłowych występuje od XII wieku. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię to zanotowano u około 1000 osób.", "Sung": "<p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sarkis": "<p>Sarkis (armeńska: Սարգիս, wymowa armeńska [sɑɾˈkhis]) to męskie imię i nazwisko. Nazwa może być również alternatywnie pisowana jako Sargis, używana zarówno przez Armenii, jak i Asyryjczyków.</p>", "Szabolcs": "<b>Szabolcs</b> – węgierskie imię męskie, noszą je np. <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Huszti\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Huszti</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Fazakas\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Fazakas</a>, <a href=\"https://pl.wikipedia.org/wiki/Szabolcs_Balajcza\" target=\"_blank\" rel=\"noopener noreferrer\">Szabolcs Balajcza</a>. Tak nazywał się, według <a href=\"https://pl.wikipedia.org/wiki/Simon_K%C3%A9zai\" target=\"_blank\" rel=\"noopener noreferrer\">Simona Kézaia</a> jeden z <a href=\"https://pl.wikipedia.org/wiki/Siedmiu_w%C4%99gierskich_wodz%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">siedmiu węgierskich wodzów</a> – Szabolcs (osoba).", "Shaul": "<p>Saul to imię i nazwisko, które mogą odnosić się do: Nazwa: Shaul (Hebrajskie שָׁאוּל Šāʼûl \"proszony, modlił się o\"), zwykle nazywany Saul w języku angielskim, pierwszy król Izraela w hebrajskiej Biblii Shaul, syn Symeona (syn Jakuba) w Księdze Rodzaju Shaul Amor (1940-2004), izraelski polityk Shaul Avigur (1899-1978), założyciel izraelskiej wspólnoty wywiadowczej Shaul Ben-Tzvi, hebrajskie imię Paula Shulmana (1922-1994), drugi dowódca...</p>", "Shuhrat": "<p>Szuhrat (prawdziwe imię - Gólom Aminżonovich Alimov) (19 kwietnia 1918 r., Ташкент - 20 czerwca 1993 r., tamże) - uzbekski i sowiecki pisarz, poeta, dramatyk i tłumacz. Narodowy pisarz OSSR (1983).</p>", "Shakir": "<p>Shakir to zarówno nazwisko, jak i nazwisko pochodzące z arabskiego, podobnie jak nazwisko lub imię Shakur. Kobieta Shakir to Shakira.</p>", "Slobodan": "We wczesnej serbskiej literaturze imię Slobodan było używane jako zamiennik (odpowiednik znaczeniowy) <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <a href=\"https://pl.wikipedia.org/wiki/Eleuteriusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Eleuterego</a>, które pochodziło od Ελευθεριος „wolny, niezależny” (podobnie jak w Polsce za odpowiednik znaczeniowy łacińskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a> od <i>ignis</i> „ogień” traktowano <a href=\"https://pl.wikipedia.org/wiki/%C5%BBegota_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Żegotę</a>, od <i>żec</i> „palić”, od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*žekti</i>, <i>*žьgǫ</i>). U południowych Słowian imię wskrzesił i na nowo spopularyzował <a href=\"https://pl.wikipedia.org/wiki/Vladimir_Jovanovi%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">Vladimir Jovanović</a> (1833-1922), <a href=\"https://pl.wikipedia.org/wiki/Serbowie\" target=\"_blank\" rel=\"noopener noreferrer\">serbski</a> <a href=\"https://pl.wikipedia.org/wiki/Liberalizm\" target=\"_blank\" rel=\"noopener noreferrer\">liberalny</a> myśliciel, który swoim dzieciom dał na imię, synowi Slobodan w 1869 r. i córce Pravda w 1871 r.", "Saif": "<p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Svetoslav": "<p>Svetoslav to imię. Do wybitnych osób z nazwiskiem należą: Svetoslav z Chorwacji (przed 997 - 1000), król Chorwacji Svetoslav Dyakov (ur. 1984), bułgarski piłkarz Śwetoslav Georgiev (ur. 1977), bułgarski piłkarze Śwetosław Minkov (1902-1966), bułgara pisarz Śwetośław Petrov (ur. 1978), były bułgarz piłkarza Śwetoslaw Petrov (UR. 1988), bułgański piłkarzy...</p>", "Saurabh": "<p>Sourav, Sourabh, Saurabh i Saurav to indyjskie imiona męskie. Saurav i Sourav oznaczają niebiańskie lub boskie, podczas gdy Saurabh i Sourabh oznaczają zapach w sanskrcie.</p>", "Sakhil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sakhile</b>.</p><p>Sakhile to afrykańska nazwa, która może odnosić się do: Sakhile, piosenkarka w muzyce Ndebele Sakhile Dube, zimbabwskiej królowej piękności Sakhile Nyoni, zimbabwiańskiego pilota Sakhile, Mpumalanga miasto w pobliżu Standerton, Afryka Południowa</p>", "Sameh": "<p>Sameh (arabski: سامح) to arabskie nazwisko i męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Shahzad": "<p>Shahzad (persk. shaʻهزاد) lub Shehzad to imię i nazwisko. Nazwa pochodzi od شاه (Shah, \"król\") i zad (Zad, \"syn\"), więc nazwa oznacza \"syn króla\".</p>", "Sahib": "<b>Sahib</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> „pan, władca”) – forma honoryfikacyjna używana w językach indyjskich.", "Smith": "<b>Smith</b> – <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> angielskiego pochodzenia. Pochodzi od staroangielskiego słowa <i>smið</i> oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Kowal\" target=\"_blank\" rel=\"noopener noreferrer\">kowala</a>. Jest to jedno z najbardziej popularnych nazwisk na świecie. W <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> posługuje się nim ponad jeden procent ludności, w tym w samych Stanach Zjednoczonych ponad 2,5 miliona ludzi.", "Sơn": "<p>Farba jest jakąkolwiek płynną, rozpuszczalną lub masticzną substancją twardy, która po pokryciu cienkiemu warstwie na powierzchni zamienia się w twardy błon. Najczęściej używane jest do ochrony, kolorowania lub tworzenia tekstur dla obiektów.</p>", "Soren": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Sajjad": "<p>Sajjad/ Sjjad سَجَّاد to imię i nazwisko pochodzące od 'przeciwiać się (przed Bogiem) ', które jest wspólne z arabskim słowem masjid masjid 'meczet'. Do wybitnych osób z tym nazwiskiem należą:</p>", "Samed": "<p>Samad lub Samed (arabsko: صمد, Ṣamad) to arabskie imię męskie.</p>", "Seán": "<p>Sean, zwanego również Seán lub Séan w języku Hiberno-angelski, jest imieniem męskim pochodzącym z Irlandii. Pochodzi z irlandzkiego wersji biblijnej hebrajskiej nazwy Yohanan (יוֹחָנָן), Seán (anglicznie Shaun/Shawn/Shon) i Séan (angliczno Shane/Shayne), wyłożonej na angielski John i Johannes/Johann/Johan w innych językach germańskich.</p>", "Sammy": "<p>Sammy jest nadmieniem, często dla ludzi o imieniu Samuel lub Samantha, a także angielskie pisownianie arabskiej nazwy Sami.</p>", "Silviu": "<p>Silviu może odnosić się do: Silviu Bălace (ur. 1978), rumunskiego piłkarza piłkarskiego Silviu Berejan (1927-2007), pisarza besarabijskiego z Mołdawii Silviu Bindea (1912-1992), rumunskiego gracza piłkarski Silviu Brucan (1916-2006), rumuńskiego polityka komunistycznego Silviu Casandra (ur. 1975), rumunskiego biegacza wyścigowego Silviu Florea (ur. 1977), rumunzkiego piłkarz rugby silviu Ilie (ur. 1988), rumunski piłkarze...</p>", "Shah": "<p>⁇ SHAH ⁇ (⁇ SHA H ⁇) - rosyjska i rosyjska grupa, pionierów radzieckiego metalu. Znana jest między innymi tym, że partii basystyki w niej kilku lat wykonywał Anatolij Krupnov, założyciel ⁇ Czarnego obelisku ⁇ .</p>", "Søren": "<b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Siva": "<p>Siva może odnosić się do: 1170 Siva, asteroida Śiva lub Shiva, bóg</p>", "Song": "<p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Sandor": "<b>Aleksander</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἀλέξανδρος, <i>aleksandros</i> – obrońca ludzi) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> składające się z dwóch członów: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;αλέξειν (bronić, wspomagać) i ἀνδρός (od ἀνήρ – mąż, mężczyzna). Całość bywa interpretowana jako „broniący mężów, troszczący się o mężów, opiekujący się mężami”.", "Serguei": "<p>Sergius to męskie imię pochodzenia starożytnego Rzymu po nazwie łacińskiej geny Sergia lub Sergii w czasach królewskich i republikańskich. Jest to powszechne chrześcijańskie imię, na cześć św. Sergiusa, i było to imię czterech papieży.</p>", "Siddharth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Siddhartha</b>.</p><p>Siddhartha może być: Nazwa Świętego Kościoła w wielu językach Zachodu Siddhartha, powieść Hermann Hesse Film Siddhartha Conrad Rooks Siddhartha Band Poza tym, indyjski aktor Siddharth Narayan jest często znany jako Siddhartha.</p>", "Sydney": "<p>Sydney - najstarsze, największe po liczbie ludności i drugim po powierzchni miastem Australii o powierzchni 12 144,6 km2, którego populacja według przepisu z 2020 roku wynosiła 5 367 206 osób. Sydney jest stolicą stanu Nowy Południowy Wales.</p>", "Saber": "<p>Sabre lub Saber (w tłumaczeniu z angielskiego i francuskiego - ⁇ saбля ⁇) może oznaczać:</p>", "Sulaiman": "<p>Salomon jest angielską transliteracją arabskiej nazwy sliman 'pokojowy' i odpowiada hebrajskiej żydowskiej nazwie שְׁלֹמֹה Shlomoh i angielskiej Salomon (/ˈsɒləmən/). Salomon był postacią biblijną, która była królem tego, co wówczas było Zjednoczonym Królestwem Izraela (kr.</p>", "Skarbimir": "<b>Skarbimir</b>, <b>Skardmir</b>, <b>Skamir</b>, <b>Skarbimirz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Skarbi-</i> („smucić, martwić, troszczyć się”) i <i>-mir</i> („pokój, spokój, dobro”). Może oznaczać „troszczący się o pokój”. Jako Skarbimir imię występuje od XII wieku.", "Stelian": "<p>Stelian to rumuńskie imię męskie. Znani ludzie z nazwiska to: Stelian Badea, rumunski piłkarz Stelian Burcea Stelian Isac, rumunsky piłkarze Stelian Moculescu Stelian Popescu Stelian Stancu Stelian Tănase</p>", "Szmul": "<p>Szmuel lub Schmuel to nowoczesna hebrajska forma imienia Samuela. Szmuel i jego odmiany mogą odnosić się do: Samuela (Biblia), hebrajskiego biblijnego proroka Księgi Samuela, księgi Tanach Shmuela Hakatana, Tanna (mistrza Mishnaic) Samuela Nehardea, Amora (mistrz Talmudic)</p>", "Saleem": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salem</b>.</p><p>Salem - izraelski metal-grupa założona w 1985 roku przez Zeeva Tannenboima. Salem to pionierów w Izraelu wśród rodzajów \"Wschodniego Metala\" i \"Ekstremalnego Metala\".</p>", "Sasho": "<p>Sasho to męskie imię, które jest diminutiwem Aleksandra i pochodzi z Bułgarii i Macedonii Północnej. Nazwa może odnosić się do: Sasho Angelov (ur. 1969), bułgarskiego piłkarza i menedżera Sasho Cirovski (ur. 1962), trenera piłki nożnej Sasho Mijalkov (ur. 1965), makedyńskiego polityka Sasho Pargov (ur. 1946), bułgarski piłkarz Sasho Petrovski (ur., 1975), australijczyka Sasho Nikolov, kanadyjski...</p>", "Sanjaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sanjay</b>.</p><p>Sanjay, również pisane Sanjai, Sanjey, Sanje i Sunjay, jest męskim imieniem pochodzenia sanskryckiego oznaczającym \"triumfant\", z sanskryckiej Sañjaya (सञ्जय), i może odnosić się do:</p>", "Su": "<p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Salwator": "<b>Salwator</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> powstałe na bazie tytułu <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a> <i>Salvatora</i> oznaczającego 'zbawcę, zbawiciela'. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> <i>Salvator</i> odnosi się zawsze do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>.", "Stevan": "<p>Stephen lub Steven to angielskie imię męskie. Jest szczególnie znacząca dla chrześcijan, ponieważ należała do św. Szczefana (w starożytnym greckim: Στέφανος, romanized: Stéphanos, lit.</p>", "Sathish": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Satish</b>.</p><p>Satish to męskie indyjskie imię (lub nazwisko patronymiczne). Do znanych osób z tym nazwiskiem należą: Satish K.</p>", "Sundar": "<p>Sundar (Devanagari: सुन्दर) to przymiot oznaczający atrakcyjność, piękno, dobro, przystojność lub przyjemność. Pochodzi z sanskrytu.</p>", "Sonu": "<p>Sonu to imię. Osoby z tym nazwiskiem to: Sonu Shamdasani (ur. 1962), brytyjski pisarz, Sonu Walia (ur. 1964), indyjska aktorka z Bollywoodu, Sonu Shivdasani (UR. 1965), brytyjska hotelowa, Sonu Nigam (ur. 1973), indyjski piosenkarz, Sonu Kakkar (ur. 1979), indyjskie piosenkarze, Sonu Sood (ur. 1973), indyjski aktor, Sonu Gowda (ur. 1990), indyjska aktorka z kin kin Kannada, Sonu Beniwal (ur. 1993), indy...</p>", "Siniša": "<p>Siniša (sirbijski cyrylski: Синиша) to sławskie imię męskie pochodzenia średniowiecznego. Może odnosić się do: Simeon Uroš \"Siniša\" (1326-1371), serbskiego władcy Epiru i Tesalii Siniša Branković (ur. 1979), serbskiego piłkarza Siniša Dobrasinović (ur. 1977), cypryjskiego piłkarz Sinișa Dragin (ur. 1960), serbo-rumunskiego reżysera filmowego Siniša Đurić (ur., 1976), bosnijskiego Serbskiego menedżera i byłego gracza...</p>", "Swen": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Sokrates": "<p>Sokrates (Antyckiego greckiego: Σωκρᾰ́της, latynikowany: Sōkrátēs, [sɔːkrátɛːs]; wietniskiego tłumaczenia: Socokrates; r. 470 - 399 pne) był starożytnym greckim filozofem, uważanym za jednego z twórców filozofii zachodniej i pierwszego moralnego filozofa zachodniej idei moralnej, a jednocześnie typowego przedstawiciela szkoły filozofii psychicznej.</p>", "Slava": "<p>Slava Balasanov (ur. 1981, Moskwa) - amerykański muzyk i artysta.</p>", "Sun": "<p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Saddam": "<b>Saddam</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> <b>صدام</b>, <i>Ṣaddām</i>) – imię męskie pochodzenia arabskiego. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/Alternacja_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">rdzenia</a> Ṣ-D-M, oznaczającego \"przeciwstawiać się\".", "Sudhir": "<p>Sudhir to indyjskie imię męskie. Sanskritskie słowo sudhīra oznacza \"bardzo mądre\", \"odpowiedzialne\".</p>", "Subhan": "<p>Subhan lub Sobhan (arabski: سبحان sub·ḥān) to męskie imię i nazwisko pochodzenia arabskiego oznaczające \"chwała, wywyższone, chwała\". Do wybitnych osób z tym nazwiskiem należą:</p>", "Shekhar": "<p>Shekhar to indyjskie imię męskie (zwane również nazwiskiem). Może odnosić się do:</p>", "Swiatoslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sher": "<p>Sher (ang. Cher, [ʃɛər]; imię przy urodzeniu - Sheryl Sarkisyan (ang.</p>", "Sotirios": "<p>Sotirios (grek. Σωτήριος) lub Sotiris (Σωτήρης) to męskie imię pochodzące z Grecji, co oznacza \"zbawienie\" (σωτηρία, σωτήριος). Sotiria (Σωτηρία) jest kobiecową wersją nazwy.</p>", "Sandu": "<p>Majowa Grygoryevna Sandu (rum. Maia Sandu; rodzaj.</p>", "Saravanan": "<p>Saravanan to tamilska męska nazwa. Ze względu na tradycję tamilską używania nazwisk patronymicznych, może być również nazwiskiem dla mężczyzn i kobiet.</p>", "Sourav": "<p>Sourav, Sourabh, Saurabh i Saurav to indyjskie imiona męskie. Saurav i Sourav oznaczają niebiańskie lub boskie, podczas gdy Saurabh i Sourabh oznaczają zapach w sanskrcie.</p>", "Srinivasa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srinivas</b>.</p><p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Swiatosław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Shahbaz": "<p>Shahbaz (persk. شهباز) to perskie słowo odnoszące się do legendarnego ptaka stróżnego Shahbaz. Jest to również powszechne imię w Iranie, Pakistanie, Afganistanie i Tadżykistanie.</p>", "Srikanth": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srikant</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srikanta</b>.</p><p>Srikanta może odnosić się do: Srikanta Acharya, indyjskiej piosenkarki Srikanta Mahata, indyjski polityk Srikanta Wadiyar (ur. 1953), indyjskiego księcia i polityka Srikanta (książka), bengalijskiej powieści Sarat Chandra Chattopadhyay Srikanta, indyjska kinematyka srikanta (górka)</p>", "Sherwin": "<p>Sherwin (ang. Sherwin): Sherwin, Bell (1869 - 1955) - amerykański publiczny działacz, prezydent Ligi Kobiet-Wyborców (1924 - 1934), córka Henry'ego Sherwina.</p>", "Seyran": "<p>Seyran to nazwa arabskiego pochodzenia, co oznacza \"podróż\". Znani ludzie z nazwiska to: Seyran Ates (ur. 1963), niemiecki prawnik Seyran Ohanyan (ur. 1962), armenijski generał Seyran Osipov (1961-2008), rosyjski piłkarz Seyran Saroyan (1967-2022), armeniński generał i polityk Seyran Shahsuvaryan (ur. 1953), armenicki generał Seylan Aksoy, turecka aktorka Seyran Öztürk, turecka aktryna</p>", "Sarp": "<p>Sarp jest gminą w prowincji Hautes-Pyrénées w regionie Occitanie w południowo-zachodniej Francji. Znajduje się w regionie o średniej wysokości 472 metrów nad poziomem morza.</p>", "Sylwan": "<b>Sylwan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"las, zagajnik\". Imię to posiada również skróconą formę <a href=\"https://pl.wikipedia.org/wiki/Sylas\" target=\"_blank\" rel=\"noopener noreferrer\">Sylas</a>.", "Stanimir": "<b>Stanimir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Stani-</i> (\"stać, stać się, stanąć\") oraz członu <i>-mir</i> (\"pokój, spokój, dobro\"). Mogło oznaczać \"niech się stanie pokój\" albo \"ten, który ustanawia pokój\".", "Symon": "<p>Symon to zarówno nazwisko, jak i imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sędzimir": "<b>Sędzimir</b>, <b>Sędomir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-mir</i> („pokój, spokój, dobro”). Być może oznaczało „ten, komu sądzone jest życie w pokoju”. Od tego imienia, występującego w całej Słowiańszczyźnie (por. czes., rus. i serbsko-chor. <i>Sudomir</i>) pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Sandomierz\" target=\"_blank\" rel=\"noopener noreferrer\">Sandomierz</a>.", "Sajith": "<p>Sajith to męskie imię pochodzenia singalijskiego. Znani ludzie z nazwiskiem to: Sajith Dissanayaka (ur. 1989), kryketar Sri Lankan Sajith Fernando (ur. 1972), kryketer Sri Lankan First Class Sajith Jagadnandan (ur. 1981), indyjski reżyser filmów w Malayalam Sajith Premadasa (ur. 1967) Sri Lankanki polityk, od 2020 roku przywódca opozycji Sajith de Silva (ur. 1998), kryketarka Sri Lanka</p>", "Sanjeewa": "<p>Sanjeewa (sinhala: සංජීව) to syńhalicka nazwa, która może odnosić się do następujących znanych osób: Nazwa Sanjeewa Munasinghe, Sri Lankanska lekarz wojskowy Sanjeewa Pushpakumara (ur. 1977), Sri Lankanka reżyser filmowy i producent Sanjeewa Silva (ur. 1975), Sri Lanka kryker Sanjeewa Weerasinghe (ur. 1968), Sri Lanki kryker Surname Buddika Sanjeewa ...</p>", "Sol": "<p>Sehol X4 (dawniej JAC Jiayue X4) - kompaktowy crossover produkowany przez chińską firmę JAC Motors pod marką Sehol. Sehol X4 był krótko nazywany Sol X4 i JAC Jiayue X4 przed stworzeniem marki Sehol.</p>", "Sahin": "<p>Şahin (turk. [ʃaːˈhin]; perskie: شاهين, romaniz. Shāhīn) to tureckie i tatarskie imię pochodzenia perskiego, co oznacza \"szarpa\" lub \"falk\" w perskim. Nazwisko to zostało przypisane osobom i rodzinom różnych etnicznych, religii i mniejszości na terytoriach Republiki Turcji po upadku wieloetnicznego Imperium Osmańskiego, w następstwie wprowadzenia ustawy o nazwiskach w 1934 r.</p>", "Shahriyar": "<p>Shahriyar lub jego warianty mogą odnosić się do:</p>", "Shamim": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamima</b>.</p><p>Shamima to kobiece arabskie imię pochodzące z arabskiego: شميمه oznacza \"słodki zapach\". Wśród znanych osób, które nosiły tę nazwę, są Shamima Akhtar (1957 - 2018), Bangladesza, śpiewająca w rewizji Shamima Akhar Tulee (ur. 1974), Bangladesz, artystka walki, Shamima Akter Liza (ur. 1989), Bangladesh International Master, Shamima Ali, fijski polityczny aktywista, Shamima Begum (ur. 1999), brytyjska kobieta, która opuściła Wielką Brytanię w wieku 15 lat, aby dołączyć do ISIL...</p>", "Saqib": "<p>Saqib jest perskim wymową pochodzącą z arabskiej nazwy Thaqib (ثاقب thāqib), jest męskim imieniem, co oznacza \"wybrany, prawdomówny\". Wśród znanych osób z tym nazwiskiem są: Saqib Ali (ur. 1975), członek Izby Delegacji Maryland Saqib Ali, kryketarz (ur. 1978), kryketar Zjednoczonych Emiratów Arabskich Saqib Bhatti, ur. 1985), brytyjski konserwatywny polityk Saqib Hanif, ur. 1994), pakistański...</p>", "Sören": "<p>Sören jest gminą w okręgu Rendsburg-Eckernförde, w niemieckim stanie Schleswig-Holstein. Miasto Sören ma powierzchnię 6,5 km2, liczba ludności w dniu 31 grudnia 2006 r. wynosi 205 osób.</p>", "Shan": "<p>Shan to państwo w Birmie, powołane na Shanów, jednego z ludów mieszkających w regionie. Jest to największe z 14 państw i innych podziałów administracyjnych Mjanmaru.</p>", "Salamon": "<p>Szalamon (Szalamon; weng. Salamon, dobrze.</p>", "Sakari": "<p>Sakari to imię i może odnosić się do: Sakari Kukko (ur. 1953), finońskiego saksofonisty i flautistki Sakari Kuosmanen (ur. 1956), finołej piosenkarki i aktorki Sakari Mattila (ur. 1989), finowego piłkarza Sakari Oramo (ur. 1965), finoskiego dyrygenta Sakari Pinomäki, finońskiej inżynierii mechanicznych i hydraulicznych systemów Sakari Timonen (ur. 1957), finowej blogerki Sakari Tuomioja (1911-1964), finowskiego polityka Yrjö Sakari Yrjö-Koskinen...</p>", "Simoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Sony": "<p>Sony Group Corporation, ⁇ Со́ни ⁇ (jap. ソニー・グループ株式会社 Soni: Гуру:пу кабусики-гайся) - japoński transnacyjny konglomerat z siedzibą w Tokio.</p>", "Seiran": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seyran</b>.</p><p>Seyran to nazwa arabskiego pochodzenia, co oznacza \"podróż\". Znani ludzie z nazwiska to: Seyran Ates (ur. 1963), niemiecki prawnik Seyran Ohanyan (ur. 1962), armenijski generał Seyran Osipov (1961-2008), rosyjski piłkarz Seyran Saroyan (1967-2022), armeniński generał i polityk Seyran Shahsuvaryan (ur. 1953), armenicki generał Seylan Aksoy, turecka aktorka Seyran Öztürk, turecka aktryna</p>", "Smail": "<p>Snail mail (w tłumaczeniu z angielskiego - ⁇ улиtoczna poczta ⁇ , rzadko smail od słów snail i mail) - frazeologia często używana w języku angielskim jako wyrażenie niezadowolenia z powolnego dostarczania zwykłej poczty, w przeciwieństwie do poczty elektronicznej.</p>", "Sulisław": "<b>Sulisław</b>, <b>Solisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> („obiecywać” albo „lepszy, możniejszy”) i <i>-sław</i> („sława”). Może oznaczać „ten, który cieszy się lepszą sławą od innych”.", "Server": "<p>W komputerze, serwer lub serwer jest częścią komputera sprzętowego lub oprogramowania (programowanie komputerowe) zapewniającego funkcje innym programom lub urządzeniach, zwanym \"klientem\". Architektura ta jest znana jako model gościnny.</p>", "Seamus": "<p>⁇ Seamus ⁇ (z angielskiego - ⁇ Sheimus ⁇ - przymiana psa) - piosenka z albumu Pink Floyd z 1971 roku Meddle.</p>", "Shreyas": "<p>Shreyas to indyjskie imię męskie, które oznacza \"dobrobyt\", \"dobrobytu\", \"oddzielnego\" lub \"wzrost\". Znani ludzie z nazwiska to: Shreyas Talpade (ur. 1976), indyjski aktor Shreyas Gopal (ur. 1993), indyjski kryker Shreyas Iyer (ur. 1994), indyjskie kryker Shryas Ketkar (ur. 2003), indyjska piłkarz Shreyas Movva (ur. 1993), kanadyjski kryker</p>", "Savio": "<p>Sávio Moreira de Oliveira (ur. 10 kwietnia 2004), znany również jako Savinho i Sávio, jest brazylijskim profesjonalnym piłkarzem, który obecnie gra w stronach za Manchester City F.C. w Premier League i Brazylii.</p>", "Sylwian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylvian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvian</b>.</p><p>Silvian to rumuńskie imię męskie. Znani ludzie z imieniem to: Silvian Cristescu (ur. 1970), rumuński piłkarz Silvian Dobre (ur. 1967), rumuński piłkarze Silvian Iosifescu (1917-2006), krytyka literacki, edukacja, tłumacz i profesor</p>", "Sandy": "<p>Sandy to drugi solowy album brytyjskiej piosenkarki folkowej Sandy Denny, nagrany z producentem Trevorem Lucasem (jej przyszłym mężem) i wydany przez Island Records (ILPS 9207) w wrześniu 1972 roku.</p>", "Sadriddin": "<p>Sadr al-Din (arabski: صدر الدين, perskiego: صدرالدین) może odnosić się do: Sadr al -Din al-Qunawi (zmarł 1274), perskiego pisarza sufijskiego Sadr al-'Dīn Mūsā (1305-1391), przywódcy porządku Safaviya Sadr ad-Dīn Abu'l Ḥasan ʿAlī Ibn Abi al-Izz (1331-1390), syryjskiego sunnickiego Hanafi jurysty i teologa Pir Sadardina (14 wieku), perskiego założyciela sekty Khoja Ismaili Sheikh Sadruddin (1434-1515), Jagirdar z Malera w Indiach Ṣadr ad-Dīna Muḥammad Shīzī, lub po prostu Mulla...</p>", "Samar": "<p>Wyspa Samar jest wyspą Filipin. Wyspa jest podzielona na trzy prowincje: prowincję Samar, prowincję North Samar i prowincję East Samar.</p>", "Slavko": "<p>Slavko - białoruski muzyczny, bitmaker, były uczestnik projektu \"Czerwony po Biały\". Bracie Krwa, lider projektu \"Czerwony na Biały\".</p>", "Sudeep": "<p>Sudip Sanjiv, bardziej znany jako Sudip (kan. Sudip, Hindi Sudip.</p>", "Slim": "<p>Slimus (z rosyjskiego. Slimus; wcześniej - Slim; rosyjski.</p>", "Safar": "<b>Safar</b> (arab. <b>صفر</b>) jest drugim miesiącem <a href=\"https://pl.wikipedia.org/wiki/Kalendarz_muzu%C5%82ma%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kalendarza muzułmańskiego</a> i tak jak wszystkie miesiące tego kalendarza jest ruchomy i przypada na różne pory roku. Podobno jego nazwa wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%BB%C3%B3%C5%82taczka_(medycyna)\" target=\"_blank\" rel=\"noopener noreferrer\">żółtaczki</a>, na którą to miano zapadać w porze roku przypadającej na miesiąc Safar przed reformą kalendarzową <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>, choć jest to tylko jedna z kilku hipotez. W tym miesiącu obchodzono kiedyś święto powrotu pielgrzymów z Mekki.", "Suliman": "<p>Suleiman (arabski: سُلَيْمان, romanized: sulaymān; angielski: or) jest arabskim imieniem żydowskiego i koranskiego króla i islamskiego proroka Salomona. Sulejman Wielki (1494-1566) był najdłużej rządzijącym sultanem Imperium Osmańskiego.</p>", "Svitlana": "<p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Shayan": "<p>Shayan (perskiej: شایان) to perskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Serdal": "<p>Serdal to tureckie imię dla mężczyzn. Jest bezpośrednio pochodząca od nazwy Serdar i jest używana wzajemnie.</p>", "Soo": "<p>Rejo Shoo, lub Rejo Sho (węgierski Soó Rezső; Soó von Bere Karoly Rezső, 1903 - 1980) - węgierska botanik, twórca własnego systemu klasyfikacji roślin połośmiennego.</p>", "Shiju": "<p>Shiju jest unisex nazwisko w Indiach, szczególnie często dla mężczyzn w Kerale. Znani ludzie z nazwiskiem to: Shiju A R (ur. 1974), aktor indyjski Shiju Nambyath (ur. 1973), scenarzysta i dialogu w filmie malayalam Shiju Kataria (ur. 21), indyjska aktorka telewizyjna i producent Shiju Sam (ur. 1978), indyjski urodzony arbiter międzynarodowego kryketu</p>", "Srinivasa Rao": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Srinivasa</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srinivas</b>.</p><p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Safet": "<p>Safet to albanskie i bosniackie męskie imię. Może odnosić się do: Safet Isović, bosniackiego wykonawcy septalinki Safet Jahič, słowenińskiego piłkarza Safet Nadarević, bosnińskiego piłki nożnej Safet Osja, albanianki piłkarz Safet Plakalo, bosnian dramatyk Safet Sušić, bosński trener piłki noże i były gracz Safvet-beg Bašagić, bosnisk pisarz</p>", "Soriano": "<p>Soriano jest prowincją Urugwaju, graniczącą z argentyńską prowincją Entre Ríos. Ministerstwo to zajmuje powierzchnię 9 008 km2, licząca 84 563 mieszkańców.</p>", "Skyler": "<p>Lista płyt muzycznych męskiego wietnamskiego pop-singerka Sơn Tùng M-TP zawiera jeden album kompozycji, dwa albumy muzyczne filmowe i 27 singli. Sơn Tùng M-TP rozpoczął karierę z underground ze świata, wydając na Zing MP3 pierwszą piosenkę \"Płyn przechodzi\" i zdobywając pierwsze sukcesy, piosenka zdobyła stałe miejsce na rankingu Piosenek ulubionych Wietnamu.</p>", "Sayan": "<p>Sayan to miasto census (powieść) w okręgu Surat w stanie Gujarat, India.</p>", "Slavomír": "<p>Sławomír (słowacki Slavomír; druga połowa IX wieku) - sławański książę z dynastii Mojmirów, który przez pewien czas był władcą Wielkiej Morawii.</p>", "Sakit": "<p>Sakit jest miastem i nagar panchayatem Etah w stanie Uttar Pradesh, India.</p>", "Satoshi": "<b>Satoshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとし, サトシ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sten": "<p>STEN - brytyjski pistolet-pullemet, stworzony w 1941 roku. Był największym masowym pistoletem-pulletowym armii Wielkiej Brytanii i jej dominionów w czasie II wojny światowej.</p>", "Shakil": "<p>Shakeel lub Shakil to nazwa arabskiej etymologii, która oznacza \"piękna\". Może odnosić się do następujących osób:</p>", "Sijo": "<p>Sijo (Hangul: 시조; Hanja: 時調 (mowa)) to jedna z średniowiecznych form poetycznych w Korei Północnej. Inne nazwy to \"Księga\" lub \"Księgi\".</p>", "Sik": "<p>Sik to dzielnica w malezyjskim stanie Kedah. Obecnie Sik ma ludność w 2010 roku szacunkową około 63865 osób.</p>", "Surinder": "<p>Surinder to indyjskie imię męskie. Do wybitnych osób z tym nazwiskiem należą: Surinder Amarnath (ur. 1948), były indyjski kryketer Test i jeden dzień, Surinder Arora, angielski biznesmen z Punjabi, którego biznes hotelowy, jak się uważa, sprawił, że wart był 225 milionów funtów Surinder Singh Bajwa (1955-2007), zastępca burmistrza Delhi Surinder Singh Kairon, syn zmarłego Sardar Pratap Singh Kairon Surinder Kapoor (1925-2011), film Bollywood ...</p>", "Sokol": "<p>Sokol Movement to organizacja ćwiczeń narzędzi do wszystkich wieków, która została po raz pierwszy założona w Praze w czeskich terenach Austro-Hungaryjskiej Imperium w 1862 roku przez Miroslava Tyrš i Jindřich Fügner. Jest oparta na zasadzie \"zdrowego umysłu w zdrowym ciele\".</p>", "Sing": "<p>Sing (z angielskiego - ⁇ петь ⁇) może oznaczać:</p>", "Srinivasan": "<p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Salwin": "<b>Salwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> oznaczające człowieka pełnego pokoju, spokojnego.", "Som": "<p>Jako trzy literne skróte, SOM (lub SoM) może oznaczać jedno z następujących: Somalia, państwo posiadające trzy litery kod ISO 3166 i kod krajowy IOC olimpijski jest \"SOM\" Społeczeństwo kolejowe Somerset, przedsiębiorstwo kolejowe należące do Amerykańskiej Stowarzyszenia Kolejowej posiadające znak \"SOM\". W nauce technologicznej: Self-organizing map, rodzaj sztucznej sieci neuronów w branży maszynowej, (patrz dalej...</p>", "Subrata": "<p>Subrota (Hindi/ Sanskrit: सुव्रत, Odia: ସୁବ୍ରତ Bengali: সুব্রত), również Subroto (czytaj i pisz jak bengalski i jawanski) lub Subrata/Subrat/Shubrat/Subroto/Suvrat (czytaj a pisz jak od odia), jest powszechną nazwą w Indiach, zwłaszcza wśród ludności Oriya i Bengali i w Indonezji zwłaszczająco wśród ludów jawanskich i sundejskich. Nazwa ta jest również dość powszechna w Indonezji, ponieważ wiele osób ma tam również nazwy pochodzące z sanskrytu...</p>", "Sky": "<p>Sky (z angielskiego - ⁇ nebo ⁇) może oznaczać: SKY - rostowska grupa pop-rock.</p>", "Sabbir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabir</b>.</p><b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Symforian": "<b>Symforian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, oznaczające „stosowny, odpowiedni”. Wśród patronów tego imienia – św. <a href=\"https://pl.wikipedia.org/wiki/Symforian_z_Autun\" target=\"_blank\" rel=\"noopener noreferrer\">Symforian</a> z dzisiejszego <a href=\"https://pl.wikipedia.org/wiki/Autun\" target=\"_blank\" rel=\"noopener noreferrer\">Autun</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>.", "Stjepan": "<p>Stjepan I (chorwacki: Stjepan) - król Chorwacji z dynastii Trpimirów, rządził w latach 1030 - 1058.</p>", "Stanisław Kazimierz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Siddhartha": "<p>Siddhartha może być: Nazwa Świętego Kościoła w wielu językach Zachodu Siddhartha, powieść Hermann Hesse Film Siddhartha Conrad Rooks Siddhartha Band Poza tym, indyjski aktor Siddharth Narayan jest często znany jako Siddhartha.</p>", "Sarfraz": "<p>Sarfrāz lub Sarfaraz (Bengali: সরফরাজ, Urdu: سرفراز) to męskie imię i nazwisko pochodzenia perskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sabah": "<p>Sabah (tur. Rano, poranne (gazety)) - turecka dzienna gazeta.</p>", "Saian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayan</b>.</p><p>Sayan to miasto census (powieść) w okręgu Surat w stanie Gujarat, India.</p>", "Szlama": "<p>Szlama (zredukowana Szlamek) to polska jydska męska nazwisko Š-L-M. Do wybitnych osób z tym nazwiskiem należą: Szlama Ber Winer (1911-1942), polski Żyd z Izbicy Kujawski, która uciekła z obozu egzekucyjnego w Chełmno Szlama Grzywacz (1909-1944), członek francuskiego oporu</p>", "Shabbir": "<p>Shabbir to męskie imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Semyon": "<p>Simeon () to imię, pochodzące z hebrajskiego שמעון (Biblijna Šimʿon, Tiberiana Šimʿôn), zwykle przetłumaczane w języku angielskim jako Shimon. W greckim jest napisane Συμεών, stąd i po łacinie Symeon.</p>", "Sorbon": "<p>Sorbon jest gminą w prowincji Ardennes, w regionie Grand Est w północnej Francji.</p>", "Stian": "<p>Stean [wypowiedź: Steejjań] to imię męskie, pochodzące z Norwegii. Jest to nowoczesna forma starożytnego norweskiego imienia Stígandr, co oznacza \"odchodźca\".</p>", "Skender": "<p>Skender (albaniewska: Skënder) (bosniacko: Skender) to męskie imię, powszechnie występujące w Albanii i na Kosowie oraz wśród osób etnicznej etniki bosniackiej w dzisiejszej Bośni i Hercegowinie, Serbii i Czarnogórii. Skender jest również używany jako nazwisko i istnieje szereg ściśle powiązanych nazwisk rodzinnych znajdujących się na całym świecie, które pochodzą z Skender (takich jak Skeja, Skejić, Skejo, Skenderi, Skenderija, Skenderović, Skenderovski, Skendžić, Schender,...</p>", "Soliman": "<p>Soliman alternatywa może odnosić się do: Soliman (nazwa), w tym lista osób z nazwiskiem Soliman Kenawy, egipski dziennikarz Soliman, Tunezja, miejsce</p>", "Sukhwinder Singh": "<p>Sukhwinder Singh (ur. 11 maja 1983) jest indyjską piłkarką, który obecnie gra dla Realu Kashmiru w pozycji goła.</p>", "Seid": "<b>Seid</b> (staronordyckie <i>seiðr</i>) – forma <a href=\"https://pl.wikipedia.org/wiki/Szamanizm\" target=\"_blank\" rel=\"noopener noreferrer\">szamanizmu</a> (nie <a href=\"https://pl.wikipedia.org/wiki/Magia\" target=\"_blank\" rel=\"noopener noreferrer\">magii</a>), uprawiana przez przedchrześcijańskich <a href=\"https://pl.wikipedia.org/wiki/Wikingowie\" target=\"_blank\" rel=\"noopener noreferrer\">wikingów</a>. Termin ten odnosi się również do nowożytnych rekonstrukcji i kopii tych praktyk. Seid, czyli norrøn sjamanisme, powiązane było z podróżami astralnymi, transem szamańskim, leczeniem, zielarstwem, używaniem run, śpiewaniem gardłowym run, bębnieniem szamańskim, tańcem itp. Jak w większości przypadków tak i tutaj ważnym elementem był rytm.", "Sinh": "<p>Funkcje hiperboliczne - rodzina funkcji elementarnych wyrażanych za pośrednictwem eksponentu i ściśle związanych z funkcjami trygonometrycznymi.</p>", "Saken": "<p>Saken (kazachski: Сәкен) to kazachskie męskie imię. Wśród znanych osób z imieniem: Saken Seifullin (1894-1939), kazachski poeta, pisarz i aktywista Saken Zhasuzakov (ur. 1957), kazachski generał i polityk</p>", "Sterling": "<p>Stirling lub Sterling (ang. Stirling, Sterling) może odnosić się do:</p>", "Sid": "<p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Świerad": "<b>Wszerad</b>, <b>Świerad</b>, <b>Świrad</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w różnych wersjach nagłosowych, oraz członu <i>-rad</i> („radosny, zadowolony”). Znaczenie imienia: „rad każdemu”.", "San": "<p>San może oznaczać: San City San Francisco</p>", "Sungmin": "<p>Lee Sung-min (이성민, Hanbi: 李 ⁇ 敏) (ur. 1 stycznia 1986), znany jako Sungmin, jest koreańskim piosenkarzem, muzykiem i aktorem z zespołu Super Junior. Był członkiem Super Junior-T, Super Junior-Happy i ostatnio został nowym członkiem super Junior-M razem z Eunhyuk.</p>", "Sikandar": "<p>Sikandar (czasami Sikander) jest perskim wariantem Aleksandra, co jest starożytnym greckim dla \"obronnika\" lub \"wojownik\" (dosłownie \"człowiek, który odpycha [nieprzyjacieli]\"). Kiedy Aleksander z Macedonii podbił Persję, Persjanie nazwali go Sikandar lidi, wariantem Iskandary.</p>", "Sen": "<p>Sen w wietnamskim może być: Gatunek wodny należący do rodziny Nelumbonaceae, w tym: Sen różowy (Nelumbo nucifera). Biały sen (Nelumbo lutea).</p>", "Sulejman": "<b>Salomon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Pochodzi od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> imienia שְׁלֹמֹה<i> (Shelomo)</i> należącego do słynnego z mądrości króla <a href=\"https://pl.wikipedia.org/wiki/Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">Izraela</a> – <a href=\"https://pl.wikipedia.org/wiki/Salomon_(kr%C3%B3l_Izraela)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomona</a>. Istnieje kilku świętych katolickich o tym imieniu.", "Satoru": "<b>Satoru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとる, サトル) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Soni": "<p>Karan Soni (ang. Karan Sani) - amerykański aktor pochodzenia indyjskiego, znany ze swoich ról w filmach ⁇ Safety not guaranteed ⁇ i ⁇ Dedpul ⁇ .</p>", "Santi": "<p>Giorgio Santi (italijsky: Giorgio santi; 1746 - 1822) - włoski botanik.</p>", "Sayat": "<p>W innym miejscu w pobliżu tego nazwy, zobacz Sayad, Azerbejdżan. Sayat jest gminą w prowincji Puy-de-Dôme w regionie Auvergne-Rhône-Alpes w środkowej Francji.</p>", "Soma": "<p>Soma - gra komputerowa w gatunku survival horror, opracowana i wydana przez szwedzką studio Frictional Games na systemy Windows, macOS, Linux, PlayStation 4 w 2015 roku. Później gra została portowała na platformę Xbox One i Nintendo Switch.</p>", "Samael": "<p>Samael to szwajcarskie zespoło muzyczne, które początkowo grało w black metal pierwszej fali. W późniejszym czasie styl grupy zmienił się, a od połowy lat 90.</p>", "Salavat": "<p>Salavat (rosyjski: ? райо́н) jest okręgem samodzielnego zarządu (raion), w regionie Baskortostan, Rosja.</p>", "Stefaan": "<p>Stefaan to holenderskie imię męskie, w wersji Stephena, które jest najczęściej stosowane w Belgii. Mieszkańcy tej nazwy to: Stefaan De Clerck (ur. 1951), belgijski polityk i były minister sprawiedliwości Stefaan Engels (ur. 1961), belgijski biegacz długodystansowy, który biegł 365 maratonów w ciągu jednego roku Stefaan Maene (ur. 1972), belgijski pływacz Stefaan Simons (ur. c.</p>", "Sabatino": "<p>Sabatino jest zarówno włoską nazwą jak i męską włoską przydatnością. Do wybitnych osób z tym nazwiskiem należą:</p>", "Srdan": "<p>Srđan (srpski cyrylski: Срђан); wymawia się [sr̩d ⁇ an];; sir-jahn) jest serbsko-chorwackim męskim imieniem, zwykle pisanym jako Srdjan, gdy litera đ nie jest dostępna. Zazwyczaj uważa się, że jest to forma nazwy Sergius, w czci męczennika i świętego chrześcijanina Sergiusa.</p>", "Shailendra": "<p>Shailendra (IAST: Śailendra) to słowo św. św. łączące słowa Śaila i Indra, co oznacza \"Król góry\". Jest powszechnie używane jako męskie imię na subkontynencie indyjskim.</p>", "Shivaji": "<p>Shivaji Raje Bhosle the Great (Marathi: शिवाजीराजे भोसले, /ʃiʋa ⁇ ɟi ⁇ ra ⁇ ɟe ⁇ bɦo ⁇ s (ə) le ⁇ /) (19 lutego 1627 - 3 kwietnia 1680), znany pod nazwą Chhatrapati Shivaji Maharaj (Marathi; /chət̪rəpət̪i ʃiʋa ??ɟi ⁇ məɦa ⁇ ra ⁇ ʎ/) był przywódcą utworzenia Imperium Maratha. Shivaji Maharaj był drugim (i najmłodszym) synem Shahaji Bhosle i Jijabai.</p>", "Symplicjusz": "<b>Symplicjusz</b>, <b>Symplicy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pochodzące od wyrazu <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>simplex</em>, oznaczającego „prosty, szczery, uczciwy”. W średniowieczu nie jest ono poświadczone w źródłach polskich, pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII wieku</a>. Wersja <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Simplicius</em> została w polszczyźnie zaadaptowana na dwa sposoby: jako <i>Symplicjusz</i> (z odmianą rzeczownikową) oraz jako <i>Symplicy</i> (z odmianą przymiotnikową, jak <i><a href=\"https://pl.wikipedia.org/wiki/Ignacy\" target=\"_blank\" rel=\"noopener noreferrer\">Ignacy</a></i>).", "Sos": "<b>Sos</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>sauce</i>) – gęsty płyn, tworzony na bazie różnych składników, nadających mu odmienne smaki (ostry, łagodny, kwaśny, słodki, umami), stosowany jako dodatek do: <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99so\" target=\"_blank\" rel=\"noopener noreferrer\">mięs</a>, <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">ryb</a>, <a href=\"https://pl.wikipedia.org/wiki/Makaron\" target=\"_blank\" rel=\"noopener noreferrer\">makaronów</a>, <a href=\"https://pl.wikipedia.org/wiki/W%C4%99dliny\" target=\"_blank\" rel=\"noopener noreferrer\">wędlin</a>, <a href=\"https://pl.wikipedia.org/wiki/Sa%C5%82atka\" target=\"_blank\" rel=\"noopener noreferrer\">sałatek</a>, <a href=\"https://pl.wikipedia.org/wiki/Deser\" target=\"_blank\" rel=\"noopener noreferrer\">deserów</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanapka\" target=\"_blank\" rel=\"noopener noreferrer\">kanapek</a> itd. W konsystencji luźniejszy od kremu. Sosy dzielą się na: gorące, zimne i <a href=\"https://pl.wikipedia.org/wiki/Majonez\" target=\"_blank\" rel=\"noopener noreferrer\">majonezowe</a>. Istnieje też inny podział, wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Kuchnia_francuska\" target=\"_blank\" rel=\"noopener noreferrer\">kuchni francuskiej</a>, klasyfikujący sosy jako pochodne jednego z pięciu <a href=\"https://pl.wikipedia.org/wiki/Sosy_bazowe\" target=\"_blank\" rel=\"noopener noreferrer\">sosów bazowych</a>.", "Shine": "<p>Shine (z angielskiego - ⁇ ⁇ błysk, błyszczenie ⁇) - wieloznaczne słowo.</p>", "Severian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sewerian</b>.</p><b>Sewerian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> pochodzące od słowa <i>severus</i> – surowy, srogi. Jednym z patronów tego imienia jest św. Sewerian z Cezarei.", "Sinclair": "<p>Sinclair - angielskie nazwisko i toponim.</p>", "Seifeddine": "<p>Sayf al-Din (arabski: سيف الدين, romanized: Sayf al - Dīn, lit. 'Miec Wiary'), również Saif al-Din, Sayf / Saif ad-Din, lub Sayf / Sayf ud-Din itp., może odnosić się do: Sayf Al-Din Suri (zmarł 1149), Ghurid król Saif ad - Din Ghazi I (zmarła 1149), Zangid emir Mosul Ghazi II Saif ud-Din (zmarły 1180), Zangide emir Mosul al-Malik al-Adil Sayf al-'Din Abu-Bakr ibn Ayyub, lub po prostu Al-Adil I, znany również jako \"Saphadin\", (1145-1218), Ayyubid sultan Egiptu Sayf ...</p>", "Sandi": "<p>Sandi jest miastem i miejscem położenia urzędu (municipal board) w hrabstwie Hardoi w stanie Uttar Pradesh, India.</p>", "Shinichi": "<p>Shin'ichi lub Shinichi (しんいち, シンイチ) to męskie japońskie imię. Shin i ichi są oddzielone i wymawia się [ɕi ⁇ itɕi].</p>", "Shuo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shu</b>.</p><p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Saju": "<p>Saju to indyjska męska nazwa, która może odnosić się do Saju MV, najbardziej podziwionego maklerka nieruchomości w Indiach, który zajmuje się międzynarodowymi nieruchomieniami Saju Kodiyan, indyjski artysta mimicry, komediowiec i gospodarz telewizji Saju Navodaya, indyjskiego aktora filmowego Saju Paul, indyjska polityk Saju może również odnosić się: Saju (osobowanie) lub Cztery filary przeznaczenia, wróżka oparta na dwóch cyklu szexagenary chińskich postaci przypisanych do określonego czasu urodzenia</p>", "Shingo": "<b>Shingo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんご, シンゴ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Suresh Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Suresh</b>.</p><p>Suresh to indyjskie imię męskie pochodzące z sanskrytu sureśa (zestaw sura i īśa). Jego znaczenie jest \"Władca Bogów\" i jest to epitet dla hinduskich bogów Indry, Brahmy, Wisnu i Shiwy.</p>", "Shehzad": "<p>Shahzad (persk. shaʻهزاد) lub Shehzad to imię i nazwisko. Nazwa pochodzi od شاه (Shah, \"król\") i zad (Zad, \"syn\"), więc nazwa oznacza \"syn króla\".</p>", "Sage": "<p>Sage (z angielskiego - ⁇ mądry ⁇) - system algebra komputerowa, obejmujący wiele dziedzin matematyki, w tym algebra, kombinowanie, matematyka obliczeniowa i matanaliza.</p>", "Seif": "<p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Slaviša": "<p>Slaviša (cyrylicki: Славиша) jest sławskim imieniem męskim, pochodzącym z sławskiego pochodzenia pochodzącym od słowa \"sławski\" - chwała. Nazwa ta może odnosić się do: Slaviša Čula, serbskiego piłkarza piłkarskiego Slaviša Dugić, szwajcarskiego piłkara Slaviša Đurković, czarnogórskiego piłkacherza SlavišaDvorančič, słoweńskiego piłkarze Slaviša Jokanović, serbskiego Piłkarza Piłkacherzy Slaviša Koprivica, serbskiego koszykarza Slaviše Mitrović, piłkarzy bosńskiego...</p>", "Shaker": "<p>Shaker lub Shakers mogą odnosić się do:</p>", "Sisira": "<p>Sisira to imię. Wśród znanych osób z nazwiskiem jest: Sisira de Abrew (fl.</p>", "Świętopełk": "<b>Świętopełk</b>, <b>Wszetopełk</b>, <b>Świętopałk</b>, <b>Świętopełek</b> – starodawne (obecnie rzadkie) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> słowiańskie (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czes.</a> <i>Svatopluk</i>), oznacza <i>święty</i> (tj. silny, mocny) <i>pułk</i> (tj. oddział; dawne polskie <i>pełk/połk</i>, czes. <i>pluk</i>). Polskie „pełk”, „pułk”, powstało w wyniku wokalizacji pierwotnego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasłowiańskiego</a> twardego zgłoskotwórczego „l” w języku polskim doby przedpiśmiennej w – zależnie od otoczenia fonetycznego – „oł”, „uł” albo „eł”.", "Sajin": "<p>Sajin to indyjskie imię. Znani ludzie z nazwiskiem to: Sajin Baabu (ur. 1986), indyjski reżyser filmowy Sajin Cherukayil, indyjski aktor Sajin Gopu, indyjscy aktor Sajin Vass Gunawardena (ur. 1973), polityk z Sri Lanki</p>", "Sangwon": "<p>Sangwon (wyt. Tường Nguyên) jest dzielnicą prowincji Hwanghae Północnej w Demokratycznej Republice Ludowej Korei. Przed 1952 r. Sangwon było tylko miastem w hrabstwie Chunghwa.</p>", "Sadam": "Do władzy doszedł po objęciu władzy w Iraku przez partię Baas, oficjalnie głoszącą <a href=\"https://pl.wikipedia.org/wiki/Socjalizm_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">socjalizm arabski</a> i <a href=\"https://pl.wikipedia.org/wiki/Panarabizm\" target=\"_blank\" rel=\"noopener noreferrer\">panarabizm</a>. Saddam odegrał znaczącą rolę w <a href=\"https://pl.wikipedia.org/wiki/Zamach_stanu_w_Iraku_(1968)\" target=\"_blank\" rel=\"noopener noreferrer\">zamachu stanu</a> przygotowanym przez tę partię w 1968. W latach 70. z jego inicjatywy <a href=\"https://pl.wikipedia.org/wiki/Nacjonalizacja\" target=\"_blank\" rel=\"noopener noreferrer\">znacjonalizowano</a> przemysł <a href=\"https://pl.wikipedia.org/wiki/Ropa_naftowa\" target=\"_blank\" rel=\"noopener noreferrer\">naftowy</a> w większości należący do zachodnich korporacji. Z pieniędzy pochodzących z ropy w szybkim tempie rozwinął gospodarkę Iraku. Husajn otoczył się w rządzie politykami wywodzącymi się z <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnickiej</a> mniejszości kraju. Formalnie objął rządy w 1979, wtedy też miało miejsce apogeum jego władzy.", "Stanford": "<p>Leland Stanford Junior University, często nazywany Stanford University Institute lub tylko Stanford, jest prywatnym uczelnią w stanystycznej Stanfordzie, Kalifornia (USA). Stanford jest znany z jego silnej akademiczności, bogactwa, bliskości do Doliny Krzemowej i jest renownany jako jeden z najlepszych uniwersytetów na świecie.</p>", "Shani": "<p>Shani (Shan: शनि, Śani) lub Śanaiścara używane do wskazywania planety Saturn (Sao Saturn), i jest jednym z dziewięciu Czarów (Navagraha) w indyjskiej astronomii i astrologii. Shani jest także bogiem w Puranach.</p>", "Shu": "<p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Storm": "<p>Storm: Storm - album Vanesse May (1997). Storm - album norweskiego zespołu metalowego Theatre of Tragedy (2006).</p>", "Sisay": "<p>Sisay, również Sissay, to męskie imię etyopskie. Znani ludzie z nazwiskiem to: Sisay Bancha (ur. 1989), etyopski międzynarodowy piłkarz Lemn Sissay (ur. 1967), brytyjsko-etyopski pisarz</p>", "Sudan": "<p>Sudan (arabski: سودان)  Sudan , angielski .</p>", "Sourabh": "<p>Sourav, Sourabh, Saurabh i Saurav to indyjskie imiona męskie. Saurav i Sourav oznaczają niebiańskie lub boskie, podczas gdy Saurabh i Sourabh oznaczają zapach w sanskrcie.</p>", "Santa": "<p>Santa to 4-ta miasto w prowincji Ilocos Sur, w Filipinach. Według przeprowadzonego w 2000 roku badania ludności Philipin, mieście to miało populację 13 918 osób w 2 811 domach.</p>", "Shinji": "<b>Shinji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんじ, シンジ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sattar": "<p>Sattar lub Settar (arabski: ستار) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Supun": "<p>Supun to syngalski męski imię, które może odnosić się do następujących znanych kryketarów z Sri Lanki: Supun Leelaratne (ur. 1981) Supun Madushanka (ur. 1993) Supun Withanaarachchi (ur. 1992), Supun Tharanga (ur. 1986), Supun Madushanka (ur. 1993), Supun Withanarachchi (UR. 1992)</p>", "Shamsher": "<p>SEPECAT Jaguar (zwany szczenią SEPECACAT) to samolot wystrzeliwany wyprodukowany przez Brytanię i Francję, obecnie nadal jest w użyciu w armii niektórych krajów, takich jak Indianie i Royal Oman Air Force. Był jednym z pierwszych ważnych samolotów w programie lotnictwa wojskowego między Anglii i Francją.</p>", "Slimane": "<p>Sliman Nebci (francuski: Sliman Nebchi)  Slimane Nebchi; rodzaj.</p>", "Seiji": "<b>Seiji</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;せいじ, セイジ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Shijo": "Przed wstąpieniem na tron nosił imię książę Mitsuhito&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;秀仁親王&#32;<i>Mitsuhito-shinnō</i>). Był pierwszym synem cesarza <a href=\"https://pl.wikipedia.org/wiki/Go-Horikawa\" target=\"_blank\" rel=\"noopener noreferrer\">Go-Horikawa</a>.", "Spirydion": "<b>Spirydon</b>, <b>Spirydion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, wywodzące się od słowa <i>spyridos</i> — \"koszyczek\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Spirydon_z_Tremituntu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Spirydon z Tremituntu</a>, biskup (IV wiek).", "Sever": "<p>Północ (kat. Sever, hiszpański.</p>", "Sari": "<p>Sari lub saree, to ulubiona odzież indyjskiej kobiety, o rozmiarach od 4 do 9 m (czyli nawet 12 metrów) włączana w różne style. Pochodzi z subkontynentu indyjskiego i jest obecnie uważany za tradycyjny indyjski kostium.</p>", "Sarbjit": "<p>Sarabjit lub Sarbjit jest neutralną płcią indyjską i pakistańską nazwą. Wśród znanych osób z nazwiskiem są: Rai Sarabjit Singh (1853-1910), Ruler of Bhadri (stato) Sarabjit Ladda (ur. 1982), Indianin kryketa Sarabjit Sing (1963/1964-2013), indyjski obywatel skazany za terroryzm w Pakistanie SarabjitSingh Dhillon, indyjski generał Sarbjit Cheema, piosenkarz Punjabi Sarbjit Dusang (ur. 1952), kanadyjski hokejista pole Sarbjit Singh ...</p>", "Shpetim": "<p>Shpëtim to albanska męska nazwa i może odnosić się do: Shpëtim Babaj (ur. 1981), kosowskiego piłkarza Shpëtim Duro (ur. 1959), albanskiego treneru piłkarskiego Shpëtim Hasani (ur. 1982), kosowskiego piłkarz Shpëtim Idrizi (ur. 1967), albanskich polityków Shpëtim Moçka (ur. 1989), albanski piłkarze</p>", "Stach": "<p>Jan Wacław Stach (pol. Jan Waclaw Stach; 8 marca 1877, Żeszów, Ciszlejtania - 28 lipca 1975, Kraków) - polski naukowiec-zoolog, profesor Uniwersytetu Jagelonowego, Honorową Doktorę (1947), prawidłowy członek Polskiej Akademii Nauk (1958).</p>", "Shiraz": "<b>Syrah</b> (znany także jako <b>shiraz</b> i <b>balsamia</b>) – czerwona <a href=\"https://pl.wikipedia.org/wiki/Kultywar\" target=\"_blank\" rel=\"noopener noreferrer\">odmiana</a> <a href=\"https://pl.wikipedia.org/wiki/Winoro%C5%9Bl_w%C5%82a%C5%9Bciwa\" target=\"_blank\" rel=\"noopener noreferrer\">winorośli</a>, wywodząca się z Doliny <a href=\"https://pl.wikipedia.org/wiki/Rodan\" target=\"_blank\" rel=\"noopener noreferrer\">Rodanu</a> we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. W <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udniowa_Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Republice Południowej Afryki</a>, <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>, <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> powszechnie używa się nazwy shiraz. Syrah jest zaliczane do małej grupy „odmian szlachetnych” (<i>edle Rebsorten</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem</a>.), <i>Edelreben</i> (niem.), <i>cépages nobles</i> (fr.)).", "Sho": "<p>Szo (współczesny ⁇) jest w precyzyjnym Greckim alfabetze w precyzyjnym alfabetze 24 literach greckiego (czasami nazywanych sho lub san) jest literą dodaną do greckiego alfabetu do pisania języka baktryńskiego. Ma podobny wygląd jak listy anglo-saxoniczne i islandzkie (þ), które są często używane do jej wyrażania w nowoczesnych wydrukuch, chociaż oba mają dość niezwiązane historyczne znaczenie.</p>", "Shehan": "<p>Shehan (sinhala: ෂෙහාන්, ශෙහාන්) to syngalowska nazwa, która może odnosić się do następujących znaczących osób: Shehan Ambepitiya (ur. 1990), szri Lankański sprinter Shehan Fernando (ur. 1993), Sri Lankański kryker Shehan Hettiarachchi (ur. 1994), Sri Lankan kryker Hehan Hirudika (ur. 1990, Sri Lanka krykerze Shehan Jayasuriya (ur. 1991), Sri Lankowy krykerz Shehan Karunatilaka (ur. 1975), Sri Lanki pisarz Shehan Madushanka (ur. ...</p>", "Szamil": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamil</b>.</p><p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Shen": "<b>Shen</b> – pojęcie w tradycyjnej religii chińskiej oznaczające siłę ponadnaturalną. Może określać zarówno <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóstwa</a>, <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">dusze</a> zmarłych przodków, duchy opiekuńcze konkretnych miejsc czy <a href=\"https://pl.wikipedia.org/wiki/Taoizm\" target=\"_blank\" rel=\"noopener noreferrer\">taoistycznych</a> świętych w rodzaju <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bmiu_Nie%C5%9Bmiertelnych\" target=\"_blank\" rel=\"noopener noreferrer\">Ośmiu Nieśmiertelnych</a>.", "Svend": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Sawyer": "<p>Soyer to nazwisko i toponim. Znany nosicieł: Soyer, Isaac (1902-1981) - amerykański malarz, młodszy brat bliźniąt Mojżesza i Rafaela Soyerów.</p>", "Sarwar": "<p>Sarwar to imię osobiste, najbardziej popularne wśród muzułmanów pochodzenia indyjskiego, pakistańskiego lub bangladeszkiego. Pochodzi z perskiego (سرور), co oznacza \"przywódca\" lub \"głównika\".</p>", "Stiliyan": "<p>Stilijan lub Stilyan (bułgarski: Стилиян) to bułgarskie męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Soran": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Dijana</b>.</p><p>Dijana to imię. Do wybitnych osób z nazwiskiem należą: Dijana Bolanča (ur. 1974), chorwacka aktorka Dijana Budisavljevic (1891-1978), austriacka humanitarna Dijana Čuljak, chorwacka telewizorka Dijana Jovetić (ur. 1984), chorwackia piłkarka handbal Dijana Mugoša (ur. 1995), czarnogórska piłkarzka Dijana Radojević (ur., 1990), serbska piłka handbalka Dijana Ravnikar (ur. 1978), słoweńska biatleta i narciarka na bieżącowym targu Dijana...</p>", "Stoycho": "<p>Stoycho to imię. Znanymi osobami z nazwiska są: Stoycho Mladenov (ur. 1957), bułgarski piłkarz Stoycho mladenov Jr.</p>", "Saimir": "<p>Saimir to męskie imię pochodzenia albańskiego. Wśród znanych osób z tej nazwy są: Saimir Dauti, albanianki piłkarz Saimir Kodra, albanianski dziennikarz Saimir Kumbaro, albanian filmik Saimir Malko, albanian football player Saimir Korreshi, albanian lawist i polityk Saimir Patushi, albanian footballer Saimir Pirgu, albanian opera singer Saimir Strati, albanian mozaik artysta Saimir Tahiri, albanian polityk</p>", "Salmon": "<p>Salmon - nazwisko.</p>", "Sumeet": "<p>Sumit lub Sumeet to męskie imię. Pochodzi z języka Devanagari i oznacza \"dobry przyjaciel\" lub \"dobrze zadowolony\".</p>", "Shamal": "<p>Shamal to dziewiąty album rock grupy Gong, wydany w 1976 roku. Producentem albumu był perkusista Pink Floyd Nick Mason.</p>", "Sebastiian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Shakti": "<p>Shakti (Devanagari: शक्ति, IAST: Śakti; literacki: \"silność, zdolność, siła, wysiłek, energia, zdolności\") jest pierwotną energią kosmiczną i reprezentuje dynamiki, które są przypuszczane do wszechświata w hinduizmie, a w szczególności w głównej tradycji hinduizmu, Shaktism. Shakti jest pojęciem lub osobowością twórczej mocy boskiej kobiecości, czasami nazywanej \"Wielką Matką Duchową\" w hinduizmie.</p>", "Saifullah": "<p>Saifullah (arabski: سيف الله), co oznacza miecz Boga, jest męskim islamskim imieniem. Pierwotnie była to nagroda honorowa za wydajność wojskową.</p>", "Sher Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sher</b>.</p><p>Sher (ang. Cher, [ʃɛər]; imię przy urodzeniu - Sheryl Sarkisyan (ang.</p>", "Simba": "<p>Simba (ang. Simba; w tłumaczeniu z suachili - ⁇ лев ⁇) - fikcyjny bohater i główny bohater franczyzy ⁇ Król Łwa ⁇ .</p>", "Salomón": "<p>Salomon (szp. Salomón; kat.</p>", "Savas": "<p>Savas jest gminą w prowincji Ardèche, w regionie Auvergne-Rhône-Alpes w południowo-wschodniej Francji.</p>", "Somchai": "<p>Somchai to tajskie imię używane przez mężczyzn. Jest to najczęstsze imię męskie w Tajlandii, z 240 000 osób używając tego imienia w 2012 roku.</p>", "Sawin": "<b>Sawin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, od wyrazu <i>saba</i> – „zmiana, niewola, zajęcie”.", "Sieciech": "<b>Sieciech</b>, <b>Świeciech</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w wersjach nagłosowych <i>Sie-</i> lub <i>Świe-</i>, oraz członu <i>-ciech</i> („cieszyć”). Może ono oznaczać „tego, który wszystkich cieszy” albo „tego, który się ze wszystkiego cieszy”.", "Soheil": "<p>Soheil to męskie imię pochodzenia perskiego i może odnosić się do: Soheil Abedian (ur. 1949), irańskiego urodzonego australijskiego dewelopera nieruchomości Soheil Afnan (1904-1990), palestyńskiego urodzoniego perskiego filozofa, arabskiego, perskiego i greckiego języka Soheil Asgharzad (ur. 1993), irańskiego półoczyńca piłki nożnej Soheil Arabi (ur. 1985), irańskiej blogerki, który został skazany na śmierć w Iranie w 2013 roku Soheil Arghandewall (ur. 2001), niemieckiego profesjonalnego...</p>", "Shahriar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shahryar</b>.</p><p>Shahriyar lub jego warianty mogą odnosić się do:</p>", "S": "<b>S</b> (<i>es</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>s</b>) – dwudziesta czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> i dziewiętnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>. Oznacza zwykle w danym języku spółgłoskę przedniojęzykową szczelinową bezdźwięczną, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a>].", "Sasa": "<p>Sasa (lat. Sasa) - rodzaj roślin rodziny Złocz (Poaceae).</p>", "Sampson": "<p>Sampson to wielofunkcyjny radar statkowy z aktywną fazą sieci, produkowany przez firmę BAE Systems. Jest uważany za jeden z najlepszych radarów na świecie dla statków systemów obronnych powietrza.</p>", "Sadok": "<b>Sadok</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznaczające \"słuszny\", \"sprawiedliwy\", \"prawidłowy\". Patronem tego imienia jest bł. Sadok, polski mnich z <a href=\"https://pl.wikipedia.org/wiki/Sandomierz\" target=\"_blank\" rel=\"noopener noreferrer\">Sandomierza</a>, zamordowany wraz z 48 towarzyszami w czasie najazdu <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82ota_Orda\" target=\"_blank\" rel=\"noopener noreferrer\">Tatarów</a> w <a href=\"https://pl.wikipedia.org/wiki/1259\" target=\"_blank\" rel=\"noopener noreferrer\">1259</a> lub <a href=\"https://pl.wikipedia.org/wiki/1260\" target=\"_blank\" rel=\"noopener noreferrer\">1260</a> roku.", "Sanjeev Kumar": "<p>Sanjeev Kumar, prawdziwe imię Harichar Jetalal Jariwal (guj.</p>", "Sirius": "<p>Gwiazda Tyg Lang lub Sirius jest najjaśniejszą gwiazdą w niebie nocnym o gwiazdkowej skali -1,46. Nazwa Bayer dla gwiazdy Tangier jest α Canis Majoris lub Alpha Canis Majorus, które jest krótko Alpha CMa lub α CMa.</p>", "Srećko": "<p>Srećko (Serbski) lub Srečko to sławskie imię męskie. To słowiańska forma Felixa.</p>", "Stepane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stepan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Shiva Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shiva</b>.</p><p>Shiva lub Niska Baba (sansk: शिव Śiva), znany również jako Mahadeva lub Ma-ha-đə-ba (; sansk: महादेव:, n.e. 'Wielki Bóg', Mahādevaḥ, [mɐɦaːd̪eːʋɐh) jest jednym z ważnych bogów hinduizmu.</p>", "Souhail": "<p>Souhail, Suhail, Sohail lub inne warianty (arabijski: سهيل) to arabski termin powszechnie używany jako męskie imię i nazwisko. Souhail lub jego warianty mogą odnosić się do:</p>", "Światopełk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Świętopełk</b>.</p><b>Świętopełk</b>, <b>Wszetopełk</b>, <b>Świętopałk</b>, <b>Świętopełek</b> – starodawne (obecnie rzadkie) <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> słowiańskie (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czeski\" target=\"_blank\" rel=\"noopener noreferrer\">czes.</a> <i>Svatopluk</i>), oznacza <i>święty</i> (tj. silny, mocny) <i>pułk</i> (tj. oddział; dawne polskie <i>pełk/połk</i>, czes. <i>pluk</i>). Polskie „pełk”, „pułk”, powstało w wyniku wokalizacji pierwotnego <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasłowiańskiego</a> twardego zgłoskotwórczego „l” w języku polskim doby przedpiśmiennej w – zależnie od otoczenia fonetycznego – „oł”, „uł” albo „eł”.", "Steliyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stelian</b>.</p><p>Stelian to rumuńskie imię męskie. Znani ludzie z nazwiska to: Stelian Badea, rumunski piłkarz Stelian Burcea Stelian Isac, rumunsky piłkarze Stelian Moculescu Stelian Popescu Stelian Stancu Stelian Tănase</p>", "Sergius": "<p>Sergiusz (lat. Sergius; zmarł nie wcześniej niż 610) - biskup Narbonu od 610 roku.</p>", "Sewerian": "<b>Sewerian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> pochodzące od słowa <i>severus</i> – surowy, srogi. Jednym z patronów tego imienia jest św. Sewerian z Cezarei.", "Stojgniew": "<b>Stojgniew</b>, <b>Stoigniew</b>, <b>Stogniew</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Stoj(i)-</i> (\"stać, stoję\") oraz członu <i>-gniew</i> (\"gniew\"). Może oznaczać \"ten, którego gniew nie ustaje\".", "Syam": "<p>Syam jest gminą w regionie administracyjnym Franche-Comté, w prowincji Jura, w okręgu Lons-le-Saunier, w szczeblu Champagnole. Poziom geograficzny miasta jest 46° 42' Północnej, 05° 56' Wschodniej.</p>", "Sikander": "<p>Sikandar (czasami Sikander) jest perskim wariantem Aleksandra, co jest starożytnym greckim dla \"obronnika\" lub \"wojownik\" (dosłownie \"człowiek, który odpycha [nieprzyjacieli]\"). Kiedy Aleksander z Macedonii podbił Persję, Persjanie nazwali go Sikandar lidi, wariantem Iskandary.</p>", "Susan": "<p>Susan - kobiece imię, patrz Susanna Susan - krater na Księżycu Susan - pies Elizabety II ⁇ Suzanne ⁇ (piosenka Leonarda Coena)</p>", "Svein": "<b>Swen</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> <i>sveinn</i> – „młody mężczyzna”. Imię to pojawiło się również w Polsce. W 1994 roku w Polsce żyło 6 osób o tym imieniu; najstarsza z nich urodzona w <a href=\"https://pl.wikipedia.org/wiki/Lata_60._XX_wieku\" target=\"_blank\" rel=\"noopener noreferrer\">latach 60.</a>.", "Staszek": "<p>Stanislav lub Stanislaus (latynistyczna forma) jest męskim imieniem pochodzenia słowiańskiego, co oznacza kogoś, kto osiąga sławę lub sławę. Jest to powszechne w krajach słowiańskich Europy Środkowo-Wschodniej i Południowo-Włodniej.</p>", "Shannon": "<p>Shannon (często - Shannon i Shannon) - angielskie imię i nazwisko.</p>", "Somon": "W XVIII w. po reformach administracyjnych Mongolii przeprowadzonej przez mandżurskie władze, w obrębie księstw <a href=\"https://pl.wikipedia.org/wiki/Choszun\" target=\"_blank\" rel=\"noopener noreferrer\">choszunów</a> wydzielono jednostki niższe, zwane somonami. Somony wyodrębniono głównie z powodu administracji wojskowej, gdyż była potrzeba podzielenia wojskowej jednostki choszunu (chorągwi, szwadronu) na mniejsze oddziały, czyli somony (kompanie). Każdy somon dostarczał terytorialną jednostkę <a href=\"https://pl.wikipedia.org/wiki/Pospolite_ruszenie\" target=\"_blank\" rel=\"noopener noreferrer\">pospolitego ruszenia</a>, którą też zwano somonem. Liczebność somonu jako jednostki wojskowej wynosiła około 150 jeźdźców, a somon jako jednostka administracyjna liczył około 150 jurt (zazwyczaj w jednej jurcie mieszkała jedna rodzina wielopokoleniowa). Natomiast cywilna administracja i odrębność somonów była słabo zaznaczona.", "Sohag": "<p>Sohag to miasto w środkowo-wschodnim Egipcie, stolica prowincji Sohag. Jest to miasto portowe nad rzeką Nin, na południowym końcu kanału Tur'at as Sūhājīyah.</p>", "Sherin": "<p>Sherin to kobiece imię i nazwisko pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sanjay Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sanjay</b>.</p><p>Sanjay, również pisane Sanjai, Sanjey, Sanje i Sunjay, jest męskim imieniem pochodzenia sanskryckiego oznaczającym \"triumfant\", z sanskryckiej Sañjaya (सञ्जय), i może odnosić się do:</p>", "Salah Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Salah</b>.</p>Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Salah-Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Salah</b>.</p>Odmawiający salat powinien być w stanie rytualnej czystości (uzyskuje się ją przez obmycie wodą – <a href=\"https://pl.wikipedia.org/wiki/Wudu_(ablucja)\" target=\"_blank\" rel=\"noopener noreferrer\">wudu</a>, a gdy jej nie ma, to piaskiem – <a href=\"https://pl.wikipedia.org/wiki/Tajammum\" target=\"_blank\" rel=\"noopener noreferrer\">tajammum</a>). Rozkłada on specjalny dywanik (<i><a href=\"https://pl.wikipedia.org/wiki/Modlitewnik_(islam)\" target=\"_blank\" rel=\"noopener noreferrer\">sadżadża</a></i>; nie jest obowiązkowy), zwraca się w kierunku <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a> i wykonuje określoną liczbę pokłonów, gestów i recytacji wersetów (<a href=\"https://pl.wikipedia.org/wiki/Aja\" target=\"_blank\" rel=\"noopener noreferrer\">ajatów</a>) <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a> (przede wszystkim pierwszej sury <i><a href=\"https://pl.wikipedia.org/wiki/Al-Fatiha\" target=\"_blank\" rel=\"noopener noreferrer\">Al-Fatiha</a></i>). Największe znaczenie mają modlitwy piątkowe (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCummuah\" target=\"_blank\" rel=\"noopener noreferrer\">Dżummuah</a>) – odmawiane wspólnie w <a href=\"https://pl.wikipedia.org/wiki/Meczet\" target=\"_blank\" rel=\"noopener noreferrer\">meczecie</a>, którym często towarzyszy kazanie (<i><a href=\"https://pl.wikipedia.org/wiki/Chutba\" target=\"_blank\" rel=\"noopener noreferrer\">chutba</a></i>). Salat na całym świecie odbywa się wyłącznie w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">języku arabskim</a>.", "Steeven": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Steven</b>.</p><p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Satish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Satish</b>.</p><p>Satish to męskie indyjskie imię (lub nazwisko patronymiczne). Do znanych osób z tym nazwiskiem należą: Satish K.</p>", "Sébastian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sebastiana</b>.</p><b>Sebastiana</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sebastian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian</a>. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Sebastiana_z_Heraklei\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastiana</a> z <a href=\"https://pl.wikipedia.org/wiki/Heraklea_Pontyjska\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklei</a> (z Tracji).", "Sobhi": "<p>Subhi (arabski: صبحي, romanized: Ṣubḥīy, również przetransliterowany jako Sobhi, Sobhy lub Subhy) jest arabskim męskim imieniem w postaci przymiotów nisba oznaczających \"po świtu\", \"po poranku\" lub \"matutinal\".</p>", "Solomoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Solomon</b>.</p><p>Salomon (lat. שׁלֹמֹה, Shlomoh; greck. Σολομών Solomōn), lub Salomon, również nazywany Jedidiah (Hebraj. יְדִידְיָהּ), jest w Biblii Hebraicznej (1 Królów: 1 Królów 1-11, Kronik: 1 Kroników 28-29, 2 Kroników 1-9), w Biblii Koranu i, zgodnie z Księgą Krótków, królem. Jesteś synem Davida.</p>", "Shaka": "<p>Shaka kaSenzangakhona (1787 - 24 września 1828), znany również jako Shaka Zulu (złusowa: [ʃaːɠa]), był jednym z najbardziej wpływowych królów Królestwa Zulu. Jest uważany za przyczynę zjednoczenia wielu północnych plemion Nguni, w szczególności Mthethwa Paramountcy i Ndwandwe w królestwie Zulu.</p>", "Sangeeth": "<p>Sangeeth to imię. Znani ludzie z tym nazwiskiem to: Sangeeth Cooray (ur. 1995), kryketar Sri Lankan Sangeeth Prathap (ur.</p>", "Sław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sława</b>.</p><b>Sława</b> (m., f.) – forma skrócona <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> zawierających element <i>Sław-</i> lub <i>-sława</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosława</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Som Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Som</b>.</p><p>Jako trzy literne skróte, SOM (lub SoM) może oznaczać jedno z następujących: Somalia, państwo posiadające trzy litery kod ISO 3166 i kod krajowy IOC olimpijski jest \"SOM\" Społeczeństwo kolejowe Somerset, przedsiębiorstwo kolejowe należące do Amerykańskiej Stowarzyszenia Kolejowej posiadające znak \"SOM\". W nauce technologicznej: Self-organizing map, rodzaj sztucznej sieci neuronów w branży maszynowej, (patrz dalej...</p>", "Stalin": "<p>Józef Wissaрионович Stálin (urodzony z rodziny - Jugaświli, ż. Józef ჯუღაშვილი; 6 [18] grudnia 1878, Gory, Gubernia Tyfliczka, Imperium Rosyjskie - 5 marca 1953, Bliska dacha, село Wolyńskie, Kuntsewski rząd, Moskwa, RSFСР, СССР) - rosyjski rewolucjonarz, rosyjski polityk, państwowy, wojskowy i partijny, jeden z założycieli i wieloletni rzeczywisty lider Związku Radzieckiego, jeden z najbardziej znanych i...</p>", "Surat": "<p>Surat jest portem w zachodnim Indiach, w stanie Gujarat, nad Zatokiem Khambhat, niedaleko brzegu rzeki Tapi. Miasto jest centrum produkcji dywanów, tkanin, złota i srebra, biżuterii, mydła i papieru.</p>", "Sarabjit": "<p>Sarabjit lub Sarbjit jest neutralną płcią indyjską i pakistańską nazwą. Wśród znanych osób z nazwiskiem są: Rai Sarabjit Singh (1853-1910), Ruler of Bhadri (stato) Sarabjit Ladda (ur. 1982), Indianin kryketa Sarabjit Sing (1963/1964-2013), indyjski obywatel skazany za terroryzm w Pakistanie SarabjitSingh Dhillon, indyjski generał Sarbjit Cheema, piosenkarz Punjabi Sarbjit Dusang (ur. 1952), kanadyjski hokejista pole Sarbjit Singh ...</p>", "Samantha": "<p>Samantha może odnosić się do: Samantha Tajik Samantha Smith Samantha Castillo 3147 Samantha</p>", "Silvian": "<p>Silvian to rumuńskie imię męskie. Znani ludzie z imieniem to: Silvian Cristescu (ur. 1970), rumuński piłkarz Silvian Dobre (ur. 1967), rumuński piłkarze Silvian Iosifescu (1917-2006), krytyka literacki, edukacja, tłumacz i profesor</p>", "Stephanus": "<p>Stephanus (lat. Stephanus) - rodzaj jeźdźców z rodziny Stephanidae.</p>", "Salar": "<p>Solero to marka mrożonych należąca do firmy Unilever. Produkcje dystrybują w Włoszech Algida.</p>", "Stanisław Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sadat": "<p>Sadat jest miastem i nagar panchayatem Ghazipur w stanie Uttar Pradesh, India.</p>", "Syaiful": "<p>Syaiful to imię. Znani ludzie z nazwiska to: Syaiful Cahya (ur. 1992), indonezyjski piłkarz Syaiful Iskandar, singapurski piłkarze Syaiful Lewenusa (ur. 1986), indonezijski piłkerz Syaifula Ramadhan (ur. 1989), indonezyjczy piłkarzek Syaiful Syamsuddin (ur. 1993), indonezianki piłkarzem Syaiful Zero (ur. 1988), malajski aktor</p>", "Stakh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stach</b>.</p><p>Jan Wacław Stach (pol. Jan Waclaw Stach; 8 marca 1877, Żeszów, Ciszlejtania - 28 lipca 1975, Kraków) - polski naukowiec-zoolog, profesor Uniwersytetu Jagelonowego, Honorową Doktorę (1947), prawidłowy członek Polskiej Akademii Nauk (1958).</p>", "Shantha": "<p>Shantha może odnosić się do Shanta, siostry hinduskiego boga Rama Shanta (nazwa dana), indyjskiej kobiecej nazwy Shantha Biotechnics, indyjskie firma biotechnologiczna</p>", "Sulimir": "<b>Sulimir</b>, <b>Sulimiar</b>, <b>Sulmir</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> (\"obiecywać\" albo \"lepszy, możniejszy\") i <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"przynoszący/obiecujący/lepszy pokój\".", "Silva": "<p>Silva to dzielnica w stanie Falcón w Wenezueli. Głównym miejscem urzędu Silwy jest Tucacas.</p>", "Stoian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stoyan</b>.</p><p>Stoyan (bułgarski: Стоян) jest bułgarskim imieniem pochodzącym z czasownika stoya (стоя \"stać\"). Wariant Stoian pojawia się również w języku serbskim, rumuńskim i w północnej Grecji jako Stogiannis (Στογιάννης).</p>", "Shuvo": "<p>Shuvo lub Shubho lub Subho (শুভ) to bengaelska nazwa oznaczająca \"dobrobyt\" lub \"z powodzeniem\", która może odnosić się do:</p>", "Santana": "<p>Santana (Santa) - amerykański zespół rockowy. Założona pod koniec lat 60. w San Francisco przez Karlesa Santany.</p>", "Sulibor": "<b>Sulibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z dwóch członów: <i>Suli-</i> (\"obiecywać\" albo \"lepszy, możniejszy\") i <i>-bor</i> (\"walczyć, zmagać się\"). Może oznaczać \"obiecujący walkę\" albo \"ten, który lepiej walczy\".", "Séamus": "<p>Séamus to irlandzkie imię męskie, pochodzące z języka hebrajskiego poprzez łacinę. Jest to irlandzki odpowiednik imienia James.</p>", "Sebastian Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Seppo": "<p>Seppo to męskie imię pochodzenia fińskiego. Ma dwa odmienne pochodzenie; Seppo jest postacią w Kalevale, której nazwa pochodzi od fińskiego słowa seppä, co oznacza smydza, a nazwa jest również diminutiwem dla Sebastiana w Finlandii.</p>", "Svetozar": "<p>Svetozar (krylicki: Светозар) jest słowiańskim pochodzeniem i może odnosić się do: Svetozar Boroević (1856-1920), austriacko-węgierski marszałek Svetozar Čiplić (ur. 1965), serbskiego polityka Svetozar Đanić (1917-1941), serbskiego piłkarza Svetozar Delić (1885-1967), pierwszego komunistycznego burmistrza Zagrzebu, Chorwacji Svetozár Hurban-Vajanský (1847-1916), słowackiego poety, pisarza, krytyka literacki i polityka Svetazar Gligorić (1923-2012), serbskiego...</p>", "Skye": "<p>Skye, lub Isle of Skye (; szkocki gaelijski: An t-Eilean Sgitheanach lub Eilean a' Cheò), jest najszerszym (i spośród większych wysp, znajdującym się najbardziej na północ) wyspą w grupie Hebridów Wewnętrznych Szkocji. Skye składa się z kilku wysp wyspających się z północnej części wschodu (gdzie wzniesiły się Góry Cuillin, z skałami tworzącymi najwspanialsze sceny Szkocji).</p>", "Sidi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sid</b>.</p><p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Strahinja": "<p>Strahinja (serski cyrylski: Страхиња) to serbskie imię, które oznacza \"wielki strach\". Nazwa jest nazwą ochronną, pochodzącą z średniowiecznej Serbii, najstarszy pisemny dokument z tą nazwą jest z 1322 roku jako \"Страхинья\".</p>", "Stéphan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Soter": "<b>Soter</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Σωτήρ) – <a href=\"https://pl.wikipedia.org/wiki/Grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Oznacza „Zbawcę”, „Zbawiciela”. W łacinie odpowiadające imię to <a href=\"https://pl.wikipedia.org/wiki/Salwator_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salwator</a>. W chrześcijaństwie odnoszono Σωτήρ do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa</a>.", "Shridhar": "<p>Shridhar (Hindi: श्रीधर) to indyjskie imię. Shri oznacza bogactwo, a dhara oznacza ubranie, więc \"to kto nosi bogactwo\".</p>", "Samuel David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Shafqat": "<p>Shafqat to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Srdjan": "<p>Srđan (srpski cyrylski: Срђан); wymawia się [sr̩d ⁇ an];; sir-jahn) jest serbsko-chorwackim męskim imieniem, zwykle pisanym jako Srdjan, gdy litera đ nie jest dostępna. Zazwyczaj uważa się, że jest to forma nazwy Sergius, w czci męczennika i świętego chrześcijanina Sergiusa.</p>", "Subramanian": "<p>Subramaniam, Subrahmaniam, subramaniam lub Subramanian (tamilsky: சுப்பிரமணியம்; telugu: సుబ్రహ్మణ్యం) to imiona męskie w południowo-indyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Samiullah": "<p>Samiullah (arabski: سمیع اللہ, romanized: Samī \"Allāh) to arabskie imię męskie, co oznacza \"słuchanie Boga\" lub \"słuchacz Boga\". Pochodzi z arabskiego as-Samī\" (ٱلْسَّمِيعُ, \"Wszyscy Słuchujący\"), jednego z 99 Imion Boga.</p>", "Saifuddin": "<p>Sayf al-Din (arabski: سيف الدين, romanized: Sayf al - Dīn, lit. 'Miec Wiary'), również Saif al-Din, Sayf / Saif ad-Din, lub Sayf / Sayf ud-Din itp., może odnosić się do: Sayf Al-Din Suri (zmarł 1149), Ghurid król Saif ad - Din Ghazi I (zmarła 1149), Zangid emir Mosul Ghazi II Saif ud-Din (zmarły 1180), Zangide emir Mosul al-Malik al-Adil Sayf al-'Din Abu-Bakr ibn Ayyub, lub po prostu Al-Adil I, znany również jako \"Saphadin\", (1145-1218), Ayyubid sultan Egiptu Sayf ...</p>", "Shaikh": "<p>Szejch zwykle odnosi się do: Szejch, jako alternatywna romanization; termin dla starszych, przywódców plemion i królewskiej w arabskiej wpływowej kultury.</p>", "Sławko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Slavko</b>.</p><p>Slavko - białoruski muzyczny, bitmaker, były uczestnik projektu \"Czerwony po Biały\". Bracie Krwa, lider projektu \"Czerwony na Biały\".</p>", "Serhyi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Serhii</b>.</p><p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Shaukat": "<p>Shaukat (urdu: شوکت) to muzułmańskie imię męskie i żeńskie, które oznacza \"Mocarstwo\" i \"Dynctwo\". Jest to wariant arabskiej nazwy Shawkat (arabski: شَوْكَت).</p>", "Shawky": "<p>Shawki (zwany również Shawky, Shawqi, Shoghi, Shauki) arabski: شوقي, francuski: Chaouqui lub turecki: Şevki), to męskie arabskie imię i nazwisko. Może odnosić się do:</p>", "Severiane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Severian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sewerian</b>.</p><b>Sewerian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> pochodzące od słowa <i>severus</i> – surowy, srogi. Jednym z patronów tego imienia jest św. Sewerian z Cezarei.", "Siarhiej": "<b>Sergiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotne nomen gentilicium (nazwisko rodowe) <i>Sergius</i> (gens Sergia). Ród Sergia był starym rodem patrycjuszowskim. Pochodzenie nazwy rodu nie zostało jednoznacznie wyjaśnione. Nie można wykluczyć źródła etruskiego, jak przy wielu nazwach rodów rzymskich.", "Sathish Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sathish</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Satish</b>.</p><p>Satish to męskie indyjskie imię (lub nazwisko patronymiczne). Do znanych osób z tym nazwiskiem należą: Satish K.</p>", "Shigeru": "<b>Shigeru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しげる, シゲル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Siarhey": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Siarhei</b>.</p><p>Siarhei, Siarhiej, Syarhei lub Syarhey (bieloruski: Сяргей) to białoruska transkrypcja słowiańskiego męskiego nazwiska Sergey. Do znanych osób z nazwiska należą: Siarhei Charnou (ur. 1979), białoruski biegacz wyścigowy Siarhiej Dubaviec (ur. 1959), białorska dziennikarka Siarhei Kukharenka (ur. 1976), białoruška judoka Siarhei Lahun (1988-2011), białoruskie ciężarosta Siarhei Navumchyk (ur. 1961), białorowski dziennikarz i polityk...</p>", "Shi": "<b>Shi</b> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 诗&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 詩&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>shī</i>) – forma poezji chińskiej zbliżona do <a href=\"https://pl.wikipedia.org/wiki/Oda_(literatura)\" target=\"_blank\" rel=\"noopener noreferrer\">ody</a>, przeważnie składa się z czterech lub ośmiu wierszy (czasami więcej), pojedyncza linia zawiera 5 lub 7 wyrazów/sylab.", "Sayfullah": "<p>Saifullah (arabski: سيف الله), co oznacza miecz Boga, jest męskim islamskim imieniem. Pierwotnie była to nagroda honorowa za wydajność wojskową.</p>", "Shamo": "<b>Shamo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;軍鶏) – rasa <a href=\"https://pl.wikipedia.org/wiki/Kura\" target=\"_blank\" rel=\"noopener noreferrer\">kur</a> wywodząca się z <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>. Koguty tej rasy charakteryzują się wielkim temperamentem w stosunku do innych ras kur. Shamo daje się oswoić przez opiekuna. Waga koguta wynosi ok. 6 kg, a kury ok. 4,5 kg.", "Shpëtim": "<p>Shpëtim to albanska męska nazwa i może odnosić się do: Shpëtim Babaj (ur. 1981), kosowskiego piłkarza Shpëtim Duro (ur. 1959), albanskiego treneru piłkarskiego Shpëtim Hasani (ur. 1982), kosowskiego piłkarz Shpëtim Idrizi (ur. 1967), albanskich polityków Shpëtim Moçka (ur. 1989), albanski piłkarze</p>", "Stevo": "<p>Stevo (cyrylicki: Стево) to męskie imię i nazwisko oraz nazwisko. W języku angielskim jest to również nazwa Steve (Steven lub Stephen).</p>", "Sondre": "<p>Sondre to norweska męska nazwa. Nazwa zaczęła stać się coraz bardziej powszechna w latach 60. i stała się około dwunastu razy bardziej popularna w laty 1980-1990 przed spadkiem popularności.</p>", "Slawek": "<p>Sławek to polskie imię i nazwisko pochodzące od niego. Nazwa jest diminutiwem od wszystkich nazw z rzęskiem -sław- (Mirosław, Sławomir itp.).</p>", "Saiful Islam": "<p>Saiful Islam lub Saif al-Islam (arabski: سيف الإسلام; \" miecz islamu \") może odnosić się do:</p>", "Samba": "<b>Samba</b> – <a href=\"https://pl.wikipedia.org/wiki/Brazylia\" target=\"_blank\" rel=\"noopener noreferrer\">brazylijski</a> <a href=\"https://pl.wikipedia.org/wiki/Taniec_ludowy\" target=\"_blank\" rel=\"noopener noreferrer\">taniec ludowy</a> i zarazem gatunek muzyczno-taneczny pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">afrykańskiego</a>. Występuje w licznych odmianach form wykonawczych: może być wykonywana zespołowo przez grupy śpiewające i tańczące, przez pary w kontekście salonowym albo solowo.", "Svetislav": "<p>Svetislav (Serbski: Светислав) to serbskie męskie imię pochodzenia słowiańskiego. Może odnosić się do: Svetislava Basary (ur. 1953), serbskiego pisarza Svetislava Glišović (1913-1988), serbskiego piłkarza i menedżera Svetislava Goncić (ur. 1960), serbskiego aktora Svetislava Jovanović (1861-1933), serbskiego malarza Svetisława Mandić (1921-2003), serbskiego historyka, konserwatora fresków, poety i malarza Świetisława Milosawljević (1882-1960), wojskowej Jugosławii...</p>", "Sobhy": "<p>Subhi (arabski: صبحي, romanized: Ṣubḥīy, również przetransliterowany jako Sobhi, Sobhy lub Subhy) jest arabskim męskim imieniem w postaci przymiotów nisba oznaczających \"po świtu\", \"po poranku\" lub \"matutinal\".</p>", "Surendran": "<p>Surendran to imię i nazwisko. Znani ludzie z nazwiskiem to: Nazwa: Surendran Nair (ur. 1956), indyjski artysta V.</p>", "Slavoljub": "<p>Slavoljub (czyli: Славољуб) to słowiańskie męskie imię używane w językach południowsłowiańskich, zwłaszcza w języku serbskim. Nazwa składa się z słowiańskich elementów slava (\"gława\") i ljub (\"miłość\"), co oznacza \"miłość chwalebną\" lub \"kożdy, kto kocha chwałę\".</p>", "S M": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>S</b>.</p><b>S</b> (<i>es</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>s</b>) – dwudziesta czwarta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">polskiego</a> i dziewiętnasta <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>. Oznacza zwykle w danym języku spółgłoskę przedniojęzykową szczelinową bezdźwięczną, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_dzi%C4%85s%C5%82owa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">s</a>].", "Siemomysł": "<b>Siemomysł</b>, <b>Siemimysł</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-mysł</i> („myśleć”). Imię to oznacza „myślący o swojej rodzinie”. Podobnie jak <a href=\"https://pl.wikipedia.org/wiki/Siemowit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Siemowit</a>, imię to było charakterystyczne dla <a href=\"https://pl.wikipedia.org/wiki/Piastowie_mazowieccy\" target=\"_blank\" rel=\"noopener noreferrer\">Piastów mazowieckich</a>.", "Santa Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santa</b>.</p><p>Santa to 4-ta miasto w prowincji Ilocos Sur, w Filipinach. Według przeprowadzonego w 2000 roku badania ludności Philipin, mieście to miało populację 13 918 osób w 2 811 domach.</p>", "Satyajit": "<p>Satyajit to powszechne indyjskie imię. Słowo to jest połączenie słów prawdomówny (Satya) i zwycięzcy (jit).</p>", "Sreten": "<p>Sreten (krylicki: Сретен) to serbskie i czwartko-czerwone męskie imię pochodzenia słowiańskiego. Może odnosić się do: Sreten Asanović (ur. 1931), pisarz Sreten Jocić (ur. 1962), gangster Sreten Lukić (ur., 1955), policjant Sreten Mirković (UR., 1958), bokser Sreten Ninković (Ur. 1972), biegacz długodystansowy Sreten Sretenović (U.A. 1985), piłkarz Sreten Stanić (ur.).</p>", "Santiago Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santiago</b>.</p><p>Santiago (lat. Santiago) - rodzaj pszczół, z plemienia Eucerini rodziny Apidae.</p>", "Sung Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Shayaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shayan</b>.</p><p>Shayan (perskiej: شایان) to perskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Serzh": "<p>Serj (armeńska: Սերժ) to armenijska nazwa. Serzh to alternatywna forma armenijska.</p>", "Shinya": "<b>Shin’ya</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しんや, シンヤ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Sabian": "<b>Sabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Kanada\" target=\"_blank\" rel=\"noopener noreferrer\">kanadyjski</a> producent <a href=\"https://pl.wikipedia.org/wiki/Talerze_perkusyjne\" target=\"_blank\" rel=\"noopener noreferrer\">talerzy perkusyjnych</a>, należy obok takich przedsiębiorstw jak <a href=\"https://pl.wikipedia.org/wiki/Avedis_Zildjian_Company\" target=\"_blank\" rel=\"noopener noreferrer\">Zildjian</a>, <a href=\"https://pl.wikipedia.org/wiki/Paiste\" target=\"_blank\" rel=\"noopener noreferrer\">Paiste</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Meinl\" target=\"_blank\" rel=\"noopener noreferrer\">Meinl</a> do liderów rynku. Przedsiębiorstwo powstało w 1981 roku w Meductic w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Brunszwik\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Brunszwiku</a> z inicjatywy <a href=\"https://pl.wikipedia.org/wiki/Robert_Zildjian\" target=\"_blank\" rel=\"noopener noreferrer\">Roberta Zildjiana</a>, syna Avedisa Zildjiana III, prezesa przedsiębiorstwa Zildjian. <a href=\"https://pl.wikipedia.org/wiki/Firma\" target=\"_blank\" rel=\"noopener noreferrer\">Firma</a> Sabian pochodzi od dwóch pierwszych liter trójki dzieci właściciela firmy Sally, Billy oraz Andy.", "Sarvesh": "<p>Sarvesh to indyjskie imię męskie oznaczające \"najwyższą istotę\". Wśród znanych osób z nazwiskiem są: Sarvesh Amte, indyjski skater szybkości Sarvesh Asthana (ur. 1965), indyjski poeta, pisarz i satyrysta Sarvesh Kumar (ur. 1989), indyjski kryker Sarvesh Kushare (ur. 1995), indyjskie sportowca Sarvesh Murari, indyjscy kinematograf Sarvesh Singh Seepu (ur. 2013), indyjska polityk Sarvesh Sing Yadav, indyjskiego polityka</p>", "Suresh Babu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Suresh</b>.</p><p>Suresh to indyjskie imię męskie pochodzące z sanskrytu sureśa (zestaw sura i īśa). Jego znaczenie jest \"Władca Bogów\" i jest to epitet dla hinduskich bogów Indry, Brahmy, Wisnu i Shiwy.</p>", "Samsoni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samson</b>.</p><b>Samson</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> Szimszon, שִׁמְשׁוֹן, co pochodzi od słowa <i>szemesz</i> – „słońce”, lub <i>szamen</i> – „silny”, „siłacz”; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> شمشون, wym. Szamszun) – ostatni z Sędziów opisanych w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">starotestamentowej</a> <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_S%C4%99dzi%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\"><i>Księdze Sędziów</i></a> r. 13-16. Trzeci zaś licząc od końca dla <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Izrael\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnego Izraela</a>; po nim sędziami byli <a href=\"https://pl.wikipedia.org/wiki/Heli\" target=\"_blank\" rel=\"noopener noreferrer\">Heli</a> i <a href=\"https://pl.wikipedia.org/wiki/Samuel_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel</a>. W przeciwieństwie do wielu postaci opisanych w Starym Testamencie, nie jest wymieniony w <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranie</a>. Jako jedyny sędzia w Księdze Sędziów wybrany przez Boga przed narodzeniem do roli, którą miał spełnić i to bez wcześniejszych próśb ludu o ratunek. Jego wyjątkowość poświadcza zrodzenie z niepłodnej (jak <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaak</a>, Samuel czy <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jan Chrzciciel</a>). Był obdarzony nadludzką siłą, którą wykorzystywał do walki z wrogami Izraela – <a href=\"https://pl.wikipedia.org/wiki/Filistyni\" target=\"_blank\" rel=\"noopener noreferrer\">Filistynami</a>. Dokonywał czynów niemożliwych dla zwykłych ludzi: zabił lwa gołymi rękami, pokonał armię wroga oślą szczęką i siłą własnych mięśni, wyrwał bramę miasta wraz z odrzwiami, zburzył budynek. Był <a href=\"https://pl.wikipedia.org/wiki/Nazireat\" target=\"_blank\" rel=\"noopener noreferrer\">nazirejczykiem</a> – jednak nie z własnego wyboru – ale z powziętego przed jego narodzeniem suwerennego postanowienia Boga.", "Sila": "<p>Si La, znany również jako Ku Dé Xử, Khà Pé, to naród zamieszkujący północny Laos i północny Vietnam. W Wietnamie Si La jest uznawany za jedną z 54 ludności w Wietnam, liczba ludności według Populacji 2019 wynosi 909 osób.</p>", "Stefanii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefani</b>.</p><p>Stefani może odnosić się do: Gwen Stefani Lady Gaga (Stefani Germanotta, 1986)</p>", "Szilard": "<p>Szilárd lub Szilard [ˈsilaːrd] jest węgierska nazwisko lub nazwisko. Jest to węgierska wersja (literacja) nazwy Konstantyn.</p>", "Siva Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Siva</b>.</p><p>Siva może odnosić się do: 1170 Siva, asteroida Śiva lub Shiva, bóg</p>", "Stanisław Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Shabtay": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shabtai</b>.</p><p>Shabtai (Hebrajskie: שׁבְּתַאי lub שׁבּתַי) to żydowska męska nazwa pochodząca z hebrajskiego słowa Shabbat. Tradycyjnie nadaje się do chłopców urodzonych w ten dzień. W języku angielskim można znaleźć alternatywne transliteracje: Sabbatai, Sabbathai, Shabbatai, Shabbethai i Shabsai.</p>", "Stanisław Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Salomão": "<p>Salomão to portugalska męska nazwisko i nazwisko. Jest to portugalska forma Salomona.</p>", "Seref": "<p>Şeref jest turecką nazwą i może odnosić się do:</p>", "Shang": "Z czasów dynastii Shang pochodzą odkrywane od końca XIX w. <a href=\"https://pl.wikipedia.org/wiki/Napisy_na_br%C4%85zach\" target=\"_blank\" rel=\"noopener noreferrer\">inskrypcje</a> na <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84skie_br%C4%85zy_rytualne\" target=\"_blank\" rel=\"noopener noreferrer\">rytualnych naczyniach z brązu</a> oraz wróżebne <a href=\"https://pl.wikipedia.org/wiki/Napisy_na_ko%C5%9Bciach_wr%C3%B3%C5%BCebnych\" target=\"_blank\" rel=\"noopener noreferrer\">inskrypcje</a> na zwierzęcych kościach (lub skorupach żółwich）.", "Sonu Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sonu</b>.</p><p>Sonu to imię. Osoby z tym nazwiskiem to: Sonu Shamdasani (ur. 1962), brytyjski pisarz, Sonu Walia (ur. 1964), indyjska aktorka z Bollywoodu, Sonu Shivdasani (UR. 1965), brytyjska hotelowa, Sonu Nigam (ur. 1973), indyjski piosenkarz, Sonu Kakkar (ur. 1979), indyjskie piosenkarze, Sonu Sood (ur. 1973), indyjski aktor, Sonu Gowda (ur. 1990), indyjska aktorka z kin kin Kannada, Sonu Beniwal (ur. 1993), indy...</p>", "Subrahmanyam": "<p>Subramaniam, Subrahmaniam, subramaniam lub Subramanian (tamilsky: சுப்பிரமணியம்; telugu: సుబ్రహ్మణ్యం) to imiona męskie w południowo-indyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Sandun": "<p>Sandun to imię. Znani ludzie z nazwiska to: Sandun Dias (ur. 1985), kryketar z Sri Lanki Sandun Fernando (ur. 1999), kryketer z Sri Lanky Sandun Mendis (ur. 2001), kryketkarz z Sri Lanku Sandun Wijemanne Nissanka (ur. 1998), Sri Lanko-amerykański dyrektor przemysłu nagrywania Sandun Rathnatunga (ur. 1990), kryketa Sri Lanki sandun Weerakkody (ur. 1993), kryketator z Sri Lanke</p>", "Sugath": "<p>Sugath to imię. Znani ludzie z nazwiskiem to: Sugath Chandrasiri Bandara (zmarł 2009), Sri Lankanski żołnierz Sugath Thilakaratne (ur. 1973), Sri Lankański sportowca</p>", "Stasio": "<b>Stanisław „Stasio” Majda</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/8_maja\" target=\"_blank\" rel=\"noopener noreferrer\">8 maja</a> <a href=\"https://pl.wikipedia.org/wiki/1978\" target=\"_blank\" rel=\"noopener noreferrer\">1978</a>) – polski muzyk, wokalista, raper, autor tekstów i <a href=\"https://pl.wikipedia.org/wiki/Satyra\" target=\"_blank\" rel=\"noopener noreferrer\">satyryk</a>. Pochodzi z <a href=\"https://pl.wikipedia.org/wiki/Zabrze\" target=\"_blank\" rel=\"noopener noreferrer\">Zabrza</a>. Zajmuje się też <a href=\"https://pl.wikipedia.org/wiki/Kino\" target=\"_blank\" rel=\"noopener noreferrer\">filmem</a>.", "Susumu": "<b>Susumu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;すすむ, ススム) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Surinder Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Surinder</b>.</p><p>Surinder to indyjskie imię męskie. Do wybitnych osób z tym nazwiskiem należą: Surinder Amarnath (ur. 1948), były indyjski kryketer Test i jeden dzień, Surinder Arora, angielski biznesmen z Punjabi, którego biznes hotelowy, jak się uważa, sprawił, że wart był 225 milionów funtów Surinder Singh Bajwa (1955-2007), zastępca burmistrza Delhi Surinder Singh Kairon, syn zmarłego Sardar Pratap Singh Kairon Surinder Kapoor (1925-2011), film Bollywood ...</p>", "Sasi": "<b>Sasi</b>, <b>Saksoni</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Saxones</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a>&#160;<em>Sachsen</em>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">ang.</a>&#160;<em>Saxons</em>) – plemię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Germanie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, osiadłe w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a> w <a href=\"https://pl.wikipedia.org/wiki/Westfalia\" target=\"_blank\" rel=\"noopener noreferrer\">Westfalii</a> i <a href=\"https://pl.wikipedia.org/wiki/Dolna_Saksonia\" target=\"_blank\" rel=\"noopener noreferrer\">Dolnej Saksonii</a>.", "Somtochukwu": "<p>Somtochukwu to Igbo unisex nazwisko z południowo-wschodniej Nigerii, co oznacza \"Dołącz do mnie w chwaleniu Boga\", \"Pójdź za mną, aby oddać cześć Bogu\" lub \"Chwalcie Boga ze mną\".</p>", "Sabyr": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabir</b>.</p><b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Sita Ram": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sita</b>.</p><p>Sita (zwane również Seeta lub Seetha /Sītā/, co oznacza \"płynę\") jest postacią kobiety z epiki Ramayana. Była żoną boga Ramy (przyjaciel Wisnu) i jest wyobraźnią Lakshmi, żony bogactwa i żony Wisnu.</p>", "Sarbjit Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sarbjit</b>.</p><p>Sarabjit lub Sarbjit jest neutralną płcią indyjską i pakistańską nazwą. Wśród znanych osób z nazwiskiem są: Rai Sarabjit Singh (1853-1910), Ruler of Bhadri (stato) Sarabjit Ladda (ur. 1982), Indianin kryketa Sarabjit Sing (1963/1964-2013), indyjski obywatel skazany za terroryzm w Pakistanie SarabjitSingh Dhillon, indyjski generał Sarbjit Cheema, piosenkarz Punjabi Sarbjit Dusang (ur. 1952), kanadyjski hokejista pole Sarbjit Singh ...</p>", "Sala": "<p>Sala (naukowa forma: Shorea robusta) jest gatunkiem roślin kwiatowych z rodziny Olii. To gatunek Gaertna.</p>", "Sekar": "<p>Manokaris to męskie imię w Indiach. Sekar może odnosić się do: Sekar Ayu Asmara, indonezyjski autor piosenek i reżyser Sekar Ayyanthole (ur. 1954), indyjski malarz Sekhar Basu (ur. 1952), indyjskiego naukowca Sekhar Das (ur. 1954, indyjski reżysor Sekhar Kammula (ur. 1972), indyjskich reżysera Sekhar Menon (ur. 1983), indyjscy aktor Sekhar Tamadian (ur. 1951), doktor Grenady</p>", "Sidnei": "<p>Sidnei to męskie imię portugalskie. Osoby z tym nazwiskiem to: Sidnei (gracz piłkarski z Kapu-Werdetu) (ur. 1986) Sidnei da Silva (ur. 1980), brazylijski piłkarz Sidnei (ur. 1983), pełne imię Sidnei Siqueira Lourenço, brazylijski piłkarze lewego obrony Sidnei Sciola (ur. 1986), brazylijczy piłkarzem Sidnei (r. 1989), Sidnei Rechel da Silva Júnior, brazyliński piłkarza środkowy obrony</p>", "Sofiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Stéfan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefani</b>.</p><p>Stefani może odnosić się do: Gwen Stefani Lady Gaga (Stefani Germanotta, 1986)</p>", "Shanaka": "<p>Shanaka to imiona z Sri Lanki. Może odnosić się do:</p>", "Shaan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shan</b>.</p><p>Shan to państwo w Birmie, powołane na Shanów, jednego z ludów mieszkających w regionie. Jest to największe z 14 państw i innych podziałów administracyjnych Mjanmaru.</p>", "Steeve": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Steve</b>.</p><p>SZ: SZ jest zjawiskiem atmosferycznym, który wygląda jak długa pasma światła w niebie. Steve Jobs - książka, biografia współzałożyciela Apple Inc Steve'a Jobs'a.</p>", "Shanmugam": "<p>Shanmugam (tamilsky: சண்முகம், romanized: Caṇmukam) to tamilska męska nazwisko. Ze względu na tamilską tradycję używania nazwisk patronymicznych może być również nazwiskiem dla mężczyzn i kobiet.</p>", "Sukhbir": "<p>Sukhbir to indyjskie imię męskie. Znani ludzie z nazwiskiem Sukhbir (muzyk) (ur. 1969), Bhangra Sukhbir singer (autorkę) (1925-2012), Punjabi pisarz powieści, pisarz opowieści, poeta i esejista Sukhbir Kataria (ur. 1964), indyjski polityk Sukhbir Singh Badal (ur. 1962), Punjabi polityk Sikhbir Singh Gill (1975-2024), indyjskie hokejista pole Sukhbir Sing Jaunapuria (ur. 1957), indyjski polityk i...</p>", "Siyabonga": "<p>Siyabonga (sybongile) to południowoafrykańskie imię i nazwisko, które oznacza \"Dziękuję lub dziękuję\". Znani ludzie z imieniem to: Siyabonga Booi (ur. 1986), gracz kryketowy Południowoafrykański Siyabonga Cwele (ur. 1957), polityk Południeafrykańska Siyabonga Gama, polityk Połowoafryki Siyabonga Ngezana (ur. 1997), piłkarz Połudnoafrykańskiego Siyabonga Mabena (ur. 2007), piłkaczeta Południaafryka Siyabonga Mbatha (ur. 1989), Południuafryka...</p>", "Sakir": "<p>Şakir (turski: Şakir) to tureckie męskie imię i nazwisko. Şakir lub Sakir może odnosić się do:</p>", "Soumitra": "<p>Soumitra może odnosić się do: Saumitra lub Lakshmana, postać w starożytnej indyjskiej epopei Ramayana, syn Sumitra Soumitra Chatterjee (1935-2020), indyjski aktor filmowy znany ze współpracy z Satyajit Ray Soumitra Dutta, indyjski autor, akademik i biznesmen Soumitra Mohan (ur. 1938), indyjski poeta w hindi Soumitra Sen (ur. 1958), emerytowany sędzia Sądu Najwyższego w Kalkutce</p>", "Sabyasachi": "<p>Sabyasachi to męskie indyjskie imię. Wśród znanych osób z tym nazwiskiem są: Kazi Sabyasachi, indyjski bengalijski elokwizyst.</p>", "Sevket": "<p>Şevket jest tureckim imieniem męskim z arabskim odpowiednikiem Shawkat. Mieszkańcy imienia Şevket to:</p>", "Shahmar": "<p>Shahmar lub Shah Mar (perskiego: شاه مار) może odnosić się do:</p>", "Sota": "<p>Sota, Soota, Souta lub SOTA mogą odnosić się do:</p>", "Sebastian Camilo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Stacy": "<p>Stacy - może oznaczać:</p>", "Solomiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Stany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stan</b>.</p><p>Stan (rosyjski: Стэн) - trzeci single Eminema z jego albumu The Marshall Mathers LP, nagrany wspólnie z piosenkarką Dido.</p>", "Sejad": "<p>Sejad jest męskim bosniackim imieniem, równoważnym arabskim męskim imieniem Sa'id. - Nie .</p>", "Sivaprasad": "<p>Sivaprasad może odnosić się do: Kaviyoor Sivaprasat, indyjski reżyser filmowy i scenarzysta Naramalli Sivaprasada (1951-2019), indyjski polityk i aktor Raja Sivaprasd (1823-1895), indyjski uczony, lingwist i historyk</p>", "Sima": "<p>Tetraponera (lat. Tetraponer) - rodzaj drewnianych mrówek z podrodzinnego rodu Pseudomyrmecinae (Formicidae). Mieszka na drzewach, mrówki w gałęziach i domatycjach roślin.</p>", "Sidy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sidi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sid</b>.</p><p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Shqiprim": "<p>Shqiprim jest przeważnie językiem albańskim męskie nazwisko. Znanymi osobami, które nosiły nazwę Shqiprim, są: Shqiprim Arifi (ur. 1976), albansko-serski polityk i biznesmen Shqiprim Binakaj (ur. 1989), kosowski piłkarz Shqiprim Taipi (ur. 1997), albanianki piłkarze</p>", "Syam Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Syam</b>.</p><p>Syam jest gminą w regionie administracyjnym Franche-Comté, w prowincji Jura, w okręgu Lons-le-Saunier, w szczeblu Champagnole. Poziom geograficzny miasta jest 46° 42' Północnej, 05° 56' Wschodniej.</p>", "Shiva Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shiva</b>.</p><p>Shiva lub Niska Baba (sansk: शिव Śiva), znany również jako Mahadeva lub Ma-ha-đə-ba (; sansk: महादेव:, n.e. 'Wielki Bóg', Mahādevaḥ, [mɐɦaːd̪eːʋɐh) jest jednym z ważnych bogów hinduizmu.</p>", "Spirydon": "<b>Spirydon</b>, <b>Spirydion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia greckiego, wywodzące się od słowa <i>spyridos</i> — \"koszyczek\". Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Spirydon_z_Tremituntu\" target=\"_blank\" rel=\"noopener noreferrer\">św. Spirydon z Tremituntu</a>, biskup (IV wiek).", "Shadab": "<p>Shadab lub Shadaab może odnosić się do:</p>", "Stephano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stephan</b>.</p><p>Christian-Friedrich Stephan, lub Stefan (niem. Christian Friedrich Stephan, 1757, Leipzig - 17 grudnia 1814, Sankt-Petersburg) - rosyjski botanik pochodzenia niemieckiego.</p>", "Serban": "<p>Șerban jest powszechną nazwą w Rumunii. Może być transkriberowana fonetycznie jako Sherban lub bez diakrytyk jako Serban.</p>", "Sai̇m": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saima</b>.</p><p>Saima może być imieniem kobiecym pochodzenia arabskiego lub fińskim imieniem kobiecym. Do wybitnych osób z tym nazwiskiem należą:</p>", "Scholastyk": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Scholastyka</b>.</p><b>Scholastyka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Zaczęto go używać w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Wywodzi się od łacińskiego słowa <i>scholasticus</i> oznaczającego <i>uczony, student, nauczyciel</i>.", "Santoso": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Santos</b>.</p><p>Santos (szp. i port. - Nieźle.</p>", "Sandra": "<b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Salin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salina</b>.</p><p>Salina jest drugim z ośmiu wysp w Wyspach Eolie (po Lipari), w Morzu Tyrrhenus, na północ od Sycylii.</p>", "Silvanus": "Miał być synem pasterza i kozy bądź kobiety z <a href=\"https://pl.wikipedia.org/wiki/Tusculum\" target=\"_blank\" rel=\"noopener noreferrer\">Tusculum</a> imieniem Valeria i jej własnego ojca. Był bogiem dokuczliwym, straszącym wędrowców przemierzających lasy, zaś Rzymianie straszyli nim dzieci.", "Sverre": "<b>Sverre</b> – tradycyjne <a href=\"https://pl.wikipedia.org/wiki/Norwegia\" target=\"_blank\" rel=\"noopener noreferrer\">norweskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię męskie</a> wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordycki\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyckiego</a> imienia <i>Sverrir</i>.", "Sameeh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sameh</b>.</p><p>Sameh (arabski: سامح) to arabskie nazwisko i męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Songo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Stanisław Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Salvator": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salwator</b>.</p><b>Salwator</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> powstałe na bazie tytułu <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a> <i>Salvatora</i> oznaczającego 'zbawcę, zbawiciela'. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> <i>Salvator</i> odnosi się zawsze do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>.", "Senol": "<p>Şenol to tureckie imię męskie. Znanymi osobami z nazwiska są: Şenol Birol (1937-2022), turecki piłkarz Şenol Can (ur. 1983), bułgarski piłkarze i menedżer Şenol Çorlu, turecki piłki nożny Şenol Fidan (ur. 1967), turecki futbolista i trener Şenol Güneş (ur. 1952), turecki fotbalista i menedżer Şenol Sunat (ur. 1956), turecki polityk i biolog.</p>", "Snowid": "<b>Snowid</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Sno-</i> (\"sen\") i <i>-wid</i> (\"widzieć\"). Może więc oznaczać \"tego, który widzi sny\".", "Santa Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santa</b>.</p><p>Santa to 4-ta miasto w prowincji Ilocos Sur, w Filipinach. Według przeprowadzonego w 2000 roku badania ludności Philipin, mieście to miało populację 13 918 osób w 2 811 domach.</p>", "Senarath": "<p>Senarath to zarówno imię, jak i nazwisko. Znani ludzie z nazwiska to: Senarath Attanayake (1966-2017), polityk Sri Lankan Senarath Paranavitana (1896-1972), archeolog Sri Lankan Prasanna Shamal Senarath, polityk Sri Lanka Seelaratna Senarath (ur. 1944), Sri Lankanska radiowa Sureni Senarath (1959-2021), aktorka Sugathapala Senarath Yapa (ur. 1935), Sri Lanka Sujeewa Senarath yapa, Sri...</p>", "Shehroz": "<p>Shahruz (perskiej: شهروز Šahruz; azerbajdżanska: Şəhruz; również angliczowana jako Shahrouz lub Shahrooz) lub Shahroz (urdu: شہروز Śahroz, również angliczone jako Shahroze lub Shehroze) jest perskie, azerbajdżeńskie i urdu męskie imię pochodzenia perskiego. Mieszkańcy tej nazwy to: Shahruz Afkhami (ur. 1962), irański polityk Shahroz Sabzwari (ur. 1985), pakistański aktor Shehroze Kashif (ur. 2002), pakistański alpinista</p>", "Sai Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sai</b>.</p><p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Shain": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shaina</b>.</p><p>Shayna (jiddish: שיינא;שיינה; polski: Szejna) lub Shaina to imię kobiety pochodzące z języka jiddish, co oznacza \"piękne\" lub \"miło\" (jiddisch: שיין (sheyn), spokrewnione z nowoczesnym niemieckim schön), a także evocative z jiddish frazy \"אַ שיינע מיידל\" (\" shayne maydel\", lub \"miła dziewczyna\"). Jego hebrajskim odpowiednikiem jest Yaffa (יפה) lub Yafit (יַפִית); w latach po Holokauście nazwa Shayna (i jej arabskiej rodzeństwo, Jamila) była często...</p>", "Sędzisław": "<b>Sędzisław</b>, <b>Sędosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-sław</i> („sława”). Być może oznaczało „ten, komu sądzona jest sława”.", "Stanisław Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sviatoslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Solan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Solana</b>.</p><p>Solana (rosyjski: Солана) - wysokiej prędkości blokchaina trzeciej generacji z otwartym kodem źródłowym, opracowana do tworzenia zdecentralizowanych aplikacji (dApps) i inteligentnych kontraktów w szczególności decentralizacji rozwiązań finansowych (DeFi).</p>", "Sita": "<p>Sita (zwane również Seeta lub Seetha /Sītā/, co oznacza \"płynę\") jest postacią kobiety z epiki Ramayana. Była żoną boga Ramy (przyjaciel Wisnu) i jest wyobraźnią Lakshmi, żony bogactwa i żony Wisnu.</p>", "Shpend": "<p>Shpend to albanieckie imię męskie i może odnosić się do: Shpend Ahmeti (ur. 1978), kosowskiego polityka Shpend Dragobia (1853-1918), albanieńskiego żołnierza i rewolucjonistki Shpend Hasani (ur. 1996), niemieckiego piłkarza</p>", "Sanny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sany</b>.</p>Nazwa marki „Sany” wywodzi się od transkrypcji na język angielski chińskiego słowa (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chin</a>. 三一; <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: <i>Sānyī</i>). Słowo to w wolnym tłumaczeniu oznacza „trzy jeden” i jest powiązane z wizją firmy i trzema fundamentami: „Zbudować pierwszorzędne przedsiębiorstwo, wspierać pierwszorzędnych pracowników i wnosić pierwszorzędny wkład w społeczeństwo”. Wszystko ma swoje odzwierciedlenie w logo marki – to trzy połączone ze sobą jedynki.", "Solidariusz": "<b>Solidariusz</b> – polskie imię męskie, stworzone w latach 80. XX wieku na cześć <a href=\"https://pl.wikipedia.org/wiki/Niezale%C5%BCny_Samorz%C4%85dny_Zwi%C4%85zek_Zawodowy_%E2%80%9ESolidarno%C5%9B%C4%87%E2%80%9D\" target=\"_blank\" rel=\"noopener noreferrer\">NSZZ „Solidarność”</a>. Jego nadawanie uznawane było za akt oporu przeciwko władzy <a href=\"https://pl.wikipedia.org/wiki/PZPR\" target=\"_blank\" rel=\"noopener noreferrer\">PZPR</a> i powodowało opór urzędników stanu cywilnego. Orzecznictwo <a href=\"https://pl.wikipedia.org/wiki/Naczelny_S%C4%85d_Administracyjny\" target=\"_blank\" rel=\"noopener noreferrer\">Naczelnego Sądu Administracyjnego</a> dopuściło jednak jego nadawanie.", "Sylas": "<b>Sylas</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, skrócona forma imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwan_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwan</a>, wywodzącego się od słowa <i>silva</i>, które oznacza \"las, zagajnik\".", "Suneel": "<p>Sunil (सुनील) to imię dla mężczyzn, często występujące w społeczności południowoazjatyckiej. Sanskrit słowo sunīla oznacza \"ciemne\", \"bardzo niebieskie\" i jest również epitetem Krsny.</p>", "Sladan": "<p>Slađan to serbskie i chorwackie imię. Znanymi osobami z nazwiska są: Slađan Ašanin (ur. 1971), chorwacki piłkarz Slađan Đukić (ur. 1966), serbski piłkarze Slađan Ilić (ur., 1969), jugosławski narciarz Slađans Nikodijević (ur.1990), serbski Piłkarz Sladan Nikolić (ur.: 1974), serbski Sladan Peric (ur. 1982), duński piłkarzem Slađan Radovanović (ur.).</p>", "Sai Kiran": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sai</b>.</p><p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Song Il": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Shintaro": "<p>Shintarō to jedno z kilku japońskich nazwisk męskich. Składają się z prefiksu, po którym następuje \"tarō\", które jest tylko powszechną nazwą wśród pierworodnych synów.</p>", "Svietoslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Świętosław</b>.</p><b>Świętosław</b>, <b>Święcesław</b>, <b>Święcsław</b>, <b>Święsław</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">chorw.</a> <i>Svjetoslav</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serb.</a> <i>Svetoslav</i>) – starosłowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Złożone jest z członów: <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sław</i> („sława”) i oznacza człowieka cieszącego się mocną sławą. W materiałach źródłowych występuje od XII wieku. Do końca <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a> imię to zanotowano u około 1000 osób.", "Saikou": "<p>Saiko może odnosić się do: Saiko, japońska epoka Saiko, hiszpański piosenkarz Saiko (band), chilijskiego zespołu rockowego Saiko Lake, w prefekturze Yamanashi, Japonia</p>", "Sebastian Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Shakur": "<p>Shakur to nazwisko i rzadko używane jako nazwisko jak Shakir. Jest też pochodząca z jednego z imion Boga w islamie, Ash-Shakur.</p>", "Sylwano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylwan</b>.</p><b>Sylwan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"las, zagajnik\". Imię to posiada również skróconą formę <a href=\"https://pl.wikipedia.org/wiki/Sylas\" target=\"_blank\" rel=\"noopener noreferrer\">Sylas</a>.", "Séan": "<p>Sean, zwanego również Seán lub Séan w języku Hiberno-angelski, jest imieniem męskim pochodzącym z Irlandii. Pochodzi z irlandzkiego wersji biblijnej hebrajskiej nazwy Yohanan (יוֹחָנָן), Seán (anglicznie Shaun/Shawn/Shon) i Séan (angliczno Shane/Shayne), wyłożonej na angielski John i Johannes/Johann/Johan w innych językach germańskich.</p>", "Saifeddine": "<p>Sayf al-Din (arabski: سيف الدين, romanized: Sayf al - Dīn, lit. 'Miec Wiary'), również Saif al-Din, Sayf / Saif ad-Din, lub Sayf / Sayf ud-Din itp., może odnosić się do: Sayf Al-Din Suri (zmarł 1149), Ghurid król Saif ad - Din Ghazi I (zmarła 1149), Zangid emir Mosul Ghazi II Saif ud-Din (zmarły 1180), Zangide emir Mosul al-Malik al-Adil Sayf al-'Din Abu-Bakr ibn Ayyub, lub po prostu Al-Adil I, znany również jako \"Saphadin\", (1145-1218), Ayyubid sultan Egiptu Sayf ...</p>", "Sviatoslav-Ivan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Saliya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sali</b>.</p><p>Sali (tur. Sali) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Seif Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Seif</b>.</p><p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Silviu-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silviu</b>.</p><p>Silviu może odnosić się do: Silviu Bălace (ur. 1978), rumunskiego piłkarza piłkarskiego Silviu Berejan (1927-2007), pisarza besarabijskiego z Mołdawii Silviu Bindea (1912-1992), rumunskiego gracza piłkarski Silviu Brucan (1916-2006), rumuńskiego polityka komunistycznego Silviu Casandra (ur. 1975), rumunskiego biegacza wyścigowego Silviu Florea (ur. 1977), rumunzkiego piłkarz rugby silviu Ilie (ur. 1988), rumunski piłkarze...</p>", "Stani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stan</b>.</p><p>Stan (rosyjski: Стэн) - trzeci single Eminema z jego albumu The Marshall Mathers LP, nagrany wspólnie z piosenkarką Dido.</p>", "Siemisław": "<b>Siemisław</b>, <b>Siemosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia „rodzina, ród; czeladź, służba, własność”) i <i>-sław</i> („sława”). Imię to wyraża życzenie sławy w przestrzeni rodzinnej.", "Stewen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Steven</b>.</p><p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Sevki": "<p>Şevki lub Sevki to imię. Znanymi osobami z nazwiska są: Şevki Balmumcu (1905-1982), turecki architekt Şevki Koru (1913-2003), turecki biegacz długodystansowy Sevki Sha'ban (ur. 1984), singapurski piłkarz</p>", "San Pedro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Sixto": "<p>Sixto to hiszpańskie imię. Może odnosić się do:</p>", "Sűleyman": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suleiman</b>.</p><p>Suleiman (arabski: سُلَيْمان, romanized: sulaymān; angielski: or) jest arabskim imieniem żydowskiego i koranskiego króla i islamskiego proroka Salomona. Sulejman Wielki (1494-1566) był najdłużej rządzijącym sultanem Imperium Osmańskiego.</p>", "Sok": "<b>Sok</b> – produkt otrzymany z dojrzałych, świeżych lub przechowywanych <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> lub <a href=\"https://pl.wikipedia.org/wiki/Warzywa\" target=\"_blank\" rel=\"noopener noreferrer\">warzyw</a>, jednego lub większej liczby gatunków, posiadający <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, <a href=\"https://pl.wikipedia.org/wiki/Smak_(fizjologia)\" target=\"_blank\" rel=\"noopener noreferrer\">smak</a> i <a href=\"https://pl.wikipedia.org/wiki/Zapach\" target=\"_blank\" rel=\"noopener noreferrer\">zapach</a> charakterystyczny dla soku z owoców lub warzyw, z których pochodzą, zdolny do <a href=\"https://pl.wikipedia.org/wiki/Fermentacja\" target=\"_blank\" rel=\"noopener noreferrer\">fermentacji</a>, lecz niesfermentowany. Soki mogą być produkowane z zagęszczonych soków lub przecierów przez odtworzenie udziału <a href=\"https://pl.wikipedia.org/wiki/Woda\" target=\"_blank\" rel=\"noopener noreferrer\">wody</a> usuniętej w procesie zagęszczania soku lub przecieru i odtworzenie aromatu oraz, gdy jest to wskazane, miazgi usuniętej z soku, lecz odzyskanej w procesie technologicznym.", "Sigvard": "<p>Sigvard może odnosić się do: Sigvard Bernadotte (1907-2002), szwedzki projektant przemysłowy Sigvard Eklund (1911-2000), dyrektor Rady Bezpieczeństwa Międzynarodowej Agencji Energii Atomowej Sigvard Ericsson (1930-2019), byłego skaterka szybkości Sigvard Hultcrantz (1888-1955), szwedzkiego strzelca sportowego Sigvard Johansson, szwedzskiego sprintu kanotnika, rywalizował w połowie lat 50. Sigvard Munk (1891-1983), duńskiego polityka z Partii Socjaldemokratycznej Sigvard Sivertsen ...</p>", "Stefen": "<p>Stefen to męskie imię. Znani ludzie z tego nazwiska to: Stefen Fangmeier (ur. 1960), amerykański reżyser Stefen Reid (ur. 1972), kanadyjski piłkarz Stefen Wisniewski (ur. 1989), amerykański piłkarze Felipe Stefen (ur. 1995), brazylijczy pisarz i fotograf</p>", "Sanath": "<p>Sanath to sinhalijskie imię męskie: Sanath Jayasuriya, kryketer z Sri Lanki. Sanath Kaluperuma, kryketar Sri Lanki.</p>", "Światowid": "<b>Idol ze Zbrucza</b>, <b>idol zbruczański</b>, <b>idol z Liczkowiec</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Ba%C5%82wan_(pos%C4%85g)\" target=\"_blank\" rel=\"noopener noreferrer\">bałwan</a> ze Zbrucza</b>, <a href=\"https://pl.wikipedia.org/wiki/Mowa_potoczna\" target=\"_blank\" rel=\"noopener noreferrer\">pot.</a> <b>Światowid</b> – kamienny <a href=\"https://pl.wikipedia.org/wiki/Idol_(wyobra%C5%BCenie)\" target=\"_blank\" rel=\"noopener noreferrer\">idol</a> pochodzący z XI wieku, wydobyty w 1848 roku z rzeki <a href=\"https://pl.wikipedia.org/wiki/Zbrucz\" target=\"_blank\" rel=\"noopener noreferrer\">Zbrucz</a> w pobliżu wsi <a href=\"https://pl.wikipedia.org/wiki/Liczkowce\" target=\"_blank\" rel=\"noopener noreferrer\">Liczkowce</a> koło <a href=\"https://pl.wikipedia.org/wiki/Husiatyn\" target=\"_blank\" rel=\"noopener noreferrer\">Husiatyna</a> na <a href=\"https://pl.wikipedia.org/wiki/Podole\" target=\"_blank\" rel=\"noopener noreferrer\">Podolu</a>.", "Silwester": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylwester</b>.</p><b>Sylwester</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>silvestris</em> oznaczającego „żyjący w lesie”, „dziki”. Poświadczone w Polsce od 1220 roku. Dawniej uważano, że imię <a href=\"https://pl.wikipedia.org/wiki/Lasota_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Lasota</a> powstało jako odpowiednik znaczeniowy Sylwestra, jednak Lasota jest poświadczony na ziemiach polskich w dokumentach wcześniej i był szerzej nadawany. Odnotowano dziesięciu świętych Sylwestrów, patronów tego imienia.", "Sanel": "<p>Sanel to imię dla mężczyzn i może odnosić się do: Sanel Borić (ur. 1987), amerykański piłkarz Sanel Jahić (ur., 1981), bosnijski piłkarze Sanel Kapidžić (ur.: 1990), bosniński piłkerz Sanel Kuljic (ur. 1977), austriacki piłkarzem</p>", "Scypion": "<b>Scypion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek\" target=\"_blank\" rel=\"noopener noreferrer\">przydomek</a>, wywodzi się od słowa <i>scipio</i>, <i>-onis</i> – \"laska, buława\" (otrzymywana przez <i><a href=\"https://pl.wikipedia.org/wiki/Ornamenta_triumphalia\" target=\"_blank\" rel=\"noopener noreferrer\">viri triumphales</a></i> i sojuszniczych władców). Imię częste w rodzie Korneliuszy.", "Sofia": "<p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Soichiro": "<p>Sōichirō, Soichiro, Souichirou lub Sohichiroh to męskie japońskie imię. Znanymi osobami z tej nazwy są: Soichiro Fujitaka (藤 ⁇ 宗一郎; ur. 1991), japoński piłkarz koszykówki Soichiro Honda (本田 宗一 Taro; 1906 - 1991), założyciel Honda Motor Company Sōichirō Hoshi (保志 総一朗; ur. 1972), japoński aktor głosu Soichiro Fuukutake (福武 總一郎; Ur. 1945), prezydent Benesse Corporation Soichiro Ito (sportowy strzelca) (伊東 総一郎;ur. 1947), japończyk...</p>", "Siva Prasad": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Siva</b>.</p><p>Siva może odnosić się do: 1170 Siva, asteroida Śiva lub Shiva, bóg</p>", "Sviatoslav-Yurii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sebastiyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Shymon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shimon</b>.</p><p>Szymon (Heb. שמעון) - imię i nazwisko.</p>", "Shadrach": "<p>Szadrach lub Szadrach to imię człowieka w biblijnej historii Szadrach, Mesach i Abednego. Może również odnosić się do:</p>", "Sammer": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samer</b>.</p><p>Samer jest gminą w francuskiej prowincji Pas-de-Calais w regionie Hauts-de-France.</p>", "Salinda": "<p>Salinda to imię. Znani ludzie z nazwiskiem to: Salinda Dissanayake (1958-2019), sri Lankański polityk Salinda Ushan (ur. 1997), sri lankański kryker</p>", "Shuhei": "<p>Shūhei, Shuhei lub Shuuhei (pisanie: 周平, 修平, 秀平, ⁇ 平 lub シュウヘイ w katakana) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shuhei Akasaki (赤 ⁇ 秀平; ur. 1991), japoński piłkarz Shuhei Aoyama (青山 周平; ur., 1984), japoński motocykler Shuhei Fujioka (poter) (ur. 1947), japowski poter Shuhei Fujisawa (藤沢 周平, 1927-1997), japoński pisarz Shuhei Fukuda (福田 秀平, ur. 1989), japończyk shuhei Hotta (⁇ 田 秀 平;...</p>", "Samuel Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Souheil": "<p>Souhail, Suhail, Sohail lub inne warianty (arabijski: سهيل) to arabski termin powszechnie używany jako męskie imię i nazwisko. Souhail lub jego warianty mogą odnosić się do:</p>", "Shozo": "<p>Shōzō, Shozo, Shouzou lub Shohzoh (pisanie: 昭三, 省三, provincia蔵, 省太, 正三, 正蔵 lub ⁇ 三) to męskie japońskie imię. Wśród znanych osób z tej nazwy są: Shōzō Fujii (藤猪 省太; ur. 1950), japoński judoca Shozo Fujita (藤田 省三; 1927-2003), japoński historyk Shōzô Hayashiya IX (九代目 林家 正蔵; ur. 1962), japoński komik i aktor głosowy Shōzò Iizuka (飯塚 昭三; 1933-2023), japowski aktor głosowa Shozo Ishihara (石原 省三, 1910-1993), japońska skaterka szybkości Shouzou...</p>", "Sibusiso": "<p>Sibusiso (busisiwe) to męskie imię pochodzące od słowa Nguni busisa, co oznacza \"błogosławić\". Zmniejszona znana wersja to Sbu/S'bu.</p>", "Sai Krishna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sai</b>.</p><p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Shamili": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamil</b>.</p><p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Shogo": "<p>Shogo, Shōgo, Shohgo lub Shougo (pisanie: 正吾, 正悟, 正五, 省吾, 昭吾, 翔吾, 浅悟, 章吾, 昇吾, 升悟, 勝吾, 鐘吾, 奨悟, 将吾, 彰吾, ⁇ 吾, 渉珊 lub 祥吾) jest męską japońską nazwą. Znani ludzie z nazwiska to: Shogo Akada (赤田 将吾; ur. 1980), japoński piłkarz baseballu Shogo Akiyama (秋山 翔吾; ur., 1988), japoński profesjonalny piłkarze baseballu Shōgo Arai (荒井 正吾; ur.; 1945), japończyk polityk Shogo Asayama (朝山 正悟; ur. 1981), japowski piłkarzem koszykówki i trenerem...</p>", "Stancho": "<p>Stancho (bułgarski: Станчо) to bułgarskie męskie imię. Znani ludzie z nazwiska to: Stancho Belkovski (1891-1962), bułgarski architekt Stancho Bonchev (1942-2013), bułgarsky piłkarz Stancho Kolev (1937-2025), bułgarski wrestler wolnego stylu Stancho Penchev (ur. 1940), bułgara ciężarosta Stancho Stanchev (1932-2017), bułgariański dyrektor teatralny</p>", "Shinichiro": "<p>Shin'ichirō, Shin'ichiro, Shin'chiirou lub Shin'ichiraoh (pisanie: 信一郎, 真一郎, 眞一郎,晋一郎,伸一郎,振一郎 lub 慎一郎) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shinichiro Furumoto (古本 伸一郎; ur. 1965), japoński polityk Shin'ichirō Ikebe (池辺 晋一郎; Ur. 1943), japoński kompozytor Shin'ichiro Hattori (服部 慎一郎; uor. 1999), japończyk profesjonalny szogier Shinichira Kawabata (川畑 伸一 Taro; ur. 1966), japowski piłkarz baseballu Shinichir...</p>", "Seyyid": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seyid</b>.</p><p>Sayyid (także \"Sayyed\", \"Seyit\", \"Seyd\", \"Syd\", \"Sayed\", \"Sayyid\", \"Sayyed\" i \"Sydna\").</p>", "Samuel Alejandro": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Shahryar": "<p>Shahriyar lub jego warianty mogą odnosić się do:</p>", "Simon-Peter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Sung Hoon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sebastianus": "Arystokrata pochodzący z <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>. Mianowany współcesarzem przez swego brata <a href=\"https://pl.wikipedia.org/wiki/Jowin\" target=\"_blank\" rel=\"noopener noreferrer\">Jowinusa</a> wkrótce po uzurpacji przez niego tronu cesarstwa zachodniorzymskiego w 411.", "Stephanos": "<p>Stephanos lub Stefanos, w greckim Στέφανος, jest męskim imieniem pochodzącym z greckiego słowa στέφανος (stéphanos), co oznacza \"krąg, koronę\" i przez rozszerzenie \"Nagroda, honor, sławę, sławą\", z czasownika στέφειν (stéphein), \"obok, do oddychania\". W starożytnej Grecji zwycięzcom konkursów przyznano korony (np. korony laury).</p>", "Sarfaraz": "<p>Sarfrāz lub Sarfaraz (Bengali: সরফরাজ, Urdu: سرفراز) to męskie imię i nazwisko pochodzenia perskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Safak": "<p>Şafak to słowo w tureckim znaczeniu świt. Jest również używany jako unisex imię i nazwisko.</p>", "Sabas": "<b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Stanisław Kostka": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sartaj": "<p>Sartaj jest męskim imieniem pochodzenia perskiego, występującym w Indiach i Pakistanie. Do wybitnych osób z tym nazwiskiem należą:</p>", "Suhan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suhani</b>.</p><p>Suhani to indyjskie imienne. Suhani oznacza \"Miłośny, umiłowany lub kochany\".</p>", "Shiva Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shiva</b>.</p><p>Shiva lub Niska Baba (sansk: शिव Śiva), znany również jako Mahadeva lub Ma-ha-đə-ba (; sansk: महादेव:, n.e. 'Wielki Bóg', Mahādevaḥ, [mɐɦaːd̪eːʋɐh) jest jednym z ważnych bogów hinduizmu.</p>", "Sirin": "Siriny symbolizują smutek, cierpienie i rozpacz, podczas gdy podobne wyglądem <a href=\"https://pl.wikipedia.org/wiki/Alkonost_(folklor)\" target=\"_blank\" rel=\"noopener noreferrer\">alkonosty</a>, oznaczają szczęście i nadzieję. W przeciwieństwie do alkonostów siriny są nastawione wrogo do człowieka.", "Sifiso": "<p>Sifiso to południowoafrykańskie imię. W tłumaczeniu na angielski oznacza \"Pragnienie\".</p>", "Sergiu-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sergiu</b>.</p><p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Su Won": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Shawki": "<p>Shawki (zwany również Shawky, Shawqi, Shoghi, Shauki) arabski: شوقي, francuski: Chaouqui lub turecki: Şevki), to męskie arabskie imię i nazwisko. Może odnosić się do:</p>", "Sayyar": "<p>Sayyar (arabski: سیار) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sapir": "<p>Edward Sapir (ang. Edward Sapir, /səˈpɪər/; 26 stycznia 1884 - 4 lutego 1939) - amerykański lingwist i antropolog.</p>", "Shunichiro": "<p>Shun'ichirō, Shun'ichiro lub Shun'ichiraou (pisanie: 俊一郎) to męskie japońskie imię. Znanymi ludźmi z nazwiskiem są: Shunichiro Okano (岡野 俊一郎) (ur. 1931), japoński piłkarz i menedżer</p>", "Sher Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sher</b>.</p><p>Sher (ang. Cher, [ʃɛər]; imię przy urodzeniu - Sheryl Sarkisyan (ang.</p>", "Shigang": "Populacja dzielnicy Shigang w 2016 roku liczyła 15&#160;174 mieszkańców – 7291 kobiet i 7883 mężczyzn. Liczba gospodarstw domowych wynosiła 4899, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,1 osób.", "Sandipan": "<p>Sandipan to męskie indyjskie imię. Może odnosić się do: Sandipan Chattopadhyay, bengalijski pisarz.</p>", "Sadun": "<p>Sadun to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Stosław": "<b>Stojsław</b>, <b>Stoisław</b>, <b>Stosław</b>, <b>Tosław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone członu <i>Stoj(i)-</i> (\"stać, stoję\") oraz członu <i>-sław</i> (\"sława\"). Notowane w Polsce od <a href=\"https://pl.wikipedia.org/wiki/1145\" target=\"_blank\" rel=\"noopener noreferrer\">1145</a> roku, po raz pierwszy w formie Stojsław (<i>Stoyslaus</i>).", "Svetlan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetlana</b>.</p><p>Claire de Loutchek (francuski: Claire de Loitchek), występująca pod pseudonimem Svetlana (francusko: Claire de Luchek).</p>", "Sarkys": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sarkis</b>.</p><p>Sarkis (armeńska: Սարգիս, wymowa armeńska [sɑɾˈkhis]) to męskie imię i nazwisko. Nazwa może być również alternatywnie pisowana jako Sargis, używana zarówno przez Armenii, jak i Asyryjczyków.</p>", "Shotaro": "<p>Shotaro (słowa: 正太郎, 昭太郎, 正太朗, 章太郎, Zhuang太郎, Shotaro, Shotaru, Shotoro, Shotara) to japońskie imię męskie. Znanymi osobami z nazwiska są: Shōtarō Adachi (足立 正太郎; 1901-1995), japoński fotograf Shōtaro Akiyama (秋山 庄太郎; 1920-2003), japoński fotograf Shotaro Ihata (井畑 翔太郎; ur. 1987), japoński piłkarz Shōtaró Ikenami (池波 正太郎, 1923-1990), japończyk Shōtarò Iribe (入部 正太朗; ur. 1989), japowski rower Shotaro Ishinomori...</p>", "Sylvian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvian</b>.</p><p>Silvian to rumuńskie imię męskie. Znani ludzie z imieniem to: Silvian Cristescu (ur. 1970), rumuński piłkarz Silvian Dobre (ur. 1967), rumuński piłkarze Silvian Iosifescu (1917-2006), krytyka literacki, edukacja, tłumacz i profesor</p>", "Simon Peter": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Steven David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Steven</b>.</p><p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Szaweł": "<b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Stefane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Shoukat": "<p>Shaukat (urdu: شوکت) to muzułmańskie imię męskie i żeńskie, które oznacza \"Mocarstwo\" i \"Dynctwo\". Jest to wariant arabskiej nazwy Shawkat (arabski: شَوْكَت).</p>", "Satur": "<b>Satur</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające \"nasycony, usatysfakcjonowany\". Istnieje przynajmniej dwóch świętych o tym imieniu.", "Shadrack": "<p>Szadrach lub Szadrach to imię człowieka w biblijnej historii Szadrach, Mesach i Abednego. Może również odnosić się do:</p>", "Szlomo": "<p>Shlomo lub Szlomo jest angielską formą śְׁלֹמֹה, hebrajskiego imienia izraelskiego króla Salomona. Jest to popularne imię wśród Żydów, zwłaszcza w Izraelu.</p>", "Sukru": "<p>Şükrü (tyrk. z arabskiego: شكري) to tureckie imię. Do wybitnych osób z nazwiskiem należą: Şükrü Halûk Akalın (ur. 1956), emeryturę tureckiego akademika i biurokrata Şükrü Altın (ur., 1956), tureckiego historyka, pisarza, wychowawcy i malarza Şükrü Balcı (1929-1993), tureckiego urzędnika i szefa policji Ali Şükrü Bey (1884-1923), tureckiej żołnierzy, dziennikarzy i polityka Şükrü Birand (1944-2019), tureckiego piłkarza Mithat ...</p>", "Surinder Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Surinder</b>.</p><p>Surinder to indyjskie imię męskie. Do wybitnych osób z tym nazwiskiem należą: Surinder Amarnath (ur. 1948), były indyjski kryketer Test i jeden dzień, Surinder Arora, angielski biznesmen z Punjabi, którego biznes hotelowy, jak się uważa, sprawił, że wart był 225 milionów funtów Surinder Singh Bajwa (1955-2007), zastępca burmistrza Delhi Surinder Singh Kairon, syn zmarłego Sardar Pratap Singh Kairon Surinder Kapoor (1925-2011), film Bollywood ...</p>", "Samuel Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Steephen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stephen</b>.</p><p>Stephen Hawking Stephen King Stephen Harper może odnosić się do:</p>", "Steveen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Steven</b>.</p><p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Sulthan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sultan</b>.</p><p>Sultan (wietn. xun-tan; arab. سلطان Sultān) jest tytułem króla w krajach, w których islam jest narodowy, i ma wiele znaczeń z czasem. Sultan to początkowo arabskie imię abstrakcyjne, które oznacza \"mocarstwo\", \"mocarstwa\" lub \"dominację\".</p>", "Sany": "Nazwa marki „Sany” wywodzi się od transkrypcji na język angielski chińskiego słowa (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chin</a>. 三一; <a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a>: <i>Sānyī</i>). Słowo to w wolnym tłumaczeniu oznacza „trzy jeden” i jest powiązane z wizją firmy i trzema fundamentami: „Zbudować pierwszorzędne przedsiębiorstwo, wspierać pierwszorzędnych pracowników i wnosić pierwszorzędny wkład w społeczeństwo”. Wszystko ma swoje odzwierciedlenie w logo marki – to trzy połączone ze sobą jedynki.", "San Juan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Sofroniusz": "<b>Sofroniusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, złożone z elementów <i>sōs</i>- („zdrowy”) i -<i>phron</i> („duch, umysł”). Oznacza człowieka mądrego, rozumnego. Istnieje kilku świętych o tym imieniu.", "Sid Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sid</b>.</p><p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Shunya": "<p>Shun'ya lub Shunya (pisanie: 俊也, ⁇ 也, 峻野, ⁇ lub ⁇ 哉) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shunya Itō (伊藤 俊也; ur. 1937), japoński reżyser filmowy Shunya Mori (毛利 ⁇ 也; ur.: 1995), japońska piłkarka Shunya Shiraishi (白石 ⁇ 也, ur.: 1990), japończyk Shunya Suganuma (⁇ 沼 ⁇ 哉, ur.: 1990), japoński piłkarz Shunya Takayama (高山 峻野, ur.: 1994), japońskiego przeszkodnika Shunya Yoneda (ur.: 1995),</p>", "Salish": "Ponadto 3310 obywateli USA zadeklarowało w 2000 roku pochodzenie <i>wyłącznie Salish</i> (4739 – <i>wyłącznie lub m.in. Salish</i>), zaś 3464 innych określiło swe pochodzenie jako <i>wyłącznie Salish and Kootenai</i> (4203 – <i>wyłącznie lub m.in. Salish and Kootenai</i>).", "Sebastian-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Sabahudin": "<p>Sabahattin to tureckie imię dla mężczyzn. Warianty nazwy, takie jak Sabahudin, występują również w byłym Imperium Osmańskim.</p>", "Shunichi": "<p>Shun'ichi lub Shunichi (pisanie: 俊一 lub ⁇ 一) to męskie japońskie imię. Do wybitnych osób z nazwiskiem należą: Shunichi Amachi (天知 俊一; 1903-1976), japoński piłkarz baseballu i menedżer Shun'ichi Amari (甘利 俊一, ur. 1936), japoński akademik Shunichi Ikenoue (池ノ上 俊一 , ur. 1967), japończyk piłkarza futbolu Shunichi iwamura (岩村 俊一 (ur. 1940), japońskiego sprintu kanoka Shun-ichi Iwasaki (岩崎 俊一), japowski inżynier Shunichi Kajima (⁇ 間 俊一 ...</p>", "Sadaf": "<p>Sadaf lub Sadaffe to kobiece imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Seppe": "<p>Seppe może odnosić się do: Seppe Baetens (ur. 1989), belgijski piłkarz siatkówki Seppe Van Holsbeke (ur. 1988), belgijski ogrodnik Sebastian Seppe Smits (ur. 1991), belgijski snowboarder Bosschenhoofd, znany również jako Seppe, wioska w gminie Halderberge, Brabant Północny, Holandia Międzynarodowe Lotnisko Breda, pierwotnie nazwane Seppe Airport, małe lotnisko w pobliżu Bosschenhoofda</p>", "Sadanand": "<p>Sadanand to indyjskie imię. Może odnosić się do Sadananda Bakre, indyjskiego malarza i rzeźbiarza Sadananda Chavana, indyjskiemu politycy Sadananda Date, indyskiego policjantki Sadananda Deshmukh, amerykańskiego pisarza i dziennikarza Sadanand Gowda, indyjskich polityków Sadananda Joshi, indyjskim przedsiębiorcy Sadanand Maharaj, fijianskiego polityka Sadananda Maiya, indyjska przedsiębiorca Sadananda Singh, indyjscy polityk Sadanand Singh...</p>", "Sreenivas": "<p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Stanisław Ludwik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Slavek": "<p>Slávek (SLAH-vek) to imię męskie. Jest to krótka forma różnych sławskich nazw kończących się -sławskim (Stanislav, Květoslav, Branislav, Rostislav, Miroslav, Miloslav, Sobiesław, Svatoslav) lub zaczynających się na Slav- (Slavomir, Slavomil).</p>", "Shinjiro": "<p>Shinjirō, Shinjiro lub Shinjirou (zwany w języku japońskim 進次郎, 新次郎, 晋二郎, 真二郎,真司郎 lub 伸次郎) jest męskie japońskie imię. Znanymi osobami z imieniem są: Shinjiro Atae (與 真司郎; ur. 1988), japoński piosenkarz i aktor Shinjiro Ehara (江原 真二郎; ur., 1936), japoński aktor Shinjuro Hiyama (⁇ 山 進次郎; ur . 1969), japończyk w baseballu Shinjirō Koizumi (小泉 進次 Taro; ur. 1981), japowski polityk Shinjiro Ono (小野 新次郎), japońskiego urzędnika rządu i dyplomat ...</p>", "Sung Mo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sabil": "Z historycznego punktu widzenia takie budynki są strukturami o znaczeniu zarówno cywilnym, jak i religijnym w miastach muzułmańskich, przede wszystkim w miastach <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Imperium Osmańskiego</a> i <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tanat_mameluk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">sułtanacie mameluków</a>.", "Skylar": "<p>Skyler lub Skylar () jest unisex nazwisko, anglicizowane pisowni nazwiska i nazwiska Schuyler. Schuyler został wprowadzony do Ameryki jako nazwisko przez holenderskich osadników XVII wieku przybywających do Nowego Jorku.</p>", "Somsak": "<p>Somsak to tajskie imię męskie. Jest to drugie najpopularniejsze imię męskie w Tajlandii, z około 230 000 osób używających tego imienia w 2012 roku.</p>", "Salman Faris": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Salman</b>.</p>Salman (również jako Salmaan lub Selman, arab. سلمان) popularne wśród <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">muzułmanów</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> oznaczające <i>błogosławiony</i>, także <i>pokój</i>.", "Sebastian Felipe": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Stefan Tadeusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Son Tung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Son</b>.</p><p>Son to wietnamskie słowo o wielu znaczeniu. Czerwony i czerwony: jeden kolor.</p>", "Szaul": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shaul</b>.</p><p>Saul to imię i nazwisko, które mogą odnosić się do: Nazwa: Shaul (Hebrajskie שָׁאוּל Šāʼûl \"proszony, modlił się o\"), zwykle nazywany Saul w języku angielskim, pierwszy król Izraela w hebrajskiej Biblii Shaul, syn Symeona (syn Jakuba) w Księdze Rodzaju Shaul Amor (1940-2004), izraelski polityk Shaul Avigur (1899-1978), założyciel izraelskiej wspólnoty wywiadowczej Shaul Ben-Tzvi, hebrajskie imię Paula Shulmana (1922-1994), drugi dowódca...</p>", "Sarabjit Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sarabjit</b>.</p><p>Sarabjit lub Sarbjit jest neutralną płcią indyjską i pakistańską nazwą. Wśród znanych osób z nazwiskiem są: Rai Sarabjit Singh (1853-1910), Ruler of Bhadri (stato) Sarabjit Ladda (ur. 1982), Indianin kryketa Sarabjit Sing (1963/1964-2013), indyjski obywatel skazany za terroryzm w Pakistanie SarabjitSingh Dhillon, indyjski generał Sarbjit Cheema, piosenkarz Punjabi Sarbjit Dusang (ur. 1952), kanadyjski hokejista pole Sarbjit Singh ...</p>", "Shehbaz": "<p>Shahbaz (persk. شهباز) to perskie słowo odnoszące się do legendarnego ptaka stróżnego Shahbaz. Jest to również powszechne imię w Iranie, Pakistanie, Afganistanie i Tadżykistanie.</p>", "Svyatoslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svyatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Suheil": "<p>Souhail, Suhail, Sohail lub inne warianty (arabijski: سهيل) to arabski termin powszechnie używany jako męskie imię i nazwisko. Souhail lub jego warianty mogą odnosić się do:</p>", "Sung Chol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Silvino": "<p>Silvino to męskie imię i nazwisko. Wśród nosicieli nazwy są:</p>", "Sung Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sigfrid": "<p>Siegfried to niemieckojęzyczne imię męskie, składające się z elementów germańskich sig \"wygrana\" i frithu \"ochrona, pokój\". Niemieckie imię ma staroskórego krewnego Sigfriðr, Sigfrøðr, co daje początek szwedzkiemu Sigfridowi (hypocorisms Sigge, Siffer), duńsko-norweskiemu Sigfred.</p>", "Srikantha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srikanta</b>.</p><p>Srikanta może odnosić się do: Srikanta Acharya, indyjskiej piosenkarki Srikanta Mahata, indyjski polityk Srikanta Wadiyar (ur. 1953), indyjskiego księcia i polityka Srikanta (książka), bengalijskiej powieści Sarat Chandra Chattopadhyay Srikanta, indyjska kinematyka srikanta (górka)</p>", "Spasoje": "<p>Spasoje (czysty cyrylski: Спасоје) to męskie imię pochodzenia słowiańskiego. Może odnosić się do: Spasoje Bulajič (ur. 1975), słoneckiego piłkarza Spasoje Samardžić (ur. 1941), serbskiego piłkarz Spasoje Tuševljak (ur. 1952), bosniackiego serbskiego ekonomisty i polityka</p>", "Sorin-Darius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sohil": "<p>Sohil to nazwa używana w całej Indiach. Często ⁇ Sohil i Soheil ⁇ są zdezorientowani, ale oba słowa są zupełnie inne.</p>", "Sebald": "<b>Sebald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, złożone z członu <i>Se-</i> oznaczającego „zwycięstwo” i <i>-bald</i> - „odważny, śmiały”. Patronem tego imienia jest św. Sebald, pustelnik (<a href=\"https://pl.wikipedia.org/wiki/VIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VIII wiek</a>), kanonizowany w XV wieku przez <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieża</a> <a href=\"https://pl.wikipedia.org/wiki/Marcin_V\" target=\"_blank\" rel=\"noopener noreferrer\">Marcina V</a>.", "Sława": "<b>Sława</b> (m., f.) – forma skrócona <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a> zawierających element <i>Sław-</i> lub <i>-sława</i>, takich jak <a href=\"https://pl.wikipedia.org/wiki/Miros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Mirosława</a>, <a href=\"https://pl.wikipedia.org/wiki/S%C5%82awomira\" target=\"_blank\" rel=\"noopener noreferrer\">Sławomira</a>.", "Sayfeddine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saifeddine</b>.</p><p>Sayf al-Din (arabski: سيف الدين, romanized: Sayf al - Dīn, lit. 'Miec Wiary'), również Saif al-Din, Sayf / Saif ad-Din, lub Sayf / Sayf ud-Din itp., może odnosić się do: Sayf Al-Din Suri (zmarł 1149), Ghurid król Saif ad - Din Ghazi I (zmarła 1149), Zangid emir Mosul Ghazi II Saif ud-Din (zmarły 1180), Zangide emir Mosul al-Malik al-Adil Sayf al-'Din Abu-Bakr ibn Ayyub, lub po prostu Al-Adil I, znany również jako \"Saphadin\", (1145-1218), Ayyubid sultan Egiptu Sayf ...</p>", "Spytek": "<b>Spycimir</b>, <b>Spyćmier</b>, <b>Spyćmir</b>, <b>Spyćmierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Spyci-</i> („nadaremnie”), oraz członu <i>-mir</i> („pokój, spokój, dobro”), zdrobniale – <b>Spytko</b>. Pisownia z końcowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>.", "Staniša": "<p>Staniša (serski cyrylski: Станиша) to serbskie imię męskie, pochodzące od słowiańskiego korzenia stan i sufiksu -iša. Tradycyjnie nadawano ją jako apotropaiczne (ochronne) imię, gdy często umierały dzieci lub gdy rodziło się wiele dzieci.</p>", "Sung Wook": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Stanisław Janusz": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Song Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Stanisław Andrzej": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sosuke": "<p>Sōsuke, Sosuke lub Sousuke (pisanie: 宗佑, 宗輔, 宗助, 壮祐, 壮介, 壮亮, 荘介, 蒼 ⁇ , 創介, そうすけ, czy ソウスケ) to męskie japońskie imię. Znanymi osobami z tej nazwy są: Sōsuke Genda (源田 壮亮; ur. 1993), japoński profesjonalny piłkarz bejsbolowy Sōsuke Henmi (逸見 宗助; 1843-1894), japoński mieczarz Sosuke Ikematsu (池松 壮亮, ur. 1990), japończyk Sōsuke Kaise (海瀬 壮祐), japońskiego artysty manga Sōsuke Namiki (並木 宗輔; 1695 - około.</p>", "Sơn Tùng": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Son</b>.</p><p>Son to wietnamskie słowo o wielu znaczeniu. Czerwony i czerwony: jeden kolor.</p>", "Skënder": "<p>Skender (albaniewska: Skënder) (bosniacko: Skender) to męskie imię, powszechnie występujące w Albanii i na Kosowie oraz wśród osób etnicznej etniki bosniackiej w dzisiejszej Bośni i Hercegowinie, Serbii i Czarnogórii. Skender jest również używany jako nazwisko i istnieje szereg ściśle powiązanych nazwisk rodzinnych znajdujących się na całym świecie, które pochodzą z Skender (takich jak Skeja, Skejić, Skejo, Skenderi, Skenderija, Skenderović, Skenderovski, Skendžić, Schender,...</p>", "Suri": "<p>W starożytnym perskim Suri oznacza \"mała księżniczka\", a w hebrajskim \"czerwony różowiec\". Suri to miasto i dzielnica w okręgu Birbhum w stanie Bengala Zachodniego, India.</p>", "Salwatore": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salwator</b>.</p><b>Salwator</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> powstałe na bazie tytułu <a href=\"https://pl.wikipedia.org/wiki/Jowisz_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Jowisza</a> <i>Salvatora</i> oznaczającego 'zbawcę, zbawiciela'. Na gruncie <a href=\"https://pl.wikipedia.org/wiki/Chrze%C5%9Bcija%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">chrześcijańskim</a> <i>Salvator</i> odnosi się zawsze do <a href=\"https://pl.wikipedia.org/wiki/Jezus_Chrystus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusa Chrystusa</a>.", "Serguey": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Serguei</b>.</p><p>Sergius to męskie imię pochodzenia starożytnego Rzymu po nazwie łacińskiej geny Sergia lub Sergii w czasach królewskich i republikańskich. Jest to powszechne chrześcijańskie imię, na cześć św. Sergiusa, i było to imię czterech papieży.</p>", "Shah Alam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shah</b>.</p><p>⁇ SHAH ⁇ (⁇ SHA H ⁇) - rosyjska i rosyjska grupa, pionierów radzieckiego metalu. Znana jest między innymi tym, że partii basystyki w niej kilku lat wykonywał Anatolij Krupnov, założyciel ⁇ Czarnego obelisku ⁇ .</p>", "Sara": "<b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Stefan Jerzy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Samuel-David": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Sharoon": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sharon</b>.</p><b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Sharbel": "<p>\"Charbel\" lub \"Sharbel\" może oznaczać:</p>", "Shahrokh": "<p>Shahrukh, Shahrokh lub Shah Rukh (persk: شاهرخ) to perskie imię oznaczające \"królewskie oblicze\" (shah oznacza \"król\", podczas gdy rukh oznacza \"olicę\"). Może odnosić się do:</p>", "Sagar Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sagar</b>.</p><p>Sagar może być: Miasto Sagar w stanie Madhya Pradesh w Indiach. Sagar, w stanie Madhya Pradesh, India.</p>", "Siri": "<p>Siri (ˈsɪəri, rosyjski. Syri, tyłek.</p>", "Seyid": "<p>Sayyid (także \"Sayyed\", \"Seyit\", \"Seyd\", \"Syd\", \"Sayed\", \"Sayyid\", \"Sayyed\" i \"Sydna\").</p>", "Stanyo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stany</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stani</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stan</b>.</p><p>Stan (rosyjski: Стэн) - trzeci single Eminema z jego albumu The Marshall Mathers LP, nagrany wspólnie z piosenkarką Dido.</p>", "Salaar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salar</b>.</p><p>Solero to marka mrożonych należąca do firmy Unilever. Produkcje dystrybują w Włoszech Algida.</p>", "Sung Chul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Swiatoslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sukhbir Singh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sukhbir</b>.</p><p>Sukhbir to indyjskie imię męskie. Znani ludzie z nazwiskiem Sukhbir (muzyk) (ur. 1969), Bhangra Sukhbir singer (autorkę) (1925-2012), Punjabi pisarz powieści, pisarz opowieści, poeta i esejista Sukhbir Kataria (ur. 1964), indyjski polityk Sukhbir Singh Badal (ur. 1962), Punjabi polityk Sikhbir Singh Gill (1975-2024), indyjskie hokejista pole Sukhbir Sing Jaunapuria (ur. 1957), indyjski polityk i...</p>", "Sebastian De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Shumpei": "<p>Shunpei lub Shumpei (pisanie: 俊平, ⁇ 平, 春平, ??平 lub ⁇ 平) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shumpei Fukahori (深 ⁇ ⁇ 平; ur. 1998), japoński piłkarz Shunpei Hashioka (橋岡 俊平; 1911-1978), japoński bokser Shumpei Inoue (井上 俊平), japończyk Shunpei Mizuno (水野 俊平, ur. 1968), japowski pisarz Shumpei Naruse (成瀬 ⁇ 平, ur., 2001), japońskiego piłkarza Shunpei Ueyama (上山 春平; 1921-2012), japoński filozof Shunpei...</p>", "Sunny Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sunny</b>.</p><p>⁇ Sunny ⁇ (z angielskiego - ⁇ Solnyшко ⁇) - piosenka napisana przez Bobby Hebb.</p>", "Sora": "<p>Sora to model sztucznej inteligencji przeznaczony do generowania wideo w wersji Full HD w krótkim opisie tekstowym. Opracowana przez firmę OpenAI, która wcześniej wydała produkty takie jak DALL-E i ChatGPT.</p>", "Soji": "<p>Sōji, Soji, Souji lub Sohji (pisanie: 総司, ⁇ 司 lub 荘司) jest męskie japońskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sergeii": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sergei</b>.</p><p>Sergius to męskie imię pochodzenia starożytnego Rzymu po nazwie łacińskiej geny Sergia lub Sergii w czasach królewskich i republikańskich. Jest to powszechne chrześcijańskie imię, na cześć św. Sergiusa, i było to imię czterech papieży.</p>", "Song Chol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Sebastyan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Santiago Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santiago</b>.</p><p>Santiago (lat. Santiago) - rodzaj pszczół, z plemienia Eucerini rodziny Apidae.</p>", "Siemirad": "<b>Siemirad</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Siemo(i)-</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*sěmьja</i> ma m.in. znaczenia \"rodzina, ród; czeladź, służba, własność\") i <i>-rad</i> (\"cieszyć się\"), mówiące o radości skierowanej do obdarzonego imieniem.", "Stanisław Edward": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sergiu-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sergiu</b>.</p><p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Seny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sen</b>.</p><p>Sen w wietnamskim może być: Gatunek wodny należący do rodziny Nelumbonaceae, w tym: Sen różowy (Nelumbo nucifera). Biały sen (Nelumbo lutea).</p>", "Sheer": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sher</b>.</p><p>Sher (ang. Cher, [ʃɛər]; imię przy urodzeniu - Sheryl Sarkisyan (ang.</p>", "Sergiu-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sergiu</b>.</p><p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Sergiu-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sergiu</b>.</p><p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Sebastian-Armando": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Shu-Hung": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shu</b>.</p><p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Siem": "<b>Simargł</b> (także <b>Siemargł</b>, <b>Semargł</b>) lub <b>Siem</b> i <b>Rgieł</b> – wschodniosłowiański bóg lub bogowie, wspomnieni w dwóch źródłach. Pochodzenie i etymologia tej/tych postaci jest przedmiotem ożywionej dyskusji. Dominującym poglądem jest interpretowanie Siemargła jako jednego bóstwa, który został zapożyczony od irańskiego <a href=\"https://pl.wikipedia.org/wiki/Simurg\" target=\"_blank\" rel=\"noopener noreferrer\">Simurga</a>. Pogląd ten jednak jest krytykowany, a część badaczy proponuje by uznać istnienie dwóch bóstw: Siema i Rgła.", "Samuel Andres": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Sviiatoslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Selvarajah": "<p>Selvarajah może odnosić się do Nadarajah Selvarajah, sri Lankanskiego tamilskiego pisarza Selvarasa Pathmanathan, tamilskiego rebelianta znanej również jako Selvarajah Pathmanathan. Selvarajah Yogachandran, tamilski rebeliant znany jako Kuttimani Selvarajah Rajivarnam, Sri Lankanka tamilska dziennikarz.</p>", "Samuel Enrique": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Souta": "<p>Sota, Soota, Souta lub SOTA mogą odnosić się do:</p>", "Spytko": "<b>Spycimir</b>, <b>Spyćmier</b>, <b>Spyćmir</b>, <b>Spyćmierz</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Spyci-</i> („nadaremnie”), oraz członu <i>-mir</i> („pokój, spokój, dobro”), zdrobniale – <b>Spytko</b>. Pisownia z końcowym <i>-rz</i> prawdopodobnie jest zapisem imienia zdrobniałego, uformowanego przy użyciu przyrostka <i>-jь</i>, pod wpływem którego wygłosowe <i>-r</i> przeszło w <i>-rz</i>.", "Silviu-Ionuţ": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silviu</b>.</p><p>Silviu może odnosić się do: Silviu Bălace (ur. 1978), rumunskiego piłkarza piłkarskiego Silviu Berejan (1927-2007), pisarza besarabijskiego z Mołdawii Silviu Bindea (1912-1992), rumunskiego gracza piłkarski Silviu Brucan (1916-2006), rumuńskiego polityka komunistycznego Silviu Casandra (ur. 1975), rumunskiego biegacza wyścigowego Silviu Florea (ur. 1977), rumunzkiego piłkarz rugby silviu Ilie (ur. 1988), rumunski piłkarze...</p>", "Sirajuddin": "<p>Sirajuddin (arabickie: سراج الدين) może odnosić się do: Munabbih ibn Kamil ibn Sirajud-Din Dhee Kibaar Abu-Abdullah al-Yamani al-San'ani, perski towarzysz Muhammada Siraj al-Din al-Sakaki (1160-1228), muzułmańskiego uczonego Siraj al -Din al-Ushi (zmarł 1179), Hanafi jurysta Siraj al-'Din Urmavi (1198-1283), Shafi ʽi jurysta Siraja al-Din el-Sajawandi (zmarła około 1203), irańskiego lingwisty Siraj al‐Din Qumri (zmarły 1227), irańskiego poety Siraj al-.Din Dhabyan (fl.</p>", "Stefan Stanisław": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Stěphane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stephan</b>.</p><p>Christian-Friedrich Stephan, lub Stefan (niem. Christian Friedrich Stephan, 1757, Leipzig - 17 grudnia 1814, Sankt-Petersburg) - rosyjski botanik pochodzenia niemieckiego.</p>", "Shaha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shah</b>.</p><p>⁇ SHAH ⁇ (⁇ SHA H ⁇) - rosyjska i rosyjska grupa, pionierów radzieckiego metalu. Znana jest między innymi tym, że partii basystyki w niej kilku lat wykonywał Anatolij Krupnov, założyciel ⁇ Czarnego obelisku ⁇ .</p>", "Sorin-Marian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Samith": "<p>Samith to imię. Znani ludzie z nazwiskiem to: Samith de Silva (ur. 1989), Sri Lankanski kryker Samith Dushantha (ur. 1984), Sri Lanka Kryker Samit Tillakaratne (ur. 1978), Sri Lanki Kryker</p>", "Soko": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sok</b>.</p><b>Sok</b> – produkt otrzymany z dojrzałych, świeżych lub przechowywanych <a href=\"https://pl.wikipedia.org/wiki/Owoc\" target=\"_blank\" rel=\"noopener noreferrer\">owoców</a> lub <a href=\"https://pl.wikipedia.org/wiki/Warzywa\" target=\"_blank\" rel=\"noopener noreferrer\">warzyw</a>, jednego lub większej liczby gatunków, posiadający <a href=\"https://pl.wikipedia.org/wiki/Barwa\" target=\"_blank\" rel=\"noopener noreferrer\">barwę</a>, <a href=\"https://pl.wikipedia.org/wiki/Smak_(fizjologia)\" target=\"_blank\" rel=\"noopener noreferrer\">smak</a> i <a href=\"https://pl.wikipedia.org/wiki/Zapach\" target=\"_blank\" rel=\"noopener noreferrer\">zapach</a> charakterystyczny dla soku z owoców lub warzyw, z których pochodzą, zdolny do <a href=\"https://pl.wikipedia.org/wiki/Fermentacja\" target=\"_blank\" rel=\"noopener noreferrer\">fermentacji</a>, lecz niesfermentowany. Soki mogą być produkowane z zagęszczonych soków lub przecierów przez odtworzenie udziału <a href=\"https://pl.wikipedia.org/wiki/Woda\" target=\"_blank\" rel=\"noopener noreferrer\">wody</a> usuniętej w procesie zagęszczania soku lub przecieru i odtworzenie aromatu oraz, gdy jest to wskazane, miazgi usuniętej z soku, lecz odzyskanej w procesie technologicznym.", "Shaian": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shayan</b>.</p><p>Shayan (perskiej: شایان) to perskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sorin-Marius": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Stefan Lech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Selen": "<p>Seleni lub selen to cząsteczka chemiczna o liczbie atomowej 34 i symbole chemicznym Se. Jest to niełonowy, chemicznie bardzo podobny do siarczanu i telury, w bardzo rzadkim stanie naturalnym w postaci pierwiastków.</p>", "Sorino": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Stefan Antoni": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sanjaya Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sanjaya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sanjay</b>.</p><p>Sanjay, również pisane Sanjai, Sanjey, Sanje i Sunjay, jest męskim imieniem pochodzenia sanskryckiego oznaczającym \"triumfant\", z sanskryckiej Sañjaya (सञ्जय), i może odnosić się do:</p>", "Sorin-Ionut": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sung Bok": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Shoichi": "<p>Shōichi, Shoichi lub Shouichi (pisanie: 昭一, 昇一, 正一, ⁇ 一, 晶一, 勝一, 升一 lub 省一) to męskie japońskie imię. Do wybitnych osób z nazwiskiem należą: Shoichi Aoki (青木 正一; ur. 1955), japoński fotograf i redaktor Shoichi Aray (荒井 ⁇ 一; 1965-2002), japoński profesjonalny wrestler i wykonawczy Shoichi Funaki (船木 勝一; urodzony 1968), japoński zawodowy wrestler Shoichi Hirose (広瀬 正一; Ur. 1918), japowski aktor Shōichi Kokushi (聖一 国師;...</p>", "Sabbir Ahmed": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sabbir</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabir</b>.</p><b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Shoma": "<p>Shōma, Shoma lub Shouma (pisanie: 翔馬, 翔雅, 匠馬, 正馬, ⁇ 磨 lub 聖真) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shoma Doi (土居聖真; ur. 1992), japoński piłkarz Shoma Kamata (⁇ 田 翔雅; ur. 1989), japońska piłkarza Shoma Mizunaga (水永 翔馬; ur. 1985), japońskiego piłkarka Shoma Morita (森田 正馬; 1874-1938), japończyk psycholog Shoma Uno (宇野 ⁇ 磨; ur. 1997), japowski pater Shouma Yamamoto (山本 匠馬; ur . 1983), japo...</p>", "Song Ryol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Salwiusz": "<b>Salwiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, genetycznie wtórne <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognomen</a> utworzone od pierwotnego <i>Salvus, Salvius</i>, co oznacza 'pochodzący od Salvusa, z rodu Salvusa'.", "Shahiduzzaman": "<p>Shahiduzzaman to bengalska męska nazwa pochodzenia arabskiego i może odnosić się do: Shahiduzzamani Sarker (ur. 1955), byłego skarbowego bicza i ministra Shahiduzzamana Selim (ur. 1961), aktora teatru, telewizji i filmu Shahiduzzama Beltu, polityka Mohammad Shahiduzzamena Khokan, polityka Mohammed Shahiduzzman Rashidnagari, polityk</p>", "Seif-Eddine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Seif</b>.</p><p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Sourav Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sourav</b>.</p><p>Sourav, Sourabh, Saurabh i Saurav to indyjskie imiona męskie. Saurav i Sourav oznaczają niebiańskie lub boskie, podczas gdy Saurabh i Sourabh oznaczają zapach w sanskrcie.</p>", "Stylian": "<b>Stylian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, od gr. <i>στυλος (stylos)</i> — \"filar\". Patronem tego imienia jest św. Stylian, pustelnik z <a href=\"https://pl.wikipedia.org/wiki/Edirne\" target=\"_blank\" rel=\"noopener noreferrer\">Adrianopolu</a> (VII wiek), patron dzieci.", "Stanisław Wojciech": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Subramanyam": "<p>Subramaniam, Subrahmaniam, subramaniam lub Subramanian (tamilsky: சுப்பிரமணியம்; telugu: సుబ్రహ్మణ్యం) to imiona męskie w południowo-indyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Stilyan": "<p>Stilijan lub Stilyan (bułgarski: Стилиян) to bułgarskie męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sakar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sakari</b>.</p><p>Sakari to imię i może odnosić się do: Sakari Kukko (ur. 1953), finońskiego saksofonisty i flautistki Sakari Kuosmanen (ur. 1956), finołej piosenkarki i aktorki Sakari Mattila (ur. 1989), finowego piłkarza Sakari Oramo (ur. 1965), finoskiego dyrygenta Sakari Pinomäki, finońskiej inżynierii mechanicznych i hydraulicznych systemów Sakari Timonen (ur. 1957), finowej blogerki Sakari Tuomioja (1911-1964), finowskiego polityka Yrjö Sakari Yrjö-Koskinen...</p>", "Sonio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Soni</b>.</p><p>Karan Soni (ang. Karan Sani) - amerykański aktor pochodzenia indyjskiego, znany ze swoich ról w filmach ⁇ Safety not guaranteed ⁇ i ⁇ Dedpul ⁇ .</p>", "Skandar": "<p>Iskandar, Iskander, Skandar, Skander, Askandar, Askander, Eskandar, Eskender, Eskinder, Iskinder, Sikandar, Sikander, Skandier, Scander lub İskender (arabski: إسكندر; amharski: እስክንድር eskinder; perskiego: اسکندر Eskandar lub سکندر Skandar), jest wariantem nazwy Aleksandra w kulturach takich jak Iran (Persia), Arabia i inne na Bliskim Wschodzie, północno-wschodniej Afryce, Azji Południowej, Kaukazie, regionie Wolgasty i Azji Środkowej. W...</p>", "Samuel-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Sigward": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigvard</b>.</p><p>Sigvard może odnosić się do: Sigvard Bernadotte (1907-2002), szwedzki projektant przemysłowy Sigvard Eklund (1911-2000), dyrektor Rady Bezpieczeństwa Międzynarodowej Agencji Energii Atomowej Sigvard Ericsson (1930-2019), byłego skaterka szybkości Sigvard Hultcrantz (1888-1955), szwedzkiego strzelca sportowego Sigvard Johansson, szwedzskiego sprintu kanotnika, rywalizował w połowie lat 50. Sigvard Munk (1891-1983), duńskiego polityka z Partii Socjaldemokratycznej Sigvard Sivertsen ...</p>", "Sebastian Karol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "Seohyun": "<p>Seo Joo-hyun (Hangul: 서주현; Hanja: 徐朱玄; Han-Vietnam: Z Zhu Hyeon; ur. 28 czerwca 1991), znana jako Seohyun, jest koreańską piosenkarką i aktorką. Jest znana jako najmłodsza członka koreańskiej grupy Girls' Generation, którą założyła i zarządza SM Entertainment.</p>", "Samuel-Mădălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Saif Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Saif</b>.</p><p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Sario": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sari</b>.</p><p>Sari lub saree, to ulubiona odzież indyjskiej kobiety, o rozmiarach od 4 do 9 m (czyli nawet 12 metrów) włączana w różne style. Pochodzi z subkontynentu indyjskiego i jest obecnie uważany za tradycyjny indyjski kostium.</p>", "Simon Michel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Shany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shani</b>.</p><p>Shani (Shan: शनि, Śani) lub Śanaiścara używane do wskazywania planety Saturn (Sao Saturn), i jest jednym z dziewięciu Czarów (Navagraha) w indyjskiej astronomii i astrologii. Shani jest także bogiem w Puranach.</p>", "Shoufeng": "Populacja gminy Shoufeng w 2016 roku liczyła 18&#160;146 mieszkańców – 8471 kobiet i 9675 mężczyzn. Liczba gospodarstw domowych wynosiła 7114, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,55 osób.", "Sreenivasa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sreenivas</b>.</p><p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "Stefan Józef": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Simona": "<b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Soshi": "<p>Soshi może odnosić się do: Soshi Tanaka (ur. 1982), japońskiej paterki figurki Okita Sōji (1842 lub 1844-1868), znanej również jako Okita Soshi, mieczkarz generacji dziewcząt Shinsengumi, lub SoShi, południowokoreańskiej grupy dziewcząt</p>", "Sonet": "Forma ta ukształtowana została we <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włoszech</a> w XIII – XIV wieku na podstawie wzorów z poezji ludowej. Twórcą sonetu jest poeta szkoły sycylijskiej <a href=\"https://pl.wikipedia.org/wiki/Iacopo_da_Lentini\" target=\"_blank\" rel=\"noopener noreferrer\">Iacopo (Giacomo) da Lentini</a>. Po nim sonet rozwijali <a href=\"https://pl.wikipedia.org/wiki/Guido_Cavalcanti\" target=\"_blank\" rel=\"noopener noreferrer\">Guido Cavalcanti</a>, <a href=\"https://pl.wikipedia.org/wiki/Guido_Guinizelli\" target=\"_blank\" rel=\"noopener noreferrer\">Guido Guinizelli</a>, <a href=\"https://pl.wikipedia.org/wiki/Dante_Alighieri\" target=\"_blank\" rel=\"noopener noreferrer\">Dante Alighieri</a> i <a href=\"https://pl.wikipedia.org/wiki/Francesco_Petrarca\" target=\"_blank\" rel=\"noopener noreferrer\">Francesco Petrarca</a>. W okresie renesansu sonety pisał <a href=\"https://pl.wikipedia.org/wiki/Micha%C5%82_Anio%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Michał Anioł</a>; wymieniał sonety z <a href=\"https://pl.wikipedia.org/wiki/Vittoria_Colonna\" target=\"_blank\" rel=\"noopener noreferrer\">Vittorią Colonną</a>.", "Sawio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Savio</b>.</p><p>Sávio Moreira de Oliveira (ur. 10 kwietnia 2004), znany również jako Savinho i Sávio, jest brazylijskim profesjonalnym piłkarzem, który obecnie gra w stronach za Manchester City F.C. w Premier League i Brazylii.</p>", "Stefan Robert": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Stojko": "<p>Stojko to sławskie imię, maleńka forma stojan. Do znanych osób z nazwiskiem należą: Stojko Vranković, chorwacki piłkarz koszykówki Stojko jest również nazwiskiem sławskim Południowo-Słowiańskim.</p>", "Seni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sen</b>.</p><p>Sen w wietnamskim może być: Gatunek wodny należący do rodziny Nelumbonaceae, w tym: Sen różowy (Nelumbo nucifera). Biały sen (Nelumbo lutea).</p>", "Szalom": "Występuje także w złożeniu <i>szalom alejchem</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שָׁלוֹם עֲלֵיכֶם&#8206; <i>szalom ale(j)chem</i>, <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid.</a>&#160;&#8207;שלום־עליכם&#8206; <i>szolem-alejchem</i>), co oznacza „pokój wam”, a na co odpowiada się najczęściej <i>alejchem szalom</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;עֲלֵיכֶם שָׁלוֹם&#8206; <i>ale(j)chem szalom</i>, <a href=\"https://pl.wikipedia.org/wiki/Jidysz\" target=\"_blank\" rel=\"noopener noreferrer\">jid.</a>&#160;&#8207;עליכם־שלום&#8206; <i>alejchem-szolem</i>) – „i wam pokój”.", "Shah Rukh": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shah</b>.</p><p>⁇ SHAH ⁇ (⁇ SHA H ⁇) - rosyjska i rosyjska grupa, pionierów radzieckiego metalu. Znana jest między innymi tym, że partii basystyki w niej kilku lat wykonywał Anatolij Krupnov, założyciel ⁇ Czarnego obelisku ⁇ .</p>", "Shaokang": "<p>Shaokang to mandarynskie pisownię chińskiego męskiego imienia. To samo imię jest również pisowane Shaw-kong w mandarynskim Wade-Giles (używane na Tajwanie) i w kantońskim wymowie.</p>", "Sung Hun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Śtefan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefani</b>.</p><p>Stefani może odnosić się do: Gwen Stefani Lady Gaga (Stefani Germanotta, 1986)</p>", "Saifallah": "<p>Saifullah (arabski: سيف الله), co oznacza miecz Boga, jest męskim islamskim imieniem. Pierwotnie była to nagroda honorowa za wydajność wojskową.</p>", "Saki": "<b>Saki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さき, サキ, 咲) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Serhii-Illia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Serhii</b>.</p><p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Sorin-Nicolae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Saul-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Saul</b>.</p><b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Sygurd": "<b>Zygfryd</b>, <b>Sygurd</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>sigu</i> i <i>fridu</i> oznaczających <i>zwycięstwo</i> i <i>opieka</i>, jako ten, który zapewnia bezpieczeństwo swym podopiecznym. Imię to było znane w Polsce od średniowiecza, m.in. w formach: Zebrzyd, Zybrzyd, Zewrzyd, Zywrzyd. Żeński odpowiednik to <a href=\"https://pl.wikipedia.org/wiki/Zygfryda\" target=\"_blank\" rel=\"noopener noreferrer\">Zygfryda</a>.", "Sanjeeva": "<p>Sanjeeva to imię. Znanymi osobami z nazwiska są: Sanjeeva Edirimanna, politykę z Sri Lanki, członek parlamentu z Sri Lanku Sanjeeva Kaviratne (1969-2014), politykę ze Sri Lanki Sanjeeva Nayaka, indyjska lichenolog Sanjeeva Ranatunga (ur. 1969), były kryker Sri Lanki G.</p>", "Serwiusz": "<b>Serwiusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, należące do nielicznej grupy najstarszych <a href=\"https://pl.wikipedia.org/wiki/Imiona_%C5%82aci%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion rzymskich</a> (imion właściwych, <i>praenomen</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Marek\" target=\"_blank\" rel=\"noopener noreferrer\">Marek</a>, <a href=\"https://pl.wikipedia.org/wiki/Tyberiusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Tyberiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Aulus\" target=\"_blank\" rel=\"noopener noreferrer\">Aulus</a>, <a href=\"https://pl.wikipedia.org/wiki/Maniusz\" target=\"_blank\" rel=\"noopener noreferrer\">Maniusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Gajusz_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gajusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Lucjusz\" target=\"_blank\" rel=\"noopener noreferrer\">Lucjusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Publiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Publiusz</a>, <a href=\"https://pl.wikipedia.org/wiki/Tytus\" target=\"_blank\" rel=\"noopener noreferrer\">Tytus</a>), oznaczające \"syn niewolnika\" (por. <i>servus</i> — \"niewolnik\"). Zaliczało się ono do tych najstarszych imion rzymskich, które były używane tylko przez niektóre rody.", "Sorin-Paul": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sariel": "<b>Sariel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajski</a>: שָׂרִיאֵל, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">grecki</a>: <i>Ατριήλ</i> \"rozkaz Boży\") jest jednym z archaniołów głównie z tradycji <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaistycznej</a>. Inne możliwe wersje jego imienia to Suriel, Suriyel (w niektórych tłumaczeniach z basenu <a href=\"https://pl.wikipedia.org/wiki/Morze_Martwe\" target=\"_blank\" rel=\"noopener noreferrer\">Morza Martwego</a>), Esdreel, Sahariel, Juriel, Seriel, Sauriel, Surya, Saraqael, Sarakiel, Jariel, Suruel, Surufel i Sourial.", "Sheetal": "<p>Sheetal (Hindi: शीतल) to hiszpańskie imię, co oznacza \"chłodne, zimne\". Jest również romanizowana jako Shital.</p>", "Swyatoslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svyatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Severi": "<p>Severi może odnosić się do: Severi (nazwa), włoska nazwisko Severan dynastia, dynastia cesarzy rzymskich, rządzi w późnym II i początku III wieku Severi (plemenie), plemię, które uczestniczyło w tworzeniu Pierwszego Bułgarskiego Imperium w VII wieku</p>", "Swetosław": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetoslav</b>.</p><p>Svetoslav to imię. Do wybitnych osób z nazwiskiem należą: Svetoslav z Chorwacji (przed 997 - 1000), król Chorwacji Svetoslav Dyakov (ur. 1984), bułgarski piłkarz Śwetoslav Georgiev (ur. 1977), bułgarski piłkarze Śwetosław Minkov (1902-1966), bułgara pisarz Śwetośław Petrov (ur. 1978), były bułgarz piłkarza Śwetoslaw Petrov (UR. 1988), bułgański piłkarzy...</p>", "Stanislas André": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanislas</b>.</p><p>Louis Stanislas Renoult (Francuz: Louis Stanisla Renoult) - francuski piosenkarz, kompozytor, aranżera, dyrygent i pedagog, znany w środowisku muzycznym pod nazwą Stanislas.</p>", "Sandie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandi</b>.</p><p>Sandi jest miastem i miejscem położenia urzędu (municipal board) w hrabstwie Hardoi w stanie Uttar Pradesh, India.</p>", "Soo Yong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Soo</b>.</p><p>Rejo Shoo, lub Rejo Sho (węgierski Soó Rezső; Soó von Bere Karoly Rezső, 1903 - 1980) - węgierska botanik, twórca własnego systemu klasyfikacji roślin połośmiennego.</p>", "Sun Ho": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Santiago De Jesus": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santiago</b>.</p><p>Santiago (lat. Santiago) - rodzaj pszczół, z plemienia Eucerini rodziny Apidae.</p>", "Stanisław Michel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Siemir": "<b>Wszemir</b>, <b>Wszemiar</b>, <b>Świemir</b>, <b>Siemir</b>, <b>Siemar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Wsze-</i> („wszystek, każdy, zawsze”) w różnych wersjach nagłosowych, oraz członu <i>-mir</i> („pokój, spokój, dobro”).", "Sędziwoj": "<b>Sędziwoj</b>, <b>Sędowoj</b>, <b>Sędźwoj</b>, <b>Sudywoj</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie. Znaczenie imienia: „ten, który sądzi wojowników”.", "Song Nam": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Sarwat": "<p>Tharwat lub Sarwat (arabski lub urdu: ثروت) to nazwisko i nazwisko pochodzące od arabskiego słowa (tharwa ثروة) oznaczające skarb. Do wybitnych osób z tym nazwiskiem należą:</p>", "Steven Alexander": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Steven</b>.</p><p>Christian Christianovich Steven (niem. Christian von Steven, 19 [30] stycznia 1781, Friedrichsgam, Gubernia Wyborga (obecnie Hamina, Finlandia) - 18 (30) kwietnia 1863, Simferopol) - rosyjski botanik pochodzenia szwedzkiego, doktor medycyny, ogrodnik i entomolog, założyciel i pierwszy dyrektor Ogrodu Nikitskiego w Krymie, prawidłowy doradca statystyczny.</p>", "Sirri": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Siri</b>.</p><p>Siri (ˈsɪəri, rosyjski. Syri, tyłek.</p>", "Sabih": "Po raz pierwszy danie pojawiło się w Izraelu w latach 50. XX wieku, w miasteczku <a href=\"https://pl.wikipedia.org/wiki/Ramat_Gan\" target=\"_blank\" rel=\"noopener noreferrer\">Ramat Gan</a>. Została tam sprowadzona przez osiedlających się tam Żydów irakijskich. Nazwa potrawy pochodzi, według niektórych źródeł, od arabskiego słowa <i>sabah</i> oznaczającego \"poranek\", według innych – od nazwiska irakijskiego imigranta, który spopularyzował tę potrawę w Izraelu.", "Sudhir Kumar": "<p>Sudhir to indyjskie imię męskie. Sanskritskie słowo sudhīra oznacza \"bardzo mądre\", \"odpowiedzialne\".</p>", "Song Hun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Soledad": "<b>Soledad</b> – żeńskie imię hiszpańskie oznaczające <i>Samotność</i>.", "Suneet": "<p>Suneet (Devanagari: सुनीत) również napisana jako Sunit, to indyjskie męskie imię. Jest to słowo sanskryckie męskie, które oznacza \"ten, kto ma dobre zachowania/etyki\" lub \"ten, który jest dobrze uprawiany\".</p>", "Serginho": "<p>Serginho jest diminutiwą formą nazwiska Sérgio i może odnosić się do:</p>", "Srboljub": "<p>Srboljub to męskie imię. Srboljub Bubnjević (ur. 1966), polityk i administrator w Serbii Srboljub Krivokuća (1928-2002), jugosłowiańsko-serski menedżer i piłkarz Srboljub Markušević (1936-2019), jugosłowańsko-srbski profesjonalny piłkarze i menedżer piłki nożnej Srboljub Milenković (ur., 1955), kosowski serbski lekarz i polityk Srboljub Nikolić (1965-2022), serbski piłkarzem i menedżerem Srboljub Stamenković...</p>", "Stephene": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stephen</b>.</p><p>Stephen Hawking Stephen King Stephen Harper może odnosić się do:</p>", "Swetoniusz": "Pochodził ze stanu <a href=\"https://pl.wikipedia.org/wiki/Ekwici\" target=\"_blank\" rel=\"noopener noreferrer\">ekwickiego</a>. Jego ojciec, Swetoniusz Laetus, był trybunem wojskowym przy XIII Legionie, gdzie walczył pod Bedriakum w oddziałach Otona, o czym Swetoniusz informuje w żywocie Otona.", "Silvestras": "<p>Silvestras to litewska męska nazwa. Jest krewnym angielskiego imienia Sylvester i francuskiego Sylvestre.</p>", "Sadun Bandara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sadun</b>.</p><p>Sadun to męskie imię i nazwisko pochodzące z arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sorin-Alexandru": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Suzan": "<p>Suzan jest gminą w prowincji Ariège, w regionie Occitanie w południowo-zachodniej Francji.</p>", "Sudip Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sudip</b>.</p><p>Sudip to indyjskie i nepalski męskie imię. Do osób z tym nazwiskiem należą: Sudip Bandyopadhyay (ur.</p>", "Sivanesan": "<p>Sivanesan to nazwisko i imię. Znani ludzie z nazwiska obejmują: Nazwa: Sivanesan Achalingam (ur. 1956), malezyjski polityk Surname: Kandiah Sivanesan, sri Lankański tamilski polityk i minister prowincjonalny Kiddinan Sivanesan (1957-2008), sri Lankajski tamilski politik i były posławnik parlamentu S.</p>", "Sung Yong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Satia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sati</b>.</p><p>Sati może odnosić się do: Sati (boża) Sati (stałe) Świadomość (sammā-sati) Cztery myśli (satipaṭṭhāna)</p>", "Saul-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Saul</b>.</p><b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Sviatosłav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svyatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Stijepo": "<p>Stijepo to chorwackie imię męskie, wariant Stjepan, serbsko-chorwackiej formy Stefana, co oznacza \"koronę\" lub \"kręg\". Znanymi osobami z nazwiska są: Stijepo Kobasica (1882-1944), dalmatyjski i jugosławski dziennikarz, autor i polityk Stijepo Njire (ur. 1991), chorwacki piłkarz Stijepo Perić (1896-1954), chorwackie prawnik, polityk i dyplomat</p>", "Syd": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sid</b>.</p><p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Saszo": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sasho</b>.</p><p>Sasho to męskie imię, które jest diminutiwem Aleksandra i pochodzi z Bułgarii i Macedonii Północnej. Nazwa może odnosić się do: Sasho Angelov (ur. 1969), bułgarskiego piłkarza i menedżera Sasho Cirovski (ur. 1962), trenera piłki nożnej Sasho Mijalkov (ur. 1965), makedyńskiego polityka Sasho Pargov (ur. 1946), bułgarski piłkarz Sasho Petrovski (ur., 1975), australijczyka Sasho Nikolov, kanadyjski...</p>", "Sorin-Cătălin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "San Antonio": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Shanlin": "Populacja dzielnicy Shanlin w 2016 roku liczyła 12&#160;201 mieszkańców – 5522 kobiety i 6679 mężczyzn. Liczba gospodarstw domowych wynosiła 4806, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,54 osób.", "Srikanta": "<p>Srikanta może odnosić się do: Srikanta Acharya, indyjskiej piosenkarki Srikanta Mahata, indyjski polityk Srikanta Wadiyar (ur. 1953), indyjskiego księcia i polityka Srikanta (książka), bengalijskiej powieści Sarat Chandra Chattopadhyay Srikanta, indyjska kinematyka srikanta (górka)</p>", "Stanisław Walenty": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sartono": "Pochodził z rodziny arystokratycznej. Studiował na <a href=\"https://pl.wikipedia.org/wiki/Uniwersytet_w_Lejdzie\" target=\"_blank\" rel=\"noopener noreferrer\">uniwersytecie w Leiden</a>. Był jednym z założycieli Ligi Narodowej Indonezji (1927), przekształconej później (1928) w <a href=\"https://pl.wikipedia.org/wiki/Indonezyjska_Partia_Narodowa\" target=\"_blank\" rel=\"noopener noreferrer\">Indonezyjską Partię Narodową</a>. Przewodniczył parlamentowi Republiki Indonezji (1949–1959).", "Szarif": "<b>Szarif</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شريف مكة&#8206;) – tytuł władców <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekki</a>. Dynastia potomków <a href=\"https://pl.wikipedia.org/wiki/Hasan_ibn_Ali\" target=\"_blank\" rel=\"noopener noreferrer\">Hasana</a>, syna <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifa</a> <a href=\"https://pl.wikipedia.org/wiki/Ali_ibn_Abi_Talib\" target=\"_blank\" rel=\"noopener noreferrer\">Alego</a> i <a href=\"https://pl.wikipedia.org/wiki/Fatima_(c%C3%B3rka_Mahometa)\" target=\"_blank\" rel=\"noopener noreferrer\">Fatimy</a>. Objęli władzę w <a href=\"https://pl.wikipedia.org/wiki/Mekka\" target=\"_blank\" rel=\"noopener noreferrer\">Mekce</a> około 960 r. Szarifowie byli zaangażowani w walki wewnętrzne między lokalnymi władcami <a href=\"https://pl.wikipedia.org/wiki/Arabia\" target=\"_blank\" rel=\"noopener noreferrer\">Arabii</a>, co uniemożliwiło im stworzenie silnego organizmu państwowego. Choć formalnie zachowywali niezależność, byli zawsze uzależnieni od władzy <a href=\"https://pl.wikipedia.org/wiki/Kalif\" target=\"_blank\" rel=\"noopener noreferrer\">kalifów</a>, a następnie <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tanat_mameluk%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Mameluków</a> i <a href=\"https://pl.wikipedia.org/wiki/Imperium_Osma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">Osmanów</a>. Ostatni szarif został obalony przez <a href=\"https://pl.wikipedia.org/wiki/Saudowie\" target=\"_blank\" rel=\"noopener noreferrer\">Saudów</a> w 1925 r.", "Sybrand": "<p>Sybrand to męskie imię. Znanymi ludźmi z nazwiskiem są: Sybrand Engelbrecht (kryketar) (ur. 1988), kryketar Południowoafrykański Sybrand Engelbrcht (połownik) (1913-1994), generał armii Południeafrykańskiej Sybrand van Haersma Buma (ur. 1965), holenderski polityk</p>", "Stefan Jan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sun Sik": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Spartakus": "<b>Spartakus</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Σπάρτακος <i>Spártakos</i>, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>Spartacus</i>; zm. <a href=\"https://pl.wikipedia.org/wiki/71_p.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">71 p.n.e.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Niewolnictwo\" target=\"_blank\" rel=\"noopener noreferrer\">niewolnik</a>, <a href=\"https://pl.wikipedia.org/wiki/Gladiator\" target=\"_blank\" rel=\"noopener noreferrer\">gladiator</a> rzymski, z pochodzenia prawdopodobnie <a href=\"https://pl.wikipedia.org/wiki/Trakowie\" target=\"_blank\" rel=\"noopener noreferrer\">Trak</a>. Przywódca największego i najgroźniejszego w historii Rzymu powstania niewolników, od jego imienia nazywanego <a href=\"https://pl.wikipedia.org/wiki/Powstanie_Spartakusa\" target=\"_blank\" rel=\"noopener noreferrer\">powstaniem Spartakusa</a>.", "Serhii-Andrii": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Serhii</b>.</p><p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Sabrina": "<b>Sabrina</b> – <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">angielskie</a> imię żeńskie. Pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiej</a> rzeki – <a href=\"https://pl.wikipedia.org/wiki/Severn\" target=\"_blank\" rel=\"noopener noreferrer\">Severn</a> (oryg. Habren). Błędną teorią jest, że Sabrina to forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Sabina\" target=\"_blank\" rel=\"noopener noreferrer\">Sabina</a>. Patronką tego imienia w Kościele katolickim jest św. Sabrina, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>.", "Som Nath": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Som</b>.</p><p>Jako trzy literne skróte, SOM (lub SoM) może oznaczać jedno z następujących: Somalia, państwo posiadające trzy litery kod ISO 3166 i kod krajowy IOC olimpijski jest \"SOM\" Społeczeństwo kolejowe Somerset, przedsiębiorstwo kolejowe należące do Amerykańskiej Stowarzyszenia Kolejowej posiadające znak \"SOM\". W nauce technologicznej: Self-organizing map, rodzaj sztucznej sieci neuronów w branży maszynowej, (patrz dalej...</p>", "Stéfano": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Stanisław Wincenty": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Shahi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shah</b>.</p><p>⁇ SHAH ⁇ (⁇ SHA H ⁇) - rosyjska i rosyjska grupa, pionierów radzieckiego metalu. Znana jest między innymi tym, że partii basystyki w niej kilku lat wykonywał Anatolij Krupnov, założyciel ⁇ Czarnego obelisku ⁇ .</p>", "Shariff": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sharif</b>.</p><p>Omar ash-Sharif (arabski: عمر الشريف)  Omar al-Sharif , angielski .</p>", "Shahabuddin": "<p>Shihab al-Din (arabsko: شهاب الدین) może odnosić się do: Adib Sabir (zmarł 1143), królewski poeta Persji Am'aq (zmarła 1148), perskiego poety Shahab al-Dina Abu Hafs Umar Suhrawardi (1144-1234), perskiego sufi Shahab al -Din Yahya ibn Habash Suhrawarди (1155-1191), perskiego filozofa Muhammada z Ghor (1162-1206), sultan dynastii Ghorid, Afganistanu Abu al-Abbas al-Mursi (1219-1286), hiszpańskiego sufi świętego Shihab al -Dina al-Qarafi (1228-1285), egipskiego prawnego...</p>", "Svetlana": "<p>Claire de Loutchek (francuski: Claire de Loitchek), występująca pod pseudonimem Svetlana (francusko: Claire de Luchek).</p>", "Sai Sandeep": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sai</b>.</p><p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Strogobor": "<b>Strogobor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Strogo-</i> (\"srogo\") oraz członu <i>-bor</i> (\"walczyć, zmagać się\"). Mogło oznaczać \"tego, który zaciekle walczy\".", "Sagaar": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sagar</b>.</p><p>Sagar może być: Miasto Sagar w stanie Madhya Pradesh w Indiach. Sagar, w stanie Madhya Pradesh, India.</p>", "Shom": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shoma</b>.</p><p>Shōma, Shoma lub Shouma (pisanie: 翔馬, 翔雅, 匠馬, 正馬, ⁇ 磨 lub 聖真) to męskie japońskie imię. Znanymi osobami z nazwiska są: Shoma Doi (土居聖真; ur. 1992), japoński piłkarz Shoma Kamata (⁇ 田 翔雅; ur. 1989), japońska piłkarza Shoma Mizunaga (水永 翔馬; ur. 1985), japońskiego piłkarka Shoma Morita (森田 正馬; 1874-1938), japończyk psycholog Shoma Uno (宇野 ⁇ 磨; ur. 1997), japowski pater Shouma Yamamoto (山本 匠馬; ur . 1983), japo...</p>", "Subramaniya": "<p>Subramaniam, Subrahmaniam, subramaniam lub Subramanian (tamilsky: சுப்பிரமணியம்; telugu: సుబ్రహ్మణ్యం) to imiona męskie w południowo-indyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Surinder Pal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Surinder</b>.</p><p>Surinder to indyjskie imię męskie. Do wybitnych osób z tym nazwiskiem należą: Surinder Amarnath (ur. 1948), były indyjski kryketer Test i jeden dzień, Surinder Arora, angielski biznesmen z Punjabi, którego biznes hotelowy, jak się uważa, sprawił, że wart był 225 milionów funtów Surinder Singh Bajwa (1955-2007), zastępca burmistrza Delhi Surinder Singh Kairon, syn zmarłego Sardar Pratap Singh Kairon Surinder Kapoor (1925-2011), film Bollywood ...</p>", "Sławosław": "<b>Sławosław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-sław</i> („sława”). <a href=\"https://pl.wikipedia.org/wiki/Andrzej_Ba%C5%84kowski\" target=\"_blank\" rel=\"noopener noreferrer\">Andrzej Bańkowski</a> twierdzi, że imię to najprawdopodobniej pierwotnie brzmiało <b>Słabosław</b>. Może oznaczać „ten, kto sławi sławę”.", "Sun Woo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Shahid Husain": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shahid</b>.</p><b>Szahid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شَهيد&#8206;, <i>šahīd</i>, „świadek, męczennik”) − termin wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a>, oznaczający osobę, która oddaje swoje życie w sprawie wiary, za co ma obiecaną nagrodę wieczną, czyli życie w raju (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCanna\" target=\"_blank\" rel=\"noopener noreferrer\">dżanna</a>).", "Sakae": "<b>Sakae</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さかえ, サカエ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> używane zarówno przez mężczyzn, jak i kobiety.", "Sevag": "<p>Sevag to popularne męskie imię używane w języku armenijskim. Oznacza to \"czarne oko\" i jest słowem skomponowanym z leksemów \"sev\" (co oznacza czarny) i \"ag\" (co znaczy oko).</p>", "Sinisa": "<p>Siniša (sirbijski cyrylski: Синиша) to sławskie imię męskie pochodzenia średniowiecznego. Może odnosić się do: Simeon Uroš \"Siniša\" (1326-1371), serbskiego władcy Epiru i Tesalii Siniša Branković (ur. 1979), serbskiego piłkarza Siniša Dobrasinović (ur. 1977), cypryjskiego piłkarz Sinișa Dragin (ur. 1960), serbo-rumunskiego reżysera filmowego Siniša Đurić (ur., 1976), bosnijskiego Serbskiego menedżera i byłego gracza...</p>", "Sonal": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sonali</b>.</p><p>Sonali to popularne indyjskie imię dla kobiet.</p>", "Sorin-Mihai": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Serj": "<p>Serj (armeńska: Սերժ) to armenijska nazwa. Serzh to alternatywna forma armenijska.</p>", "Santiago Joaquin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santiago</b>.</p><p>Santiago (lat. Santiago) - rodzaj pszczół, z plemienia Eucerini rodziny Apidae.</p>", "Seno": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sen</b>.</p><p>Sen w wietnamskim może być: Gatunek wodny należący do rodziny Nelumbonaceae, w tym: Sen różowy (Nelumbo nucifera). Biały sen (Nelumbo lutea).</p>", "Shamyl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamil</b>.</p><p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Sadath": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sadat</b>.</p><p>Sadat jest miastem i nagar panchayatem Ghazipur w stanie Uttar Pradesh, India.</p>", "Sotyrios": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sotirios</b>.</p><p>Sotirios (grek. Σωτήριος) lub Sotiris (Σωτήρης) to męskie imię pochodzące z Grecji, co oznacza \"zbawienie\" (σωτηρία, σωτήριος). Sotiria (Σωτηρία) jest kobiecową wersją nazwy.</p>", "Salome": "<p>Salome (Hebrajskie: שְלוֹמִית, Shlomit, związane z שָׁלוֹם, Shalom oznaczający pokój, Σαλώμη) znana również jako Salome III była żydowska księżniczką, córką Herodowa II, syna Heroda Wielkiego z księżniczą Herodias. Była niewiastką Heroda Wielkiego i córką własną Heroda Antipa.</p>", "San Miguel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Shakeer": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shaker</b>.</p><p>Shaker lub Shakers mogą odnosić się do:</p>", "Srikant": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Srikanta</b>.</p><p>Srikanta może odnosić się do: Srikanta Acharya, indyjskiej piosenkarki Srikanta Mahata, indyjski polityk Srikanta Wadiyar (ur. 1953), indyjskiego księcia i polityka Srikanta (książka), bengalijskiej powieści Sarat Chandra Chattopadhyay Srikanta, indyjska kinematyka srikanta (górka)</p>", "Sorin-Cristian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Serhiiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Serhii</b>.</p><p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Sylwery": "<b>Sylweriusz</b>, <b>Sylwery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Sylweriusz_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">papież Sylweriusz</a>.", "Szmuel": "<p>Szmuel lub Schmuel to nowoczesna hebrajska forma imienia Samuela. Szmuel i jego odmiany mogą odnosić się do: Samuela (Biblia), hebrajskiego biblijnego proroka Księgi Samuela, księgi Tanach Shmuela Hakatana, Tanna (mistrza Mishnaic) Samuela Nehardea, Amora (mistrz Talmudic)</p>", "Shabtai": "<p>Shabtai (Hebrajskie: שׁבְּתַאי lub שׁבּתַי) to żydowska męska nazwa pochodząca z hebrajskiego słowa Shabbat. Tradycyjnie nadaje się do chłopców urodzonych w ten dzień. W języku angielskim można znaleźć alternatywne transliteracje: Sabbatai, Sabbathai, Shabbatai, Shabbethai i Shabsai.</p>", "Swyatoslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svyatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sharafuddin": "<p>Sharaf al-Din (arabski: شرف الدين, romanized: Sharaf al - Din, lit. 'Honor/Eminence of the Faith') i Sharif al-Din są dwa powiązane muzułmańskie nazwiska męskie.</p>", "Santhana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Santana</b>.</p><p>Santana (Santa) - amerykański zespół rockowy. Założona pod koniec lat 60. w San Francisco przez Karlesa Santany.</p>", "Sulochan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sulochana</b>.</p><p>Sulochana (Hindi: सुलोचना, \"kożdy z pięknymi oczami\") jest popularną indyjską nazwą żeńską i może odnosić się do:</p>", "Svetyslav": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetislav</b>.</p><p>Svetislav (Serbski: Светислав) to serbskie męskie imię pochodzenia słowiańskiego. Może odnosić się do: Svetislava Basary (ur. 1953), serbskiego pisarza Svetislava Glišović (1913-1988), serbskiego piłkarza i menedżera Svetislava Goncić (ur. 1960), serbskiego aktora Svetislava Jovanović (1861-1933), serbskiego malarza Svetisława Mandić (1921-2003), serbskiego historyka, konserwatora fresków, poety i malarza Świetisława Milosawljević (1882-1960), wojskowej Jugosławii...</p>", "Ståle": "<p>Ståle to norweska nazwisko męskie. Do wybitnych osób z tym nazwiskiem należą: Ståle Dyrvik (ur. 1943), norweski historyk Ståle Eskeland (ur. 1943), norweski jurysta Ståle Kleiberg (ur. 1958), norweskiej kompozytora i muzykalem Ståle Kyllingstad (1903-1987), norweskiego rzeźbiarza i projektanta Ståle Petter Lyngstadaas, norweskiego badacza Ståle Økland (ur. 1976), norweskich pisarzy, eksperta w dziedzinie trendów i publicznego mówcy Ståle Steen Sæthre (ur. ...</p>", "Simon-Daniel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Sarvesh Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sarvesh</b>.</p><p>Sarvesh to indyjskie imię męskie oznaczające \"najwyższą istotę\". Wśród znanych osób z nazwiskiem są: Sarvesh Amte, indyjski skater szybkości Sarvesh Asthana (ur. 1965), indyjski poeta, pisarz i satyrysta Sarvesh Kumar (ur. 1989), indyjski kryker Sarvesh Kushare (ur. 1995), indyjskie sportowca Sarvesh Murari, indyjscy kinematograf Sarvesh Singh Seepu (ur. 2013), indyjska polityk Sarvesh Sing Yadav, indyjskiego polityka</p>", "Sikiru": "<p>Sikiru to powszechne męskie nazwisko nigerijskie. Znani ludzie z nazwiska to: Sikiru Adepoju (ur. 1950), nigerijski perkusista i artysta nagrywający Sikiru Adesina (1971-2016), nigerijski aktor filmowy, reżyser i producent Sikiru Kayode Adetona (ur. 1934), nigeriński monarch Sikiru Adeyemi (ur. 1998), nigerianski sprinter Sikiru Ajibowu Adeyiga (ur. 1938), nigerianin Sikuru Alimi (ur. 1942), nigeriany bokser Sikiru Alimi...</p>", "Samuel-Claudiu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Sebastian Leonardo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sebastian</b>.</p><b>Sebastian</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;σεβαστός oznaczającego „czcigodny, dostojny”. Odpowiada łacińskiemu <i><a href=\"https://pl.wikipedia.org/wiki/August_(tytu%C5%82)\" target=\"_blank\" rel=\"noopener noreferrer\">Augustus</a></i>. Chrześcijańskim patronem tego imienia jest św.&#160;<a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sebastian\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian, męczennik rzymski</a>.", "San Diego": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Shamsuddin": "<p>Shams al-Din (arabski: شمس الدين, lit. \"słońce wiary\") to arabskie imię lub tytuł.</p>", "Stanisław Zygmunt": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Stev": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Steve</b>.</p><p>SZ: SZ jest zjawiskiem atmosferycznym, który wygląda jak długa pasma światła w niebie. Steve Jobs - książka, biografia współzałożyciela Apple Inc Steve'a Jobs'a.</p>", "Saqlain": "<p>Saqlain to imię i nazwisko. Do wybitnych osób z nazwiskiem należą: Muhammad Saqlain (ur. 1978), pakistański hokejista pole Saqlain Mushtaq (ur. 1976), pakistański kryketar Saqlain Sajib (ur. 1988), kryketar Bangladeszu</p>", "Syarhei": "<p>Siarhei, Siarhiej, Syarhei lub Syarhey (bieloruski: Сяргей) to białoruska transkrypcja słowiańskiego męskiego nazwiska Sergey. Do znanych osób z nazwiska należą: Siarhei Charnou (ur. 1979), białoruski biegacz wyścigowy Siarhiej Dubaviec (ur. 1959), białorska dziennikarka Siarhei Kukharenka (ur. 1976), białoruška judoka Siarhei Lahun (1988-2011), białoruskie ciężarosta Siarhei Navumchyk (ur. 1961), białorowski dziennikarz i polityk...</p>", "Suhada": "<p>Suhada może odnosić się do: Suhada Gamlath, szrilankański prawnik Suhada Koka, film</p>", "Siyao": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Siya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sia</b>.</p><p>Siia Kate Izabel Furrler (ang. Sia Kate Isobelle Furler, rodzaj.</p>", "Stanisław  William": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Seli̇m Can": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Selim</b>.</p><b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Sulpicjusz": "<b>Sulpicjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, pierwotnie <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a>. Jego etymologia jest niejasna, można przypuszczać, że <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_etruski\" target=\"_blank\" rel=\"noopener noreferrer\">etruska</a>.", "Sorin-Adrian": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorin</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Shiva Lal": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shiva</b>.</p><p>Shiva lub Niska Baba (sansk: शिव Śiva), znany również jako Mahadeva lub Ma-ha-đə-ba (; sansk: महादेव:, n.e. 'Wielki Bóg', Mahādevaḥ, [mɐɦaːd̪eːʋɐh) jest jednym z ważnych bogów hinduizmu.</p>", "Siva Reddy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Siva</b>.</p><p>Siva może odnosić się do: 1170 Siva, asteroida Śiva lub Shiva, bóg</p>", "Sung Kyu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sung Woo": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sid Ali": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sid</b>.</p><p>Gordon Cowans (ang. Gordon Cowans; 27 października 1958) - angielski piłkarz, półobrony.</p>", "Srinivas Reddy": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Srinivas</b>.</p><p>Srinivasa (sanskrit श्रीनिवास) to hinduska nazwa. Termin Śrinivasa jest pochodzenia Vaishnava, połączenie dwóch słow św. Śri (श्री) i nivasa (निवास).</p>", "San Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Samuel A": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Soreño": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Soren</b>.</p><b>Seweryn</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. <i>Severus</i> oznacza „surowy, srogi, poważny”. Wśród imion nadawanych nowo narodzonym dzieciom, Seweryn w 2017 r. zajmował 106. miejsce w grupie imion męskich.", "Subbarao": "<p>Subbarao lub Subba Rao (Telugu: సుబ్బారావు, Kannada: ಸುಬ್ಬ ರಾವ್), czasami pisowany SubbaRow lub Subba Row, to indyjska nazwa.</p>", "Surendra Bahadur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Surendra</b>.</p><p>Surendra to indyjskie imię męskie. Wśród znanych osób z tym nazwiskiem są: Surendra (aktorzy), indyjski piosenkarz i aktor Surendra Bhave Surendra Chaturvedi Surendra Dubey Surendra Gambhir Surendra Hiranandani Surendra Jain Surendra Jha 'Suman' Surendra Kumar Datta Surendra Kumor Sinha Surendra Lal Surendra Lath Surendra Mishra Surendra Mohanty Surendra Motilal Patel Surendra Nath Mitra Surendra NAT Surendra z Nepalu Surendra Pal Surendra...</p>", "Sudip Raj": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sudip</b>.</p><p>Sudip to indyjskie i nepalski męskie imię. Do osób z tym nazwiskiem należą: Sudip Bandyopadhyay (ur.</p>", "Simon-Pavel": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Sung Min": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Silviu-Andrei": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silviu</b>.</p><p>Silviu może odnosić się do: Silviu Bălace (ur. 1978), rumunskiego piłkarza piłkarskiego Silviu Berejan (1927-2007), pisarza besarabijskiego z Mołdawii Silviu Bindea (1912-1992), rumunskiego gracza piłkarski Silviu Brucan (1916-2006), rumuńskiego polityka komunistycznego Silviu Casandra (ur. 1975), rumunskiego biegacza wyścigowego Silviu Florea (ur. 1977), rumunzkiego piłkarz rugby silviu Ilie (ur. 1988), rumunski piłkarze...</p>", "Stanisław André": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sergiu-Bogdan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sergiu</b>.</p><p>Sergiu to rumuńska nazwa, która może odnosić się do: Sergiu Băhăian Sergiu Celibidache Sergiu Dan Sergiu Floroaia Sergiu Klainerman Sergiu Nicolaescu Sergiu P. Pașca Sergiu Samarian Sergiu Suciu</p>", "Samuel Jose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Suen": "<b>Nanna, Nannar</b> – <a href=\"https://pl.wikipedia.org/wiki/Sumerowie\" target=\"_blank\" rel=\"noopener noreferrer\">sumeryjski</a> <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3stwa_lunarne\" target=\"_blank\" rel=\"noopener noreferrer\">bóg Księżyca</a>. Nazywany też był <i>Suen, Zuen</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_akadyjski\" target=\"_blank\" rel=\"noopener noreferrer\">akad.</a> <b>Sin</b>). Inne imiona: <i>Aszimbabar</i>, <i>Namrasit</i>, <i>Inbu</i>. Jego imię zapisywano również liczbą trzydzieści (tyle jest dni w <a href=\"https://pl.wikipedia.org/wiki/Miesi%C4%85c_synodyczny\" target=\"_blank\" rel=\"noopener noreferrer\">miesiącu synodycznym</a>).", "Surendra Kumar": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Surendra</b>.</p><p>Surendra to indyjskie imię męskie. Wśród znanych osób z tym nazwiskiem są: Surendra (aktorzy), indyjski piosenkarz i aktor Surendra Bhave Surendra Chaturvedi Surendra Dubey Surendra Gambhir Surendra Hiranandani Surendra Jain Surendra Jha 'Suman' Surendra Kumar Datta Surendra Kumor Sinha Surendra Lal Surendra Lath Surendra Mishra Surendra Mohanty Surendra Motilal Patel Surendra Nath Mitra Surendra NAT Surendra z Nepalu Surendra Pal Surendra...</p>", "Sattam": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Satam</b>.</p><p>Satam lub Sattam (arabski: سطام), (sanskrit: सत्तम) to męskie imię. Może odnosić się do innej formy (arabski: صدام, Ṣaddām) oznaczającej \"tylko kto konfronta\", lub Sattam (sanskrit: सत्तम), oznaczającego \"wystarczający\" lub \"piękny\"</p>", "Sung Hwan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Silvia": "<p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Światoslaw": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Soo Jong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Soo</b>.</p><p>Rejo Shoo, lub Rejo Sho (węgierski Soó Rezső; Soó von Bere Karoly Rezső, 1903 - 1980) - węgierska botanik, twórca własnego systemu klasyfikacji roślin połośmiennego.</p>", "Stefan Karol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefan</b>.</p><b>Stefan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;Στέφανος, <i>Stefanos</i>). Wywodzi się od słowa oznaczającego znak zwycięstwa – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;στέφανος oznacza „wieniec”. Pierwotnym polskim odpowiednikiem było imię <a href=\"https://pl.wikipedia.org/wiki/Szczepan\" target=\"_blank\" rel=\"noopener noreferrer\">Szczepan</a>.", "Sonni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Soni</b>.</p><p>Karan Soni (ang. Karan Sani) - amerykański aktor pochodzenia indyjskiego, znany ze swoich ról w filmach ⁇ Safety not guaranteed ⁇ i ⁇ Dedpul ⁇ .</p>", "Subramanya": "<p>Subramaniam, Subrahmaniam, subramaniam lub Subramanian (tamilsky: சுப்பிரமணியம்; telugu: సుబ్రహ్మణ్యం) to imiona męskie w południowo-indyjskiej części. Ze względu na tradycję używania nazwisk patronymowych w południowoindyjskich krajach może to być także nazwisko dla mężczyzn i kobiet.</p>", "Sergiiy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sergii</b>.</p><p>Serhii (ukraina: Сергій [serˈɦij]) to ukraińskie męskie imię pochodzące od starożytnego rzymskiego nazwiska ogólnego Sergius. Do innych transliteracji nazwy należą Sergiy, Serhiy, Sergii i Serhij.</p>", "Shahzada": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shahzad</b>.</p><p>Shahzad (persk. shaʻهزاد) lub Shehzad to imię i nazwisko. Nazwa pochodzi od شاه (Shah, \"król\") i zad (Zad, \"syn\"), więc nazwa oznacza \"syn króla\".</p>", "Sílvio": "<p>Silvio to włoskie imię męskie, męskie odpowiednik Silvii. Sílvio to wariant portugalskiego nazwiska.</p>", "Shital": "<p>Sheetal (Hindi: शीतल) to hiszpańskie imię, co oznacza \"chłodne, zimne\". Jest również romanizowana jako Shital.</p>", "Stanisław Marek": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Simphiwe": "<p>Simphiwe to południowoafrykańskie imię. Znani ludzie z nazwiska obejmują: Simphiwe Dana (ur. 1980), południowoafrykański piosenkarz-powieściarz Simphiwe Dludlu (ur. 1987), połudnoafrykańska obrońca piłki nożnej Simphiwe Khonco, południo Afrykański bokser Simphiwe Nongqayi (ur. 1972), południeafrykańskiego bokser Simphiwa Yiba (ur. 1992), gracz kryketa z Południowej Afryki</p>", "Sviatoslav-Mykola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Satam": "<p>Satam lub Sattam (arabski: سطام), (sanskrit: सत्तम) to męskie imię. Może odnosić się do innej formy (arabski: صدام, Ṣaddām) oznaczającej \"tylko kto konfronta\", lub Sattam (sanskrit: सत्तम), oznaczającego \"wystarczający\" lub \"piękny\"</p>", "Samuel-Florin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Samuel</b>.</p><b>Samuel</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>, które wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> <i>Šmū'el</i>, oznaczającego „<i>uproszony od Boga</i>”, „<i>wyproszony od Boga</i>”, „<i>Bóg wysłuchał</i>”, „<i>imię Boga</i>” lub „<i>jego imię to Bóg</i>”. W Polsce imię to jest poświadczone od 1401 roku, a w XVII wieku należało do najpopularniejszych imion szlacheckich. Nosił je ostatni z sędziów izraelskich oraz pięciu innych świętych katolickich.", "Serafin Jr": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Serafin</b>.</p><b>Serafin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa oznaczającego \"płomienny\". Nazwa często spotykana w <a href=\"https://pl.wikipedia.org/wiki/Stary_Testament\" target=\"_blank\" rel=\"noopener noreferrer\">Starym Testamencie</a>.", "Sylwia": "<b>Sylwia</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> Silvia) – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusz</a> (nie: <a href=\"https://pl.wikipedia.org/wiki/Sylwester\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwester</a>), imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, oznaczające „leśna” lub „żyjąca w lesie”. Były dwie święte o tym imieniu.", "Stanisława": "<b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Stefania": "<b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sabina": "<b>Sabina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Sabin\" target=\"_blank\" rel=\"noopener noreferrer\">Sabin</a>.", "Sonia": "<b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sławomira": "<b>Sławomira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-mira</i> („pokój, spokój, dobro”). Mogło oznaczać „sławiąca pokój”. Notowane w źródłach od <a href=\"https://pl.wikipedia.org/wiki/1386\" target=\"_blank\" rel=\"noopener noreferrer\">1386</a> roku, występujące także w wariantach <i><b>Sławomirz</b></i> (fem.) i <i><b>Sławomirza</b></i>. Przykładowe dawne możliwe zdrobnienia: Sławna, Sławka, Sławnica, Sławocha.", "Samanta": "<b>Samanta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o semickim – aramejskim – pochodzenia. Znaczyć mogło <i>słuchająca</i>, ale inne źródła sugerują związek z imieniem męskim Samuel. Imię ma stosunkowo krótką historię. Pojedyncze wypadki wystąpienia tego imienia odkryto w kronikach rodzin z Nowej Anglii z <a href=\"https://pl.wikipedia.org/wiki/XVIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVIII wieku</a>. Nie używano go praktycznie do lat siedemdziesiątych <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a>, kiedy w telewizji pojawił się serial „Bewitched”, w Polsce nadawany pod tytułem „<a href=\"https://pl.wikipedia.org/wiki/O%C5%BCeni%C5%82em_si%C4%99_z_czarownic%C4%85_(serial_telewizyjny)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożeniłem się z czarownicą</a>”. Jego tytułowa bohaterka, sympatyczna czarownica, nosiła właśnie imię Samantha. Od tego czasu imię Samanta stało się bardziej powszechne.", "Sophie": "<p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Snizhana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Stella": "<b>Stella</b>, <b>Stela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego gwiazdę. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Estella_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Stella</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a> w <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>. Stella występuje w <i><a href=\"https://pl.wikipedia.org/wiki/Fantazy\" target=\"_blank\" rel=\"noopener noreferrer\">Fantazym</a></i> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>, a jako imię chrzestne była notowana w Polsce co najmniej od 1820 roku.", "Salomea": "<b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sophia": "<p>SOPHIA (grek. - Włoski.</p>", "Sarah": "<b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Sviatlana": "<p>Światlana (bieloruska: Святлана) to białoruska nazwisko kobiety i może odnosić się do: Światlanie Khakhlonowej (ur. 1984), białoruskiej pływaczki Światlane Kouhan (ur. 1980), białorski biegacz na długą metę Światlany Kudzelich (ur. 1987), białoruśki biegaczka na długę metę Śwjatlana Makshtarova (ur. 1994), białorowski-azerbajdżanski indywidualny i synchronizowany trampolinista Światłań Pirazhenka (ur. 1992), białoraśki tenisista Świjatlana...</p>", "Seweryna": "<b>Seweryna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Seweryn\" target=\"_blank\" rel=\"noopener noreferrer\">Seweryn</a>. Patronką tego imienia jest św. Septymia Seweryna, wspominana razem ze swoim mężem, św. Flawiuszem Juliuszem Katerwiuszem i synem, św. Bassusem.", "Sybilla": "<b>Sybilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; w mitologii greckiej <a href=\"https://pl.wikipedia.org/wiki/Sybilla_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość.", "Stefaniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Selena": "<p>Selena Quintanilla-Pérez (zwł. Selena Quintana-Pérez, znana pod mononimem Selena; 16 kwietnia 1971, Lake-Jackson, USA - 31 marca 1995, Corpus-Kristi, USA) - amerykańska piosenkarka, autorka piosenek, model, aktorka i projektant.</p>", "Swietłana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Sylvia": "<p>Sylvia (lat. Sylvia) - gatunek ptaków z rodziny sławków (Sylviidae).</p>", "Sylwestra": "<b>Sylwestra</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwester\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwester</a>, utworzonego od przymiotnika <i>silvestris</i>, co oznacza „żyjący w lesie, dziki”. Istnieje dziesięciu świętych Sylwestrów, patronów tego imienia.", "Scholastyka": "<b>Scholastyka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Zaczęto go używać w <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aredniowiecze\" target=\"_blank\" rel=\"noopener noreferrer\">średniowieczu</a>. Wywodzi się od łacińskiego słowa <i>scholasticus</i> oznaczającego <i>uczony, student, nauczyciel</i>.", "Szarlota": "<b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Serafina": "<b>Serafina</b> – żeński odpowiednik hebrajskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Serafin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Serafin</a>.", "Solomiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Susana": "<p>Susana (lat. Susana) - rodzaj owady z pęcherzystkami (Tenthredinidae), które są wyróżniane w osobnej podrodzinniej Susaninae. 10 gatunków.</p>", "Scarlett": "<p>Scarlett może oznaczać: Scarlett - rosyjsko-chińska marka handlowa wykorzystywana do sprzedaży małych maszyny domowej Sasha ⁇ Scarlett ⁇ Hostin (ur. 1993) - kanadyjska cybersportynka w StarCraft II.</p>", "Sofya": "<p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Suzanne": "<p>Susan - kobiece imię, patrz Susanna Susan - krater na Księżycu Susan - pies Elizabety II ⁇ Suzanne ⁇ (piosenka Leonarda Coena)</p>", "Switłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svitlana</b>.</p><p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Sabine": "<p>Joseph Sabine (ang. Joseph Sabine, 6 czerwca 1770 - 24 stycznia 1837) - brytyjski botanik, uznany za autorytet w zakresie linki, migracji i zwyczajów brytyjskich ptaków.</p>", "Sylwana": "<b>Sylwana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego \"las, zagajnik\". Wbrew czasem powtarzanym informacjom żeńskie imię Sylwana nie ma patronki. Istnieje święty, ale Sylwan (zobacz: <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sylwan\" target=\"_blank\" rel=\"noopener noreferrer\">Święty Sylwan</a>).", "Safiya": "<p>Safiya (arabsko: صفية, romanized: Ṣafiyya) to arabska nazwa, oznaczająca \"czystość\".</p>", "Saturnina": "<b>Saturnina</b> – żeński odpowiednik łacińskiego <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Saturnin\" target=\"_blank\" rel=\"noopener noreferrer\">Saturnin</a>. Imię to nosiło kilka świętych katolickich: Saturnina, męczennica rzymska, Saturnina z Neuenheerse i Saturnina z <a href=\"https://pl.wikipedia.org/wiki/Arras_(Francja)\" target=\"_blank\" rel=\"noopener noreferrer\">Arras</a>.", "Stefaniya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sylwina": "<b>Sylwina</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Sylwin_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwin</a>, które zostało utworzone od <a href=\"https://pl.wikipedia.org/wiki/Sylwiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sylwiusza</a> przy pomocy <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">przyrostka</a> <i>-inus</i>, który wskazywał na pochodzenie od kogoś lub zdrabniał. Imię to nadawane jest w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1827\" target=\"_blank\" rel=\"noopener noreferrer\">1827</a> roku.", "Seda": "<p>Sunsilk (rosyjski: Сансилк) - brytyjska marka środków do pielęgnacji włosów należąca do firmy Unilever.</p>", "Soraya": "<p>Soraya Arnelas Rubiales (szp. Soraya Arnelas Rubiales) - hiszpańska piosenkarka, uczestnicząca w konkursie piosenki ⁇ Eurodyspozycja-2009 ⁇ .</p>", "Świętosława": "<b>Świętosława</b>, <b>Święcsława</b>, <b>Święsława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie. Złożone jest z członu <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sława</i> („sława”). Może oznaczać: „ta, której sława jest mocna”.", "Sheila": "<p>Sheila - rodzaj wieloczęściowych robaków z rodziny Polynoidae Sheila - singl Tommy Rowe Sheila (hisz. Sheila) - postać hiszpańskiego serialu ⁇ Moje ulubione sąsiedzi ⁇ , w której grała Jaisa Esteve</p>", "Sybila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sybilla</b>.</p><b>Sybilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; w mitologii greckiej <a href=\"https://pl.wikipedia.org/wiki/Sybilla_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość.", "Sienna": "<p>Toyota Sienna - miniwans, produkowany przez japońską firmę Toyota od 1997 roku. Samochód otrzymał swoją nazwę w czci legendarnego starożytnego toskańskiego miasta Siena (Sjen).</p>", "Selina": "<p>Selina () jest imieniem żeńskim, uważanym za wariant Selene, bogini i osobowości Księżyca w mitologii i religii greckiej, lub zmiana pisowni nazwy Celina, która pochodzi od rzymskiej nazwy Cecilia, odnosząc się do kobiety z rodziny Caecilia. W Wielkiej Brytanii ten wariant pisowni zaczął być używany w 1600 roku.</p>", "Shirley": "<p>Shirley, Shirley (ang. Shirley) - angielskojęzyczne imię własne.</p>", "Serena": "<b>Serena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego „czysta, spokojna, pogodna”. Patronem tego imienia jest św. Seren, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Sonya": "<p>Sonia jest imieniem kobiecym w wielu częściach świata, w tym na Zachodzie, Rosji, Iranie i Azji Południowej. Sonia i jej warianty pisowni Sonja i Sonya są używane w wielu krajach, w tym Rosji, jako diminutiw dla Sofiya (greckiego Sophia \"Mądrość\").</p>", "Switlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svitlana</b>.</p><p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Sona": "<p>Sona Sona to miasto z 14 269 mieszkańcami w włoskiej prowincji Verona. Miasto to ma powierzchnię 41,14 km2.</p>", "Svietlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Swietłana</b>.</p><b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Stanislawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stanisław</b>.</p><b>Stanisław</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów s<i>tani-</i> („stać, stać się, stanąć”) oraz <i>-sław</i> („sława”). Oznacza tego, który „stanie się sławnym”. Do końca XV wieku imię to zanotowano u około 1500 osób, a więc należało ono do <a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych w Polsce</a> obok <a href=\"https://pl.wikipedia.org/wiki/Wi%C4%99ces%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Więcesława</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C4%99dziwuj\" target=\"_blank\" rel=\"noopener noreferrer\">Sędziwuja</a>.", "Sydonia": "<b>Sydonia</b>, <b>Sidonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, oznaczające „kobieta z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Sydon\" target=\"_blank\" rel=\"noopener noreferrer\">Sydon</a></i>”. Imię to pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> w. Uważano niekiedy, że czeskie imię <i>Zdenka</i> jest odpowiednikiem Sydonii, niemniej rozpowszechnienie tego pierwszego imienia już w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> i względna rzadkość Sydonii powodują, że należy zakładać, iż imion tych nie łączy ze sobą związek.", "Swietlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svietlana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Swietłana</b>.</p><b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Snezhana": "<p>Snezhana jest wariantem Snežany, gdy jest transliteratowana z cyrylskiego Снежана (rosyjski, bułgarski itp.) Snezhana Apostolova (ur. 1972), bułgarska ekonomistka i polityk, M.P. Snezhana Abarzhi Snezhana Kerkova Snezhana Khristakieva Snezhana Kurgambaeva Snezhana Mikhaylova Snezhana Yurukova</p>", "Sviatoslava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Snizhanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Snizhana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Sigrid": "<p>Sigrid (norw. Sigrid, pełne imię - Sigrid Solbakk Robe (norw.</p>", "Shoshana": "<p>Shoshana (Shoshánna (h), שׁוֹשַׁנָּה) to hebrajskie imię żeńskie. Jest to nazwa co najmniej dwóch kobiet w Biblii i dzięki Σουσάννα (Sousanna) przekształciła się w takie europejskie i chrześcijańskie nazwiska, jak Susanna, Susan, Susanne, Susana, Susannah, Suzanne, Susie, Suzie, Sanna i Zuzana.</p>", "Samuela": "<b>Samuela</b> – żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Samuel_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Samuel</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskich</a> słów oznaczających „imię Boże” lub niech „Bóg wysłucha”.", "Salwina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salwin</b>.</p><b>Salwin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> oznaczające człowieka pełnego pokoju, spokojnego.", "Summer": "<p>Sammer (ang. Summer, Rosjanka.</p>", "Savannah": "<p>Savannah: Savanna (automoda) - atomoda ciężarowo-pasażerska, zbudowana pod koniec lat 50. w USA. GNU Savannah - platforma Fundacji Wolnego Oprogramowania do hostingu i wspólnego rozwoju wolnego oprogramowania.</p>", "Silviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Stéphanie": "<p>Stéphanie Marie Elisabeth Grimaldi (ur. 1 lutego 1965) - księżniczka Monako z rodu Grimaldi.</p>", "Seli̇n": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Selina</b>.</p><p>Selina () jest imieniem żeńskim, uważanym za wariant Selene, bogini i osobowości Księżyca w mitologii i religii greckiej, lub zmiana pisowni nazwy Celina, która pochodzi od rzymskiej nazwy Cecilia, odnosząc się do kobiety z rodziny Caecilia. W Wielkiej Brytanii ten wariant pisowni zaczął być używany w 1600 roku.</p>", "Szarlotta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szarlota</b>.</p><b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Stefani": "<p>Stefani może odnosić się do: Gwen Stefani Lady Gaga (Stefani Germanotta, 1986)</p>", "Stenia": "<p>Stenia jest rodzajem roślin kwiatowych w rodzinie Polski.</p>", "Silviya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Sneha": "<p>Sneha (hindi: स्नेहा) to popularne hinduskie imienne imienne, co oznacza \"Affekcja\".</p>", "Samia": "<p>Samia - rodzaj szczurów skrzydeł z rodziny pawińskookąt i podrodzin Arsenurinae.</p>", "Sylwiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylwian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylvian</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvian</b>.</p><p>Silvian to rumuńskie imię męskie. Znani ludzie z imieniem to: Silvian Cristescu (ur. 1970), rumuński piłkarz Silvian Dobre (ur. 1967), rumuński piłkarze Silvian Iosifescu (1917-2006), krytyka literacki, edukacja, tłumacz i profesor</p>", "Szczęsna": "<b>Szczęsna</b> – staropolskie&#8201; <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od słowa \"szczęśliwa\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szcz%C4%99sny\" target=\"_blank\" rel=\"noopener noreferrer\">Szczęsny</a>; jest uważana za odpowiednik znaczeniowy <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Szcz%C4%99sny_Feli%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt Szczęsny Feliński</a>.", "Sindy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Saule": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saul</b>.</p><b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Świetłana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Sinead": "<p>⁇ Sinéad ⁇ (Shinead) - drugi single symfoników-metalowych Within Temptation z ich piątego albumu studiowego The Unforgiving, wydanego 15 lipca 2011 roku. Grupa ogłosiła wydanie singla 15 kwietnia 2011 roku, a 19 maja wiadomo, że single będzie zawierał kilka remixów tanecznych.</p>", "Stefany": "<p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Sorina": "<p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Samara": "<b>Samara</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>.", "Sultana": "<p>Sultana lub Sultanah może odnosić się do:</p>", "Salomeja": "<p>Salomėja to litewska imiona żeńska. Salomėja Nėris (1904-1945), litewska poeta Salomėja Stakauskaitė (1890-1971), litewski wychowawca i polityk Salomėja Zaksaitė (ur. 1985), litewsko szachowca</p>", "Safira": "<b>Safira</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">egipskiego</a>. Może być inną formą imion Zefira czy <a href=\"https://pl.wikipedia.org/wiki/Zefiryna\" target=\"_blank\" rel=\"noopener noreferrer\">Zefiryna</a> - od przekształcenia nazwy <i>Saphira</i> - <i>Sephira</i> - <i>Sephirine</i>.", "Sheryl": "<p>Sheryl to imię kobiety. Podobna nazwa Sherill może być męska lub żeńska.</p>", "Świetlana": "<b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Selene": "<p>Selena (lat. Selene) - rodzaj morskiej ryby promieniowania z rodziny stavrydów (Carangidae).</p>", "Sandra Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Sigrida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigrid</b>.</p><p>Sigrid (norw. Sigrid, pełne imię - Sigrid Solbakk Robe (norw.</p>", "Siobhan": "<b>Joanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>: Jo-hanan – „<a href=\"https://pl.wikipedia.org/wiki/Tetragram\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”.", "Sulisława": "<b>Sulisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z dwóch członów: <i>Suli-</i> („obiecywać” albo „lepszy, możniejszy”) i <i>-sława</i>. Może oznaczać „ta, która cieszy się lepszą sławą od innych”. W źródłach polskich poświadczone jako Sulisława (1228) i zdrobnienie <b>Sulichna</b> (1136).", "Serra": "<p>Serra jest miasto w stanie Espírito Santo w Brazylii. Miasto to ma powierzchnię 553,254 km2, liczba ludności w 2007 roku wynosi 394370 osób, a jego gęstość wynosi 712,82 osoby/km2.</p>", "Shreya": "<p>Shreya to indyjskie imienne. Jest to imię hinduskiej bogini Lakshmi i oznacza atrybuty Lakshmi - szczęście, piękno i doskonałość.</p>", "Stephania": "<p>Stefaniia (lat. Stephania) - rodzaj roślin rodziny Mięśniowe (Menispermaceae).</p>", "Salina": "<p>Salina jest drugim z ośmiu wysp w Wyspach Eolie (po Lipari), w Morzu Tyrrhenus, na północ od Sycylii.</p>", "Sidonia": "<b>Sydonia</b>, <b>Sidonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, oznaczające „kobieta z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Sydon\" target=\"_blank\" rel=\"noopener noreferrer\">Sydon</a></i>”. Imię to pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> w. Uważano niekiedy, że czeskie imię <i>Zdenka</i> jest odpowiednikiem Sydonii, niemniej rozpowszechnienie tego pierwszego imienia już w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> i względna rzadkość Sydonii powodują, że należy zakładać, iż imion tych nie łączy ze sobą związek.", "Sabryna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabrina</b>.</p><b>Sabrina</b> – <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">angielskie</a> imię żeńskie. Pochodzi od nazwy <a href=\"https://pl.wikipedia.org/wiki/Walia\" target=\"_blank\" rel=\"noopener noreferrer\">walijskiej</a> rzeki – <a href=\"https://pl.wikipedia.org/wiki/Severn\" target=\"_blank\" rel=\"noopener noreferrer\">Severn</a> (oryg. Habren). Błędną teorią jest, że Sabrina to forma pochodna imienia <a href=\"https://pl.wikipedia.org/wiki/Sabina\" target=\"_blank\" rel=\"noopener noreferrer\">Sabina</a>. Patronką tego imienia w Kościele katolickim jest św. Sabrina, męczennica z <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a>.", "Sushma": "<p>Sushma (nepali: सुष्मा) to imiona żeńskie w Indiach i Nepalu. To znaczy \"ściskająca piękno\" albo pierwszy promienie słońca lub piękne kobiety.</p>", "Sania": "<p>Sania (lat. Sania) - rodzaj sztabotchatobrukowych przeponczotkowych skrzydeł rodziny braconiodów.</p>", "Szilvia": "<p>Szilvia to węgierska pisownię imienia Silvia. Może odnosić się do: Szilvia Bertha (ur. 1977), węgierskiej politykki Szilvia Gogh, węgierskiej nurkowcy i wykonawcy kaskuterów Szilvia Mednyánszky (ur. 1971), węgarskiej sprint canoeistki Szilvie Péter Szabó (ur. 1982), węgarski piosenkarz zespołu NOX Szilvia Szabó, węgarskiego sprint canoistki Ssilvia Sunyovszky (ur. 1948), węgii aktorka</p>", "Siena": "<p>Siena jest stolicą prowincji Siena w regionie Toskana, Włochy. Miasto ma powierzchnię 118 km2, liczba ludności wynosi 54,526 osób (w dniu 30 września 2010 r.).</p>", "Selima": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Selim</b>.</p><b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Sancja": "<b>Sancja</b>, również <b>Sanczia</b> lub <b>Sancza</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa <i>sancta</i> oznaczającego „święta”. Patronką tego imienia jest m.in. bł. <a href=\"https://pl.wikipedia.org/wiki/Sancja_Szymkowiak\" target=\"_blank\" rel=\"noopener noreferrer\">Sancja Szymkowiak</a>, zakonnica, zm. w 1942 r.", "Saniya": "<p>Saniya lub Saniyya lub Saniyah to imiona żeńskie. Znanymi osobami z tej nazwy są: Saniya Anklesaria, indyjska aktorka Saniya Chong (urodzona w 1994 roku), amerykańska piłkarka koszykówki Saniya Habboub (1901-1983), libański lekarz Saniyah Hall (urodzony w 2008 roku), amerykanka piłkarzka Saniya Iyappan (urodzono w 2002 roku), indyjska aktryna Saniya Naz (urodzone w 1988 roku), pakistańska polityka Saniya Rivers (urodzonych w 2003 roku), amerykanka piłkarska Sania Saleh (urodzena w 2003 roku) i Saniya...</p>", "Sindi": "<p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Stephany": "<p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Steffi": "<p>Steffi jest imieniem kobiece, często skróconą formą (hipokoryzm) Stephanie lub Stefanie. Steffi to imię: Steffi Duna (1910-1992), węgierskiej aktorki filmowej Erzébet Berindey Steffi Götzelt (urodzona 1960), starego tenisa Steffi Graf (urodzony 1969), niemieckiej egzystencjonistki Steffi Jacob (urodzone 1975), niemieńskiej wyścigki w szkieletów Steffi Jones (urodzono 1972), niemiecka menedżerka piłki nożnej i emeryturka Stefanie Koch (urodzonych 1981),...</p>", "Sharmila": "<p>Sharmila (hindi: शर्मिला) to popularne hindusko-sanskrityjskie imię dla kobiet, co oznacza \"komfort\", \"radość\" i \"ochrona\".</p>", "Synthia": "<p>Mycoplasma laboratorium (lat.) - zaplanowany częściowo-syntetyczny szczot bakterii rodu Mycoplasmy (Mycoplasma), otrzymany z genomu Mycoplassa genitalium. Projekt ten w dziedzinie biologii syntetycznej jest prowadzony przez dwudziestę naukowców z Instytutu J.</p>", "Sanaa": "<p>Sana'a jest stolicą i największym miastem Jemenu i centrum prowincji Sana'a. Administracyjnie miasto nie jest częścią regionu, ale tworzy własny dzielnicę zwaną \"Amanat Al-Asemah\".</p>", "Shakira": "<p>Shakira Isabel Mebarak Ripol (hisp. Shakira Isabel Mebarak Ripoll; urodz.</p>", "Skyla": "<p>Lucy Batty, najbardziej znana pod pseudonimem Skaila (ang.</p>", "Sonata": "<b>Sonata</b> – instrumentalna <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma</a> cykliczna.", "Samina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sam</b>.</p><p>Sam (ang. Sam) - skrócenie męskich i żeńskich nazw Samuel, Samuel, Samantha, Samhit, ale może być pełnym nazwiskiem, a także zarówno męskim, jak i żeńskim.</p>", "Salomé": "<p>Salome (hisz. Salomé, prawdziwe imię Maria Rosa Marco, hisz.</p>", "Swetlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetlana</b>.</p><p>Claire de Loutchek (francuski: Claire de Loitchek), występująca pod pseudonimem Svetlana (francusko: Claire de Luchek).</p>", "Shelley": "<p>George Ernest Shelley (ang. George Ernest Shelly) - brytyjski ornitolog i geolog.</p>", "Susmita": "<p>Susmita (zwane również Sushmita i Sushmitha i Sushmithak) to hindusko-sanskrityckie imię indyjskie. Wśród znanych osób z tej nazwy są: Susmita Bauri (ur. 1975), indyjska polityka Sushmita Mitra, indyjska naukowiec komputerowy Sushmita Sen (ur. 1975), indyjska aktorka, modelka i zwycięzca konkursu Miss Universe 1994 Sushmitha Singha Roy (ur. 1984), indyjskie heptatleta Susmita Bose, indyjsko-amerykańska naukowca i inżynier, profesor...</p>", "Shweta": "<p>Shweta (Devanagari: श्वेता) to indyjskie hinduskie imię dla kobiet. Sanskrit słowo śveta literycznie oznacza \"biały\".</p>", "Sia": "<p>Siia Kate Izabel Furrler (ang. Sia Kate Isobelle Furler, rodzaj.</p>", "Sanita": "<p>⁇ Samarski Stroyfarfor ⁇ - firma produkująca santechnikę i wyroby ceramiczne w mieście Samar, główną produkcję znajduje się w wsi Stroykeramik pod Samarą. Wykonują wyroby sanitarno-budowne pod marką handlową ⁇ Sanita ⁇ i ceramograniczoną płytkę pod markami handlowimi ⁇ Grasaro ⁇ i ⁇ Kerranova ⁇ .</p>", "Sakura": "<p>Sakura - rosyjski kolektyw rockowy, utworzony w 2001 roku w Moskwie. Od 2013 roku grupa nie prowadziła aktywnej działalności, oprócz pożegnalnych koncertów w 2017 roku.</p>", "Śnieżana": "<b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Sofiia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Syndia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Syndi</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Sebastiana": "<b>Sebastiana</b> – forma żeńska <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sebastian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastian</a>. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Sebastiana_z_Heraklei\" target=\"_blank\" rel=\"noopener noreferrer\">Sebastiana</a> z <a href=\"https://pl.wikipedia.org/wiki/Heraklea_Pontyjska\" target=\"_blank\" rel=\"noopener noreferrer\">Heraklei</a> (z Tracji).", "Stefanny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefany</b>.</p><p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Shanaya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shanaia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shanai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shana</b>.</p><p>Shakugan no Shana (jap. 灼眼のシャナ Сякуган но Сяна), znana również jako po prostu Сяна - seria romansów ⁇ light-novel ⁇ napisanych przez Yasitiro Takahassi i ilustrujących Noidezi Itō, a także powiązanych z nimi utworów anime i manga.</p>", "Sophio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophi</b>.</p><p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Stanisława Kazimiera": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Shilpa": "<p>Shilpa (Devanagari: शिल्पा) to indyjskie imię żeńskie, co oznacza \"szkiculat\", \"statuę\" i \"dzieło sztuki\".</p>", "Saima": "<p>Saima może być imieniem kobiecym pochodzenia arabskiego lub fińskim imieniem kobiecym. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sefora": "Była jedną z siedmiu córek <a href=\"https://pl.wikipedia.org/wiki/Midianici\" target=\"_blank\" rel=\"noopener noreferrer\">madianickiego</a> kapłana <a href=\"https://pl.wikipedia.org/wiki/Jetro\" target=\"_blank\" rel=\"noopener noreferrer\">Jetry</a>. Po zabójstwie Egipcjanina Mojżesz uciekł do kraju Madianitów, zatrzymał się przy studni, do której właśnie udawały się napoić owce córki Jetry. Kiedy inni pasterze próbowali je przepędzić, Mojżesz stanął w ich obronie. Jetro dowiedział się o zajściu i zaprosił Mojżesza do swojego domu. Ten zamieszkał u niego i poślubił Seforę, która dała mu syna imieniem <a href=\"https://pl.wikipedia.org/wiki/Gerszom\" target=\"_blank\" rel=\"noopener noreferrer\">Gerszom</a> (Wj 2,16-22). <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Wyj%C5%9Bcia\" target=\"_blank\" rel=\"noopener noreferrer\">Księga Wyjścia</a> wzmiankuje później również o ich drugim potomku, <a href=\"https://pl.wikipedia.org/wiki/Eliezer_(syn_Moj%C5%BCesza)\" target=\"_blank\" rel=\"noopener noreferrer\">Eliezerze</a> (Wj 18,4).", "Saga": "<p>Dybki (lat. Saga) - rodzaj prostokrętych owadów z podrodzin Saginae rodziny prawdziwych młodzieńców.</p>", "Sybille": "<b>Sybilla</b>, <b>Sibylla</b> (mitologia grecka) – <a href=\"https://pl.wikipedia.org/wiki/Wieszcz\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość. Początkowo istniała jedna Sybilla, później jednak ich liczba zwiększyła się do ok. 10. Najbardziej czczoną Sybillą była wieszczka z <a href=\"https://pl.wikipedia.org/wiki/Erythraj\" target=\"_blank\" rel=\"noopener noreferrer\">Erytrei</a> utożsamiana z sybillą z <a href=\"https://pl.wikipedia.org/wiki/Cumae\" target=\"_blank\" rel=\"noopener noreferrer\">Cumae</a> – <a href=\"https://pl.wikipedia.org/wiki/Sybilla_Kuma%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Sybillą Kumańską</a> (od niej miały pochodzić <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99gi_sybilli%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">księgi sybillińskie</a>).", "Salwa": "<b>Salwa</b> – jednoczesny wystrzał z wielu sztuk <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84_palna\" target=\"_blank\" rel=\"noopener noreferrer\">broni palnej</a>. Strzelanie salwami pozwalało zrekompensować niską szybkostrzelność broni, poprzez wypuszczenie wielu <a href=\"https://pl.wikipedia.org/wiki/Pocisk\" target=\"_blank\" rel=\"noopener noreferrer\">pocisków</a> naraz, zwiększające prawdopodobieństwo rażenia celu. Było zwłaszcza elementem taktyki piechoty używającej <a href=\"https://pl.wikipedia.org/wiki/Bro%C5%84_odprzodowa\" target=\"_blank\" rel=\"noopener noreferrer\">broni odprzodowej</a> (np. <a href=\"https://pl.wikipedia.org/wiki/Kontrmarsz\" target=\"_blank\" rel=\"noopener noreferrer\">kontrmarsz</a>). Strzelanie salwami, przede wszystkim <a href=\"https://pl.wikipedia.org/wiki/Salwa_burtowa\" target=\"_blank\" rel=\"noopener noreferrer\">salwami burtowymi</a>, było także częste w czasie starć <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%99t\" target=\"_blank\" rel=\"noopener noreferrer\">okrętów</a> na morzu od wieku <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII</a> aż do połowy wieku <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a>, kiedy to <a href=\"https://pl.wikipedia.org/wiki/Artyleria\" target=\"_blank\" rel=\"noopener noreferrer\">artyleria</a> w tego typu starciach straciła na znaczeniu na rzecz <a href=\"https://pl.wikipedia.org/wiki/Pocisk_rakietowy\" target=\"_blank\" rel=\"noopener noreferrer\">broni rakietowej</a>. W przypadku <a href=\"https://pl.wikipedia.org/wiki/Okr%C4%99t\" target=\"_blank\" rel=\"noopener noreferrer\">okrętów</a> strzelanie salwami pozwalało ponadto obserwować miejsce upadku pocisków, w celu korekt celowania.", "Sobiesława": "<b>Sobiesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sobie-</i> i <i>-sława</i> (\"sława\"). Oznacza \"zachowująca sławę dla siebie\" lub \"zapracowująca na sławę dla siebie\". Imię w źródłach polskich poświadczone od XIII wieku (1265 rok).", "Sybilia": "<b>Sybilla</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>; w mitologii greckiej <a href=\"https://pl.wikipedia.org/wiki/Sybilla_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">wieszczka</a> przepowiadająca przyszłość.", "Swetha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sweta</b>.</p><p>Sweta hallucinata (lat. Sweta hallocinata) - gatunek skaczących cykaczek (Cicadellidae) z podrodzin Typhlocybinae (stryb Dikraneurini). Endemiczne w południowo-wschodniej Azji.</p>", "Savana": "<p>Chevrolet Express i GMC Savana - samochody komercyjne produkowane przez General Motors, produkowane od 1996 roku. Wydawnictwo Chevrolet Express rozpoczęło się w 1995 roku na fabryce GM w Wentsville (USA).</p>", "Saraswati": "<b>Saraswati</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskryt</a>: सरस्वती) – jest jedną z trzech najważniejszych bogiń w świecie <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmu</a>; imiona pozostałych to <a href=\"https://pl.wikipedia.org/wiki/Lakszmi\" target=\"_blank\" rel=\"noopener noreferrer\">Lakszmi</a> i <a href=\"https://pl.wikipedia.org/wiki/Parwati\" target=\"_blank\" rel=\"noopener noreferrer\">Parwati</a> – tworzą one „trójpostaciowość” bogiń (<i><a href=\"https://pl.wikipedia.org/wiki/Tridewi\" target=\"_blank\" rel=\"noopener noreferrer\">Tridewi</a></i>), stanowiąc niejako odpowiedź na męską <i>Trimurti</i>, złożoną z <a href=\"https://pl.wikipedia.org/wiki/Brahma\" target=\"_blank\" rel=\"noopener noreferrer\">Brahmy</a>, <a href=\"https://pl.wikipedia.org/wiki/Wisznu\" target=\"_blank\" rel=\"noopener noreferrer\">Wisznu</a> i <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aiwa\" target=\"_blank\" rel=\"noopener noreferrer\">Sziwy</a>. Według <a href=\"https://pl.wikipedia.org/wiki/Lista_postaci_z_mitologii_indyjskiej\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii indyjskiej</a> małżonka Boga-<a href=\"https://pl.wikipedia.org/wiki/Demiurg\" target=\"_blank\" rel=\"noopener noreferrer\">demiurga</a> <a href=\"https://pl.wikipedia.org/wiki/Brahma\" target=\"_blank\" rel=\"noopener noreferrer\">Brahmy</a>. Uważana za wcielenie wiedzy; bogini prawdy, mądrości i przebaczenia, patronka nauk, <a href=\"https://pl.wikipedia.org/wiki/Sztuka_indyjska\" target=\"_blank\" rel=\"noopener noreferrer\">sztuk pięknych</a>, muzyki oraz (pierwotnie) rzek. Miała przemieszczać się po wodzie na grzbiecie <a href=\"https://pl.wikipedia.org/wiki/Cygnini\" target=\"_blank\" rel=\"noopener noreferrer\">łabędzia</a>. Innym zwierzęciem utożsamianym z Saraswati jest jeden z symboli <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">Indii</a> – <a href=\"https://pl.wikipedia.org/wiki/Paw_indyjski\" target=\"_blank\" rel=\"noopener noreferrer\">paw</a>. Jej imieniem nazwano wyschniętą obecnie <a href=\"https://pl.wikipedia.org/wiki/Saraswati_(rzeka)\" target=\"_blank\" rel=\"noopener noreferrer\">rzekę</a> w <a href=\"https://pl.wikipedia.org/wiki/Podzia%C5%82_administracyjny_Indii\" target=\"_blank\" rel=\"noopener noreferrer\">stanie</a> <a href=\"https://pl.wikipedia.org/wiki/Gud%C5%BAarat\" target=\"_blank\" rel=\"noopener noreferrer\">Gujarat</a>.", "Shelby": "<p>Shelby (ang. Shelby) - angielskie nazwisko i toponim.</p>", "Stefanija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sunshine": "<p>Sunshine to wieloznaczny termin. Może oznaczać:</p>", "Solana": "<p>Solana (rosyjski: Солана) - wysokiej prędkości blokchaina trzeciej generacji z otwartym kodem źródłowym, opracowana do tworzenia zdecentralizowanych aplikacji (dApps) i inteligentnych kontraktów w szczególności decentralizacji rozwiązań finansowych (DeFi).</p>", "Światosława": "<b>Świętosława</b>, <b>Święcsława</b>, <b>Święsława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie. Złożone jest z członu <i>Święto-</i> („święty”, „silny, mocny”) i <i>-sława</i> („sława”). Może oznaczać: „ta, której sława jest mocna”.", "Silje": "<p>Silje to norweska nazwisko dla kobiet. Jest to skrócona forma łacińskiego nazwiska kobiety Caecilia / Cecilie z nazwiska rodziny Caecilius, które powstało z łacińskiej przymiotki Caecus, \"ślepy\".</p>", "Soniya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sweta": "<p>Sweta hallucinata (lat. Sweta hallocinata) - gatunek skaczących cykaczek (Cicadellidae) z podrodzin Typhlocybinae (stryb Dikraneurini). Endemiczne w południowo-wschodniej Azji.</p>", "Szymona": "<b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Sonali": "<p>Sonali to popularne indyjskie imię dla kobiet.</p>", "Symona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Symon</b>.</p><p>Symon to zarówno nazwisko, jak i imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Silwia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Sayaka": "<b>Sayaka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さやか, サヤカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Seren": "<b>Seren</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego „czysty, spokojny, pogodny”. Patronem tego imienia jest św. Seren, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Sati": "<p>Sati może odnosić się do: Sati (boża) Sati (stałe) Świadomość (sammā-sati) Cztery myśli (satipaṭṭhāna)</p>", "Sarmila": "<p>Sharmila (hindi: शर्मिला) to popularne hindusko-sanskrityjskie imię dla kobiet, co oznacza \"komfort\", \"radość\" i \"ochrona\".</p>", "Shushan": "<p>Susa to starożytne miasto proto-elamite, Elam, Pierwsza Imperium Perskie, Parthian i Sasanid z Iranu. To jedno z najważniejszych miast na Bliskim Wschodzie.</p>", "Safiye": "<b>Safiye</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1550\" target=\"_blank\" rel=\"noopener noreferrer\">1550</a> na <a href=\"https://pl.wikipedia.org/wiki/Korfu\" target=\"_blank\" rel=\"noopener noreferrer\">Korfu</a> lub Rezi, zm. <a href=\"https://pl.wikipedia.org/wiki/1619\" target=\"_blank\" rel=\"noopener noreferrer\">1619</a> w <a href=\"https://pl.wikipedia.org/wiki/Stambu%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Stambule</a>) – niewolnica weneckiego lub albańskiego pochodzenia, konkubina sułtana <a href=\"https://pl.wikipedia.org/wiki/Murad_III\" target=\"_blank\" rel=\"noopener noreferrer\">Murada III</a>, matka sułtana <a href=\"https://pl.wikipedia.org/wiki/Mehmed_III\" target=\"_blank\" rel=\"noopener noreferrer\">Mehmeda III</a>. Pełny tytuł: <i>Devletlu İsmetlu Haseki Safiye Valide Sultan Aliyyetu'ş-Şan Hazretleri</i>.", "Suyeon": "<p>Weki Meki (Hangul: 위키미키) to koreańska grupa muzyczna, która została założona i zarządzana przez Fantagio Music w 2017 roku. Grupa składa się z ośmiu członków: Suyeon, Elly, Yoojung, Doyeon, Sei, Lua, Rina i Lucy.</p>", "Sławomiła": "<b>Sławomiła</b> – współczesne <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię żeńskie</a> (nienotowane w dawnych źródłach) złożone z członów Sław- (\"sława\") i -mił (\"miła\", \"miłująca\").", "Shantel": "<b>Shantel</b>, właśc. <b>Stefan Hantel</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/2_marca\" target=\"_blank\" rel=\"noopener noreferrer\">2 marca</a> <a href=\"https://pl.wikipedia.org/wiki/1968\" target=\"_blank\" rel=\"noopener noreferrer\">1968</a> w <a href=\"https://pl.wikipedia.org/wiki/Mannheim\" target=\"_blank\" rel=\"noopener noreferrer\">Mannheim</a>) – niemiecki <a href=\"https://pl.wikipedia.org/wiki/DJ\" target=\"_blank\" rel=\"noopener noreferrer\">DJ</a> i <a href=\"https://pl.wikipedia.org/wiki/Producent_muzyczny\" target=\"_blank\" rel=\"noopener noreferrer\">producent muzyczny</a> wywodzący się z rodziny pochodzącej z <a href=\"https://pl.wikipedia.org/wiki/Bukowina_p%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">północnej Bukowiny</a>.", "Somayeh": "<p>Somayeh (arabsko: سمیه) jest perskim wymową arabskiej kobiecej nazwy Sumaya. Wśród znanych osób z imieniem: Somayeh Tohidlou (ur. 1979), irański bloger i aktywista polityczny Somayeh Mahmoudi, irański polityk i obecny członek parlamentu Iranu Somayeh Mohammadi (ur. 1980), irański członek Mujahedin-e Khalq Somayeh Abbaspour (ur. 1985), irański pałaolympijski łucznik</p>", "Sinéad": "<b>Joanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Jan\" target=\"_blank\" rel=\"noopener noreferrer\">Jan</a> pochodzącego z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">języka hebrajskiego</a>: Jo-hanan – „<a href=\"https://pl.wikipedia.org/wiki/Tetragram\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> jest łaskawy”.", "Sherry": "<p>Sherry (Hiszpański: jerez [xeˈɾeθ] or [xeˈˈɾes]) to wina wypełniona (zwiększająca stężenie wina), wykonana z białych winogron uprawianych w pobliżu miasta Jerez de la Frontera w Andaluzji, Hiszpania. Sherry są produkowane w różnych stylach głównie z palomino, od wersji lekkiej, podobnej do białego wina w posiłku, jak Manzanilla i Fino, ciemniejszych i cięższych wersji, które są dozwolone...</p>", "Shahnaz": "<p>Shahnaz (persk. شهناز) to nazwisko i nazwisko pochodzące z Persu. Nazwa pochodzi od شاه (Shah, \"król\") i ناز (naz, \"pady\"), co oznacza \"pady króla\".</p>", "Sushmita": "<p>Susmita (zwane również Sushmita i Sushmitha i Sushmithak) to hindusko-sanskrityckie imię indyjskie. Wśród znanych osób z tej nazwy są: Susmita Bauri (ur. 1975), indyjska polityka Sushmita Mitra, indyjska naukowiec komputerowy Sushmita Sen (ur. 1975), indyjska aktorka, modelka i zwycięzca konkursu Miss Universe 1994 Sushmitha Singha Roy (ur. 1984), indyjskie heptatleta Susmita Bose, indyjsko-amerykańska naukowca i inżynier, profesor...</p>", "Shanice": "<p>Shanis Lorraine Wilson-Nox (ur. 14 maja 1973), znana lepiej jako Shanis - amerykańska piosenkarka.</p>", "Shiela": "<p>Shiela to imię. Mieszkańcy tej nazwy to: Shiela Grant Duff (1913-2004), brytyjska autorka, dziennikarka i zagraniczna korespondentka Shiela Makoto (ur. 1990), zimbabwska obrońca futbolu stowarzyszenia Shiela Marie Pineda (ur. 1991), filipińską piłkarkę siatkówki Shiela Mehra, indyjska ginekolog Shiela Valderrama (ur. 1978), filipina aktorka teatralna muzyczna</p>", "Shana": "<p>Shakugan no Shana (jap. 灼眼のシャナ Сякуган но Сяна), znana również jako po prostu Сяна - seria romansów ⁇ light-novel ⁇ napisanych przez Yasitiro Takahassi i ilustrujących Noidezi Itō, a także powiązanych z nimi utworów anime i manga.</p>", "Soleil": "<p>SOLEIL (Source Optimisée de Lumière d'Énergie Intermédiaire du LURE). Poza tym Fr.</p>", "Symeona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Symeon</b>.</p><b>Szymon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim’on</i>, lub <i><b>שִׁמְעוֹן</b></i> <i>Szime’on</i>, „<a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a> wysłuchał”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, biblijnego. Początkowo stosowana w polskich przekładach Biblii forma tego imienia <b>Symeon</b> to rzadziej dziś używana forma, bardziej rozpowszechniona na Wschodzie. Niektórzy autorzy uznają imię za greckie, widząc w nim bądź tylko zhellenizowaną formę semickiego Szimeon, bądź rzeczywiste imię pochodzenia greckiego. W <a href=\"https://pl.wikipedia.org/wiki/Hagiografia\" target=\"_blank\" rel=\"noopener noreferrer\">hagiografii</a> istnieje podział na świętych o imieniu <b>Szymon</b> i <b>Symeon</b> będącego oboczną formą pierwszego imienia.", "Suzette": "<p>Suzette jest gminą w prowincji Vaucluse w regionie Provence-Alpes-Côte d'Azur w południowo-wschodniej Francji. Ośrodek znajduje się w regionie o średniej wysokości 425 metrów nad poziomem morza.</p>", "Sloane": "<p>Hans Sloan, czyli Hans Sloan. Hans Slon (ang.</p>", "Stalina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stalin</b>.</p><p>Józef Wissaрионович Stálin (urodzony z rodziny - Jugaświli, ż. Józef ჯუღაშვილი; 6 [18] grudnia 1878, Gory, Gubernia Tyfliczka, Imperium Rosyjskie - 5 marca 1953, Bliska dacha, село Wolyńskie, Kuntsewski rząd, Moskwa, RSFСР, СССР) - rosyjski rewolucjonarz, rosyjski polityk, państwowy, wojskowy i partijny, jeden z założycieli i wieloletni rzeczywisty lider Związku Radzieckiego, jeden z najbardziej znanych i...</p>", "Shiho": "<b>Shiho</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しほ, シホ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Siya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sia</b>.</p><p>Siia Kate Izabel Furrler (ang. Sia Kate Isobelle Furler, rodzaj.</p>", "Szejna": "<p>Shayna (jiddish: שיינא;שיינה; polski: Szejna) lub Shaina to imię kobiety pochodzące z języka jiddish, co oznacza \"piękne\" lub \"miło\" (jiddisch: שיין (sheyn), spokrewnione z nowoczesnym niemieckim schön), a także evocative z jiddish frazy \"אַ שיינע מיידל\" (\" shayne maydel\", lub \"miła dziewczyna\"). Jego hebrajskim odpowiednikiem jest Yaffa (יפה) lub Yafit (יַפִית); w latach po Holokauście nazwa Shayna (i jej arabskiej rodzeństwo, Jamila) była często...</p>", "Sanela": "<p>Sanela to bosniackie imię i nazwisko, które mają następujące kobiety: Sanela Diana Jenkins (ur. 1973), bosniacka przedsiębiorca i filantropka Sanela Knezović (ur. 1979), bosniackiej chorwaty, Sanela Redžić, bosniacka sportowca z niepełnosprawnością, Sanela Sijerčić, bosnjacka piosenkarka ludowa.</p>", "Sakhila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sakhil</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sakhile</b>.</p><p>Sakhile to afrykańska nazwa, która może odnosić się do: Sakhile, piosenkarka w muzyce Ndebele Sakhile Dube, zimbabwskiej królowej piękności Sakhile Nyoni, zimbabwiańskiego pilota Sakhile, Mpumalanga miasto w pobliżu Standerton, Afryka Południowa</p>", "Stephani": "<p>Stephani (niemieckie) - niemieckie nazwisko.</p>", "Suzie": "<p>Suzie lub Susie to żeńskie imię i nazwisko, a jest krótką formą (hipokoryzm) Suzanne, Susannah lub Susan. Wśród znanych osób z tej nazwy są:</p>", "Sayuri": "<b>Sayuri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さゆり, サユリ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Shadia": "<p>Fatma Ahmed Kamal Shaker (egypcki: فاطمة أحمد كمال شاكر), bardziej znana pod pseudonimem Shadia, (شادية Shādiyya; 8 lutego 1931 - 28 listopada 2017) była egipską aktorką i piosenkarką. Była znana z roli w komediach i dramatikach w latach 50. i 60.</p>", "Sare": "<p>Sare (baskie: Sara) jest gmina w prowincji Pyrénées-Atlantiques w południowo-zachodniej Francji.</p>", "Sheva": "<p>Andriy Mykolayovych Shevchenko (ukraina: Андрій Миколайович Шевченко [ɑndˈrij mɪkoˈlɑjovɪtʃ ʃɛwˈtʃɛnko], urodzony 29 września 1976 roku w Dvirkivschyna, prowincja Kijowa) jest byłym ukraińskim piłkarzem i trenerem piłkarskim. W 2004 roku zdobył Złoty Bal.</p>", "Sybil": "<p>Sibilia była w starożytnej Grecji, najpierw w Delfie, prorokówką. Frygijski Sibyl Erythraean Sibyl Hellespontine Sibyl Sybil lub Sibyl może również odnosić się do:</p>", "Sumi": "Nowa koreańska szkoła była więc odpowiednikiem chińskiej tradycji <a href=\"https://pl.wikipedia.org/wiki/Caodong\" target=\"_blank\" rel=\"noopener noreferrer\">caodong</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a> chodong). Była to jedyna szkoła z dziewięciu, która nie pochodziła od mistrzów szkoły <a href=\"https://pl.wikipedia.org/wiki/Hongzhou_zong\" target=\"_blank\" rel=\"noopener noreferrer\">hongzhou</a>, czyli uczniów <a href=\"https://pl.wikipedia.org/wiki/Mazu_Daoyi\" target=\"_blank\" rel=\"noopener noreferrer\">Mazu Daoyi</a>.", "Sarahi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sarah</b>.</p><b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Santia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Santi</b>.</p><p>Giorgio Santi (italijsky: Giorgio santi; 1746 - 1822) - włoski botanik.</p>", "Sofio": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophio</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophi</b>.</p><p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Stefana": "<p>Stefana to imię. Do wybitnych osób z tym nazwiskiem należą: Stefana Miladinović, serbska polityka Stefana Veljković, serbska piłkarka siatkówki</p>", "Sandra Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Sierra": "<p>Sierra (hisp. sierra, dosłownie ⁇ zbcowana piła ⁇ , inaczej ⁇ górna łańcuch ⁇) - składająca się część własnych nazw i nazwisk.</p>", "Sharifa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sharif</b>.</p><p>Omar ash-Sharif (arabski: عمر الشريف)  Omar al-Sharif , angielski .</p>", "Saulė": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saul</b>.</p><b>Szaweł</b>, Saul – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> (&#8207;שָׁאוּל&#8206; <i>šā’ūl</i> „uproszony, pożądany”).", "Shaira": "<p>Shaira jest ptaszką w rodzynie Chrysomelidae. Opis ten został naukowo opisan w 1936 roku przez Maulika.</p>", "Sheyla": "<p>Sheyla to imię. Znanymi osobami z nazwiska są: Sheyla Bonnick, jamajskie piosenkarka i wykonawczyka, aktywna od 1975 roku Sheyla Tadeo (urodzona 1973), meksykańska aktorka, komika i piosenkarz</p>", "Setareh": "<p>Setareh lub Setare (perskie: سِتاره) to kobiece imię pochodzenia perskiego oznaczające \"gwiazdę\" lub \"niegody\". Jego odpowiednik w językach tajczyckim i uzbekskim jest Sitora.</p>", "Sunmi": "<p>Lee Sonmi (kor. 李善美; rod.</p>", "Sundari": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sundar</b>.</p><p>Sundar (Devanagari: सुन्दर) to przymiot oznaczający atrakcyjność, piękno, dobro, przystojność lub przyjemność. Pochodzi z sanskrytu.</p>", "Sachiko": "<b>Sachiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さちこ, サチコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sumire": "<b>Sumire</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;すみれ, スミレ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Sarah Jane": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sarah</b>.</p><b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Shaina": "<p>Shayna (jiddish: שיינא;שיינה; polski: Szejna) lub Shaina to imię kobiety pochodzące z języka jiddish, co oznacza \"piękne\" lub \"miło\" (jiddisch: שיין (sheyn), spokrewnione z nowoczesnym niemieckim schön), a także evocative z jiddish frazy \"אַ שיינע מיידל\" (\" shayne maydel\", lub \"miła dziewczyna\"). Jego hebrajskim odpowiednikiem jest Yaffa (יפה) lub Yafit (יַפִית); w latach po Holokauście nazwa Shayna (i jej arabskiej rodzeństwo, Jamila) była często...</p>", "Solène": "<p>Solène to francuskie imię, w współczesnym użyciu głównie kobiece, ale historycznie używane również dla mężczyzn: Solène (biskup), biskup Chartres i św. Solène z Akwitania, 3 w. chrześcijanin martyred w Chartres, Francja Solène Rigot Solène Ndama Solène Durand, francuski piłkarz piłkarski Solène Jambaqué Solène Coulot (1989-2010)</p>", "Sophiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophia</b>.</p><p>SOPHIA (grek. - Włoski.</p>", "Stine": "<p>Stine to imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Swetłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetlana</b>.</p><p>Claire de Loutchek (francuski: Claire de Loitchek), występująca pod pseudonimem Svetlana (francusko: Claire de Luchek).</p>", "Sotera": "<b>Sotera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Gr.\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, wywodzące się od słowa <i>σωτηρια (soteria)</i> – \"zbawienie\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Soter\" target=\"_blank\" rel=\"noopener noreferrer\">Soter</a>. Jego patronką jest św. Sotera, zm. w <a href=\"https://pl.wikipedia.org/wiki/304\" target=\"_blank\" rel=\"noopener noreferrer\">304</a> roku.", "Sewera": "<b>Sewera</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81ac.\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od słowa <i>severa</i> - \"surowa, poważna\". Patronką tego imienia jest św. Sewera z <a href=\"https://pl.wikipedia.org/wiki/Trewir\" target=\"_blank\" rel=\"noopener noreferrer\">Trewiru</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/VII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">VII wieku</a>.", "Sephora": "<p>Sephora (z rosyjskiego Sephora) - sieć sklepów perfumerowo-kosmetycznych.</p>", "Samiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samia</b>.</p><p>Samia - rodzaj szczurów skrzydeł z rodziny pawińskookąt i podrodzin Arsenurinae.</p>", "Suraia": "<p>Suraia jest gminą w prowincji Vrancea w Rumunii. W 2002 roku liczba ludności wynosiła 7800.</p>", "Sabba": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saba</b>.</p><b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Séverine": "<p>Severin (francuski: Séverin)  Séverine, prawdziwe imię Jozián Grizo (francuski: Séverine).</p>", "Shubhangi": "<p>Shubhangi to imię. Znani ludzie z nazwiska to: Shubhangi Atre (ur. 1981), indyjska aktorka telewizyjna Shubhangi Gokhale (ur. 1968), indyjskie aktorka Shubhangi Kulkarni (ur. 1959), indyjski kryker Shubhangi Latkar (ur. 1972), indycka aktorka filmowa</p>", "Shahida": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shahid</b>.</p><b>Szahid</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;شَهيد&#8206;, <i>šahīd</i>, „świadek, męczennik”) − termin wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a>, oznaczający osobę, która oddaje swoje życie w sprawie wiary, za co ma obiecaną nagrodę wieczną, czyli życie w raju (<a href=\"https://pl.wikipedia.org/wiki/D%C5%BCanna\" target=\"_blank\" rel=\"noopener noreferrer\">dżanna</a>).", "Savitri": "<p>Savitri lub Savithri mogą odnosić się do:</p>", "Śnieżanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Satoko": "<b>Satoko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとこ, サトコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Samya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samia</b>.</p><p>Samia - rodzaj szczurów skrzydeł z rodziny pawińskookąt i podrodzin Arsenurinae.</p>", "Sanaz": "<p>Sanaz (ساناز sânâz) to perskie imię dla kobiet . W perskim składa się z sa oznacza \"podobność\" i naz oznacza \"słodkość\".</p>", "Szakira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shakira</b>.</p><p>Shakira Isabel Mebarak Ripol (hisp. Shakira Isabel Mebarak Ripoll; urodz.</p>", "Satomi": "<b>Satomi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さとみ, サトミ ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, jest także używane jako nazwisko.", "Shaima": "<p>Shaimaa (arabsko: شيماء) to kobiece imię arabskiego pochodzenia. Shayma była nazwą proroka Muhammada (r.</p>", "Sashka": "<p>Sasha to nazwa, która pochodziła wśród sławskich narodów z Europy Wschodniej i Południowej jako skrócona wersja Aleksandra i Aleksandra. Jest również używane jako nazwisko, choć bardzo rzadko.</p>", "Sheina": "<p>Shana lub Shanna mogą odnosić się do:</p>", "Sahara": "W źródłach pojawiają się różne informacje dotyczące powierzchni pustyni. Ocenia się, że powierzchnia Sahary wynosi 7 mln, 8,6 mln lub 9,2 mln <a href=\"https://pl.wikipedia.org/wiki/Kilometr_kwadratowy\" target=\"_blank\" rel=\"noopener noreferrer\">km²</a> powierzchni.", "Sajida": "<p>Sajida to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Safiyah": "<p>Safiya (arabsko: صفية, romanized: Ṣafiyya) to arabska nazwa, oznaczająca \"czystość\".</p>", "Snezhanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Snezhana</b>.</p><p>Snezhana jest wariantem Snežany, gdy jest transliteratowana z cyrylskiego Снежана (rosyjski, bułgarski itp.) Snezhana Apostolova (ur. 1972), bułgarska ekonomistka i polityk, M.P. Snezhana Abarzhi Snezhana Kerkova Snezhana Khristakieva Snezhana Kurgambaeva Snezhana Mikhaylova Snezhana Yurukova</p>", "Sigrun": "Sigrun, mimo rodzinnej tragedii, wyszła za Helgiego i urodziła mu synów (oznacza to, że przestała być walkirią). Jej szczęście nie trwało jednak długo, gdyż Helgi zginął z ręki <a href=\"https://pl.wikipedia.org/wiki/Daga\" target=\"_blank\" rel=\"noopener noreferrer\">Daga</a> wypełniającego – wbrew złożonej ongiś przysiędze wierności – obowiązek rodowej zemsty. Oszalała z rozpaczy Sigrun nie tylko rzuciła na brata-mściciela straszliwą i nieodwołalną klątwę, ale nawet zaczęła myśleć o samobójstwie. Któregoś dnia służąca przyniosła jej prośbę Helgiego o spotkanie w kopcu grobowym i małżonkowie spędzili ze sobą noc pełną wspomnień i miłości. Cud ten, mimo nadziei Sigrun, nie powtórzył się więcej i nieszczęsna umarła wkrótce z żalu i tęsknoty. Opowiadano jednak, że Helgi i Sigrun urodzili się po raz drugi (w istocie dla niej były to trzecie narodziny): on jako Helgi Haddingjaskati, ona – jako walkiria Kara, córka Halfdana.", "Sóley": "<b>Sóley Stefánsdóttir</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/20_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">20 października</a> <a href=\"https://pl.wikipedia.org/wiki/1986\" target=\"_blank\" rel=\"noopener noreferrer\">1986</a> w <a href=\"https://pl.wikipedia.org/wiki/Reykjav%C3%ADk\" target=\"_blank\" rel=\"noopener noreferrer\">Reykjavíku</a>), znana również jako <b>Sóley</b> – pochodząca z <a href=\"https://pl.wikipedia.org/wiki/Islandia\" target=\"_blank\" rel=\"noopener noreferrer\">Islandii</a> piosenkarka, pianistka, autorka tekstów oraz członkini zespołu indie-folk <a href=\"https://pl.wikipedia.org/wiki/Seabear\" target=\"_blank\" rel=\"noopener noreferrer\">Seabear</a>. W 2010 roku wydała zawierający sześć utworów album <a href=\"https://pl.wikipedia.org/wiki/EP\" target=\"_blank\" rel=\"noopener noreferrer\">EP</a> <i>Theater Island</i>, który poprzedzał wydanie jej debiutanckiego albumu <i>We Sink</i>.", "Susane": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Susan</b>.</p><p>Susan - kobiece imię, patrz Susanna Susan - krater na Księżycu Susan - pies Elizabety II ⁇ Suzanne ⁇ (piosenka Leonarda Coena)</p>", "Szoszana": "<b>Zuzanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijnego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשַׁנָּה&#8206; (<i>szoszana</i>), zapożyczonego przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">język grecki</a>, a pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;שׁוֹשָׁן&#8206; (<i>szoszan</i>), oznaczającego „lilia”, co z kolei prawdopodobnie wywodziło się od egipskiego <i>seszen</i>, czyli „lotos”. W Polsce imię to jest notowane w dokumentach od 1265 roku, w formach Zuzanna/Żużanna, a także pochodnych: Zanna/Żanna, Zanka/Zańka, Ożanka (zob. też <a href=\"https://pl.wikipedia.org/wiki/O%C5%BCanna_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Ożanna</a>), Zużka, Zuchna, Oszka. Wśród imion nadawanych nowo narodzonym dzieciom, Zuzanna w 2017 zajmowała 2. miejsce w grupie imion żeńskich.", "Shizuka": "<b>Shizuka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しずか, シズカ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone głównie przez kobiety, rzadko noszone przez mężczyzn.", "Sepideh": "<p>Sepideh lub Sepid może odnosić się do:</p>", "Samaya": "<b>Samaja</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">skt.</a> <i>sam</i> – razem + <i>aja</i> – iść; <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tybeta%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">tyb.</a> <i>dam tsig</i>), termin dosłownie tłumaczony jako obietnica, choć może mieć również inne znaczenia, takie jak porozumienie, zaangażowanie, wskazanie, ograniczenie.", "Sophie Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Svyatoslava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svyatoslav</b>.</p><p>Sviatoslav jest rosyjską i ukraińską nazwą pochodzenia słowiańskiego. Kognaty obejmują Świętośława, Swatosława, Święto śława, Svetisława.</p>", "Sinikka": "<p>Sinikka to fińskie imię dla kobiet. Jego dzień uroczystości obchodzony jest 2 września.</p>", "Shagufta": "<p>Shagufta lub Shegufta, pochodzące od Shekofteh (perskiego: شکفته), jest perskim językiem kobiece nazwisko, które oznacza radosny, pełen rozwoju lub otwarty. Wśród różnych wersji znajduje się nazwa Shegufa w darskim języku lub Shekoufeh lub Shokoufeh w perskim, które oba oznaczają kwiat.</p>", "Sibongile": "<p>Sibongile (męski Siyabonga) to kobiece imię pochodzące od słowa Nguni bonga, co oznacza \"dziękować\". Wśród znanych osób z tej nazwy są: Sibongile Besani, południowoafrykański polityk Sibongile Khumalo (1957-2021), południo Afrykański piosenkarz Sibongile Mchunu, połudnoafrykańska polityk Sibongeile Mlambo, Zimbabwewska aktorka Sibongile Ndashe, południeafrykańskiego prawnika i działacza w dziedzinie praw człowieka Sibongile Judith Nkomo, południaafrykańczy polityk Sibongoile...</p>", "Sofia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Shauna": "<p>Shauna (ir. Seána) to irlandzkie nazwisko dla kobiet. Jest to kobieca wersja męskich nazw Shawn lub Sean, które obydwie pochodzą z Johna.</p>", "Sulochana": "<p>Sulochana (Hindi: सुलोचना, \"kożdy z pięknymi oczami\") jest popularną indyjską nazwą żeńską i może odnosić się do:</p>", "Sylviia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylvia</b>.</p><p>Sylvia (lat. Sylvia) - gatunek ptaków z rodziny sławków (Sylviidae).</p>", "Sophie-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Solomiia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sunisa": "<p>Sunisa to imię. Znani ludzie z nazwiska to: Sunisa Lee (ur. 2003), amerykańska gimnastka Sunisa Kawrungruang (ur. 1972), tajskiej sprinterka Sunisa Srangthaisong (ur. 1988), tajską piłkarz</p>", "Svitłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Switłana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svitlana</b>.</p><p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Sułtana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sultan</b>.</p><p>Sultan (wietn. xun-tan; arab. سلطان Sultān) jest tytułem króla w krajach, w których islam jest narodowy, i ma wiele znaczeń z czasem. Sultan to początkowo arabskie imię abstrakcyjne, które oznacza \"mocarstwo\", \"mocarstwa\" lub \"dominację\".</p>", "Szaron": "<b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Smaranda": "<p>Smaranda to rumuńska nazwisko żeńskie, które może odnosić się do: Smaranda Brăescu (1897-1948), rumuńskiej pionierki spadochronu i lotnictwa Smaranda Enache (ur. 1950), rumuński polityk Smaranda Gheorghiu (1857-1944), rumuński poeta, pisarz powieści, esejista, dramatyk, edukacja, feministka i podróżnik Smaranda Olarinde, nigerijski profesor prawa</p>", "Shanell": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shanelle</b>.</p><p>Shanelle to imię kobiece. Znanymi osobami z nazwiska są: Shanelle Arjoon (urodzona w 1997 roku), trynidadyjska piłkarka Shanelle Jackson (urodzone w 1980 roku), amerykańska polityka Shanelle Nyasiase (urodzony w 1997 roku) - etyopska modelka mody w Sudanie Południowym.</p>", "Shriya": "<p>Shriya to imiona żeńskie w językach Indii. Inne literacie obejmują: Shreeya, Shreeyya Shriya oznacza hinduską boginię Lakshmi i ma wiele znaczeń, w tym: Prosperity: Indyjska nazwa dla dziewczyn i chłopców, która oznacza \"prosperity\" Szczęśliwy: Znaczenie nazwy Shriya Bogactwo: Znaczenie sanskrytu słowa Śriyā w Jyotisha Królowa mądrości: Znaczenie Sanskrytu słowa śriyā w buddyzmie tybetańskim Władcy chwały: A...</p>", "Shiori": "<b>Shiori</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しおり, シオリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Sun Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Selime": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Selim</b>.</p><b>Selim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Turcy\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Imiona_arabskie\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a> imienia Salim, co oznacza „bezpieczny”.", "Syifa": "<p>Syifa to indonezyjska nazwa. Znanymi osobami z nazwiska są: Syifa Hadju (ur. 2000), indonezyjska aktorka i piosenkarka Syifa Nurafifah Kamal (ur. 1991), indonezijska łukarka.</p>", "Sharlotta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szarlotta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szarlota</b>.</p><b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Samiha": "<p>Samiha (arabsko: سميحة lub سامحة; bengajski: সামিহা) to arabskie kobiece imię, kobieca forma Samih lub Sameh. Do wybitnych osób z nazwiskiem należą: Samiha Ayoub (1932-2025), egipska aktorka Samiha Ayverdi (1905-1993), turecki pisarz Samiha Al-Fayez (ur. 1993), jordanka publiczna i filantrop Samha Khalil (1923-1999), palestyńskiej postaci politycznej i pracownika charytatywnego Samiha Khrais (ur. 1956), jordanki pisarz,...</p>", "Siria": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Siri</b>.</p><p>Siri (ˈsɪəri, rosyjski. Syri, tyłek.</p>", "Shanny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shany</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shani</b>.</p><p>Shani (Shan: शनि, Śani) lub Śanaiścara używane do wskazywania planety Saturn (Sao Saturn), i jest jednym z dziewięciu Czarów (Navagraha) w indyjskiej astronomii i astrologii. Shani jest także bogiem w Puranach.</p>", "Saiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayan</b>.</p><p>Sayan to miasto census (powieść) w okręgu Surat w stanie Gujarat, India.</p>", "Shaimaa": "<p>Shaimaa (arabsko: شيماء) to kobiece imię arabskiego pochodzenia. Shayma była nazwą proroka Muhammada (r.</p>", "Sidonie": "<p>Sidonia lub Sidonie to żeńskie imię, które może odnosić się do:</p>", "Stefania Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sophy": "<p>Sophy jest alternatywnym pisownią kobiecej nazwy Sophie, z imienia Sophia, co oznacza \"mądre\".</p>", "Sajina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sajin</b>.</p><p>Sajin to indyjskie imię. Znani ludzie z nazwiskiem to: Sajin Baabu (ur. 1986), indyjski reżyser filmowy Sajin Cherukayil, indyjski aktor Sajin Gopu, indyjscy aktor Sajin Vass Gunawardena (ur. 1973), polityk z Sri Lanki</p>", "Shazia": "<p>Shazia (urdu: شازیہ) to kobiece imię arabskiego pochodzenia. Do wybitnych osób z tym nazwiskiem należą:</p>", "Susy": "<p>Susy to kobiece imię, czasami skrócona forma (hipokoryzm) Susan, Susanne, Susannah itp. Susy może odnosić się do:</p>", "Saloni": "<p>Saloni (Hindi: सलोनी) to imiona żeńskie pochodzenia indyjskiego. Znanymi osobami z nazwiska są: Saloni (aktorka) (Zohra Begum; 1950-2010), pakistańska aktorka Saloni Aswani (ur. 1987), indyjska aktorka i modelka Saloni Batra (ur. 1997), indyjskia aktorka Salini Chopra (ur. 1991), indyjski urodzony australijski aktor i model Saloni Daini (ur. 2001), indyjskich aktorek i komika Saloni Gaur (ur. 1999), indyskiej komików i impresjonistki Saloni Malhotra,...</p>", "Shalu": "Populacja dzielnicy Shalu w 2016 roku liczyła 91&#160;338 mieszkańców – 45&#160;158 kobiet i 46&#160;180 mężczyzn. Liczba gospodarstw domowych wynosiła 28&#160;835, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 3,17 osób.", "Svetoslava": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetoslav</b>.</p><p>Svetoslav to imię. Do wybitnych osób z nazwiskiem należą: Svetoslav z Chorwacji (przed 997 - 1000), król Chorwacji Svetoslav Dyakov (ur. 1984), bułgarski piłkarz Śwetoslav Georgiev (ur. 1977), bułgarski piłkarze Śwetosław Minkov (1902-1966), bułgara pisarz Śwetośław Petrov (ur. 1978), były bułgarz piłkarza Śwetoslaw Petrov (UR. 1988), bułgański piłkarzy...</p>", "Smitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Smith</b>.</p><b>Smith</b> – <a href=\"https://pl.wikipedia.org/wiki/Nazwisko\" target=\"_blank\" rel=\"noopener noreferrer\">nazwisko</a> angielskiego pochodzenia. Pochodzi od staroangielskiego słowa <i>smið</i> oznaczającego <a href=\"https://pl.wikipedia.org/wiki/Kowal\" target=\"_blank\" rel=\"noopener noreferrer\">kowala</a>. Jest to jedno z najbardziej popularnych nazwisk na świecie. W <a href=\"https://pl.wikipedia.org/wiki/Wielka_Brytania\" target=\"_blank\" rel=\"noopener noreferrer\">Wielkiej Brytanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">Stanach Zjednoczonych</a> posługuje się nim ponad jeden procent ludności, w tym w samych Stanach Zjednoczonych ponad 2,5 miliona ludzi.", "Shanai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shana</b>.</p><p>Shakugan no Shana (jap. 灼眼のシャナ Сякуган но Сяна), znana również jako po prostu Сяна - seria romansów ⁇ light-novel ⁇ napisanych przez Yasitiro Takahassi i ilustrujących Noidezi Itō, a także powiązanych z nimi utworów anime i manga.</p>", "Svetłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetlan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svetlana</b>.</p><p>Claire de Loutchek (francuski: Claire de Loitchek), występująca pod pseudonimem Svetlana (francusko: Claire de Luchek).</p>", "Souhaila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Souhail</b>.</p><p>Souhail, Suhail, Sohail lub inne warianty (arabijski: سهيل) to arabski termin powszechnie używany jako męskie imię i nazwisko. Souhail lub jego warianty mogą odnosić się do:</p>", "Sayana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayan</b>.</p><p>Sayan to miasto census (powieść) w okręgu Surat w stanie Gujarat, India.</p>", "Sherine": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sherin</b>.</p><p>Sherin to kobiece imię i nazwisko pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Saniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sania</b>.</p><p>Sania (lat. Sania) - rodzaj sztabotchatobrukowych przeponczotkowych skrzydeł rodziny braconiodów.</p>", "Sawina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sawin</b>.</p><b>Sawin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, od wyrazu <i>saba</i> – „zmiana, niewola, zajęcie”.", "Semiramida": "Imię Semiramida nadal jest popularne na obszarze Bliskiego Wschodu.", "Sofiia-Viktoriia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Solina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sol</b>.</p><p>Sehol X4 (dawniej JAC Jiayue X4) - kompaktowy crossover produkowany przez chińską firmę JAC Motors pod marką Sehol. Sehol X4 był krótko nazywany Sol X4 i JAC Jiayue X4 przed stworzeniem marki Sehol.</p>", "Sea": "Nazwa jednostki wymawiana jest bardzo podobnie do arabskiego słowa ṣāʿ (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;صاع&#8206;), które w <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamskiej</a> <a href=\"https://pl.wikipedia.org/wiki/Jurysprudencja\" target=\"_blank\" rel=\"noopener noreferrer\">jurysprudencji</a> również oznacza jednostkę objętości, określaną na podstawie <a href=\"https://pl.wikipedia.org/wiki/Hadis\" target=\"_blank\" rel=\"noopener noreferrer\">hadisów</a> na 2430 <a href=\"https://pl.wikipedia.org/wiki/Centymetr_sze%C5%9Bcienny\" target=\"_blank\" rel=\"noopener noreferrer\">ml</a> do 2512 ml, jest więc znacznie mniejsza od sea.", "Sheila Mae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sheila</b>.</p><p>Sheila - rodzaj wieloczęściowych robaków z rodziny Polynoidae Sheila - singl Tommy Rowe Sheila (hisz. Sheila) - postać hiszpańskiego serialu ⁇ Moje ulubione sąsiedzi ⁇ , w której grała Jaisa Esteve</p>", "Sheilla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sheila</b>.</p><p>Sheila - rodzaj wieloczęściowych robaków z rodziny Polynoidae Sheila - singl Tommy Rowe Sheila (hisz. Sheila) - postać hiszpańskiego serialu ⁇ Moje ulubione sąsiedzi ⁇ , w której grała Jaisa Esteve</p>", "Slawa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Slava</b>.</p><p>Slava Balasanov (ur. 1981, Moskwa) - amerykański muzyk i artysta.</p>", "Senta": "<b>Senta</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> głównej bohaterki <a href=\"https://pl.wikipedia.org/wiki/Lataj%C4%85cy_Holender_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">opery <i>Latający Holender</i></a> (1843) <a href=\"https://pl.wikipedia.org/wiki/Richard_Wagner\" target=\"_blank\" rel=\"noopener noreferrer\">Richarda Wagnera</a>. Od 1860 zaczęto je nadawać w <a href=\"https://pl.wikipedia.org/wiki/Niemcy\" target=\"_blank\" rel=\"noopener noreferrer\">Niemczech</a>.", "Shanika": "<p>Shanika to kobiece imię. Znani ludzie z nazwiska obejmują: Shanika Bruce (ur. 1995), kryketarka z Barbady, Shanika Karunasekera, sri Lanka inżynier Shanika Madumali (ur. 1990), sri lankański gracz rugby siedem (ur. 1991), amerykański przestępca Shanika Roberts-Odle, barbadyjska polityka Shanika Warren-Markland, brytyjska aktorka</p>", "Shayna": "<p>Shayna (jiddish: שיינא;שיינה; polski: Szejna) lub Shaina to imię kobiety pochodzące z języka jiddish, co oznacza \"piękne\" lub \"miło\" (jiddisch: שיין (sheyn), spokrewnione z nowoczesnym niemieckim schön), a także evocative z jiddish frazy \"אַ שיינע מיידל\" (\" shayne maydel\", lub \"miła dziewczyna\"). Jego hebrajskim odpowiednikiem jest Yaffa (יפה) lub Yafit (יַפִית); w latach po Holokauście nazwa Shayna (i jej arabskiej rodzeństwo, Jamila) była często...</p>", "Sophi": "<p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Siara": "Siara jest pierwszym pokarmem każdego nowo narodzonego ssaka, w tym noworodków człowieka. Unikalny skład <i>colostrum</i> ma fundamentalne znaczenie we wczesnym karmieniu potomka. W porównaniu do <a href=\"https://pl.wikipedia.org/wiki/Mleko\" target=\"_blank\" rel=\"noopener noreferrer\">mleka</a> właściwego <a href=\"https://pl.wikipedia.org/wiki/Matka\" target=\"_blank\" rel=\"noopener noreferrer\">matki</a>, siara jest szczególnie bogata w <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82ka\" target=\"_blank\" rel=\"noopener noreferrer\">białka</a>, z których większość jest mało odżywcza, ale gra ważną rolę w dojrzewaniu <a href=\"https://pl.wikipedia.org/wiki/Uk%C5%82ad_pokarmowy\" target=\"_blank\" rel=\"noopener noreferrer\">przewodu pokarmowego</a> młodych ssaków. Zawiera dużo witaminy A, sodu i <a href=\"https://pl.wikipedia.org/wiki/Chlorki\" target=\"_blank\" rel=\"noopener noreferrer\">chlorków</a>, a stosunkowo niewiele węglowodanów, potasu i tłuszczu w porównaniu z mlekiem.", "Stacie": "<p>Stacy, czasami stawiana jako Stacey, Staci, Stacie lub Stacii, jest powszechną nazwą dla kobiet i mężczyzn. Czasami jest również używana jako nazwisko.</p>", "Sara-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Senie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seni</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sen</b>.</p><p>Sen w wietnamskim może być: Gatunek wodny należący do rodziny Nelumbonaceae, w tym: Sen różowy (Nelumbo nucifera). Biały sen (Nelumbo lutea).</p>", "Susmitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Susmita</b>.</p><p>Susmita (zwane również Sushmita i Sushmitha i Sushmithak) to hindusko-sanskrityckie imię indyjskie. Wśród znanych osób z tej nazwy są: Susmita Bauri (ur. 1975), indyjska polityka Sushmita Mitra, indyjska naukowiec komputerowy Sushmita Sen (ur. 1975), indyjska aktorka, modelka i zwycięzca konkursu Miss Universe 1994 Sushmitha Singha Roy (ur. 1984), indyjskie heptatleta Susmita Bose, indyjsko-amerykańska naukowca i inżynier, profesor...</p>", "Szerin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sherin</b>.</p><p>Sherin to kobiece imię i nazwisko pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sofy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophy</b>.</p><p>Sophy jest alternatywnym pisownią kobiecej nazwy Sophie, z imienia Sophia, co oznacza \"mądre\".</p>", "Safiyya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Safiya</b>.</p><p>Safiya (arabsko: صفية, romanized: Ṣafiyya) to arabska nazwa, oznaczająca \"czystość\".</p>", "Senna": "<i><b>Senna</b></i> – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> roślin należący do rodziny <a href=\"https://pl.wikipedia.org/wiki/Bobowate\" target=\"_blank\" rel=\"noopener noreferrer\">bobowatych</a> (<i>Fabaceae</i>) z podrodziny <a href=\"https://pl.wikipedia.org/wiki/Brezylkowe\" target=\"_blank\" rel=\"noopener noreferrer\">brezylkowych</a> (<i>Caesalpinioideae</i>). Obejmuje ok. 280–300 gatunków. Występują w całej <a href=\"https://pl.wikipedia.org/wiki/Strefa_mi%C4%99dzyzwrotnikowa\" target=\"_blank\" rel=\"noopener noreferrer\">strefie międzyzwrotnikowej</a>, a nieliczne gatunki rosną także w <a href=\"https://pl.wikipedia.org/wiki/Strefy_umiarkowane\" target=\"_blank\" rel=\"noopener noreferrer\">strefach umiarkowanych</a>. <a href=\"https://pl.wikipedia.org/wiki/Zasi%C4%99g_(biogeografia)\" target=\"_blank\" rel=\"noopener noreferrer\">Zasięg</a> rodzaju obejmuje całą <a href=\"https://pl.wikipedia.org/wiki/Ameryka_Po%C5%82udniowa\" target=\"_blank\" rel=\"noopener noreferrer\">Amerykę Południową</a>, <a href=\"https://pl.wikipedia.org/wiki/Afryka\" target=\"_blank\" rel=\"noopener noreferrer\">Afrykę</a> i <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australię</a> oraz południową część <a href=\"https://pl.wikipedia.org/wiki/Ameryka_P%C3%B3%C5%82nocna\" target=\"_blank\" rel=\"noopener noreferrer\">Ameryki Północnej</a> i <a href=\"https://pl.wikipedia.org/wiki/Azja\" target=\"_blank\" rel=\"noopener noreferrer\">Azji</a>. Rodzaj najbardziej zróżnicowany jest na kontynentach amerykańskich, gdzie obecnych jest 206 gatunków. W Australii obecne są 33 gatunki, w Afryce kontynentalnej 20, na <a href=\"https://pl.wikipedia.org/wiki/Madagaskar\" target=\"_blank\" rel=\"noopener noreferrer\">Madagaskarze</a> 9, w Azji południowej występują pojedyncze gatunki. Rośliny te rosną głównie w suchych formacjach zaroślowych i leśnych, na <a href=\"https://pl.wikipedia.org/wiki/Sawanna\" target=\"_blank\" rel=\"noopener noreferrer\">sawannach</a>, w <a href=\"https://pl.wikipedia.org/wiki/Caatinga\" target=\"_blank\" rel=\"noopener noreferrer\">caatindze</a>, <a href=\"https://pl.wikipedia.org/wiki/Cerrado\" target=\"_blank\" rel=\"noopener noreferrer\">cerrado</a>, w formacjach nadbrzeżnych, nieliczne występują w <a href=\"https://pl.wikipedia.org/wiki/Wilgotny_las_r%C3%B3wnikowy\" target=\"_blank\" rel=\"noopener noreferrer\">wilgotnych lasach równikowych</a>. Liczne gatunki zostały rozprzestrzenione poza pierwotnym zasięgiem i stały się uciążliwymi <a href=\"https://pl.wikipedia.org/wiki/Gatunek_inwazyjny\" target=\"_blank\" rel=\"noopener noreferrer\">gatunkami inwazyjnymi</a>.", "Sawanna": "<b>Sawanna</b> – <a href=\"https://pl.wikipedia.org/wiki/Formacje_trawiaste\" target=\"_blank\" rel=\"noopener noreferrer\">formacja trawiasta</a> <a href=\"https://pl.wikipedia.org/wiki/Strefa_mi%C4%99dzyzwrotnikowa\" target=\"_blank\" rel=\"noopener noreferrer\">strefy międzyzwrotnikowej</a> o <a href=\"https://pl.wikipedia.org/wiki/Klimat\" target=\"_blank\" rel=\"noopener noreferrer\">klimacie</a> gorącym, z wyraźnie zaznaczonymi 3 porami roku, tj. <a href=\"https://pl.wikipedia.org/wiki/Pora_deszczowa\" target=\"_blank\" rel=\"noopener noreferrer\">deszczową</a> (ze średnią temperaturą 18–24&#160;°C) oraz dwiema <a href=\"https://pl.wikipedia.org/wiki/Pora_sucha\" target=\"_blank\" rel=\"noopener noreferrer\">porami suchymi</a>: chłodną (średnio 14–20&#160;°C) i gorącą (26–30&#160;°C, niekiedy nawet do 45&#160;°C). Sawanny bywają wykorzystywane jako naturalne <a href=\"https://pl.wikipedia.org/wiki/Pastwisko\" target=\"_blank\" rel=\"noopener noreferrer\">pastwiska</a>. Fauna zamieszkująca tę formację to głównie <a href=\"https://pl.wikipedia.org/wiki/Fitofag\" target=\"_blank\" rel=\"noopener noreferrer\">roślinożercy</a> żyjący w bardzo licznych stadach.", "Svietłana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Swietłana</b>.</p><b>Świetlana</b>, <b>Swietłana</b> – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>. Stanowi ona literackie tłumaczenie greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Fotyna\" target=\"_blank\" rel=\"noopener noreferrer\">Fotyna</a> na rosyjski. Oznacza „jasną, świetlistą”. Imię bardzo popularne w XX wieku w <a href=\"https://pl.wikipedia.org/wiki/Rosja\" target=\"_blank\" rel=\"noopener noreferrer\">Rosji</a>, na <a href=\"https://pl.wikipedia.org/wiki/Bia%C5%82oru%C5%9B\" target=\"_blank\" rel=\"noopener noreferrer\">Białorusi</a>, <a href=\"https://pl.wikipedia.org/wiki/Ukraina\" target=\"_blank\" rel=\"noopener noreferrer\">Ukrainie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Bu%C5%82garia\" target=\"_blank\" rel=\"noopener noreferrer\">Bułgarii</a>, ale spotykane także w innych krajach słowiańskich, np. na <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owacja\" target=\"_blank\" rel=\"noopener noreferrer\">Słowacji</a>; wcześniej nieistniejące lub bardzo rzadkie.", "Sorana": "<p>Sorana może odnosić się do: Sorana (Pescia), wioska w Pistoia, Toskana, Włochy Sorana beans, rodzaj beans cannellini uprawiany w Sorana Sorana Cîrstea (urodzony 1990), rumuński tenisa Sorana Păcurar (bardziej znany jako tylko Sorana) rumuński piosenkarz i autor piosenek Sorana Gurian (1913-1956), moldawski pisarz i tłumacz Marcia Servilia Sorana (około 40-66 AD), córka rzymskiego senatora Barea Soranus, część Stoic Opposition Callicore sorana, a...</p>", "Sameen": "<p>Sameen to imię. Znani ludzie z nazwiskiem to: Sameen Gul (ur. 1999), pakistański kryketar Sameen Kandanearachchi (ur. 1988), kryketar Sri Lanki</p>", "Solomiya-Mariya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sanjida": "<p>Sanjida (Bengali: সানজিদা/সনজীদা, romanizowana: Sanjida/Sanjeeda) to femininowe imię w Bangladeszu.</p>", "Saria": "<b>Saria</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐝𐐁𐐡𐐌𐐂) – imię żeńskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Sherryl": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sheryl</b>.</p><p>Sheryl to imię kobiety. Podobna nazwa Sherill może być męska lub żeńska.</p>", "Sewerina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sewer</b>.</p><b>Sewer</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/Przymiotnik\" target=\"_blank\" rel=\"noopener noreferrer\">przymiotnika</a> <i>severus</i>, 'surowy, poważny'. Należało w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnym Rzymie</a> do popularniejszych <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">cognominów</a> (przydomków). W latach 193-235 w Rzymie panowała dynastia <a href=\"https://pl.wikipedia.org/wiki/Sewerowie\" target=\"_blank\" rel=\"noopener noreferrer\">Sewerów</a>, do której należeli m.in. <a href=\"https://pl.wikipedia.org/wiki/Septymiusz_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Septymiusz Sewer</a>, <a href=\"https://pl.wikipedia.org/wiki/Karakalla\" target=\"_blank\" rel=\"noopener noreferrer\">Karakalla</a>, <a href=\"https://pl.wikipedia.org/wiki/Heliogabal_(cesarz_rzymski)\" target=\"_blank\" rel=\"noopener noreferrer\">Heliogabal</a>, <a href=\"https://pl.wikipedia.org/wiki/Aleksander_Sewer\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksander Sewer</a>. Od niego zostało następnie utworzone imię <a href=\"https://pl.wikipedia.org/wiki/Seweryn\" target=\"_blank\" rel=\"noopener noreferrer\">Seweryn</a>.", "Swiatlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sviatlana</b>.</p><p>Światlana (bieloruska: Святлана) to białoruska nazwisko kobiety i może odnosić się do: Światlanie Khakhlonowej (ur. 1984), białoruskiej pływaczki Światlane Kouhan (ur. 1980), białorski biegacz na długą metę Światlany Kudzelich (ur. 1987), białoruśki biegaczka na długę metę Śwjatlana Makshtarova (ur. 1994), białorowski-azerbajdżanski indywidualny i synchronizowany trampolinista Światłań Pirazhenka (ur. 1992), białoraśki tenisista Świjatlana...</p>", "Shanelle": "<p>Shanelle to imię kobiece. Znanymi osobami z nazwiska są: Shanelle Arjoon (urodzona w 1997 roku), trynidadyjska piłkarka Shanelle Jackson (urodzone w 1980 roku), amerykańska polityka Shanelle Nyasiase (urodzony w 1997 roku) - etyopska modelka mody w Sudanie Południowym.</p>", "Soheila": "<p>Soheila to imię żeńskie pochodzenia perskiego i może odnosić się do: Soheila Esfahani, irańskiej urodzonej artystki i edukacyjki Soheila Fors (urodzona 1967), irańsko-szwedzkiej działacki na rzecz praw kobiet i pisarki Soheila Hejab (urodzony 1990), irańskiej prawnika, politycznej aktywistki i aktywistek praw obywatelskich Soheila Jolodarzadeh (urodzono 1959), irańskiego reformisty Soheila Mansourian (urodzone 1988), irańską sportowcę wushu Soheila Sokhanvari (urodzoną 1964),...</p>", "Sariyya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sariya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saria</b>.</p><b>Saria</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐝𐐁𐐡𐐌𐐂) – imię żeńskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Syndi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Steffany": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefany</b>.</p><p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Sayra": "<p>Sayra to imię. Wśród znanych osób z tym nazwiskiem jest Sayra DeVito (fl.</p>", "Sareh": "<p>Sareh (/Sar-eh/, sاره) to perskie imię żeńskie. Wśród znanych osób z tej nazwy są: Sareh Bayat (ur. 1979), irańska aktorka, telewizyjna prezydentka i modelka Sareh Javanmardi (ur. 1984), irańskie strzelaninę paraolympijską Sareh Mansouri (ur. Zahra Seddiqi Hamedani w 1991), irański aktywista LGBTQ obecnie w korytarzu śmierci Sareh Nouri (ur. 1979), persk-amerykański projektant mody znany z modnych sukni weselnych i pasów ślubnych</p>", "Samboja": "<b>Samboja</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Sam-</i> (\"samotna, jedyna\") oraz członu <i>-boj-a</i> (\"bicie, walka\"). Oznacza \"tę, która walczy samotnie\".", "Sandra Liliana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Sophija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophia</b>.</p><p>SOPHIA (grek. - Włoski.</p>", "Sindia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Shwetha": "<p>Shweta (Devanagari: श्वेता) to indyjskie hinduskie imię dla kobiet. Sanskrit słowo śveta literycznie oznacza \"biały\".</p>", "Safiyyah": "<p>Safiya (arabsko: صفية, romanized: Ṣafiyya) to arabska nazwa, oznaczająca \"czystość\".</p>", "Su Jin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Skarlett": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Scarlett</b>.</p><p>Scarlett może oznaczać: Scarlett - rosyjsko-chińska marka handlowa wykorzystywana do sprzedaży małych maszyny domowej Sasha ⁇ Scarlett ⁇ Hostin (ur. 1993) - kanadyjska cybersportynka w StarCraft II.</p>", "Susila": "<p>Susila (sinhala: සුසිලා) to kobiece imię. Wśród znanych osób z tym nazwiskiem są: Susila Bonnerjee (zmarła w 1920 roku), lekarz i suffragista Susila Kottage (urodzona w 1957 roku), śri Lankańska aktorka Susila Kuragama (1943-2016), śri Lankowa aktorka</p>", "Sindy Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sindy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Sofiia-Olha": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sayyara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayyar</b>.</p><p>Sayyar (arabski: سیار) to męskie imię i nazwisko pochodzenia arabskiego. Do wybitnych osób z tym nazwiskiem należą:</p>", "Salimata": "<p>Salimata to kobiece nazwisko afrykańskie, forma Salima, kobieca forma arabskiego Salim, co oznacza \"bezpieczne\" lub nienaruszone. Wśród znanych osób z nazwiskiem to: Salimata Diarra (ur. 1994), malijska piłkarka Salimata Fofana (ur. 1997), niewypowiedziana judoka Salimata Koné (ur. 1990), malijska Piłkarka salimata Lam (ur. 1998).</p>", "Sophiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sophia</b>.</p><p>SOPHIA (grek. - Włoski.</p>", "Saarah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sarah</b>.</p><b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Sofia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Snizhana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Snizhana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Sumru": "<p>Sumru to arabskie słowo, które odnosi się do najwyższej części czegoś; szczytu lub szczytu.</p>", "Svytlana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Svitlana</b>.</p><p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Sara Sofia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Shihan": "<b>Shihan</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;師範) – <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie</a> słowo oznaczające: (1) instruktora, nauczyciela, trenera; (2) tytuł honorowy nauczyciela modelowego lub „nauczyciela wyznaczającego standardy”, przyznawany certyfikatem licencyjnym w japońskich sztukach walki (<a href=\"https://pl.wikipedia.org/wiki/Bud%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">budō</a>) instruktorom poziomu mistrzowskiego.", "Shakila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shakil</b>.</p><p>Shakeel lub Shakil to nazwa arabskiej etymologii, która oznacza \"piękna\". Może odnosić się do następujących osób:</p>", "Svitlana-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Svitlana</b>.</p><p>Svitlana (ukraina: Світлана) to ukraińska kobieta i może odnosić się do: Svitlana Akhadova (ur. 1993), ukraińskiej kanokę Svitlana Azarova (ur., 1976), ukraińsko-holenderskiej kompozytora współczesnej muzyki klasycznej Svitlana Bevza, ukraińskiego projektanta mody Svitlana Biedarieva, ukraińskiej historykę sztuki, artystkę i kuratorkę Svitlana Bilyayeva (ur. 1946), archeologa specjalizującego się w Ukrainie, Złotych Hordach i Osmańskim ...</p>", "Suhani": "<p>Suhani to indyjskie imienne. Suhani oznacza \"Miłośny, umiłowany lub kochany\".</p>", "Sandra Marcela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Sumia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sumi</b>.</p>Nowa koreańska szkoła była więc odpowiednikiem chińskiej tradycji <a href=\"https://pl.wikipedia.org/wiki/Caodong\" target=\"_blank\" rel=\"noopener noreferrer\">caodong</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a> chodong). Była to jedyna szkoła z dziewięciu, która nie pochodziła od mistrzów szkoły <a href=\"https://pl.wikipedia.org/wiki/Hongzhou_zong\" target=\"_blank\" rel=\"noopener noreferrer\">hongzhou</a>, czyli uczniów <a href=\"https://pl.wikipedia.org/wiki/Mazu_Daoyi\" target=\"_blank\" rel=\"noopener noreferrer\">Mazu Daoyi</a>.", "Stanisława Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Sofiia-Nataliia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Shu-Han": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shu</b>.</p><p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Sirkka": "<p>Sirkka to fińskie imię dla kobiet.</p>", "Syma": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sima</b>.</p><p>Tetraponera (lat. Tetraponer) - rodzaj drewnianych mrówek z podrodzinnego rodu Pseudomyrmecinae (Formicidae). Mieszka na drzewach, mrówki w gałęziach i domatycjach roślin.</p>", "Shpresa": "<p>Shpresa to albaniańska nazwisko dla kobiet oznaczające \"oczekiwanie\" (shpresë). Do osób nosijących nazwę Shpresa należą: Shpresa Gjongecaj (ur. 1952), albanian archeolog i numismatysta Shpresa Kureta (ur. 1959), ambasador Albanii w Polsce Shpresa Lleshaj, członek szwedzkiego pop duo Flora Cash</p>", "Shahlo": "<p>Shahla (arabsko: شَهْلَاء [ALA-LC: Shahlāʼ]; azerbaińskie: Şəhla; bengalijskie: শাহলা; indonezyjskie: Syahla; perskiego: Шаҳла; tajczyckie: Шаҳло; urdu: شَہلا; uzbekski: Shahlo) jest imieniem żeńskim używanym w całym świecie muzułmańskim. Oparty jest na kobiecej formie arabskiego przymiotnika أَشْهَل (ʾašhal) w znaczeniu \"które oczy mają شُهْلَة (šuhla) \", co podobno oznaczało \"niebieski lub zielonośwy odcień\" w klasycznym arabskim języku, lub \"czarny z pewnym błękitnością w...</p>", "Shabana": "<p>Shabana to kobiece imię i nazwisko pochodzenia arabskiego. Mieszkańcy imienia Shabana to:</p>", "Szadia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shadia</b>.</p><p>Fatma Ahmed Kamal Shaker (egypcki: فاطمة أحمد كمال شاكر), bardziej znana pod pseudonimem Shadia, (شادية Shādiyya; 8 lutego 1931 - 28 listopada 2017) była egipską aktorką i piosenkarką. Była znana z roli w komediach i dramatikach w latach 50. i 60.</p>", "Stefania Wanda": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Strzeżysława": "<b>Strzeżysława</b>, <b>Strzesława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Strzeży-</i> („strzec”) oraz członu <i>-sława</i> („sława”). Oznacza „tę, która strzeże sławy”. W źródłach poświadczone w XII wieku.", "Sudipa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sudip</b>.</p><p>Sudip to indyjskie i nepalski męskie imię. Do osób z tym nazwiskiem należą: Sudip Bandyopadhyay (ur.</p>", "Stanisława Krystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Sladjana": "<p>Slađana może odnosić się do: Slađana Božović, serbskiej piłkarki Slađana Bulatović, czarnogorska piłkarka Slađana Slađa Delibašić, serbska piłkarz Slađana Đurić, serbskiego naukowca Slađana Erić, serbskie piłkarko Slađana Golić, serbski piłkarek Slađana slađa Guduraš, boskańska piłka Slađane Milošević, serbská piłkarzka Slađana Mirković, serbska piłarka slađana Perunović, węgierka węgierka węgielka węgielska...</p>", "Sun Mi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Sakunthala": "<p>Shakuntala jest postacią z hinduistycznej epoki Mahabharata. Shakuntala lub warianty pisowni, takie jak Sacontala lub Sakuntala, mogą odnosić się do:</p>", "Sharon Daniela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sharon</b>.</p><b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Sharlota": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szarlota</b>.</p><b>Karolina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Karol\" target=\"_blank\" rel=\"noopener noreferrer\">Karol</a>. Innym żeńskim odpowiednikiem imienia Karol jest <a href=\"https://pl.wikipedia.org/wiki/Karola\" target=\"_blank\" rel=\"noopener noreferrer\">Karola</a>. Imię Karolina jest pochodzenia starogermańskiego, od słowa charal, carl.", "Sameera": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sameer</b>.</p><p>Samir (zwany również Sameer) to męskie imię, które jest powszechne w Azji Południowej, na Bliskim Wschodzie i w Azji Środkowej. W arabskim samir (سمير) oznacza \"święty\", \"społeczny\", \"lojalny\" lub \"pyszny\".</p>", "Shamila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamil</b>.</p><p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Sevinc": "<p>Sevinç jest wspólną nazwą turecką. W języku tureckim \"Sevinç\" oznacza \"radość\", \"szczęście\" lub \"zdrowość\".</p>", "Sofiia-Nadiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Souzan": "<p>Souzan (arabski: سوزان, romanized: Sūzān) jest alternatywną formą kobiecej nazwy Susan, często transkrypcją jej arabskiej wersji. Znanymi osobami z nazwiska są: Souzan Barakat (1998-2011), ofiara niemiecko-jazydzkiego zabójstwa Souzan El-Eid, libanesko-amerykański onkolog chirurgiczny piersi Souzan Fatayer (ur. 1965), palestyński-italijski tłumacz, akademik i aktywista</p>", "Solomiia-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Soniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sarojini": "<p>Sarojini to kobiece imię. Wśród znanych osób z nazwiskiem są: Sarojini Charles, Sri Lankanska tamilowa urzędnik publiczny Sarojini Naidu (1879-1949), prezydent Indii Konferencji Narodowej Sarojini Pillay (21st Century), fijianska akademicka Sarojini Sahoo (ur. 1956), indyjska pisarka feministka Sarojeni Yogeswaran (ur. 1998), Sri Lankanka polityk</p>", "Sun Hwa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Salia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sali</b>.</p><p>Sali (tur. Sali) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Shoshan": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shoshana</b>.</p><p>Shoshana (Shoshánna (h), שׁוֹשַׁנָּה) to hebrajskie imię żeńskie. Jest to nazwa co najmniej dwóch kobiet w Biblii i dzięki Σουσάννα (Sousanna) przekształciła się w takie europejskie i chrześcijańskie nazwiska, jak Susanna, Susan, Susanne, Susana, Susannah, Suzanne, Susie, Suzie, Sanna i Zuzana.</p>", "Sofiia-Anastasiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Szebora": "Wszebora po raz pierwszy została odnotowana w dokumentach w <a href=\"https://pl.wikipedia.org/wiki/1409\" target=\"_blank\" rel=\"noopener noreferrer\">1409</a>, forma Świebora – w <a href=\"https://pl.wikipedia.org/wiki/1442\" target=\"_blank\" rel=\"noopener noreferrer\">1442</a>, zaś Szabora||Siabora – w <a href=\"https://pl.wikipedia.org/wiki/1443\" target=\"_blank\" rel=\"noopener noreferrer\">1443</a>. Zdrobnieniem od tego imienia mogła być Świechna.", "Szczepana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szczepan</b>.</p><b>Szczepan</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie. Pierwotna spolonizowana forma greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>, przejęta do polszczyzny w czasach najdawniejszych, jeszcze przed ustaleniem się w języku polskim spółgłoski <i><a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_wargowo-z%C4%99bowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">f</a></i> – która była wówczas zastępowana przez <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[p]</a> lub <a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_zwarta_dwuwargowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">[b]</a> (tę drugą w zapożyczeniach niemieckich lub w wyrazach przejętych za niemieckim pośrednictwem) – w brzmieniu <b>Szczepan</b> i dopiero wtórnie sprowadzona do języka polskiego w brzmieniu <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sol Gyong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sol</b>.</p><p>Sehol X4 (dawniej JAC Jiayue X4) - kompaktowy crossover produkowany przez chińską firmę JAC Motors pod marką Sehol. Sehol X4 był krótko nazywany Sol X4 i JAC Jiayue X4 przed stworzeniem marki Sehol.</p>", "Sun Jong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Sasikala": "<b>Vivekanandan Krishnaveni Sasikala</b>, znana częściej jako <b>Sasikala</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tamilski\" target=\"_blank\" rel=\"noopener noreferrer\">tamil.</a>&#160;சசிகலா; ur. <a href=\"https://pl.wikipedia.org/wiki/18_sierpnia\" target=\"_blank\" rel=\"noopener noreferrer\">18 sierpnia</a> <a href=\"https://pl.wikipedia.org/wiki/1957\" target=\"_blank\" rel=\"noopener noreferrer\">1957</a> w Thiruthuraipoondi) – <a href=\"https://pl.wikipedia.org/wiki/Indie\" target=\"_blank\" rel=\"noopener noreferrer\">indyjska</a> polityk. Pochodzi ze społeczności Thevarów. Wpływy zawdzięcza bliskiej relacji z <a href=\"https://pl.wikipedia.org/wiki/Jayaram_Jayalalitha\" target=\"_blank\" rel=\"noopener noreferrer\">Jayalalithą</a>, której powierniczką była na przestrzeni kilku dekad. Zaangażowała się w działalność <a href=\"https://pl.wikipedia.org/wiki/Og%C3%B3lnoindyjska_Partia_Ludu_Drawid%C3%B3w\" target=\"_blank\" rel=\"noopener noreferrer\">Ogólnoindyjskiej Partii Ludu Drawidów</a> (AIADMK), odegrała istotną, zakulisową rolę w kryzysie sukcesyjnym po śmierci <a href=\"https://pl.wikipedia.org/wiki/M.G._Ramachandran\" target=\"_blank\" rel=\"noopener noreferrer\">M.G. Ramachandrana</a>. Uwikłana w liczne skandale korupcyjne, zbudowała rozległe imperium biznesowe. Po śmierci Jayalalithy jedna z głównych postaci walczących o kontrolę nad AIADMK, sekretarz generalna partii (2016–2017). Pozbawiona partyjnego członkostwa, od 2017 do 2021 odbywała karę pozbawienia wolności za korupcję w więzieniu w Bengaluru. Zaangażowała się w działalność ugrupowania Amma Makkal Munnetra Kazhagam (AMMK), podjęła też działania celem odzyskania kontroli nad AIADMK. Uwieczniona w indyjskiej <a href=\"https://pl.wikipedia.org/wiki/Kultura_popularna\" target=\"_blank\" rel=\"noopener noreferrer\">kulturze popularnej</a>, przez zwolenników określana mianem <i>chinnammy</i> (małej mateczki), wykorzystuje też tytuł <i>Puratchi Thai</i> (rewolucyjnej matki).", "Su Jeong": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Syndy": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Solomiia-Iryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Shohreh": "<p>Shohreh (perskiego: شهره) to perskie imię żeńskie oznaczające \"znane\".</p>", "Sun Hui": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Shena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shen</b>.</p><b>Shen</b> – pojęcie w tradycyjnej religii chińskiej oznaczające siłę ponadnaturalną. Może określać zarówno <a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">bóstwa</a>, <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">dusze</a> zmarłych przodków, duchy opiekuńcze konkretnych miejsc czy <a href=\"https://pl.wikipedia.org/wiki/Taoizm\" target=\"_blank\" rel=\"noopener noreferrer\">taoistycznych</a> świętych w rodzaju <a href=\"https://pl.wikipedia.org/wiki/O%C5%9Bmiu_Nie%C5%9Bmiertelnych\" target=\"_blank\" rel=\"noopener noreferrer\">Ośmiu Nieśmiertelnych</a>.", "Sayma": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saima</b>.</p><p>Saima może być imieniem kobiecym pochodzenia arabskiego lub fińskim imieniem kobiecym. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sonia-Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sabi̇ha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabih</b>.</p>Po raz pierwszy danie pojawiło się w Izraelu w latach 50. XX wieku, w miasteczku <a href=\"https://pl.wikipedia.org/wiki/Ramat_Gan\" target=\"_blank\" rel=\"noopener noreferrer\">Ramat Gan</a>. Została tam sprowadzona przez osiedlających się tam Żydów irakijskich. Nazwa potrawy pochodzi, według niektórych źródeł, od arabskiego słowa <i>sabah</i> oznaczającego \"poranek\", według innych – od nazwiska irakijskiego imigranta, który spopularyzował tę potrawę w Izraelu.", "Sharon Mae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sharon</b>.</p><b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Stefi": "<p>Stefi to kobiece imię. Znani ludzie z nazwiska to: Stefi Baum (ur. 1958), amerykański astronom Stefi Geyer (1888-1956), węgierski skrzypiec Stefi Talman (ur. 1958, szwajcarski designer obuwia</p>", "Synnøve": "<p>Święta Sunniwa (w 10. wieku; Stary Norsek: Sunnifa, z Starego angielskiego Sunngifu) jest świętym patronem norweskiego Kościoła Norweskiego diecezji Bjørgvin, a także całej zachodniej Norwegii. Sunniva była czczona wraz z bratem Albanem, który w norweskiej tradycji był zidentyfikowany z świętym Albanem, rzymskim brytyjskim świętym.</p>", "Silwija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silwia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Silvia Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Sofiia-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sriyani": "<p>Sriyani może odnosić się do Sriyani Amarasena, Sri Lankanska aktorka Sriyani Dhammika Menike, Sri Lanka wysoki skakacz Sriyani Kulawansa, Sri Lankowy obstawiarz Sriyani Wijewickrama, Sri Lanki polityk</p>", "Suhana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suhan</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suhani</b>.</p><p>Suhani to indyjskie imienne. Suhani oznacza \"Miłośny, umiłowany lub kochany\".</p>", "Sun Hee": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Satsuki": "<b>Satsuki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;さつき, サツキ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a> rzadko noszone przez mężczyzn, używane także jako nazwisko.", "Sofiia-Solomiia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Snezana": "<p>Snežana (cyrylicki: Снежана), również przetransliterowana Snezhana, jest słowiańskim, cyrkazyjskim i litewskim imieniem żeńskim, prawdopodobnie pochodzącym od sneg (\"snow\"). Jedną z interpretacji jest to, że Snežana jest nazwą pochodzenia ludowego, pochodzącą z słów \"snow\" i \"jana\".</p>", "Sygryda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigrida</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigrid</b>.</p><p>Sigrid (norw. Sigrid, pełne imię - Sigrid Solbakk Robe (norw.</p>", "Sameeha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sameeh</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sameh</b>.</p><p>Sameh (arabski: سامح) to arabskie nazwisko i męskie imię. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sandra Viviana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Sary": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sari</b>.</p><p>Sari lub saree, to ulubiona odzież indyjskiej kobiety, o rozmiarach od 4 do 9 m (czyli nawet 12 metrów) włączana w różne style. Pochodzi z subkontynentu indyjskiego i jest obecnie uważany za tradycyjny indyjski kostium.</p>", "Sonija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sandya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandy</b>.</p><p>Sandy to drugi solowy album brytyjskiej piosenkarki folkowej Sandy Denny, nagrany z producentem Trevorem Lucasem (jej przyszłym mężem) i wydany przez Island Records (ILPS 9207) w wrześniu 1972 roku.</p>", "Sosina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sos</b>.</p><b>Sos</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">fr.</a> <i>sauce</i>) – gęsty płyn, tworzony na bazie różnych składników, nadających mu odmienne smaki (ostry, łagodny, kwaśny, słodki, umami), stosowany jako dodatek do: <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99so\" target=\"_blank\" rel=\"noopener noreferrer\">mięs</a>, <a href=\"https://pl.wikipedia.org/wiki/Ryby\" target=\"_blank\" rel=\"noopener noreferrer\">ryb</a>, <a href=\"https://pl.wikipedia.org/wiki/Makaron\" target=\"_blank\" rel=\"noopener noreferrer\">makaronów</a>, <a href=\"https://pl.wikipedia.org/wiki/W%C4%99dliny\" target=\"_blank\" rel=\"noopener noreferrer\">wędlin</a>, <a href=\"https://pl.wikipedia.org/wiki/Sa%C5%82atka\" target=\"_blank\" rel=\"noopener noreferrer\">sałatek</a>, <a href=\"https://pl.wikipedia.org/wiki/Deser\" target=\"_blank\" rel=\"noopener noreferrer\">deserów</a>, <a href=\"https://pl.wikipedia.org/wiki/Kanapka\" target=\"_blank\" rel=\"noopener noreferrer\">kanapek</a> itd. W konsystencji luźniejszy od kremu. Sosy dzielą się na: gorące, zimne i <a href=\"https://pl.wikipedia.org/wiki/Majonez\" target=\"_blank\" rel=\"noopener noreferrer\">majonezowe</a>. Istnieje też inny podział, wywodzący się z <a href=\"https://pl.wikipedia.org/wiki/Kuchnia_francuska\" target=\"_blank\" rel=\"noopener noreferrer\">kuchni francuskiej</a>, klasyfikujący sosy jako pochodne jednego z pięciu <a href=\"https://pl.wikipedia.org/wiki/Sosy_bazowe\" target=\"_blank\" rel=\"noopener noreferrer\">sosów bazowych</a>.", "Shulamith": "<p>Shulamis (Hebrajskie: שולמית) lub Shulamit jest kobiece formy hebrajskiego imienia Salomona (Hebrajskim: \"Shlomo\", Hebrajskim: שְלמה), związane z słowem \"shalom\" (Hebrajsky: שָׁלוֹם), czyli \"pokój\". \"Shula\" jest skróceniem.</p>", "Shinobu": "<b>Shinobu</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;しのぶ, シノブ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">japońskie imię</a> używane zarówno przez mężczyzn, jak i kobiety.", "Slađana": "<p>Slađana może odnosić się do: Slađana Božović, serbskiej piłkarki Slađana Bulatović, czarnogorska piłkarka Slađana Slađa Delibašić, serbska piłkarz Slađana Đurić, serbskiego naukowca Slađana Erić, serbskie piłkarko Slađana Golić, serbski piłkarek Slađana slađa Guduraš, boskańska piłka Slađane Milošević, serbská piłkarzka Slađana Mirković, serbska piłarka slađana Perunović, węgierka węgierka węgielka węgielska...</p>", "Suzuka": "<p>Suzuka może odnosić się do: Suzuka (białka), gatunku białków z rodziny Carabidae Suzuka (manga), japońskiej serii manga i anime Suzuka Mountains Suzuka, Mie, miasto w prefekturze Mie, Japan Suzuka Circuit, tor wyścigowy 1000 km Suzuka, wyścig samochodów sportowych Grand Prix Japonii, Grand Prix Formuły 1 często nazywany \"Suzuka\" po miejscu Suzuka 8 godzin, wyścigi motocyklowe Suzuka 8 godziny (arcada gra) \"Światło\" Suzuka, postać z Outlaw ...</p>", "Svjetlana": "<p>Svetlana (cyrylicki: Светлана) to kobiece imię pochodzenia rosyjskiego, pochodzące od słowiańskiego słowa svet (cyrylice: свет), co oznacza \"światło\". Wśród odwrażonych form są Sveta, Svetlanka, Svetulya, Svetunya, Svetusya, Svetukha, Svetusha, Veta, Svetka i Lana.</p>", "Su Hyang": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sofiia-Oleksandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sharone": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sharon</b>.</p><b>Szaron</b>, <b>Sharon</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׁרוֹן) – hebrajskie imię stosowane dla obu płci, które oznacza dosłownie <i>żyzną równinę</i>.", "Sarangerel": "<p>Sarangerel (Mongolijczyk: Сарангэрэл) to imiona kobiece pochodzące z Mongolii. Pochodzi od mongolskiego: \"sarán\", lit.</p>", "Sofia-Ioana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Szczęsna Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Szczęsna</b>.</p><b>Szczęsna</b> – staropolskie&#8201; <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Wywodzi się od słowa \"szczęśliwa\". Żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szcz%C4%99sny\" target=\"_blank\" rel=\"noopener noreferrer\">Szczęsny</a>; jest uważana za odpowiednik znaczeniowy <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> imienia <a href=\"https://pl.wikipedia.org/wiki/Feliksa\" target=\"_blank\" rel=\"noopener noreferrer\">Feliksa</a>, <a href=\"https://pl.wikipedia.org/wiki/Felicja\" target=\"_blank\" rel=\"noopener noreferrer\">Felicja</a>. Patronem tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Zygmunt_Szcz%C4%99sny_Feli%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Zygmunt Szczęsny Feliński</a>.", "Sophie-Rose": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Sindy Vanessa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sindy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Syla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sila</b>.</p><p>Si La, znany również jako Ku Dé Xử, Khà Pé, to naród zamieszkujący północny Laos i północny Vietnam. W Wietnamie Si La jest uznawany za jedną z 54 ludności w Wietnam, liczba ludności według Populacji 2019 wynosi 909 osób.</p>", "Světlana": "Organizacja powstała we wrześniu 1948 roku w <a href=\"https://pl.wikipedia.org/wiki/Zlin\" target=\"_blank\" rel=\"noopener noreferrer\">Zlinie</a>. Doszło wówczas do spotkania b. partyzantów <a href=\"https://pl.wikipedia.org/wiki/Josef_Matou%C5%A1\" target=\"_blank\" rel=\"noopener noreferrer\">Josefa Matouša</a> i Rudolfa Lenharda z towarzyszami broni z partyzantki Jaromírem Vrbą, Josefem Burešem, braćmi Aloisem i Antonínem Doležalami oraz Antonínem Slabikiem. Dwaj pierwsi byli przedstawicielami b. dowódcy partyzanckiego <a href=\"https://pl.wikipedia.org/wiki/Josef_V%C3%A1vra-Sta%C5%99%C3%ADk\" target=\"_blank\" rel=\"noopener noreferrer\">Josefa Vávry-Staříka</a>, przebywającego we <a href=\"https://pl.wikipedia.org/wiki/Francja\" target=\"_blank\" rel=\"noopener noreferrer\">Francji</a>. Współpracował on z francuskimi służbami specjalnymi Deuxiéme Bureau. Po początkowym poparciu dla <a href=\"https://pl.wikipedia.org/wiki/Komunizm\" target=\"_blank\" rel=\"noopener noreferrer\">komunistów</a> zraził się do ich rządów i zagrożony aresztowaniem przedostał się na Zachód, gdzie postanowił utworzyć konspiracyjną organizację antykomunistyczną złożoną z b. podkomendnych z okresu okupacji niemieckiej. Została ona nazwana \"Světlana\" od imienia córki J. Vávry-Staříka. Jednakże organizacja od samego początku znajdowała się pod kontrolą czechosłowackich służb bezpieczeństwa <a href=\"https://pl.wikipedia.org/wiki/St%C3%A1tn%C3%AD_bezpe%C4%8Dnost\" target=\"_blank\" rel=\"noopener noreferrer\">StB</a>, którzy ją zinfiltrowali. Po początkowym spokojnym okresie rozbudowywania struktur już w marcu <a href=\"https://pl.wikipedia.org/wiki/1949\" target=\"_blank\" rel=\"noopener noreferrer\">1949</a> r. rozpoczęły się aresztowania członków organizacji. Od kwietnia <a href=\"https://pl.wikipedia.org/wiki/1950\" target=\"_blank\" rel=\"noopener noreferrer\">1950</a> r. trwały procesy, na których padło 16 wyroków śmierci, dot. m.in. J. Vávry-Staříka, J. Matouša i R. Lenharda (13 wykonano). Josef Vávra-Stařík został porwany przez ŠtB i wywiezieny do <a href=\"https://pl.wikipedia.org/wiki/Praga\" target=\"_blank\" rel=\"noopener noreferrer\">Pragi</a>. W kwietniu <a href=\"https://pl.wikipedia.org/wiki/1953\" target=\"_blank\" rel=\"noopener noreferrer\">1953</a> r. skazano go na karę śmierci, wykonaną 26 sierpnia tego roku.", "Sabiana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabian</b>.</p><b>Sabian</b> – <a href=\"https://pl.wikipedia.org/wiki/Kanada\" target=\"_blank\" rel=\"noopener noreferrer\">kanadyjski</a> producent <a href=\"https://pl.wikipedia.org/wiki/Talerze_perkusyjne\" target=\"_blank\" rel=\"noopener noreferrer\">talerzy perkusyjnych</a>, należy obok takich przedsiębiorstw jak <a href=\"https://pl.wikipedia.org/wiki/Avedis_Zildjian_Company\" target=\"_blank\" rel=\"noopener noreferrer\">Zildjian</a>, <a href=\"https://pl.wikipedia.org/wiki/Paiste\" target=\"_blank\" rel=\"noopener noreferrer\">Paiste</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Meinl\" target=\"_blank\" rel=\"noopener noreferrer\">Meinl</a> do liderów rynku. Przedsiębiorstwo powstało w 1981 roku w Meductic w <a href=\"https://pl.wikipedia.org/wiki/Nowy_Brunszwik\" target=\"_blank\" rel=\"noopener noreferrer\">Nowym Brunszwiku</a> z inicjatywy <a href=\"https://pl.wikipedia.org/wiki/Robert_Zildjian\" target=\"_blank\" rel=\"noopener noreferrer\">Roberta Zildjiana</a>, syna Avedisa Zildjiana III, prezesa przedsiębiorstwa Zildjian. <a href=\"https://pl.wikipedia.org/wiki/Firma\" target=\"_blank\" rel=\"noopener noreferrer\">Firma</a> Sabian pochodzi od dwóch pierwszych liter trójki dzieci właściciela firmy Sally, Billy oraz Andy.", "Shaindel": "<p>Shana lub Shanna mogą odnosić się do:</p>", "Seda Nur": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Seda</b>.</p><p>Sunsilk (rosyjski: Сансилк) - brytyjska marka środków do pielęgnacji włosów należąca do firmy Unilever.</p>", "Sumya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sumia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sumi</b>.</p>Nowa koreańska szkoła była więc odpowiednikiem chińskiej tradycji <a href=\"https://pl.wikipedia.org/wiki/Caodong\" target=\"_blank\" rel=\"noopener noreferrer\">caodong</a> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a> chodong). Była to jedyna szkoła z dziewięciu, która nie pochodziła od mistrzów szkoły <a href=\"https://pl.wikipedia.org/wiki/Hongzhou_zong\" target=\"_blank\" rel=\"noopener noreferrer\">hongzhou</a>, czyli uczniów <a href=\"https://pl.wikipedia.org/wiki/Mazu_Daoyi\" target=\"_blank\" rel=\"noopener noreferrer\">Mazu Daoyi</a>.", "Sofiia-Anhelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Serenada": "<b>Serenada</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>:", "Saly": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sali</b>.</p><p>Sali (tur. Sali) - własna nazwa; rozpowszechniona w postaci nazwisk.</p>", "Soo Ah": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Soo</b>.</p><p>Rejo Shoo, lub Rejo Sho (węgierski Soó Rezső; Soó von Bere Karoly Rezső, 1903 - 1980) - węgierska botanik, twórca własnego systemu klasyfikacji roślin połośmiennego.</p>", "Shaniqua": "<p>Shaniqua to imiona żeńskie, pochodzące z społeczności afroamerykańskiej, zyskujące popularność począwszy od lat 70. i osiągając szczyt w początkach lat 90. Często jest to przedstawiony jako prototyp \"nazywanego getta\", tj.</p>", "Snyzhana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Snizhana</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Shirou": "<p>Shiro, Shirō, Shirow lub Shirou mogą odnosić się do:</p>", "Sai Manasa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sai</b>.</p><p>Wróc oznacza: \"wrot\", \"orne\" \"jesus\" \"zbroj\" \"wrot\" \"wroto\" \"wroty\" \"wrót\" \"wrop\" \"wrob\" \"wrog\" \"wrod\" \"wróc\" \"wrotu\" \"wrost\" \"wrong\" \"wroth\" \"wrest\" \"wrott\" \"wrok\" \"wrought\" \"wrou\" \"wros\" \"wrotus\" \"wrots\" \"wrops\" \"wrosh\" \"wrough\" \"wrose\" \"wross\" \"wrast\" \"wrush\" \"wrus\" \"wrut\" \"wrup\" \"wrust\" \"wrist\" \"wrostrz\" \"wrupt\" \"wruth\" \"wrump\" \"wrug\" \"wruste\" \"wring\" \"wrash\" \"wray\" \"wrusty\" \"wror\" \"write\" \"wroker\" \"wrings\" \"wron\" \"wrun\" \"wrung\" \"wry\" \"wrang\" \"wr</p>", "Sariya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saria</b>.</p><b>Saria</b> (<a href=\"https://pl.wikipedia.org/wiki/Alfabet_deseret\" target=\"_blank\" rel=\"noopener noreferrer\">deseret</a> 𐐝𐐁𐐡𐐌𐐂) – imię żeńskie występujące w wyznaniach należących do <a href=\"https://pl.wikipedia.org/wiki/Ruch_%C5%9Bwi%C4%99tych_w_dniach_ostatnich\" target=\"_blank\" rel=\"noopener noreferrer\">ruchu świętych w dniach ostatnich</a> (mormonów).", "Shan-Shan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shan</b>.</p><p>Shan to państwo w Birmie, powołane na Shanów, jednego z ludów mieszkających w regionie. Jest to największe z 14 państw i innych podziałów administracyjnych Mjanmaru.</p>", "Sane": "<b>Scanner Access Now Easy</b> (SANE) – <a href=\"https://pl.wikipedia.org/wiki/Wieloplatformowo%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">wieloplatformowy</a> interfejs programowania aplikacji <a href=\"https://pl.wikipedia.org/wiki/Application_Programming_Interface\" target=\"_blank\" rel=\"noopener noreferrer\">API</a>, który umożliwia dostęp do większości <a href=\"https://pl.wikipedia.org/wiki/Skaner_(czytnik)\" target=\"_blank\" rel=\"noopener noreferrer\">skanerów optycznych</a>. Interfejs Sane jest rozwijany na zasadach <a href=\"https://pl.wikipedia.org/wiki/FLOSS\" target=\"_blank\" rel=\"noopener noreferrer\">FLOSS</a>, co oznacza, że każdy może pomóc w jego tworzeniu.", "Sofia-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Shanya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shany</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shani</b>.</p><p>Shani (Shan: शनि, Śani) lub Śanaiścara używane do wskazywania planety Saturn (Sao Saturn), i jest jednym z dziewięciu Czarów (Navagraha) w indyjskiej astronomii i astrologii. Shani jest także bogiem w Puranach.</p>", "Sandipani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandipan</b>.</p><p>Sandipan to męskie indyjskie imię. Może odnosić się do: Sandipan Chattopadhyay, bengalijski pisarz.</p>", "Sike": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sik</b>.</p><p>Sik to dzielnica w malezyjskim stanie Kedah. Obecnie Sik ma ludność w 2010 roku szacunkową około 63865 osób.</p>", "Sułamita": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sulamit</b>.</p><p>Shulamis (Hebrajskie: שולמית) lub Shulamit jest kobiece formy hebrajskiego imienia Salomona (Hebrajskim: \"Shlomo\", Hebrajskim: שְלמה), związane z słowem \"shalom\" (Hebrajsky: שָׁלוֹם), czyli \"pokój\". \"Shula\" jest skróceniem.</p>", "Su Yeon": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sofiia-Kateryna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sandra Yaneth": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Seifeddin": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seifeddine</b>.</p><p>Sayf al-Din (arabski: سيف الدين, romanized: Sayf al - Dīn, lit. 'Miec Wiary'), również Saif al-Din, Sayf / Saif ad-Din, lub Sayf / Sayf ud-Din itp., może odnosić się do: Sayf Al-Din Suri (zmarł 1149), Ghurid król Saif ad - Din Ghazi I (zmarła 1149), Zangid emir Mosul Ghazi II Saif ud-Din (zmarły 1180), Zangide emir Mosul al-Malik al-Adil Sayf al-'Din Abu-Bakr ibn Ayyub, lub po prostu Al-Adil I, znany również jako \"Saphadin\", (1145-1218), Ayyubid sultan Egiptu Sayf ...</p>", "Solomiia Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sharlene": "<p>Sharlene to angielskie imię żeńskie, które jest diminutiwem Charles. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sidoniia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sidonia</b>.</p><b>Sydonia</b>, <b>Sidonia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łaciny</a>, oznaczające „kobieta z miasta <i><a href=\"https://pl.wikipedia.org/wiki/Sydon\" target=\"_blank\" rel=\"noopener noreferrer\">Sydon</a></i>”. Imię to pojawiło się w <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX</a> w. Uważano niekiedy, że czeskie imię <i>Zdenka</i> jest odpowiednikiem Sydonii, niemniej rozpowszechnienie tego pierwszego imienia już w <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a>–<a href=\"https://pl.wikipedia.org/wiki/XIII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIII wieku</a> i względna rzadkość Sydonii powodują, że należy zakładać, iż imion tych nie łączy ze sobą związek.", "Saraa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Suheila": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suheil</b>.</p><p>Souhail, Suhail, Sohail lub inne warianty (arabijski: سهيل) to arabski termin powszechnie używany jako męskie imię i nazwisko. Souhail lub jego warianty mogą odnosić się do:</p>", "Sofiia-Mykhailyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Seka": "<b>Hsekju</b> albo <b>Seka</b> – znany wyłącznie z imienia władca <a href=\"https://pl.wikipedia.org/wiki/Dolny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">Dolnego Egiptu</a> z okresu predynastycznego (koniec IV tysiąclecia <a href=\"https://pl.wikipedia.org/wiki/P.n.e.\" target=\"_blank\" rel=\"noopener noreferrer\">p.n.e.</a>). Imię jego widnieje jako drugie z kolei (pierwsze jest nieczytelne) w najwyższej linii <a href=\"https://pl.wikipedia.org/wiki/Kamie%C5%84_z_Palermo\" target=\"_blank\" rel=\"noopener noreferrer\">kamienia z Palermo</a>, bazaltowej steli zawierającej roczniki od czasów mitycznych do <a href=\"https://pl.wikipedia.org/wiki/V_dynastia\" target=\"_blank\" rel=\"noopener noreferrer\">V dynastii</a>. Nie został potwierdzony w żadnym innym źródle. Jego panowanie jest zatem podważane – możliwe, że był jedynie postacią mityczną lub nawet całkowicie zmyśloną.", "Sara Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Sindie": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Su Hyun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sylweriusza": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylweriusz</b>.</p><b>Sylweriusz</b>, <b>Sylwery</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, którego patronem jest <a href=\"https://pl.wikipedia.org/wiki/Sylweriusz_(papie%C5%BC)\" target=\"_blank\" rel=\"noopener noreferrer\">papież Sylweriusz</a>.", "Sereen": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Seren</b>.</p><b>Seren</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, od słowa oznaczającego „czysty, spokojny, pogodny”. Patronem tego imienia jest św. Seren, męczennik (<a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wiek</a>).", "Sonatina": "<b>Sonatina</b> – <a href=\"https://pl.wikipedia.org/wiki/Forma_muzyczna\" target=\"_blank\" rel=\"noopener noreferrer\">forma muzyczna</a>, krótka, miniaturowa <a href=\"https://pl.wikipedia.org/wiki/Sonata\" target=\"_blank\" rel=\"noopener noreferrer\">sonata</a>, zwykle przeznaczona do celów dydaktycznych.", "Somayyeh": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Somayeh</b>.</p><p>Somayeh (arabsko: سمیه) jest perskim wymową arabskiej kobiecej nazwy Sumaya. Wśród znanych osób z imieniem: Somayeh Tohidlou (ur. 1979), irański bloger i aktywista polityczny Somayeh Mahmoudi, irański polityk i obecny członek parlamentu Iranu Somayeh Mohammadi (ur. 1980), irański członek Mujahedin-e Khalq Somayeh Abbaspour (ur. 1985), irański pałaolympijski łucznik</p>", "Stanisława Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Sharee": "<p>Sharee jest nazwą żeńską prawdopodobnie inspirowaną francuską chérie, co oznacza kochanie (od poprzedniego przyczyn czasowego chérir, do pielęgnowania). Nazwa była dobrze używana dla dziewczyn w Ameryce Północnej od połowy lat 20. do początku lat 90.</p>", "Sophie Catherine": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Songul": "<p>Songül to tureckie imię dla kobiet. \"Son+gül\" dosłownie oznacza \"ostatni róża\".</p>", "Silvia Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Samirah": "<p>Samira to imię w sanskrcie, arabskim lub perskim. W sanskrycie Sameera lub Samira (sanskrit: समीरः, romanized: samīraḥ) jest kobiece nazwisko, co oznacza \"wietr, wiatr\" lub \"Vāyu, bóstwo wiatru\".</p>", "Sofia-Mariia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Steliana": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stelian</b>.</p><p>Stelian to rumuńskie imię męskie. Znani ludzie z nazwiska to: Stelian Badea, rumunski piłkarz Stelian Burcea Stelian Isac, rumunsky piłkarze Stelian Moculescu Stelian Popescu Stelian Stancu Stelian Tănase</p>", "Shirley Milena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shirley</b>.</p><p>Shirley, Shirley (ang. Shirley) - angielskojęzyczne imię własne.</p>", "Sofia Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Sayani": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sayan</b>.</p><p>Sayan to miasto census (powieść) w okręgu Surat w stanie Gujarat, India.</p>", "Stefannia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sia</b>.</p><p>Siia Kate Izabel Furrler (ang. Sia Kate Isobelle Furler, rodzaj.</p>", "Stefania Małgorzata": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sulamit": "<p>Shulamis (Hebrajskie: שולמית) lub Shulamit jest kobiece formy hebrajskiego imienia Salomona (Hebrajskim: \"Shlomo\", Hebrajskim: שְלמה), związane z słowem \"shalom\" (Hebrajsky: שָׁלוֹם), czyli \"pokój\". \"Shula\" jest skróceniem.</p>", "Simoné": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Simon</b>.</p><p>Eugène Simon (francuski: Eugène Simon, 30 kwietnia 1848 r., Paryż - 17 listopada 1924 r., Paryża) - francuski arachnolog, karcinolog i ornitolog.</p>", "Stefania Jadwiga": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Santa Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Santa</b>.</p><p>Santa to 4-ta miasto w prowincji Ilocos Sur, w Filipinach. Według przeprowadzonego w 2000 roku badania ludności Philipin, mieście to miało populację 13 918 osób w 2 811 domach.</p>", "Saffiyah": "<p>Safiya (arabsko: صفية, romanized: Ṣafiyya) to arabska nazwa, oznaczająca \"czystość\".</p>", "Saila": "<p>Saila to imię. Wariacje obejmują Säilä.</p>", "Sappir": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sapir</b>.</p><p>Edward Sapir (ang. Edward Sapir, /səˈpɪər/; 26 stycznia 1884 - 4 lutego 1939) - amerykański lingwist i antropolog.</p>", "Su Ann": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sun Ae": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Sapira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sapir</b>.</p><p>Edward Sapir (ang. Edward Sapir, /səˈpɪər/; 26 stycznia 1884 - 4 lutego 1939) - amerykański lingwist i antropolog.</p>", "Sreelekha": "<p>Sreelekha to indyjskie imię. Wśród znanych osób z nazwiskiem są: Sreelekha Mitra (ur. 1971), indyjska aktorka bengalijska w filmie i telewizji Sreelekha Mukherji, indyjska bengalijka R.</p>", "Sofia-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "San San": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>San</b>.</p><p>San może oznaczać: San City San Francisco</p>", "Sofiia-Evelina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Su-Chuan": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sameena": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sameen</b>.</p><p>Sameen to imię. Znani ludzie z nazwiskiem to: Sameen Gul (ur. 1999), pakistański kryketar Sameen Kandanearachchi (ur. 1988), kryketar Sri Lanki</p>", "Stella-Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stella</b>.</p><b>Stella</b>, <b>Stela</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego gwiazdę. Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Estella_(m%C4%99czennica)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Stella</a>, żyjąca w <a href=\"https://pl.wikipedia.org/wiki/Galia\" target=\"_blank\" rel=\"noopener noreferrer\">Galii</a> w <a href=\"https://pl.wikipedia.org/wiki/III_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">III wieku</a>. Stella występuje w <i><a href=\"https://pl.wikipedia.org/wiki/Fantazy\" target=\"_blank\" rel=\"noopener noreferrer\">Fantazym</a></i> <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>, a jako imię chrzestne była notowana w Polsce co najmniej od 1820 roku.", "Sofia Alejandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Sholeh": "<p>Sholeh (arabski شعله) może odnosić się do:</p>", "Synne": "<p>Święta Sunniwa (w 10. wieku; Stary Norsek: Sunnifa, z Starego angielskiego Sunngifu) jest świętym patronem norweskiego Kościoła Norweskiego diecezji Bjørgvin, a także całej zachodniej Norwegii. Sunniva była czczona wraz z bratem Albanem, który w norweskiej tradycji był zidentyfikowany z świętym Albanem, rzymskim brytyjskim świętym.</p>", "Sun Sim": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Sakhile": "<p>Sakhile to afrykańska nazwa, która może odnosić się do: Sakhile, piosenkarka w muzyce Ndebele Sakhile Dube, zimbabwskiej królowej piękności Sakhile Nyoni, zimbabwiańskiego pilota Sakhile, Mpumalanga miasto w pobliżu Standerton, Afryka Południowa</p>", "Saamiya": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samiya</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samia</b>.</p><p>Samia - rodzaj szczurów skrzydeł z rodziny pawińskookąt i podrodzin Arsenurinae.</p>", "Solomiia-Vasylyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sofiia Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Slawomira": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sławomir</b>.</p><b>Sławomir</b>, <b>Sławimir</b>, <b>Sławomier</b>, <b>Sławmir</b> – staropolskie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię pochodzenia słowiańskiego</a>, złożone z członów <i>Sławo-</i> („sława, sławić”) i <i>-mir</i> („pokój, spokój, dobro, świat”). Imię to prawdopodobnie znaczyło tyle, co „ten, który zdobywa sławę poprzez pokój, pokojowe zachowanie, zaprowadzanie porządku, spokoju” (w przeciwieństwie do imion typu <a href=\"https://pl.wikipedia.org/wiki/Borzys%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Borzysław</a>, w których sława zdobywana jest w walce).", "Soffiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Song Sun": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Suneeta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suneet</b>.</p><p>Suneet (Devanagari: सुनीत) również napisana jako Sunit, to indyjskie męskie imię. Jest to słowo sanskryckie męskie, które oznacza \"ten, kto ma dobre zachowania/etyki\" lub \"ten, który jest dobrze uprawiany\".</p>", "Suzanne Marie": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Suzanne</b>.</p><p>Susan - kobiece imię, patrz Susanna Susan - krater na Księżycu Susan - pies Elizabety II ⁇ Suzanne ⁇ (piosenka Leonarda Coena)</p>", "Sandy Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandy</b>.</p><p>Sandy to drugi solowy album brytyjskiej piosenkarki folkowej Sandy Denny, nagrany z producentem Trevorem Lucasem (jej przyszłym mężem) i wydany przez Island Records (ILPS 9207) w wrześniu 1972 roku.</p>", "Simona-Alexandra": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Simona</b>.</p><b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Su Bin": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sofronia": "<b>Sofronia</b> – włoskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z elementów <i>sōs</i>- (\"zdrowy\") i -<i>phron</i> (\"duch, umysł\"), oznaczające kobietę mądrą, rozumną.", "Shamima": "<p>Shamima to kobiece arabskie imię pochodzące z arabskiego: شميمه oznacza \"słodki zapach\". Wśród znanych osób, które nosiły tę nazwę, są Shamima Akhtar (1957 - 2018), Bangladesza, śpiewająca w rewizji Shamima Akhar Tulee (ur. 1974), Bangladesz, artystka walki, Shamima Akter Liza (ur. 1989), Bangladesh International Master, Shamima Ali, fijski polityczny aktywista, Shamima Begum (ur. 1999), brytyjska kobieta, która opuściła Wielką Brytanię w wieku 15 lat, aby dołączyć do ISIL...</p>", "Sung Hee": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sara-Natalia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Suneetha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suneeta</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Suneet</b>.</p><p>Suneet (Devanagari: सुनीत) również napisana jako Sunit, to indyjskie męskie imię. Jest to słowo sanskryckie męskie, które oznacza \"ten, kto ma dobre zachowania/etyki\" lub \"ten, który jest dobrze uprawiany\".</p>", "Sindiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Souraya": "<p>Soraya (perskiej: ثریا) to kobiece imię arabskie i perskie. Pochodzi od arabskiej nazwy gromady gwiazd Plejady, Thurayyā lub Suraya (arabski: ثُرَيَّا).</p>", "Simonne": "<p>Simone i Simona mają nazwiska, które w zależności od języka mogą być używane jako męskie lub żeńskie nazwiska. Pochodząc z greckiego tłumaczenia hebrajskiego imienia Szymon, nazwa stała się popularna z powodu chrześcijaństwa Europy i biblijnych postaci takich jak Simeon (syn Jakuba) i Simeon (Ewangelia Łukasza).</p>", "Sabina Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sabina</b>.</p><b>Sabina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> męskiego <a href=\"https://pl.wikipedia.org/wiki/Sabin\" target=\"_blank\" rel=\"noopener noreferrer\">Sabin</a>.", "Sofiia-Stefaniia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sonia Patricia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sofiia-Melaniia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Santhi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Santi</b>.</p><p>Giorgio Santi (italijsky: Giorgio santi; 1746 - 1822) - włoski botanik.</p>", "Snieżanna": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Śnieżana</b>.</p><b>Śnieżka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie. Ma ono związek z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_serbsko-chorwacki\" target=\"_blank\" rel=\"noopener noreferrer\">serbsko-chorwackim</a> imieniem Sniega, które stanowiło dwuczłonowe imię złożone z członu <i>S-</i> i <i>-niega</i>, por. <a href=\"https://pl.wikipedia.org/wiki/Dobroniega\" target=\"_blank\" rel=\"noopener noreferrer\">Dobroniega</a>.", "Sorina-Narcisa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sorina</b>.</p><p>Sorina to zarówno kobiece rumuńskie imię i nazwisko. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sanella": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sanela</b>.</p><p>Sanela to bosniackie imię i nazwisko, które mają następujące kobiety: Sanela Diana Jenkins (ur. 1973), bosniacka przedsiębiorca i filantropka Sanela Knezović (ur. 1979), bosniackiej chorwaty, Sanela Redžić, bosniacka sportowca z niepełnosprawnością, Sanela Sijerčić, bosnjacka piosenkarka ludowa.</p>", "Stanisława Teresa": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stanisława</b>.</p><b>Stanisława</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> żeńskie, złożone z członu <i>Stani-</i> („stać, stać się, stanąć”) oraz członu <i>-sława</i> („sława”). Wywodzi się od słów oznaczających „stań się sławną”. Męskie odpowiedniki: <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Stasław</a>, <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Tasław</a>. W źródłach polskich poświadczone od XIII wieku.", "Sofia-Georgiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Sihle": "<p>Sihle to imię Nguni, które oznacza \"piękne\". Nazwa jest skróceniem Siphesihle, co oznacza \"piękny dar\".</p>", "Saifa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saif</b>.</p><p>Saif, Seif, Sayf lub Seife (arabijski: سيف, amharic: ሰይፍ) to słowo w językach semitycznych oznaczające \" miecz \", a jako nazwisko, \"bojownik\" lub \"ochroniarz [niczegoś] \". Konogatami są asyryjski neoaramejski: ⁇ (Sayfo), hebrajski: סַיִף (sáyip̄), aramejski cesarski: סִיְפָּא (saypā) i prawdopodobnie starożytny egipski (koptycki: ⁇) sēfe.</p>", "Samiia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Samia</b>.</p><p>Samia - rodzaj szczurów skrzydeł z rodziny pawińskookąt i podrodzin Arsenurinae.</p>", "Sundara": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sundar</b>.</p><p>Sundar (Devanagari: सुन्दर) to przymiot oznaczający atrakcyjność, piękno, dobro, przystojność lub przyjemność. Pochodzi z sanskrytu.</p>", "Sita Devi": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sita</b>.</p><p>Sita (zwane również Seeta lub Seetha /Sītā/, co oznacza \"płynę\") jest postacią kobiety z epiki Ramayana. Była żoną boga Ramy (przyjaciel Wisnu) i jest wyobraźnią Lakshmi, żony bogactwa i żony Wisnu.</p>", "Sylvija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sylvia</b>.</p><p>Sylvia (lat. Sylvia) - gatunek ptaków z rodziny sławków (Sylviidae).</p>", "Sofyia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sarrah": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sarah</b>.</p><b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Sherina": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sherin</b>.</p><p>Sherin to kobiece imię i nazwisko pochodzące z Persu. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sofiia-Olena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Stefania-Elena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Shamilla": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamila</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shamil</b>.</p><p>Shamil (arabsko: شَامِل shāmil) jest stosunkowo rzadkie arabskie imię mężczyzny. Nazwa pochodzi zwykle od przymiotnika, które ma kilka związanych znaczeń z arabskiego \"pełny, wszechstronny, uniwersalny\", ale może również oznaczać \"ocieleśnienie, głębokie\".</p>", "Songa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Song</b>.</p><p>Song jest dystrykiem w malezyjskim stanie Sarawak. Obecnie Song ma w 2010 roku około 20046 mieszkańców.</p>", "Sandija": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandi</b>.</p><p>Sandi jest miastem i miejscem położenia urzędu (municipal board) w hrabstwie Hardoi w stanie Uttar Pradesh, India.</p>", "Saija": "<p>Saija to nazwisko i kobiece imię używane w Finlandii. Znanymi osobami z nazwiska są: Saija Tarkki (ur. 1982), fiński hokejista lodowy Saija Varjus (ur. 1965), fiński muzyka</p>", "Szimona": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Szymona</b>.</p><b>Szymona</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i><b>שמעון</b></i> <i>Szim'eon</i> – \"<a href=\"https://pl.wikipedia.org/wiki/B%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">Bóg</a> wysłuchał\") – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Szymon\" target=\"_blank\" rel=\"noopener noreferrer\">Szymon</a>, pochodzenia biblijnego. Innym, bardziej rozpowszechnionym w Polsce żeńskim odpowiednikiem imienia Szymon jest <a href=\"https://pl.wikipedia.org/wiki/Ksymena\" target=\"_blank\" rel=\"noopener noreferrer\">Ksymena</a>, zapośredniczona przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">język hiszpański</a>.", "Sandia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sandi</b>.</p><p>Sandi jest miastem i miejscem położenia urzędu (municipal board) w hrabstwie Hardoi w stanie Uttar Pradesh, India.</p>", "Sara Manuela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Sonia-Rebeca": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sonia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sophie Barbara": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Sharron": "<p>Sharon (hebrajski: שָׁרוֹן Šārôn 'przestrzenię'), również pisowniany jako Saron, jest nazwiskiem hebrajskim. W obszarze anglojęzycznych Sharon jest obecnie głównie nazwą żeńską, ale historycznie była również używana jako męska nazwisko.</p>", "Sabi̇re": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sabir</b>.</p><b>Lingua franca</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> „język Franków”) – w szerokim znaczeniu: <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> o charakterze międzynarodowym lub międzygrupowym, używany jako środek porozumiewania się na obszarach wielojęzycznych i między osobami niemającymi wspólnego języka ojczystego.", "Shanni": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shanny</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shany</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shani</b>.</p><p>Shani (Shan: शनि, Śani) lub Śanaiścara używane do wskazywania planety Saturn (Sao Saturn), i jest jednym z dziewięciu Czarów (Navagraha) w indyjskiej astronomii i astrologii. Shani jest także bogiem w Puranach.</p>", "Stefany Paola": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefany</b>.</p><p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Sara Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sara</b>.</p><b>Sara</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> שָׂרָה, spokrewnione z <a href=\"https://pl.wikipedia.org/wiki/Dialekt_babilo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">babil.</a> <i>Szarratu</i> – „księżniczka”, postać wysokiej rangi) – postać <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">biblijna</a>, bohaterka <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rodzaju\" target=\"_blank\" rel=\"noopener noreferrer\">Księgi Rodzaju</a>, córka <a href=\"https://pl.wikipedia.org/wiki/Terach\" target=\"_blank\" rel=\"noopener noreferrer\">Teracha</a>, żona <a href=\"https://pl.wikipedia.org/wiki/Abraham\" target=\"_blank\" rel=\"noopener noreferrer\">Abrahama</a>, matka <a href=\"https://pl.wikipedia.org/wiki/Izaak\" target=\"_blank\" rel=\"noopener noreferrer\">Izaaka</a>. Pierwotnie jej imię brzmiało Sarai (hebr. שָׂרָי), według Księgi Rodzaju (Rdz 17,15) Bóg zmienił je na Sara w ramach przymierza zawartego po tym, jak jej niewolnica <a href=\"https://pl.wikipedia.org/wiki/Hagar_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Hagar</a> doczekała się z jej mężem syna <a href=\"https://pl.wikipedia.org/wiki/Izmael\" target=\"_blank\" rel=\"noopener noreferrer\">Izmaela</a>.", "Saloméa": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salome</b>.</p><p>Salome (Hebrajskie: שְלוֹמִית, Shlomit, związane z שָׁלוֹם, Shalom oznaczający pokój, Σαλώμη) znana również jako Salome III była żydowska księżniczką, córką Herodowa II, syna Heroda Wielkiego z księżniczą Herodias. Była niewiastką Heroda Wielkiego i córką własną Heroda Antipa.</p>", "Shu-Yu": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shu</b>.</p><p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Sofiia-Tereza": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sheryll": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sheryl</b>.</p><p>Sheryl to imię kobiety. Podobna nazwa Sherill może być męska lub żeńska.</p>", "Sofia-Florina": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Shaula": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shaul</b>.</p><p>Saul to imię i nazwisko, które mogą odnosić się do: Nazwa: Shaul (Hebrajskie שָׁאוּל Šāʼûl \"proszony, modlił się o\"), zwykle nazywany Saul w języku angielskim, pierwszy król Izraela w hebrajskiej Biblii Shaul, syn Symeona (syn Jakuba) w Księdze Rodzaju Shaul Amor (1940-2004), izraelski polityk Shaul Avigur (1899-1978), założyciel izraelskiej wspólnoty wywiadowczej Shaul Ben-Tzvi, hebrajskie imię Paula Shulmana (1922-1994), drugi dowódca...</p>", "Silvia Juliana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Sinegugu": "<p>Sinegugu to unisex. Znanymi osobami z nazwiska są: Amanda Sinegugu Dlamini (ur. 1988), gracz piłkarski i komentator Południowoafrykański Sinegugu Maseko (ur. 1997), kryketarz Południeafrykańska</p>", "Slavomíra": "<b>Sławomira</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Sławo-</i> („sława”) i <i>-mira</i> („pokój, spokój, dobro”). Mogło oznaczać „sławiąca pokój”. Notowane w źródłach od <a href=\"https://pl.wikipedia.org/wiki/1386\" target=\"_blank\" rel=\"noopener noreferrer\">1386</a> roku, występujące także w wariantach <i><b>Sławomirz</b></i> (fem.) i <i><b>Sławomirza</b></i>. Przykładowe dawne możliwe zdrobnienia: Sławna, Sławka, Sławnica, Sławocha.", "Sophie-Charlotte": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sophie</b>.</p><p>Sophie Xeon (ang. Sophie Xeon; 17 września 1986, Glasgow - 30 stycznia 2021, Atena), znana mononimnie jako Sophie (ang.</p>", "Sthefania": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sushmitha": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sushmita</b>.</p><p>Susmita (zwane również Sushmita i Sushmitha i Sushmithak) to hindusko-sanskrityckie imię indyjskie. Wśród znanych osób z tej nazwy są: Susmita Bauri (ur. 1975), indyjska polityka Sushmita Mitra, indyjska naukowiec komputerowy Sushmita Sen (ur. 1975), indyjska aktorka, modelka i zwycięzca konkursu Miss Universe 1994 Sushmitha Singha Roy (ur. 1984), indyjskie heptatleta Susmita Bose, indyjsko-amerykańska naukowca i inżynier, profesor...</p>", "Sol Maria": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sol</b>.</p><p>Sehol X4 (dawniej JAC Jiayue X4) - kompaktowy crossover produkowany przez chińską firmę JAC Motors pod marką Sehol. Sehol X4 był krótko nazywany Sol X4 i JAC Jiayue X4 przed stworzeniem marki Sehol.</p>", "Shanie": "<p>Shana lub Shanna mogą odnosić się do:</p>", "Sergia": "<b>Sergia</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Sergiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Sergiusz</a> wywodzącego się od nazwy <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu <i>Sergia</i>. Patronką imienia jest <a href=\"https://pl.wikipedia.org/wiki/Julia_Rapiej\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Maria Sergia od Matki Bożej Bolesnej</a>, siostra sakramentka, wspominana razem z <a href=\"https://pl.wikipedia.org/wiki/Adela_Mardosewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Marią Stellą</a> i innymi towarzyszkami.", "Solomiia-Anna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Solomiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Shu-Ting": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Shu</b>.</p><p>Shu (; oznacza \"nieprzytomny\") był jednym z pierwotnych bogów w Egipcie, wcielającym się w powietrze, w mieście Heliopolis. Był bogiem w Wielkiej Dziewiątej Górze Heliopolis.</p>", "Su Young": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>", "Sung Hui": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sung</b>.</p><p>Występujące lub wyższe, lub zbiorcze, drzewa (dwuczęściowe: Ficus racemosa, czyli Ficus glomerata Roxb., 1802) to duże, szybkie, drzewnice z rodziny Moraków. Wady rosną w tropikach i subtropikach w miejscach oświeconych lasów, głównie przy brzegu jezior, jezior i rzek.</p>", "Sandra Lorena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sandra</b>.</p><b>Sandra</b> – żeńskie imię powstałe jako usamodzielnione zdrobnienie imienia <a href=\"https://pl.wikipedia.org/wiki/Aleksandra\" target=\"_blank\" rel=\"noopener noreferrer\">Aleksandra</a>; może stanowić również zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Kasandra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Kasandry</a>. W Polsce imię Sandra zaczęło być sporadycznie nadawane prawdopodobnie w latach 20 <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX</a> w., a większą popularność zdobyła w latach osiemdziesiątych XX w.; obecnie nadawalność tego imienia wykazuje tendencję spadkową. Wśród imion nadawanych nowo narodzonym dzieciom Sandra zajmuje aktualnie 61. miejsce w grupie imion żeńskich.", "Silvia-Mihaela": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Silvia</b>.</p><p>Królowa Silvia (szwedz. Silvia, Sveriges Drottning), urodzona Silvia Renata Zommertlatt (niem.</p>", "Sanah": "Pseudonim „sanah” powstał po skróceniu angielskiej wersji pierwszego imienia piosenkarki – Susannah (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_polski\" target=\"_blank\" rel=\"noopener noreferrer\">po polsku</a> „Zuzanna”). Przedtem występowała pod pseudonimem „Ayreen” (po polsku „Irena”), pochodzącym od jej drugiego imienia.", "Simple": "<b>Simple SA</b> – polski producent rozwiązań informatycznych oferujący systemy <a href=\"https://pl.wikipedia.org/wiki/Planowanie_zasob%C3%B3w_przedsi%C4%99biorstwa\" target=\"_blank\" rel=\"noopener noreferrer\">ERP</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_relacjami_z_klientami\" target=\"_blank\" rel=\"noopener noreferrer\">CRM</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_procesami_biznesowymi\" target=\"_blank\" rel=\"noopener noreferrer\">BPM</a>, <a href=\"https://pl.wikipedia.org/wiki/Zarz%C4%85dzanie_zasobami_ludzkimi\" target=\"_blank\" rel=\"noopener noreferrer\">HRM</a> i <a href=\"https://pl.wikipedia.org/wiki/Business_Intelligence\" target=\"_blank\" rel=\"noopener noreferrer\">BI</a>. W latach 2000–2022 roku Simple SA była notowana na <a href=\"https://pl.wikipedia.org/wiki/Gie%C5%82da_Papier%C3%B3w_Warto%C5%9Bciowych_w_Warszawie\" target=\"_blank\" rel=\"noopener noreferrer\">Giełdzie Papierów Wartościowych w Warszawie</a>.", "Sancia": "<p>Sanchia lub Sancia to kobiece imię pochodzące z hiszpańskiego i portugalskiego pochodzenia z łaciny sanctus lub sancta, co oznacza święty lub święty. Nazwa, która ma wiele form, jest kobiecością hiszpańskiego i portugalskiego imienia Sancho.</p>", "Sofi̇a": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sofya</b>.</p><p>Sophia, również napisana Sofia, jest kobiece imię, z greckiego Σοφία, Sophía 'Mądrość'. Do innych form są Sophie, Sofiya, Sofija, Sophy, Sophea i Sofie.</p>", "Sairah": "<p>Sara to powszechne kobiece imię hebrajskiego pochodzenia. Jego popularność wynika z biblijnej matrycy, Sary, żony Abrahama i głównej postaci w religii abrahamskich.</p>", "Shulin": "Populacja dzielnicy Shulin w 2016 roku liczyła 184&#160;400 mieszkańców – 92&#160;336 kobiet i 92&#160;064 mężczyzn. Liczba gospodarstw domowych wynosiła 66&#160;035, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,79 osób.", "Sofia-Ştefania": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Skarletta": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Skarlett</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Scarlett</b>.</p><p>Scarlett może oznaczać: Scarlett - rosyjsko-chińska marka handlowa wykorzystywana do sprzedaży małych maszyny domowej Sasha ⁇ Scarlett ⁇ Hostin (ur. 1993) - kanadyjska cybersportynka w StarCraft II.</p>", "Ségolène": "<b>Segolena</b>, Zygolena – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, pierwotnie stanowiące spieszczoną formę <a href=\"https://pl.wikipedia.org/wiki/Zyglinda\" target=\"_blank\" rel=\"noopener noreferrer\">Zyglindy</a> (<i>Seglinde //Siglinde</i>), imienia złożonego z członów <i>sig</i> – \"zwycięstwo\" i <i>lind</i> – \"tarcza ochronna\". Patronką tego imienia jest św. Segolena (Zygolena), <a href=\"https://pl.wikipedia.org/wiki/Opat\" target=\"_blank\" rel=\"noopener noreferrer\">ksieni</a> z Troclar (w pobliżu <a href=\"https://pl.wikipedia.org/wiki/Albi\" target=\"_blank\" rel=\"noopener noreferrer\">Albi</a>).", "Stefania Irena": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Stefania</b>.</p><b>Stefania</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Stefan\" target=\"_blank\" rel=\"noopener noreferrer\">Stefan</a>.", "Sarah-Louise": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sarah</b>.</p><b>Sara</b>, z języka angielskiego <b>Sarah</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, oznacza: „księżniczka”.", "Salomeea": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Salomea</b>.</p><b>Salomea</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a>. Wywodzi się, podobnie jak imię męskie <a href=\"https://pl.wikipedia.org/wiki/Salomon_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Salomon</a>, od hebrajskiego słowa <i>šalom</i> oznaczającego „pokój”, „pomyślność”. Judejska księżniczka <a href=\"https://pl.wikipedia.org/wiki/Salome_III\" target=\"_blank\" rel=\"noopener noreferrer\">Salome</a> tańcem skłoniła <a href=\"https://pl.wikipedia.org/wiki/Herod_Antypas\" target=\"_blank\" rel=\"noopener noreferrer\">Heroda</a> do wydania wyroku na <a href=\"https://pl.wikipedia.org/wiki/Jan_Chrzciciel\" target=\"_blank\" rel=\"noopener noreferrer\">Jana Chrzciciela</a>. W Polsce imię to zanotowano w XII wieku. Nosiły je m.in. księżniczki piastowskie.", "Sędzisława": "<b>Sędzisława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Sędzi-</i> („sądzić”) oraz członu <i>-sława</i> („sława”). Być może oznaczało „ta, której sądzona jest sława”. Imię wystąpiło w średniowiecznych dokumentach w 1250 r., a w męskiej formie w 1211.", "Sofiia-Marta": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sofia-Claudia": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofia</b>.</p><p>Sofia (Bulgarska: София Sofiya), jest stolicą i największym miastem Republiki Bułgarii z populacją 1.270.010 (jest 14 największym miejskim w Unii Europejskiej), a populacją 1.386.702 w miejskim regionie, Miasto Stoliczne. Miasto znajduje się w zachodniej Bułgarii, w strefie pod wodą Gór Vitosha, i jest centrum administracyjnym, kulturalnym, gospodarczym i edukacyjnym tego kraju, jest Beta-Miejskim Światem.</p>", "Serwaa": "<p>Serwaa to zarówno żeniczne imię i nazwisko z Ghany. Do wybitnych osób z tym nazwiskiem należą:</p>", "Sathi": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sati</b>.</p><p>Sati może odnosić się do: Sati (boża) Sati (stałe) Świadomość (sammā-sati) Cztery myśli (satipaṭṭhāna)</p>", "Shanaia": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shanai</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Shana</b>.</p><p>Shakugan no Shana (jap. 灼眼のシャナ Сякуган но Сяна), znana również jako po prostu Сяна - seria romansów ⁇ light-novel ⁇ napisanych przez Yasitiro Takahassi i ilustrujących Noidezi Itō, a także powiązanych z nimi utworów anime i manga.</p>", "Stephanny": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefanny</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Stefany</b>.</p><p>Stephanie lub Stefanie to imię kobiety pochodzące od greckiego imienia Στέφανος (Stephanos), co oznacza \"krąg, żarlandę, królową lub koronę świąteczną\". W innych językach znajdują się Stefanie niemiecka, Stefania włoska, czeska, polska i rosyjska, Estefânia portugalska (choć używanie tej wersji stało się rzadkie, a powszechnie używane są angielskie i francuskie wersje) oraz Estefanía hiszpańskie.</p>", "Sun Maya": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sun</b>.</p><p>Sun (rosyjski Słońce): The Sun - brytyjski tabloid, założony w 1964 roku.</p>", "Saeeda": "<p>Saida, Saidah (arabski: سَعِيدة saʽīdah) również napisana jako Sayda, Saeeda lub Sayeeda, jest kobiecową formą arabskiego męskiego nazwiska Sa'id. Saida to kurdyjskie imię, oznaczające \"kochanie matki\".</p>", "Sofiia-Khrystyna": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sabai": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Saba</b>.</p><b>Sabbas, Sabas, Saba</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">aramejskiego</a>, od <i>saba</i> – „starzec, dziad, dziadek”. Jego patronem jest <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99ty_Sawa\" target=\"_blank\" rel=\"noopener noreferrer\">święty Saba (Sawa)</a>, najważniejszy święty w <a href=\"https://pl.wikipedia.org/wiki/Serbski_Ko%C5%9Bci%C3%B3%C5%82_Prawos%C5%82awny\" target=\"_blank\" rel=\"noopener noreferrer\">Serbskiej Cerkwi</a>, a także inni święci, również katoliccy, w liczbie co najmniej piętnastu. <i><b>Sawa</b></i> zaś jest nowogrecką formą imienia, występującą na obszarze chrześcijaństwa prawosławnego, od której być może pochodzą m.in. takie nazwiska, jak Sawa, Sawka, Sawczyn, <a href=\"https://pl.wikipedia.org/wiki/Sawiccy\" target=\"_blank\" rel=\"noopener noreferrer\">Sawicki</a>.", "Sola": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sol</b>.</p><p>Sehol X4 (dawniej JAC Jiayue X4) - kompaktowy crossover produkowany przez chińską firmę JAC Motors pod marką Sehol. Sehol X4 był krótko nazywany Sol X4 i JAC Jiayue X4 przed stworzeniem marki Sehol.</p>", "Sofiia-Nikol": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sofiia</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Zofia</b>.</p><b>Zofia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Pochodzi od słowa σοφία (<i>sophía</i>) oznaczającego „mądrość”.", "Sigryda": "<p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigrida</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sigrid</b>.</p><p>Sigrid (norw. Sigrid, pełne imię - Sigrid Solbakk Robe (norw.</p>", "Sindy Tatiana": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Sindy</b>.</p><p style=\"color:var(--faint);font-size:.92em\">Wariant zapisu imienia <b>Sindi</b>.</p><p>Sindi jest miastem i miejscem miejscowości Wardha w stanie Maharashtra w Indiach.</p>", "Su-Ling": "<p style=\"color:var(--faint);font-size:.92em\">Imię złożone; pierwszy człon: <b>Su</b>.</p><p>Sukhoi (rosyjski: Сухой) to rosyjska firma produkująca duże samoloty wojskowe. Założona przez Pavla Osipovicha Sukhoi w 1939 roku pod nazwą Biuro Projektowe Sukhoi (OKB-51, biuro projektowe, prefix Su), obecnie znane jako Firma Sukhoi.</p>"};
